window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["nasai_4"] = {"2001":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبٍ أَنَّهُ أَخْبَرَهُ أَنَّ أَبَاهُ كَعْبَ بْنَ مَالِكٍ كَانَ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا نَسَمَةُ الْمُؤْمِنِ طَائِرٌ فِي شَجَرِ الْجَنَّةِ حَتَّى يَبْعَثَهُ اللَّهُ عَزَّ وَجَلَّ إِلَى جَسَدِهِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari ['Abdurrahman bin Ka'b] bahwasanya bapaknya [Ka'b bin Malik] pernah bercerita dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \" Ruh seorang mukmin beterbangan di pepohonan surga hingga Allah Azza wa Jalla membangkitkannya ke dalam jasadnya pada hari kiamat.\""},"2002":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُلَيْمَانُ وَهُوَ ابْنُ الْمُغِيرَةِ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَكُنَّا مَعَ عُمَرَ بَيْنَ مَكَّةَ وَالْمَدِينَةِ أَخَذَ يُحَدِّثُنَا عَنْ أَهْلِ بَدْرٍ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُرِينَا مَصَارِعَهُمْ بِالْأَمْسِ قَالَ هَذَا مَصْرَعُ فُلَانٍ إِنْ شَاءَ اللَّهُ غَدًا قَالَ عُمَرُ وَالَّذِي بَعَثَهُ بِالْحَقِّ مَا أَخْطَئُوا تِيكَ فَجُعِلُوا فِي بِئْرٍ فَأَتَاهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَادَى يَا فُلَانُ بْنَ فُلَانٍ يَا فُلَانُ بْنَ فُلَانٍ هَلْ وَجَدْتُمْ مَا وَعَدَ رَبُّكُمْ حَقًّا فَإِنِّي وَجَدْتُ مَا وَعَدَنِي اللَّهُ حَقًّا فَقَالَ عُمَرُ تُكَلِّمُ أَجْسَادًا لَا أَرْوَاحَ فِيهَا فَقَالَ مَا أَنْتُمْ بِأَسْمَعَ لِمَا أَقُولُ مِنْهُمْ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dia berkata; telah menceritakan kepada kami [Tsabit] dari [Anas] dia berkata; \"Kami pernah bersama [Umar] berada di antara Mekkah dan Madinah, ia segera bercerita kepada kami tentang orang-orang yang meninggal dunia pada perang Badar. Lalu ia berkata; \" Rasulullah shallallahu 'alaihi wasallam benar-benar memperlihatkan kepada kami tempat terbunuh mereka kemarin, beliau bersabda: 'Ini adalah tempat terbunuh si fulan - insya Allah - besok.' Umar berkata; 'Demi Dzat yang telah mengutusmu dengan kebenaran, apa kesalahan mereka itu sehingga di masukkan ke dalam sumur?. Lalu Nabi shallallahu 'alaihi wasallam mendatangi mereka seraya memenggil, 'Wahai fulan bin fulan, Wahai fulan bin fulan, Apakah kalian benar-benar mendapatkan apa yang dijanjikan oleh Rabb kalian? Sungguh benar-benar aku telah mendapatkan yang dijanjikan Allah kepadaku.' Umar lalu berkata; 'Engkau berbicara dengan jasad yang tidak ada ruhnya? ' maka beliau bersabda: 'Kalian tidak lebih mendengar dari mereka terhadap apa yang ku katakan'.\""},"2003":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَسَمِعَ الْمُسْلِمُونَ مِنْ اللَّيْلِ بِبِئْرِ بَدْرٍ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يُنَادِي يَا أَبَا جَهْلِ بْنَ هِشَامٍ وَيَا شَيْبَةُ بْنَ رَبِيعَةَ وَيَا عُتْبَةُ بْنَ رَبِيعَةَ وَيَا أُمَيَّةَ بْنَ خَلَفٍ هَلْ وَجَدْتُمْ مَا وَعَدَ رَبُّكُمْ حَقًّا فَإِنِّي وَجَدْتُ مَا وَعَدَنِي رَبِّي حَقًّا قَالُوا يَا رَسُولَ اللَّهِ أَوَ تُنَادِي قَوْمًا قَدْ جَيَّفُوا فَقَالَ مَا أَنْتُمْ بِأَسْمَعَ لِمَا أَقُولُ مِنْهُمْ وَلَكِنَّهُمْ لَا يَسْتَطِيعُونَ أَنْ يُجِيبُوا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Humaid] dari [Anas] dia berkata; Kaum muslimin mendengar pada malam hari di sumur Badar Rasulullah shallallahu 'alaihi wasallam berdiri memanggil; \"Wahai Abu Jahal bin Hisyam, Wahai Syaibah bin Rabi'ah, Wahai Utbah bin Rabi'ah, Wahai Umayyah bin Khalaf, Apakah kalian telah mendapatkan apa yang dijanjikan oleh Rabb kalian? Maka sungguh aku telah mendapatkan kebenaran dari apa yang telah dijanjikan Allah kepadaku.\" Mereka berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, Apakah engkau memanggil kaum yang telah menjadi bangkai?\", maka beliau menjawab: \"Tidaklah kalian lebih bisa mendengar dari mereka terhadap apa yang kukatakan, tetapi mereka tidak mampu menjawab.\""},"2004":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ قَالَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَفَ عَلَى قَلِيبِ بَدْرٍ فَقَالَ هَلْ وَجَدْتُمْ مَا وَعَدَ رَبُّكُمْ حَقًّا قَالَ إِنَّهُمْ لَيَسْمَعُونَ الْآنَ مَا أَقُولُ لَهُمْ فَذُكِرَ ذَلِكَ لِعَائِشَةَ فَقَالَتْ وَهِلَ ابْنُ عُمَرَ إِنَّمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُمْ الْآنَ يَعْلَمُونَ أَنَّ الَّذِي كُنْتُ أَقُولُ لَهُمْ هُوَ الْحَقُّ ثُمَّ قَرَأَتْ قَوْلَهُ{ إِنَّكَ لَا تُسْمِعُ الْمَوْتَى }حَتَّى قَرَأَتْ الْآيَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dia berkata; telah menceritakan kepada kami ['Abdah] dari [Hisyam] dari [bapaknya] dari [Ibnu 'Umar] bahwa Nabi shallallahu 'alaihi wasallam berdiri di atas sumur Badar, lalu bersabda: \"Apakah kalian telah mendapatkan kebenaran dari apa yang dijanjikan Rabb kalian?\" beliau bersabda lagi: \" mereka sekarang benar-benar mendengar apa yang kukatakan kepada mereka.\" Lalu hal itu dilaporkan kepada [Aisyah], maka ia berkata, \"Ibnu Umar salah atau lupa, hanya Rasulullah shallallahu 'alaihi wasallam bersabda: ' Mereka sekarang mengetahui bahwa apa yang kukatakan kepada mereka adalah kebenaran.' Kemudian ia membaca firman Allah -Ta'ala-, 'kamu tidak dapat menjadikan orang-orang yang mati mendengar…'.\" (Qs. An-Naml 27: 80). Hingga ia membaca satu ayat tersebut."},"2005":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ وَمُغِيرَةُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ بَنِي آدَمَ وَفِي حَدِيثِ مُغِيرَةَ كُلُّ ابْنِ آدَمَ يَأْكُلُهُ التُّرَابُ إِلَّا عَجْبَ الذَّنَبِ مِنْهُ خُلِقَ وَفِيهِ يُرَكَّبُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dan [Mughirah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap bani (anak) Adam -dalam lafazh lain pada Hadits Mughirah: setiap Ibnu (anak) Adam- akan dimakan oleh tanah, kecuali tulang ekor yang menjadi asal penciptaannya dan karenanyalah ia akan disusun kembali.\""},"2006":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ عَزَّ وَجَلَّ كَذَّبَنِي ابْنُ آدَمَ وَلَمْ يَكُنْ يَنْبَغِي لَهُ أَنْ يُكَذِّبَنِي وَشَتَمَنِي ابْنُ آدَمَ وَلَمْ يَكُنْ يَنْبَغِي لَهُ أَنْ يَشْتُمَنِي أَمَّا تَكْذِيبُهُ إِيَّايَ فَقَوْلُهُ إِنِّي لَا أُعِيدُهُ كَمَا بَدَأْتُهُ وَلَيْسَ آخِرُ الْخَلْقِ بِأَعَزَّ عَلَيَّ مِنْ أَوَّلِهِ وَأَمَّا شَتْمُهُ إِيَّايَ فَقَوْلُهُ اتَّخَذَ اللَّهُ وَلَدًا وَأَنَا اللَّهُ الْأَحَدُ الصَّمَدُ لَمْ أَلِدْ وَلَمْ أُولَدْ وَلَمْ يَكُنْ لِي كُفُوًا أَحَدٌ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah menceritakan kepada kami [Syu'aib bin Al Laits] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Allah Azza wa Jalla berfirman: 'Anak Adam telah mendustakan-Ku padahal tidak sepantasnya ia mendustakan-Ku, Anak Adam telah mencaci maki-Ku padahal tidak sepantasnya mencaci maki-Ku. Adapun pendustaanya kepada-Ku yaitu perkataanya, 'Bahwa Aku tidak akan mengembalikannya sebagaimana Aku telah memulai penciptaannya! ' padahal penciptaan terakhir tidaklah lebih sulit bagi-Ku dari yang pertama. Sedangkan caci makinya kepada-Ku yaitu perkataannya, 'Allah telah menjadikan seorang anak! Padahal Akulah Allah yang maha Esa tempat bergantung, padahal aku tidak beranak dan tidak diperanakan dan tidak ada seorang pun yang menyamai-Ku'.\""},"2007":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَسْرَفَ عَبْدٌ عَلَى نَفْسِهِ حَتَّى حَضَرَتْهُ الْوَفَاةُ قَالَ لِأَهْلِهِ إِذَا أَنَا مُتُّ فَأَحْرِقُونِي ثُمَّ اسْحَقُونِي ثُمَّ اذْرُونِي فِي الرِّيحِ فِي الْبَحْرِ فَوَاللَّهِ لَئِنْ قَدَرَ اللَّهُ عَلَيَّ لَيُعَذِّبَنِّي عَذَابًا لَا يُعَذِّبُهُ أَحَدًا مِنْ خَلْقِهِ قَالَ فَفَعَلَ أَهْلُهُ ذَلِكَ قَالَ اللَّهُ عَزَّ وَجَلَّ لِكُلِّ شَيْءٍ أَخَذَ مِنْهُ شَيْئًا أَدِّ مَا أَخَذْتَ فَإِذَا هُوَ قَائِمٌ قَالَ اللَّهُ عَزَّ وَجَلَّ مَا حَمَلَكَ عَلَى مَا صَنَعْتَ قَالَ خَشْيَتُكَ فَغَفَرَ اللَّهُ لَهُ","id":"Telah mengabarkan kepada kami [Katsir bin 'Ubaid] dia berkata; telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Az Zuhri] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah] dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada seorang hamba yang berlebih-lebihan atas dirinya sendiri hingga kematian menjemputnya. Ia berkata berpesan keluarganya, \"Jika aku mati, maka bakarlah aku, kemudian lumatkanlah aku lalu taburkanlah saat ada angin di laut. Demi Allah sungguh jika Allah mentakdirkan atas diriku, niscaya Dia akan menyiksaku dengan siksaan yang tidak pernah ditimpakan kepada seorang pun dari makhluk-Nya! -Beliau bersabda-: Lalu keluarganya melakukan hal itu. Kemudian Allah Azza wa Jalla berfirman kepada segala sesuatu yang telah berikrar menghukumi dirinya sendiri 'Lakukanlah apa yang telah engkau putuskan untuk dirimu!.\" ketika ia berdiri di hadapan Allah -Azza wa Jalla - Dia berfirman, \"Apa yang mendorongmu untuk melakukan apa yang telah engkau perbuat?\" ia berkata; 'Rasa takut kepada-Mu.\"Lalu Allah mengampuninya.\""},"2008":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنْ حُذَيْفَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ رَجُلٌ مِمَّنْ كَانَ قَبْلَكُمْ يُسِيءُ الظَّنَّ بِعَمَلِهِ فَلَمَّا حَضَرَتْهُ الْوَفَاةُ قَالَ لِأَهْلِهِ إِذَا أَنَا مُتُّ فَأَحْرِقُونِي ثُمَّ اطْحَنُونِي ثُمَّ اذْرُونِي فِي الْبَحْرِ فَإِنَّ اللَّهَ إِنْ يَقْدِرْ عَلَيَّ لَمْ يَغْفِرْ لِي قَالَ فَأَمَرَ اللَّهُ عَزَّ وَجَلَّ الْمَلَائِكَةَ فَتَلَقَّتْ رُوحَهُ قَالَ لَهُ مَا حَمَلَكَ عَلَى مَا فَعَلْتَ قَالَ يَا رَبِّ مَا فَعَلْتُ إِلَّا مِنْ مَخَافَتِكَ فَغَفَرَ اللَّهُ لَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Rib'i] dari [Hudzaifah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Ada salah seorang di antara orang-orang sebelum kalian berburuk sangka terhadap perbuatannya sendiri, setelah kematian menjemputnya, ia berkata kepada keluarganya; \"Jika aku mati, bakarlah aku, lumatkanlah aku, lalu taburkanlah aku di laut, Allah jika mentakdirkan atas diriku, tidak akan memberikan ampunan kepadaku.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Lalu Allah - Azza wa Jalla - memerintahkan para malaikat untuk mengambil ruhnya. Allah berfirman kepadanya: \"Apa yang mendorongmu untuk melakukan apa yang telah engkau perbuat? Dia berkata; \"Wahai Rabbku, tidaklah aku perbuat kecuali karena rasa takut kepada-Mu.\" Lalu Allah mengampuninya.\""},"2009":{"ar":"و أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى الْمِنْبَرِ يَقُولُ إِنَّكُمْ مُلَاقُو اللَّهَ عَزَّ وَجَلَّ حُفَاةً عُرَاةً غُرْلًا","id":"Dan telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam berkhutbah di atas mimbar, beliau bersabda: \" Kalian akan bertemu Allah -Azza Wa Jalla- dalam keadaan tidak beralas kaki, telanjang serta tidak berkhitan.\""},"2010":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي الْمُغِيرَةُ بْنُ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُحْشَرُ النَّاسُ يَوْمَ الْقِيَامَةِ عُرَاةً غُرْلًا وَأَوَّلُ الْخَلَائِقِ يُكْسَى إِبْرَاهِيمُ عَلَيْهِ السَّلَام ثُمَّ قَرَأَ{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ }","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; telah menceritakan kepadaku [Al Mughirah bin An Nu'man] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Manusia akan dihimpun pada hari kiamat dalam keadaan telanjang serta tidak berkhitan. Dan makhluk pertama yang akan diberi pakaian ialah Ibrahim Alaihissalam, kemudian beliau membaca ayat, \"Sebagaimana Kami telah memulai penciptaan pertama, begitulah Kami akan megulanginya.\" (Qs. Al Anbiyaa' 21: 104)."},"2011":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ أَخْبَرَنِي الزُّبَيْدِيُّ قَالَ أَخْبَرَنِي الزُّهْرِيُّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُبْعَثُ النَّاسُ يَوْمَ الْقِيَامَةِ حُفَاةً عُرَاةً غُرْلًا فَقَالَتْ عَائِشَةُ فَكَيْفَ بِالْعَوْرَاتِ قَالَ{ لِكُلِّ امْرِئٍ مِنْهُمْ يَوْمَئِذٍ شَأْنٌ يُغْنِيهِ }","id":"Telah mengabarkan kepadaku ['Amru bin 'Utsman] dia berkata; telah menceritakan kepada kami [Baqiyyah] dia berkata; telah mengabarkan kepadaku [Az Zubaidi] dia berkata; telah mengabarkan kepadaku [Az Zuhri] dari ['Urwah] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia akan dibangkitkan pada hari kiamat dalam keadaan tidak beralas kaki, telanjang serta tidak berkhitan.\" Lalu Aisyah bertanya; \"Bagaimana dengan aurat?\" beliau menjawab dengan membaca ayat: \"Setiap orang dari mereka pada hari itu mempunyai urusan yang cukup menyibukkannya.\" (Qs. Abasa 80: 37)."},"2012":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا أَبُو يُونُسَ الْقُشَيْرِيُّ قَالَ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ تُحْشَرُونَ حُفَاةً عُرَاةً قُلْتُ الرِّجَالُ وَالنِّسَاءُ يَنْظُرُ بَعْضُهُمْ إِلَى بَعْضٍ قَالَ إِنَّ الْأَمْرَ أَشَدُّ مِنْ أَنْ يُهِمَّهُمْ ذَلِكَ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Abu Yunus Al Qusyairi] dia berkata; telah menceritakan kepadaku [Ibnu Abu Mulaikah] dari [Al Qasim bin Muhammad] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Kalian dihimpun dalam keadaan tidak beralas kaki serta telanjang.\" Aku bertanya; \"Laki-laki dan wanita sebagian mereka melihat sebagian yang lain?\" Beliau bersabda: \" Urusan sat itu lebih berat daripada disibukkan dengan hal itu.\""},"2013":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو هِشَامٍ قَالَ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ أَبُو بَكْرٍ قَالَ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحْشَرُ النَّاسُ يَوْمَ الْقِيَامَةِ عَلَى ثَلَاثِ طَرَائِقَ رَاغِبِينَ رَاهِبِينَ اثْنَانِ عَلَى بَعِيرٍ وَثَلَاثَةٌ عَلَى بَعِيرٍ وَأَرْبَعَةٌ عَلَى بَعِيرٍ وَعَشْرَةٌ عَلَى بَعِيرٍ وَتَحْشُرُ بَقِيَّتَهُمْ النَّارُ تَقِيلُ مَعَهُمْ حَيْثُ قَالُوا وَتَبِيتُ مَعَهُمْ حَيْثُ بَاتُوا وَتُصْبِحُ مَعَهُمْ حَيْثُ أَصْبَحُوا وَتُمْسِي مَعَهُمْ حَيْثُ أَمْسَوْا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Abu Hisyam] dia berkata; telah menceritakan kepada kami [Wuhaib bin Khalid Abu Bakr] dia berkata; telah menceritakan kepada kami [Ibnu Thawus] dari [bapaknya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia akan dihimpun pada hari kiamat berdasarkan tiga kelompok: Mereka dalam keadaan berharap serta takut, dua orang di atas unta, tiga orang di atas unta, empat orang di atas unta, sepuluh orang di atas unta dan selebihnya dihimpun oleh api, api itu tidur siang bersama mereka ketika mereka tidur siang, bermalam bersama mereka ketika mereka bermalam, berada di pagi hari bersama mereka ketika mereka di pagi hari, dan api itu berada di sore hari ketika mereka di sore hari.\""},"2014":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ الْوَلِيدِ بْنِ جُمَيْعٍ قَالَ حَدَّثَنَا أَبُو الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ عَنْ أَبِي ذَرٍّ قَالَإِنَّ الصَّادِقَ الْمَصْدُوقَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِي أَنَّ النَّاسَ يُحْشَرُونَ ثَلَاثَةَ أَفْوَاجٍ فَوْجٌ رَاكِبِينَ طَاعِمِينَ كَاسِينَ وَفَوْجٌ تَسْحَبُهُمْ الْمَلَائِكَةُ عَلَى وُجُوهِهِمْ وَتَحْشُر��هُمْ النَّارُ وَفَوْجٌ يَمْشُونَ وَيَسْعَوْنَ يُلْقِي اللَّهُ الْآفَةَ عَلَى الظَّهْرِ فَلَا يَبْقَى حَتَّى إِنَّ الرَّجُلَ لَتَكُونُ لَهُ الْحَدِيقَةُ يُعْطِيهَا بِذَاتِ الْقَتَبِ لَا يَقْدِرُ عَلَيْهَا","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dari [Al Walid bin Jumai'] dia berkata; telah menceritakan kepada kami [Abu Ath Thufail] dari [Hudzaifah bin Asad] dari [Abu Dzarr] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Manusia dikumpulkan pada hari kiamat dalam tiga kelompok. Satu Kelompok menunggang kendaraan dengan mendapat makanan dan pakaian, kelompok yang lain wajahnya diseret oleh para malaikat dan dihimpun api, dan kelompok ketiga, mereka berjalan dan berlari yang Allah mematikan mereka di atas hewan tunggangannya hingga tidak ada lagi yang tersisa, hingga ada seseorang yang memiliki kebun, dia diberi unta beserta barang bawaannya, namun dia tidak mampu lagi menerimanya.\""},"2015":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ أَخْبَرَنَا وَكِيعٌ وَوَهْبُ بْنُ جَرِيرٍ وَأَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَوْعِظَةِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ مَحْشُورُونَ إِلَى اللَّهِ عَزَّ وَجَلَّ عُرَاةً قَالَ أَبُو دَاوُدَ حُفَاةً غُرْلًا وَقَالَ وَكِيعٌ وَوَهْبٌ عُرَاةً غُرْلًا كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ قَالَ أَوَّلُ مَنْ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ عَلَيْهِ السَّلَام وَإِنَّهُ سَيُؤْتَى قَالَ أَبُو دَاوُدَ يُجَاءُ وَقَالَ وَهْبٌ وَوَكِيعٌ سَيُؤْتَى بِرِجَالٍ مِنْ أُمَّتِي فَيُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ رَبِّ أَصْحَابِي فَيُقَالُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ فَلَمَّا تَوَفَّيْتَنِي إِلَى قَوْلِهِ وَإِنْ تَغْفِرْ لَهُمْ }الْآيَةَ فَيُقَالُ إِنَّ هَؤُلَاءِ لَمْ يَزَالُوا مُدْبِرِينَ قَالَ أَبُو دَاوُدَ مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ مُنْذُ فَارَقْتَهُمْ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah mengabarkan kepada kami [Waki'] dari [Wahb bin Jarir] dan [Abu Dawud] dari [Syu'bah] dari [Al Mughirah bin An Nu'man] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam berdiri untuk memberikan nasihat, lalu beliau bersabda: \"Wahai manusia, kalian akan dihimpun menuju kepada Allah Azza wa Jalla - dalam keadaan telanjang-. Abu Daud berkata; \"Dalam keadaan tidak beralas kaki serta tidak berkhitan.\" Waki' dan Wahab berkata dengan redaksi; \"Dalam keadaan telanjang serta tidak berkhitan. Sebagaimana Kami telah memulai penciptaan pertama, begitulah Kami akan mengulanginya.\" Beliau bersabda: \"Orang yang pertama kali diberi pakaian pada hari kiamat adalah Ibrahim -Alaihis Salam- dan pakaian tersebut akan diberikan. [Abu Daud] berkata; beliau bersabda: \"Didatangkan\" [Wahab] dan [Waki'] berkata; \"Mereka dikenai hukuman sebagai golongan sebelah kiri (karena kemurtadan setelah masa kenabian). Aku lalu berkata; \"Wahai Rabbku! Sahabatku\". Lantas ada suara; \"Kamu tidak tahu apa yang mereka lakukan setelahmu\" lantas kuucapkan sebagaimana ucapan seorang hambna yang shalih; \"Dan aku menjadi saksi terhadap mereka, selama aku berada di antara mereka. Maka setelah Engkau wafatkan aku...\" (Qs. Al Maaidah 4: 117) sampai firman-Nya, \"dan jika Engkau mengampuni mereka…\" (Qs. Al Maaidah 4: 118). Dan seterusnya. Lalu dikatakan, \" mereka masih tetap berpaling.\" Abu Daud berkata; \"Mereka murtad semenjak engkau berpisah dengan mereka-.\""},"2016":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ زَيْدٍ وَهُوَ ابْنُ أَبِي الزَّرْقَاءِ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا خَالِدُ بْنُ مَيْسَرَةَ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ قُرَّةَ عَنْ أَبِيهِ قَالَكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَلَسَ يَجْلِسُ إِلَيْهِ نَفَرٌ مِنْ أَصْحَابِهِ وَفِيهِمْ رَجُلٌ لَهُ ابْنٌ صَغِيرٌ يَأْتِيهِ مِنْ خَلْفِ ظَهْرِهِ فَيُقْعِدُهُ بَيْنَ يَدَيْهِ فَهَلَكَ فَامْتَنَعَ الرَّجُلُ أَنْ يَحْضُرَ الْحَلْقَةَ لِذِكْرِ ابْنِهِ فَحَزِنَ عَلَيْهِ فَفَقَدَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَالِي لَا أَرَى فُلَانًا قَالُوا يَا رَسُولَ اللَّهِ بُنَيُّهُ الَّذِي رَأَيْتَهُ هَلَكَ فَلَقِيَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ بُنَيِّهِ فَأَخْبَرَهُ أَنَّهُ هَلَكَ فَعَزَّاهُ عَلَيْهِ ثُمَّ قَالَ يَا فُلَانُ أَيُّمَا كَانَ أَحَبُّ إِلَيْكَ أَنْ تَمَتَّعَ بِهِ عُمُرَكَ أَوْ لَا تَأْتِي غَدًا إِلَى بَابٍ مِنْ أَبْوَابِ الْجَنَّةِ إِلَّا وَجَدْتَهُ قَدْ سَبَقَكَ إِلَيْهِ يَفْتَحُهُ لَكَ قَالَ يَا نَبِيَّ اللَّهِ بَلْ يَسْبِقُنِي إِلَى بَابِ الْجَنَّةِ فَيَفْتَحُهَا لِي لَهُوَ أَحَبُّ إِلَيَّ قَالَ فَذَاكَ لَكَ","id":"Telah mengabarkan kepada kami [Harun bin Zaid bin Abu Az Zarqa] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Khalid bin Maisarah] dia berkata; aku mendengar [Mu'awiyah bin Qurrah] dari [bapaknya], dia berkata; \"Adalah kebiasaan Nabi shallallahu 'alaihi wasallam jika sedang duduk, beberapa orang dari sahabatnya duduk menemaninya. Diantara mereka ada seorang yang memiliki anak kecil yang mendatangi beliau dari belakang punggungnya, lalu beliau mendudukkan di depannya. Pada suatu hari anak itu meninggal dunia. Maka orang tersebut berhalangan untuk menghadiri majelis karena ingat anaknya, ia bersedih atas kematiannya. Lalu Nabi shallallahu 'alaihi wasallam merasa kehilangan dan bertanya: \"Mengapa aku tidak melihat si fulan?\" mereka menjawab, \"Wahai Rasulullah shallallahu 'alaihi wasallam, Anak kecilnya yang engkau lihat telah meninggal dunia, \" lalu Rasulullah shallallahu 'alaihi wasallam bertemu dengannya dan bertanya tentang anaknya? Ia memberitahukan bahwa anaknya telah meninggal dunia, lalu beliau melawatnya, kemudian bersabda: \"Wahai fulan, manakah yang lebih engkau cintai, engkau menikmati umurmu bersama anakmu? Atau kelak engkau tidak mendatangi salah satu pintu surga kecuali engkau mendapatkan anakmu telah mendahuluimu lalu membukakannya untukmu?\" ia menjawab; \"Wahai Nabi Allah, bahkan jika ia mendahuluiku menuju pintu surga lalu ia membukakannya untukku lebih aku cintai.\" Beliau bersabda: \"Itulah bagianmu.\""},"2017":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ عَنْ عَبْدِ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَأُرْسِلَ مَلَكُ الْمَوْتِ إِلَى مُوسَى عَلَيْهِ السَّلَام فَلَمَّا جَاءَهُ صَكَّهُ فَفَقَأَ عَيْنَهُ فَرَجَعَ إِلَى رَبِّهِ فَقَالَ أَرْسَلْتَنِي إِلَى عَبْدٍ لَا يُرِيدُ الْمَوْتَ فَرَدَّ اللَّهُ عَزَّ وَجَلَّ إِلَيْهِ عَيْنَهُ وَقَالَ ارْجِعْ إِلَيْهِ فَقُلْ لَهُ يَضَعُ يَدَهُ عَلَى مَتْنِ ثَوْرٍ فَلَهُ بِكُلِّ مَا غَطَّتْ يَدُهُ بِكُلِّ شَعْرَةٍ سَنَةٌ قَالَ أَيْ رَبِّ ثُمَّ مَهْ قَالَ الْمَوْتُ قَالَ فَالْآنَ فَسَأَلَ اللَّهَ عَزَّ وَجَلَّ أَنْ يُدْنِيَهُ مِنْ الْأَرْضِ الْمُقَدَّسَةِ رَمْيَةً بِحَجَرٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَوْ كُنْتُ ثَمَّ لَأَرَيْتُكُمْ قَبْرَهُ إِلَى جَانِبِ الطَّرِيقِ تَحْتَ الْكَثِيبِ الْأَحْمَرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dari ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [bapaknya] dari [Abu Hurairah] dia berkata; \"Malaikat yang diberi tugas mengurus kematian pernah diutus untuk menemui Musa Alaihis Salam. Setelah malaikat datang menemuinya, Musa memukulnya, lalu matanya buta sebelah dan ia kembali menemui Rabbnya seraya berkata; \"Engkau telah mengutusku untuk menemui seorang hamba yang tidak menginginkan kematiannya.\" Maka Allah Azza wa Jalla mengembalikan matanya dan berfirman: \"Kembalilah dan katakan kepadanya; \"Hendaklah Musa meletakkan tangannya di atas punggung sapi jantan, maka yang ditutup oleh tangannya adalah bagian umurnya dan setiap rambut -yang ditutup oleh tangannya sama dengan masa- satu tahun.\" Ia bertanya; \"Wahai Rabbku, kemudian apa?\" Dia berfirman: \"Itulah kematiannya.\" Malaikat berkata; \"Sekarang akan beres\", lalu ia memohon kepada Allah Azza Wa Jalla agar didekatkan dari bumi yang disucikan sejauh lemparan batu.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Andai aku berada di sana, niscaya akan aku perlihatkan kuburannya kepada kalian di samping jalan di bawah bukit merah.\""},"2018":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ قَالَ حَدَّثَنَا أَبُو سُهَيْلٍ عَنْ أَبِيهِ عَنْ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِأَنَّ أَعْرَابِيًّا جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَائِرَ الرَّأْسِ فَقَالَ يَا رَسُولَ اللَّهِ أَخْبِرْنِي مَاذَا فَرَضَ اللَّهُ عَلَيَّ مِنْ الصَّلَاةِ قَالَ الصَّلَوَاتُ الْخَمْسُ إِلَّا أَنْ تَطَوَّعَ شَيْئًا قَالَ أَخْبِرْنِي بِمَا افْتَرَضَ اللَّهُ عَلَيَّ مِنْ الصِّيَامِ قَالَ صِيَامُ شَهْرِ رَمَضَانَ إِلَّا أَنْ تَطَوَّعَ شَيْئًا قَالَ أَخْبِرْنِي بِمَا افْتَرَضَ اللَّهُ عَلَيَّ مِنْ الزَّكَاةِ فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَرَائِعِ الْإِسْلَامِ فَقَالَ وَالَّذِي أَكْرَمَكَ لَا أَتَطَوَّعُ شَيْئًا لَا أَنْقُصُ مِمَّا فَرَضَ اللَّهُ عَلَيَّ شَيْئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَحَ إِنْ صَدَقَ أَوْ دَخَلَ الْجَنَّةَ إِنْ صَدَقَ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il bin Ja'far] dia berkata; telah menceritakan kepada kami [Abu Suhail] dari [Bapaknya] dari [Thalhah bin 'Ubaidullah] bahwa seorang Badui menemui Rasulullah shallallahu 'alaihi wasallam dengan rambur kusut, lalu bertanya; \"Wahai Rasulullah shallallahu 'alaihi wasallam, beritahukanlah kepadaku shalat apa yang Allah wajibkan atas diriku?\" beliau menjawab: \"Shalat lima waktu, kecuali jika engkau sedikit mengerjakan yang sunnah.\" Ia bertanya; \"Beritahukanlah kepadaku puasa apa yang Allah wajibkan atas diriku?\" beliau menjawab: \"Puasa di bulan Ramadhan, kecuali jika engkau sedikit mengerjakan yang sunnah.\" Ia bertanya; \"Beritahukanlah kepadaku apa yang Allah wajibkan atas diriku berupa zakat?\" maka Rasulullah shallallahu 'alaihi wasallam memberitahukan kepadanya tentang syari'at Islam, lalu ia berkata; \"Demi Dzat yang telah memuliakanmu, aku tidak mengerjakan yang sunnah sedikit pun, serta tidak akan mengurangi dari apa yang Allah wajibkan atas diriku sedikit pun! Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ia beruntung jika benar, atau ia akan masuk surga jika benar.\""},"2019":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَنُهِينَا فِي الْقُرْآنِ أَنْ نَسْأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَيْءٍ فَكَانَ يُعْجِبُنَا أَنْ يَجِيءَ الرَّجُلُ الْعَاقِلُ مِنْ أَهْلِ الْبَادِيَةِ فَيَسْأَلَهُ فَجَاءَ رَجُلٌ مِنْ أَهْلِ الْبَادِيَةِ فَقَالَ يَا مُحَمَّدُ أَتَانَا رَسُولُكَ فَأَخْبَرَنَا أَنَّكَ تَزْعُمُ أَنَّ اللَّهَ عَزَّ وَجَلَّ أَرْسَلَكَ قَالَ صَدَقَ قَالَ فَمَنْ خَلَقَ السَّمَاءَ قَالَ اللَّهُ قَالَ فَمَنْ خَلَقَ الْأَرْضَ قَالَ اللَّهُ قَالَ فَمَنْ نَصَبَ فِيهَا الْجِبَالَ قَالَ اللَّهُ قَالَ فَمَنْ جَعَلَ فِيهَا الْمَنَافِعَ قَالَ اللَّهُ قَالَ فَبِالَّذِي خَلَقَ السَّمَاءَ وَالْأَرْضَ وَنَصَبَ فِيهَا الْجِبَالَ وَجَعَلَ فِيهَا الْمَنَافِعَ آللَّهُ أَرْسَلَكَ قَالَ نَعَمْ قَالَ وَزَعَمَ رَسُولُكَ أَنَّ عَلَيْنَا خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ قَالَ صَدَقَ قَالَ فَبِالَّذِي أَرْسَلَكَ آللَّهُ أَمَرَكَ بِهَذَا قَالَ نَعَمْ قَالَ وَزَعَمَ رَسُولُكَ أَنَّ عَلَيْنَا زَكَاةَ أَمْوَالِنَا قَالَ صَدَقَ قَالَ فَبِالَّذِي أَرْسَلَكَ آللَّهُ أَمَرَكَ بِهَذَا قَالَ نَعَمْ قَالَ وَزَعَمَ رَسُولُكَ أَنَّ عَلَيْنَا صَوْمَ شَهْرِ رَمَضَانَ فِي كُلِّ سَنَةٍ قَالَ صَدَقَ قَالَ فَبِالَّذِي أَرْسَلَكَ آللَّهُ أَمَرَكَ بِهَذَا قَالَ نَعَمْ قَالَ وَزَعَمَ رَسُولُكَ أَنَّ عَلَيْنَا الْحَجَّ مَنْ اسْتَطَاعَ إِلَيْهِ سَبِيلًا قَالَ صَدَقَ قَالَ فَبِالَّذِي أَرْسَلَكَ آللَّهُ أَمَرَكَ بِهَذَا قَالَ نَعَمْ قَالَ فَوَالَّذِي بَعَثَكَ بِالْحَقِّ لَا أَزِيدَنَّ عَلَيْهِنَّ شَيْئًا وَلَا أَنْقُصُ فَلَمَّا وَلَّى قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَئِنْ صَدَقَ لَيَدْخُلَنَّ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] dia berkata; telah menceritakan kepada kami [Abu 'Amir Al 'Aqadi] dia berkata; telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas] dia berkata; \"Dalam Al Qur'an kita dilarang bertanya kepada Nabi shallallahu 'alaihi wasallam tentang sesuatu. Sangat mengherankan kami jika ada seorang yang berakal dari penduduk kampung hendak datang lalu bertanya kepada beliau. kemudian seorang dari penduduk kampung itu pun datang seraya berkata; \"Wahai Muhammad, utusanmu telah datang kepada kami, lalu ia memberitahukan kepada kami bahwa kamu menganggap Allah Azza wa Jalla telah mengutusmu?\" beliau menjawab: \"Benar.\" Ia bertanya; \"Lalu siapa yang telah menciptakan langit?\" Beliau menjawab, \"Allah.\" Ia bertanya; \"Siapakah yang menegakkan gunung-gunung?\" Beliau menjawab: \"Allah.\" Ia bertanya; \"Siapa yang telah menjadikan berbagai manfaat di dalamnya.\" Beliau menjawab: \"Allah.\" Ia bertanya; \"Demi Dzat yang telah menciptakan langit dan bumi, menegakkan gunung-gunung dan menjadikan manfaat di dalamnya, Apakah Allah telah mengutusmu?\" Beliau menjawab: \"Ya.\" Ia bertanya; \"Dan utusanmu menganggap bahwa kita diwajibkan untuk mengerjakan shalat lima waktu sehari semalam?\" Beliau menjawab: \"Benar.\" Ia bertanya; \"Maka demi Dzat yang telah mengutusmu, apakah Allah memerintahkanmu untuk mengerjakan hal ini?\" Beliau menjawab: \"Ya.\" Ia bertanya; \"Utusanmu menganggap bahwa kita berkewajiban untuk mengeluarkan zakat harta benda kita?\" Beliau menjawab: \"Benar.\" Ia bertanya; \"Demi Dzat yang telah mengutusmu, Apakah Allah telah memerintahkanmu untuk mengerjakan hal ini? Beliau menjawab: \"Ya.\" Dia bertanya lagi; \"Dan utusanmu menganggap bahwa kita diwajibkan untuk berpuasa di bulan Ramadlan pada setiap tahunnya?\" Beliau menjawab: \"Benar.\" Ia bertanya; \"Maka demi Dzat yang telah mengutusmu, apakah Allah memerintahkanmu untuk mengerjakan hal ini?\" Beliau menjawab: \"Ya. Dia bertanya lagi; 'Dan utusanmu menganggap bahwa kita di wajibkan untuk menunaikan haji bagi siapa yang mampu mengadakan perjalanannya?\" Beliau menjawab: \"Benar.\" Ia bertanya; \"Demi Dzat yang telah mengutusmu, apakah Allah telah memerintahkanmu untuk melakukan hal ini?\" Beliau menjawab: \"Ya.\" Ia berkata; \"Demi Dzat yang telah mengutusmu dengan kebenaran, sungguh aku tidak akan menambah sedikit pun atas semua itu dan tidak akan menguranginya.\" Setelah ia pergi, Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh jika ia benar, niscaya masuk surga.\""},"2020":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ عَنْ اللَّيْثِ عَنْ سَعِيدٍ عَنْ شَرِيكِ بْنِ أَبِي نَمِرٍ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُبَيْنَا نَحْنُ جُلُوسٌ فِي الْمَسْجِدِ جَاءَ رَجُلٌ عَلَى جَمَلٍ فَأَنَاخَهُ فِي الْمَسْجِدِ ثُمَّ عَقَلَهُ فَقَالَ لَهُمْ أَيُّكُمْ مُحَمَّدٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئٌ بَيْنَ ظَهْرَانَيْهِمْ قُلْنَا لَهُ هَذَا الرَّجُلُ الْأَبْيَضُ الْمُتَّكِئُ فَقَالَ لَهُ الرَّجُلُ يَا ابْنَ عَبْدِ الْمُطَّلِبِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَجَبْتُكَ فَقَالَ الرَّجُلُ إِنِّي سَائِلُكَ يَا مُحَمَّدُ فَمُشَدِّدٌ عَلَيْكَ فِي الْمَسْأَلَةِ فَلَا تَجِدَنَّ فِي نَفْسِكَ قَالَ سَلْ مَا بَدَا لَكَ فَقَالَ الرَّجُلُ نَشَدْتُكَ بِرَبِّكَ وَرَبِّ مَنْ قَبْلَكَ آللَّهُ أَرْسَلَكَ إِلَى النَّاسِ كُلِّهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ اللَّهَ آللَّهُ أَمَرَكَ أَنْ تُصَلِّيَ الصَّلَوَاتِ الْخَمْسَ فِي الْيَوْمِ وَاللَّيْلَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ اللَّهَ آللَّهُ أَمَرَكَ أَنْ تَصُومَ هَذَا الشَّهْرَ مِنْ السَّنَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ اللَّهَ آللَّهُ أَمَرَكَ أَنْ تَأْخُذَ هَذِهِ الصَّدَقَةَ مِنْ أَغْنِيَائِنَا فَتَقْسِمَهَا عَلَى فُقَرَائِنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ فَقَالَ الرَّجُلُ آمَنْتُ بِمَا جِئْتَ بِهِ وَأَنَا رَسُولُ مَنْ وَرَائِي مِنْ قَوْمِي وَأَنَا ضِمَامُ بْنُ ثَعْلَبَةَ أَخُو بَنِي سَعْدِ بْنِ بَكْرٍخَالَفَهُ يَعْقُوبُ بْنُ إِبْرَاهِيمَ","id":"Telah mengabarkan kepada kami ['Isa bin Hammad] dari [Al Laits] dari [Sa'id] dari [Syarik bin Abu Namir] bahwasanya dia mendengar [Anas bin Malik] berkata; \"Ketika kami sedang duduk di masjid, datanglah seseorang dengan menaiki seekor unta, ia menderumkannya di masjid, kemudian mengikatnya lalu bertanya kepada mereka, \"Manakah di antara kalian yang bernama Muhammad?\" padahal Rasulullah shallallahu 'alaihi wasallam sedang bersandar di antara mereka. Kami berkata kepadanya; \"Orang putih yang sedang bersandar ini.\" Orang tersebut berkata kepada beliau; \"Wahai anak Abdul Muththallib.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah menjawab panggilanmu.\" Orang itu berkata; \"Sungguh aku akan bertanya kepadamu wahai Muhammad, dan mendesakmu dalam bertanya, maka janganlah engkau marah! Beliau bersabda: \"Tanyakanlah apa yang terlintas dalam pikiranmu.\" Lalu orang itu bertanya; \"Aku bersumpah atas nama Rabbmu dan Rabb orang-orang sebelum kamu, apakah Allah telah mengutusmu kepada seluruh manusia?\" maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, ya.\" Ia bertanya, \"Aku bersumpah atas nama Allah, apakah Allah telah memerintahkanmu untuk mengerjakan shalat lima waktu dalam sehari semalam? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, ya.\" Ia bertanya; \"Aku bersumpah atas nama Allah, apakah Allah telah memerintahkanmu untuk berpuasa pada bulan ini setiap tahun.\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, Ya.\" Ia bertanya; \"Aku bersumpah atas nama Allah, apakah Allah telah memerintahkanmu untuk mengambil zakat ini dari orang-orang kaya di antara kami, lalu dibagikan kepada orang-orang fakir di antara kami? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, Ya.\" Orang itu berkata; \"Aku beriman dengan apa yang telah engkau bawa dan aku adalah utusan kaumku yang mereka berada di belakangku. Aku adalah Dhimam bin Tsa'labah berasal dari Bani Sa'd bin Bakr.\" Ya'qub bin Ibrahim menyelisihi Hadits ini."},"2021":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ مِنْ كِتَابِهِ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنَا ابْنُ عَجْلَانَ وَغَيْرُهُ مِنْ إِخْوَانِنَا عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُبَيْنَمَا نَحْنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُلُوسٌ فِي الْمَسْجِدِ دَخَلَ رَجُلٌ عَلَى جَمَلٍ فَأَنَاخَهُ فِي الْمَس��جِدِ ثُمَّ عَقَلَهُ ثُمَّ قَالَ أَيُّكُمْ مُحَمَّدٌ وَهُوَ مُتَّكِئٌ بَيْنَ ظَهْرَانَيْهِمْ فَقُلْنَا لَهُ هَذَا الرَّجُلُ الْأَبْيَضُ الْمُتَّكِئُ فَقَالَ لَهُ الرَّجُلُ يَا ابْنَ عَبْدِ الْمُطَّلِبِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَجَبْتُكَ قَالَ الرَّجُلُ يَا مُحَمَّدُ إِنِّي سَائِلُكَ فَمُشَدِّدٌ عَلَيْكَ فِي الْمَسْأَلَةِ قَالَ سَلْ عَمَّا بَدَا لَكَ قَالَ أَنْشُدُكَ بِرَبِّكَ وَرَبِّ مَنْ قَبْلَكَ آللَّهُ أَرْسَلَكَ إِلَى النَّاسِ كُلِّهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ اللَّهَ آللَّهُ أَمَرَكَ أَنْ تَصُومَ هَذَا الشَّهْرَ مِنْ السَّنَةِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ اللَّهَ آللَّهُ أَمَرَكَ أَنْ تَأْخُذَ هَذِهِ الصَّدَقَةَ مِنْ أَغْنِيَائِنَا فَتَقْسِمَهَا عَلَى فُقَرَائِنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ فَقَالَ الرَّجُلُ إِنِّي آمَنْتُ بِمَا جِئْتَ بِهِ وَأَنَا رَسُولُ مَنْ وَرَائِي مِنْ قَوْمِي وَأَنَا ضِمَامُ بْنُ ثَعْلَبَةَ أَخُو بَنِي سَعْدِ بْنِ بَكْرٍخَالَفَهُ عُبَيْدُ اللَّهِ بْنُ عُمَرَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim] dalam kitabnya, dia berkata; telah menceritakan kepada kami [pamanku], dia berkata; telah menceritakan kepada kami [Al Laits] dia berkata; telah menceritakan kepada kami [Ibnu 'Ajlan] dan selainnya dari saudara-saudara kami, dari [Sa'id Al Maqburi] dari [Syarik bin 'Abdullah bin Abu Namir] bahwasanya dia mendengar [Anas bin Malik] berkata; \"Ketika kami sedang duduk di samping Rasulullah shallallahu 'alaihi wasallam di masjid, seseorang masuk dengan menaiki seekor unta, ia menderumkannya untanya kemudian mengikatnya, lalu berkata; \"Manakah di antara kalian yang bernama Muhammad?\" padahal beliau saat itu sedang bersandar di antara mereka, lalu kami katakan, \"Orang putih yang sedang bersandar ini.\" Orang tersebut berkata kepada beliau; \"Wahai anak Abdul Muththallib.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah menjawab panggilanmu.\" Orang itu berkata; \"Sungguh aku akan bertanya kepadamu wahai Muhammad, dan mendesakmu dalam bertanya. Beliau bersabda: \"Tanyakanlah apa yang terlintas dalam pikiranmu.\" Lalu orang itu bertanya; \"Aku bersumpah atas nama Rabbmu dan Rabb orang-orang sebelum kamu, apakah Allah telah mengutusmu kepada seluruh manusia?\" maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, ya.\" Ia bertanya, \"Aku bersumpah atas nama Allah, apakah Allah telah memerintahkanmu untuk berpuasa pada bulan ini setiap tahun.\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, Ya.\" Ia bertanya; \"Aku bersumpah atas nama Allah, apakah Allah telah memerintahkanmu untuk mengambil zakat ini dari orang-orang kaya di antara kami, lalu dibagikan kepada orang-orang fakir di antara kami? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, Ya.\" Orang itu berkata; \"Aku beriman dengan apa yang telah engkau bawa dan aku adalah utusan kaumku yang mereka berada di belakangku. Aku adalah Dhimam bin Tsa'labah berasal dari Bani Sa'd bin Bakr.\" 'Ubaidullah bin Umar menyelisihinya."},"2022":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا إِسْحَقُ قَالَ حَدَّثَنَا أَبُو عُمَارَةَ حَمْزَةُ بْنُ الْحَارِثِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ أَبِي يَذْكُرُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَبَيْنَمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَصْحَابِهِ جَاءَ رَجُلٌ مِنْ أَهْلِ الْبَادِيَةِ قَالَ أَيُّكُمْ ابْنُ عَبْدِ الْمُطَّلِبِ قَالُوا هَذَا الْأَمْغَرُ الْمُرْتَفِقُ قَالَ حَمْزَةُ الْأَمْغَرُ الْأَبْيَضُ مُشْرَبٌ حُمْرَةً فَقَالَ إِنِّي سَائِلُكَ فَمُشْتَدٌّ عَلَيْكَ فِي الْمَسْأَلَةِ قَالَ سَلْ عَمَّا بَدَا لَكَ قَالَ أَسْأَلُكَ بِرَبِّكَ وَرَبِّ مَنْ قَبْلَكَ وَرَبِّ مَنْ بَعْدَكَ آللَّهُ أَرْسَلَكَ قَالَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ بِهِ آللَّهُ أَمَرَكَ أَنْ تُصَلِّيَ خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ قَالَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ بِهِ آللَّهُ أَمَرَكَ أَنْ تَأْخُذَ مِنْ أَمْوَالِ أَغْنِيَائِنَا فَتَرُدَّهُ عَلَى فُقَرَائِنَا قَالَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ بِهِ آللَّهُ أَمَرَكَ أَنْ تَصُومَ هَذَا الشَّهْرَ مِنْ اثْنَيْ عَشَرَ شَهْرًا قَالَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ بِهِ آللَّهُ أَمَرَكَ أَنْ يَحُجَّ هَذَا الْبَيْتَ مَنْ اسْتَطَاعَ إِلَيْهِ سَبِيلًا قَالَ اللَّهُمَّ نَعَمْ قَالَ فَإِنِّي آمَنْتُ وَصَدَّقْتُ وَأَنَا ضِمَامُ بْنُ ثَعْلَبَةَ","id":"Telah mengabarkan kepada kami [Abu Bakr bin 'Ali] dia berkata; telah menceritakan kepada kami [Ishaq] dia berkata; telah menceritakan kepada kami [Abu 'Umarah Hamzah bin Al Harits bin 'Umair] dia berkata; aku mendengar [bapakku] menyebutkan dari ['Ubaidullah bin 'Umar] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] dia berkata; \"Ketika Nabi bersama para sahabat, datanglah seorang dari penduduk kampung seraya bertanya; \"Manakah di antara kalian yang menjadi anak Abdul Muththallib?\" Mereka menjawab, \"Orang putih yang sedang bersandar ini!\" Hamzah (perawi hadits ini) berkata; \"Orang putih artinya putih kemerah-merahan\". Lalu ia berkata; \"Sungguh aku akan bertanya kepadamu, dan aku betul-betul serius dalam bertanya ini.\" Beliau bersabda: \"Tanyakanlah apa yang terlintas dalam pikiranmu.\" Lalu orang itu bertanya; \"Aku bersumpah atas nama Rabbmu dan Rabb orang-orang sebelum kamu, apakah Allah telah mengutusmu kepada seluruh manusia?\" Beliau menjawab: \"Ya Allah, ya.\" Ia bertanya; \"Aku bersumpah atas nama Allah, apakah Allah telah memerintahkanmu untuk mengerjakan shalat lima waktu dalam sehari semalam? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, ya.\" Ia bertanya; \"Aku bersumpah atas nama Allah, apakah Allah telah memerintahkanmu untuk mengambil zakat ini dari orang-orang kaya di antara kami, lalu dibagikan kepada orang-orang fakir di antara kami? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, Ya.\" Ia bertanya; \"Aku bersumpah atas nama Allah, apakah Allah telah memerintahkanmu untuk melaksanakan puasa pada bulan ini di setiap tahunnya? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, Ya.\" Ia bertanya; \"Aku bersumpah atas nama Allah, apakah Allah telah memerintahkanmu untuk menunaikan haji ke Baitullah ini bagi orang yang mampu mengadakan perjalanannya? Beliau menjawab, \"Ya Allah, Ya.\" Ia itu berkata, \"Maka sungguh aku telah beriman dan percaya dan aku adalah Dhimam bin Tsa'labah.\""},"2023":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ كَانَ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجْوَدَ النَّاسِ وَكَانَ أَجْوَدَ مَا يَكُونُ فِي رَمَضَانَ حِينَ يَلْقَاهُ جِبْرِيلُ وَكَانَ جِبْرِيلُ يَلْقَاهُ فِي كُلِّ لَيْلَةٍ مِنْ شَهْرِ رَمَضَانَ فَيُدَارِسُهُ الْقُرْآنَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ يَلْقَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام أَجْوَدَ بِالْخَيْرِ مِنْ الرِّيحِ الْمُرْسَلَةِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Dawud] dari [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] bahwasanya ['Abdullah bin 'Abbas] pernah berkata; \"Rasulullah shallallahu 'alaihi wasallam adalah manusia yang paling dermawan dan beliau akan tampak lebih dermawan pada bulan Ramadhan; ketika Jibril menemuinya. Jibril menemuinya setiap malam pada bulan Ramadhan dan mengajarkan Al Qur'an.\" Ibnu Abbas berkata; \"Rasulullah shallallahu 'alaihi wasallam ketika ditemui Jibril -Alaihis Salam- lebih dermawan dalam hal kebaikan daripada angin yang berhembus.\""},"2024":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ الْبُخَارِيُّ قَالَ حَدَّثَنِي حَفْصُ بْنُ عُمَرَ بْنِ الْحَارِثِ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا مَعْمَرٌ وَالنُّعْمَانُ بْنُ رَاشِدٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْمَا لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ لَعْنَةٍ تُذْكَرُ كَانَ إِذَا كَانَ قَرِيبَ عَهْدٍ بِجِبْرِيلَ عَلَيْهِ السَّلَام يُدَارِسُهُ كَانَ أَجْوَدَ بِالْخَيْرِ مِنْ الرِّيحِ الْمُرْسَلَةِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ حَدِيثُ يُونُسَ بْنِ يَزِيدَ وَأَدْخَلَ هَذَا حَدِيثًا فِي حَدِيثٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il Al Bukhari] dia berkata; telah menceritakan kepadaku [Hafsh bin 'Umar bin Al Harits] dia berkata; telah menceritakan kepada kami [Hammad] dia berkata; telah menceritakan kepada kami [Ma'mar] dan [An Nu'man bin Rasyid] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah melakuan sebuah cacian pun. Ketika waktu untuk bertemu dengan Jibril Alaihis Salam yang pernah mengajarinya telah dekat, beliau lebih dermawan dalam hal kebaikan daripada angin yang berhembus.\" Abu Abdurrahman berkata; 'Hadits ini salah, yang benar adalah Hadits Yunus bin Yazid dan dia memasukan Hadits ini ke dalam Hadits lain.\""},"2025":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا أَبُو سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ شَهْرُ رَمَضَانَ فُتِّحَتْ أَبْوَابُ الْجَنَّةِ وَغُلِّقَتْ أَبْوَابُ النَّارِ وَصُفِّدَتْ الشَّيَاطِينُ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Abu Suhail] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika telah memasuki bulan Ramadhan, pintu surga dibuka dan pintu neraka ditutup, dan syetan dibelenggu.\""},"2026":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ الْجُوْزَجَانِيُّ قَالَ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ أَنْبَأَنَا نَافِعُ بْنُ يَزِيدَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ رَمَضَانُ فُتِّحَتْ أَبْوَابُ الْجَنَّةِ وَغُلِّقَتْ أَبْوَابُ النَّارِ وَصُفِّدَتْ الشَّيَاطِينُ","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub Al Juzajani] dia berkata; telah menceritakan kepada kami [Ibnu Abu Maryam] dia berkata; telah memberitakan kepada kami [Nafi' bin Yazid] dari ['Uqail] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Abu Suhail] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika datang bulan Ramadhan, pintu surga dibuka dan pintu neraka ditutup, dan syetan dibelenggu.\""},"2027":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي نَافِعُ بْنُ أَبِي أَنَسٍ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ رَمَضَانُ فُتِّحَتْ أَبْوَابُ الْجَنَّةِ وَغُلِّقَتْ أَبْوَابُ جَهَنَّمَ وَسُلْسِلَتْ الشَّيَاطِينُ","id":"Telah mengabarkan kepada kami ['Abdullah bin Sa'd bin Ibrahim] dia berkata; telah menceritakan kepada kami [pamanku], dia berkata; telah menceritakan kepada kami [bapakku] dari [Shalih] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Nafi' bin Abu Anas] bahwasanya [bapaknya] menceritakan kepadanya, ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika masuk bulan Ramadlan, pintu surga dibuka dan pintu neraka Jahanam ditutup, dan syetan dirantai.\""},"2028":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي ابْنُ أَبِي أَنَسٍ مَوْلَى التَّيْمِيِّينَ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ج��اءَ رَمَضَانُ فُتِّحَتْ أَبْوَابُ الرَّحْمَةِ وَغُلِّقَتْ أَبْوَابُ جَهَنَّمَ وَسُلْسِلَتْ الشَّيَاطِينُ","id":"Telah mengabarkan kepada kami [Muhammad bin Khalid] dia berkata; telah menceritakan kepada kami [Bisyr bin Syu'aib] dari [bapaknya] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku [Ibnu Abu Anas] -budak At Taimiyyun- bahwasanya [bapaknya] menceritakan kepadanya, ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Ramadlan tiba, pintu rahmat dibuka dan pintu neraka Jahanam ditutup, dan syetan dirantai.\""},"2029":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ فِي حَدِيثِهِ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابنِ شِهَابٍ عَنْ ابْنِ أَبِي أَنَسٍ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ رَمَضَانُ فُتِّحَتْ أَبْوَابُ الْجَنَّةِ وَغُلِّقَتْ أَبْوَابُ جَهَنَّمَ وَسُلْسِلَتْ الشَّيَاطِينُرَوَاهُ ابْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dalam haditsnya dari [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Ibnu Abu Anas] bahwasanya [bapaknya] menceritakan kepadanya, ia mendegar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika tiba bulan Ramadlan, pintu syurga dibuka dan pintu neraka Jahanam ditutup, dan syetan dirantai.\" Ibnu Ishaq telah meriwayatkannya dari Az Zuhri."},"2030":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ ابْنِ أَبِي أَنَسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ شَهْرُ رَمَضَانَ فُتِّحَتْ أَبْوَابُ الْجَنَّةِ وَغُلِّقَتْ أَبْوَابُ النَّارِ وَسُلْسِلَتْ الشَّيَاطِينُقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا يَعْنِي حَدِيثَ ابْنِ إِسْحَقَ خَطَأٌ وَلَمْ يَسْمَعْهُ ابْنُ إِسْحَقَ مِنْ الزُّهْرِيِّ وَالصَّوَابُ مَا تَقَدَّمَ ذِكْرُنَا لَهُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; [bapakku] telah menceritakan kepada kami, dari [Ibnu Ishaq] dari [Az Zuhri] dari [Ibnu Abu Anas] dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika masuk -bulan- Ramadhan, pintu syurga dibuka dan pintu neraka ditutup, dan syetan dirantai.\" Abu Abdurrahman berkata; 'Hadits ini salah, Ibnu Ishaq tidak pernah mendengarnya dari Az Zuhri, yang benar adalah Hadits yang telah disebutkan sebelumnya.'"},"2031":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ وَذَكَرَ مُحَمَّدَ بْنَ مُسْلِمٍ عَنْ أُوَيْسِ بْنِ أَبِي أُوَيْسٍ عَدِيدِ بَنِي تَيْمٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذَا رَمَضَانُ قَدْ جَاءَكُمْ تُفَتَّحُ فِيهِ أَبْوَابُ الْجَنَّةِ وَتُغَلَّقُ فِيهِ أَبْوَابُ النَّارِ وَتُسَلْسَلُ فِيهِ الشَّيَاطِينُقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الْحَدِيثُ خَطَأٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; [bapakku] telah menceritakan kepada kami dari [Ibnu Ishaq] dia berkata; dan [Muhammad bin Muslim] menyebutkan dari [Uwais bin Abu Uwais] keturunan Bani Tamim dari [Anas bin Malik] bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \"Inilah bulan Ramadlan telah datang kepada kalian, di bulan itu pintu surga dibuka dan pintu neraka ditutup, dan syetan dirantai.\" Abu Abdurrahman berkata; 'Hadits ini salah.'"},"2032":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُرَغِّبُ فِي قِيَامِ رَمَضَانَ مِنْ غَيْرِ عَزِيمَةٍ وَقَالَ إِذَا دَخَلَ رَمَضَانُ فُتِّحَتْ أَبْوَابُ الْجَنَّةِ وَغُلِّقَتْ أَبْوَابُ الْجَحِيمِ وَسُلْسِلَتْ فِيهِ الشَّيَاطِينُأَرْسَلَهُ ابْنُ الْمُبَارَكِ","id":"Telah mengabarkan kepada kami [Abu Bakr bin 'Ali] dia berkata; telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dia berkata; telah menceritakan kepada kami ['Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam menganjurkan untuk melaksanakan Qiyamullail di -bulan- Ramadlan tanpa anjuran kuat (bukan yang menunjukkan keharusan) dan bersabda: \"Jika bulan Ramadlan tiba, pintu surga dibuka dan pintu neraka Jaham ditutup, dan syetan dirantai di bu; lan itu.\" Ibnu Mubarak memursalkan Hadits ini."},"2033":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حِبَّانُ بْنُ مُوسَى خُرَاسَانِيٌّ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ رَمَضَانُ فُتِحَتْ أَبْوَابُ الرَّحْمَةِ وَغُلِّقَتْ أَبْوَابُ جَهَنَّمَ وَسُلْسِلَتْ الشَّيَاطِينُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] dia berkata; telah memberitakan kepada kami [Hibban bin Musa Al Khurasani] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Ma'mar] dari [Az Zuhri] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jika masuk -bulan- Ramadlan, pintu rahmat dibuka, pintu neraka Jahanam ditutup, dan syetan dirantai."},"2034":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ هِلَالٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاكُمْ رَمَضَانُ شَهْرٌ مُبَارَكٌ فَرَضَ اللَّهُ عَزَّ وَجَلَّ عَلَيْكُمْ صِيَامَهُ تُفْتَحُ فِيهِ أَبْوَابُ السَّمَاءِ وَتُغْلَقُ فِيهِ أَبْوَابُ الْجَحِيمِ وَتُغَلُّ فِيهِ مَرَدَةُ الشَّيَاطِينِ لِلَّهِ فِيهِ لَيْلَةٌ خَيْرٌ مِنْ أَلْفِ شَهْرٍ مَنْ حُرِمَ خَيْرَهَا فَقَدْ حُرِمَ","id":"Telah mengabarkan kepada kami [Bisyr bin Hilal] dia berkata; telah menceritakan kepada kami ['Abdul Warits] dari [Ayyub] dari [Abu Qibalah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ramadlan telah datang kepada kalian, -ia adalah- bulan berkah, Allah -Azza wa Jalla- telah mewajibkan kepada kalian berpuasa. Di buan itu pintu langit dibuka, dan pintu neraka Jahim ditutup dan syetan pembangkang dibelenggu. Demi Allah di bulan itu ada satu malam yang lebih baik dari seribu bulan. Barangsiapa yang tidak mendapat kebaikannya, maka sungguh ia tidak mendapatkannya.\""},"2035":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَرْفَجَةَ قَالَعُدْنَا عُتْبَةَ بْنَ فَرْقَدٍ فَتَذَاكَرْنَا شَهْرَ رَمَضَانَ فَقَالَ مَا تَذْكُرُونَ قُلْنَا شَهْرَ رَمَضَانَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تُفْتَحُ فِيهِ أَبْوَابُ الْجَنَّةِ وَتُغْلَقُ فِيهِ أَبْوَابُ النَّارِ وَتُغَلُّ فِيهِ الشَّيَاطِينُ وَيُنَادِي مُنَادٍ كُلَّ لَيْلَةٍ يَا بَاغِيَ الْخَيْرِ هَلُمَّ وَيَا بَاغِيَ الشَّرِّ أَقْصِرْقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Atha bin As Saib] dari ['Arfajah] dia berkata; \"Kami pernah mengunjungi [Uthbah bin Farqad], lalu kami saling mengingatkan bulan Ramadlan, kemudian ia bertanya; \"Apa yang kalian ingat? Kami menjawab; \"Bulan Ramadlan\". Ia berkata; 'Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Di dalamnya pintu surga dibuka dan pintu neraka di tutup. Syetan di belenggu dan setiap malam ada seorang penyeru memanggil; wahai orang-orang yang mencari kebaikan kemarilah, wahai orang yang mencari kejahatan berhentilah.' Abu Abdurrahman berkata; 'Yang ini salah, '"},"2036":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَرْفَجَةَ قَالَكُنْتُ فِي بَيْتٍ فِيهِ عُتْبَةُ بْنُ فَرْقَدٍ فَأَرَدْتُ أَنْ أُحَدِّثَ بِحَدِيثٍ وَكَانَ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَأَنَّهُ أَوْلَى بِالْحَدِيثِ مِنِّي فَحَدَّثَ الرَّجُلُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي رَمَضَانَ تُفْتَحُ فِيهِ أَبْوَابُ السَّمَاءِ وَتُغْلَقُ فِيهِ أَبْوَابُ النَّارِ وَيُصَفَّدُ فِيهِ كُلُّ شَيْطَانٍ مَرِيدٍ وَيُنَادِي مُنَادٍ كُلَّ لَيْلَةٍ يَا طَالِبَ الْخَيْرِ هَلُمَّ وَيَا طَالِبَ الشَّرِّ أَمْسِكْ","id":"Telah mengabarkan kepada kami, [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Atha' bin Saib] dari [Arjafah], ia berkata; Aku pernah berada di rumah Utbah bin Farqad, lalu aku ingin menceritakan suatu hadits. Dan di sana ada [seorang sahabat] Nabi shallallahu 'alaihi wasallam, sepertinya ia lebih pantas untuk menceritakan hadits tersebut daripada aku. Maka orang itu menceritakan hadits dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Di -bulan- Ramadlan pintu langit dibuka dan pintu neraka ditutup setiap syetan yang membangkang dibelenggu dan seorang penyeru memanggil setiap malam; 'Wahai orang yang mencari kebaikan, kemarilah, wahai orang yang mencari kejahatan tahanlah (berhentilah) '.\""},"2037":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ أَنْبَأَنَا الْمُهَلَّبُ بْنُ أَبِي حَبِيبَةَ ح وَأَنْبَأَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ الْمُهَلَّبِ بْنِ أَبِي حَبِيبَةَ قَالَ أَخْبَرَنِي الْحَسَنُ عَنْ أَبِي بَكْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقُولَنَّ أَحَدُكُمْ صُمْتُ رَمَضَانَ وَلَا قُمْتُهُ كُلَّهُ وَلَا أَدْرِي كَرِهَ التَّزْكِيَةَ أَوْ قَالَ لَا بُدَّ مِنْ غَفْلَةٍ وَرَقْدَةٍاللَّفْظُ لِعُبَيْدِ اللَّهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Yahya bin Sa'id] dia berkata; telah memberitakan kepada kami [Al Muhallab bin Abu Habibah]. Demikian juga diriwayatkan dari jalur lain, dan telah memberitakan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Al Muhallab bin Abu Habibah] dia berkata; telah mengabarkan kepadaku [Al Hasan] dari [Abu Bakrah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah salah seorang diantara kalian mengatakan, 'Aku telah melaksanakan puasa bulan ramadlan, dan jangan pula mengatakan; 'Aku telah melaksanakan qiyamul lail di bulan ramadlan secara keseluruhan. Perawi berkata; 'Aku tidak mengerti apakah beliau tidak menyukai tazkiyah (merasa diri suci), atau juga beliau bersabda: 'Karena pasti mereka akan mendapatkan kemalasan dalam melaksanakannya.' Lafazh ini dari Abdullah."},"2038":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ بْنِ خَالِدٍ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يُخْبِرُنَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِامْرَأَةٍ مِنْ الْأَنْصَارِ إِذَا كَانَ رَمَضَانُ فَاعْتَمِرِي فِيهِ فَإِنَّ عُمْرَةً فِيهِ تَعْدِلُ حَجَّةً","id":"Telah mengabarkan kepada kami ['Imran bin Yazid bin Khalid] dia berkata; telah menceritakan kepada kami [Syu'aib] dia berkata; telah mengabarkan kepadaku [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku ['Atha] dia berkata; Aku mendengar [Ibnu 'Abbas] mengabarkan kepada kami, dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada seorang wanita Anshar: \"Jika Ramadhan tiba, tunaikanlah ibadah Umrah, karena Umrah di bulan itu sebanding dengan satu kali haji.\""},"2039":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ أَبِي حَرْمَلَةَ قَالَ أَخْبَرَنِي كُرَيْبٌأَنَّ أُمَّ الْفَضْلِ بَعَثَتْهُ إِلَى مُعَاوِيَةَ بِالشَّامِ قَالَ فَقَدِمْتُ الشَّامَ فَقَضَيْت�� حَاجَتَهَا وَاسْتَهَلَّ عَلَيَّ هِلَالُ رَمَضَانَ وَأَنَا بِالشَّامِ فَرَأَيْتُ الْهِلَالَ لَيْلَةَ الْجُمُعَةِ ثُمَّ قَدِمْتُ الْمَدِينَةَ فِي آخِرِ الشَّهْرِ فَسَأَلَنِي عَبْدُ اللَّهِ بْنُ عَبَّاسٍ ثُمَّ ذَكَرَ الْهِلَالَ فَقَالَ مَتَى رَأَيْتُمْ فَقُلْتُ رَأَيْنَاهُ لَيْلَةَ الْجُمُعَةِ قَالَ أَنْتَ رَأَيْتَهُ لَيْلَةَ الْجُمُعَةِ قُلْتُ نَعَمْ وَرَآهُ النَّاسُ فَصَامُوا وَصَامَ مُعَاوِيَةُ قَالَ لَكِنْ رَأَيْنَاهُ لَيْلَةَ السَّبْتِ فَلَا نَزَالُ نَصُومُ حَتَّى نُكْمِلَ ثَلَاثِينَ يَوْمًا أَوْ نَرَاهُ فَقُلْتُ أَوَ لَا تَكْتَفِي بِرُؤْيَةِ مُعَاوِيَةَ وَأَصْحَابِهِ قَالَ لَا هَكَذَا أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Muhammad bin Abu Harmalah] dia berkata; telah mengabarkan kepadaku [Kuraib] bahwa Ummul Fadhl mengutusnya untuk menemui Mu'awiyah di Syam, ia menuturkan; \"Maka aku datang ke Syam, lalu menyelesaikan keperluannya. Hilal Ramadlan nampak jelas atas diriku ketika aku berada di Syam, dan aku melihat hilal pada malam jum'at. Kemudian aku datang ke Madinah di akhir bulan, lalu aku bertanya kepada [Abdullah bin Abbas], kemudian ia menyebutkan tentang hilal dan bertanya; \"Kapan kalian melihatnya?\" Aku menjawab, \"Kami melihatnya pada malam jum'at.\" Ia bertanya; \"Kamu melihatnya pada malam jum'at?\" aku menjawab; \"Ya, dan orang-orang melihatnya lalu mereka berpuasa dan Mu'awiyah pun berpuasa.\" Dia berkata; \"Tetapi kami melihatnya pada malam sabtu! Maka kita tetap berpuasa hingga kita menggenapkan tiga puluh hari atau ketika kita melihatnya lagi. Aku bertanya; \"Tidakkah kita merasa cukup dengan ru'yah Mu'awiyah dan sahabatnya?\" ia menjawab; \"Tidak, demikianlah Rasulullah shallallahu 'alaihi wasallam memerintahkan kita.\""},"2040":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَأَيْتُ الْهِلَالَ فَقَالَ أَتَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ قَالَ نَعَمْ فَنَادَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ صُومُوا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul 'Aziz bin Abu Rizmah] dia berkata; telah memberitakan kepada kami [Al Fadhl bin Musa] dari [Sufyan] dari [Simak] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata; \"Seorang Badui datang kepada Nabi shallallahu 'alaihi wasallam ia berkata aku melihat hilal, beliau bersabda: 'Apakah engkau bersaksi bahwa tiada tuhan yang patut disembah selain Allah dan Muhammad adalah hamba dan utusanNya? ' ia menjawab iya, kemudian Nabi shallallahu 'alaihi wasallam mengumumkan agar berpuasa.\""},"2041":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبْصَرْتُ الْهِلَالَ اللَّيْلَةَ قَالَ أَتَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ قَالَ نَعَمْ قَالَ يَا بِلَالُ أَذِّنْ فِي النَّاسِ فَلْيَصُومُوا غَدًاأَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ عَنْ أَبِي دَاوُدَ عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ مُرْسَلٌ أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ نُعَيْمٍ مِصِّيصِيٌّ قَالَ أَنْبَأَنَا حِبَّانُ بْنُ مُوسَى الْمَرْوَزِيُّ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ مُرْسَلٌ","id":"Telah mengabarkan kepada kami [Musa bin 'Abdurrahman] dia berkata; telah menceritakan kepada kami [Husain] dari [Zaidah] dari [Simak] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata; \"Seorang Badui datang kepada Nabi shallallahu 'alaihi wasallam ia berkata aku telah melihat hilal malam ini, beliau bersabda: 'Apakah engkau bersaksi bahwa tiada tuhan yang patut disembah selain Allah dan Muhammad adalah hamba dan utusanNya? ' ia menjawab iya, kemudian Nabi shallallahu 'alaihi wasallam bersabda: 'Wahai Bilal! Umumkanlah kepada manusia bahwa besok berpuasa.\" Telah mengabarkan [Ahmad bin Sulaiman] dari [Abu Daud] dari [Sufyan] dari [Simak] dari [Ikrimah] secara mursal. Telah mengabarkan kepada kami [Muhammad bin Hatim bin Nu'aim Mishishi] dia berkata; Telah memberitakan kepada kami [Hibban bin Musa Al Marwazi] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Sufyan] dari [Simak] dari [Ikrimah] secara mursal."},"2042":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ شَبِيبٍ أَبُو عُثْمَانَ وَكَانَ شَيْخًا صَالِحًا بِطَرَسُوسَ قَالَ أَنْبَأَنَا ابْنُ أَبِي زَائِدَةَ عَنْ حُسَيْنِ بْنِ الْحَارِثِ الْجَدَلِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زَيْدِ بْنِ الْخَطَّابِأَنَّهُ خَطَبَ النَّاسَ فِي الْيَوْمِ الَّذِي يُشَكُّ فِيهِ فَقَالَ أَلَا إِنِّي جَالَسْتُ أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَاءَلْتُهُمْ وَإِنَّهُمْ حَدَّثُونِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ وَانْسُكُوا لَهَا فَإِنْ غُمَّ عَلَيْكُمْ فَأَكْمِلُوا ثَلَاثِينَ فَإِنْ شَهِدَ شَاهِدَانِ فَصُومُوا وَأَفْطِرُوا","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami [Sa'id bin Syabib Abu 'Utsman] -dan dia adalah seorang syaikh yang Shalih di Tharasus- dia berkata; telah memberitakan kepada kami [Ibnu Abu Zaidah] dari [Husain bin Al Harits Al Jadali] dari ['Abdurrahman bin Zaid bin Al Khaththab] bahwa ia berkhutbah di hadapan manusia di hari yang diragukan untuk berpuasa di dalamnya. Lalu ia berkata; \"Ketahuilah aku pernah duduk [bersama sahabat Rasulullah shallallahu 'alaihi wasallam], dan aku bertanya kepada mereka. Mereka menceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berpuasalah kalian karena melihatnya, berbukalah kalian karena melihatnya dan sembelihlah kurban karena melihatnya pula. Jika -hilal- itu tertutup dari pandangan kalian, sempurnakanlah menjadi tiga puluh hari, jika ada dua orang saksi, berpuasa dan berbukalah kalian.\""},"2043":{"ar":"أَخْبَرَنَا مُؤَمَّلُ بْنُ هِشَامٍ عَنْ إِسْمَعِيلَ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ فَإِنْ غُمَّ عَلَيْكُمْ الشَّهْرُ فَعُدُّوا ثَلَاثِينَ","id":"Telah mengabarkan kepada kami [Muammal bin Hisyam] dari [Isma'il] dari [Syu'bah] dari [Muhammad bin Ziyad] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berpuasalah jika kalian melihatnya (hilal) dan berbukalah jika kalian melihatnya jika terjadi mendung, hitunglah tiga puluh hari.\""},"2044":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا وَرْقَاءُ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ فَإِنْ غُمَّ عَلَيْكُمْ فَاقْدِرُوا ثَلَاثِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Yazid] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Warqa'] dari [Syu'bah] dari [Muhammad bin Ziyad] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berpuasalah kalian karena melihat (hilal) dan berbukalah kalian karena melihatnya pula. Jika -hilal- itu tertutup dari pandangan kalian, maka genapkanlah menjadi tiga puluh hari.\""},"2045":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ النَّيْسَابُورِيُّ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ الْهِلَالَ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ غُمَّ عَلَيْكُمْ فَصُومُوا ثَلَاثِينَ يَوْمًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin 'Abdullah An Naisaburi] dia berkata; telah menceritakan kepada kami [Sulaiman bin Dawud] dia berkata; telah menceritakan kepada kami [Ibrahim] dari [Muhammad bin Muslim] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian melihat hilal, berpuasalah dan jika kalian melihatnya maka berbukalah. Jika -hilal- tertutup dari pandangan kalian, maka berpuasalah tiga puluh hari.\""},"2046":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا رَأَيْتُمْ الْهِلَالَ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ غُمَّ عَلَيْكُمْ فَاقْدِرُوا لَهُ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; telah menceritakan kepadaku [Salim bin 'Abdullah] bahwasanya ['Abdullah bin 'Umar] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian melihat hilal, berpuasalah dan jika kalian melihatnya, berbukalah. Jika -hilal- itu tertutup dari pandangan kalian, perkirakanlah untuknya.\""},"2047":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ رَمَضَانَ فَقَالَ لَا تَصُومُوا حَتَّى تَرَوْا الْهِلَالَ وَلَا تُفْطِرُوا حَتَّى تَرَوْهُ فَإِنْ غُمَّ عَلَيْكُمْ فَاقْدِرُوا لَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Sa'd] dan [Al Harits bin Miskin] secara baca, dan Aku mendengarnya, lafazh ini miliknya, dari [Ibnul Qasim] dari [Malik] dari [Nafi'] dari [Ibnu 'Umar] bahwa Rasulullah shallallahu 'alaihi wasallam menyebutkan Ramadlan, lalu bersabda: \"Janganlah kalian berpuasa hingga kalian melihat hilal dan janganlah berbuka hingga kalian melihatnya. Jika -hilal- itu tertutup dari pandangan kalian, genapkanlah untuknya.\""},"2048":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصُومُوا حَتَّى تَرَوْهُ وَلَا تُفْطِرُوا حَتَّى تَرَوْهُ فَإِنْ غُمَّ عَلَيْكُمْ فَاقْدِرُوا لَهُ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dia berkata; telah menceritakan kepadaku [Nafi'] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian berpuasa hingga kalian melihat hilal dan janganlah berbuka hingga kalian melihatnya. Jika -hilal- itu tertutup dari pandangan kalian, genapkanlah untuknya.\""},"2049":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ صَاحِبَ حِمْصَ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْهِلَالَ فَقَالَ إِذَا رَأَيْتُمُوهُ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ غُمَّ عَلَيْكُمْ فَعُدُّوا ثَلَاثِينَ","id":"Telah mengabarkan kepada kami [Abu Bakr bin 'Ali] -penduduk Himsh- dia berkata; telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dia berkata; telah menceritakan kepada kami [Muhammad bin Bisyr] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam menyebutkan hilal, lalu bersabda: \"Jika kalian melihatnya, berpuasalah dan jika kalian melihatnya maka berbukalah. Jika tertutup dari pandangan kalian, hitunglah menjadi tiga puluh hari.\""},"2050":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ أَبُو الْجَوْزَاءِ وَهُوَ ثِقَةٌ بَصْرِيٌّ أَخُو أَبِي الْعَالِيَةِ قَالَ أَنْبَأَنَا حِبَّانُ بْنُ هِلَالٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ فَإِنْ غُمَّ عَلَيْكُمْ فَأَكْمِلُوا الْعِدَّةَ ثَلَاثِينَ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Utsman Abul Jauza] -dan dia adalah seorang yang tsiqah, berasal dari Bashrah, saudara Abul 'Aliyah- dia berkata; telah memberitakan kepada kami [Hibban bin Hilal] dia berkata; telah menceritakan kepada kami [Hammad bin Sa'd] dari ['Amr bin Dinar] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berpuasalah kalian karena melihatnya dan berbukalah kalian karena melihatnya pula. Jika tertutup dari pandangan kalian, maka sempurnakanlah bilangan -bulan- menjadi tiga puluh hari.\""},"2051":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ مُحَمَّدِ بْنِ حُنَيْنٍ عَنْ ابْنِ عَبَّاسٍ قَالَعَجِبْتُ مِمَّنْ يَتَقَدَّمُ الشَّهْرَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الْهِلَالَ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ غُمَّ عَلَيْكُمْ فَأَكْمِلُوا الْعِدَّةَ ثَلَاثِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Yazid] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [Muhammad bin Hunain] dari [Ibnu 'Abbas] dia berkata; Aku heran terhadap orang yang mendahului bulan, padahal Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Jika kalian melihat hilal, maka berpuasalah dan jika kalian melihatnya, berbukalah. Jika -hilal- tertutup dari pandangan kalian, sempurnakanlah bilangan -bulan- menjadi tiga puluh hari.\""},"2052":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقَدَّمُوا الشَّهْرَ حَتَّى تَرَوْا الْهِلَالَ قَبْلَهُ أَوْ تُكْمِلُوا الْعِدَّةَ ثُمَّ صُومُوا حَتَّى تَرَوْا الْهِلَالَ أَوْ تُكْمِلُوا الْعِدَّةَ قَبْلَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Rib'i bin Hirasy] dari [Hudzaifah bin Al Yaman] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah kalian mendahului bulan (Ramadhan) hingga kalian melihat hilal sebelumnya atau menyempurnakan bilangan, kemudian berpuasalah kalian hingga melihat hilal atau menyempurnakan bilangan -bulan- sebelumnya.\""},"2053":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقَدَّمُوا الشَّهْرَ حَتَّى تُكْمِلُوا الْعِدَّةَ أَوْ تَرَوْا الْهِلَالَ ثُمَّ صُومُوا وَلَا تُفْطِرُوا حَتَّى تَرَوْا الْهِلَالَ أَوْ تُكْمِلُوا الْعِدَّةَ ثَلَاثِينَأَرْسَلَهُ الْحَجَّاجُ بْنُ أَرْطَاةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Rib'i] dari [sebagian Sahabat] Nabi shallallahu 'alaihi wasallam \"Janganlah kalian mendahului bulan (Ramadlan) hingga kalian menyempurnakan bilangan -bulan- atau melihat hilal -sebelumnya-, kemudian berpuasalah kalian dan janganlah berbuka hingga kalian melihat hilal atau menyempurnakan bilangan -bulan- menjadi tiga puluh hari.\""},"2054":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ حَدَّثَنَا حِبَّانُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ الْحَجَّاجِ بْنِ أَرْطَاةَ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الْهِلَالَ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ غُمَّ عَلَيْكُمْ فَأَتِمُّوا شَعْبَانَ ثَلَاثِينَ إِلَّا أَنْ تَرَوْا الْهِلَالَ قَبْلَ ذَلِكَ ثُمَّ صُومُوا رَمَضَانَ ثَلَاثِينَ إِلَّا أَنْ تَرَوْا الْهِلَالَ قَبْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] dia berkata; telah menceritakan kepada kami [Hibban] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Al Hajjaj bin Arthah] dari [Manshur] dari [Rib'i] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian melihat hilal, berpuasalah dan jika kalian melihatnya, berbukalah. Jika -hilal- tertutup dari pandangan kalian, sempurnakanlah -hitungan- bulan Sya'ban menjadi tiga puluh -hari-, kecuali jika kalian melihat hilal sebelum itu, kemudian berpuasalah di bulan Ramadlan tiga puluh hari kecuali jika kalian melihat hilal sebelum itu.\""},"2055":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا حَاتِمُ بْنُ أَبِي صَغِيرَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عِكْرِمَةَ قَالَ حَدَّثَنَا ابْنُ عَبَّاسٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ فَإِنْ حَالَ بَيْنَكُمْ وَبَيْنَهُ سَحَابٌ فَأَكْمِلُوا الْعِدَّةَ وَلَا تَسْتَقْبِلُوا الشَّهْرَ اسْتِقْبَالًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dia berkata; telah menceritakan kepada kami [Hatim bin Abu Shaghirah] dari [Simak bin Harb] dari ['Ikrimah] dia berkata; telah menceritakan kepada kami [Ibnu 'Abbas] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Berpuasalah kalian karena melihatnya dan berbukalah karena melihatnya pula. Jika ada awan menghalangi antara kalian dan hilal, sempurnakanlah bilangan -bulan- janganlah kalian menghadap bulan (selanjutnya).\""},"2056":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَصُومُوا قَبْلَ رَمَضَانَ صُومُوا لِلرُّؤْيَةِ وَأَفْطِرُوا لِلرُّؤْيَةِ فَإِنْ حَالَتْ دُونَهُ غَيَايَةٌ فَأَكْمِلُوا ثَلَاثِينَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Simak] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berpuasa sebelum Ramadlan, berpuasalah kalian karena melihatnya dan berbukalah kalian karena melihatnya. Jika ada mendung yang menghalangi di bawahnya, sempurnakanlah bilangan -bulan- menjadi tiga puluh hari.\""},"2057":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ عَنْ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْأَقْسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا يَدْخُلَ عَلَى نِسَائِهِ شَهْرًا فَلَبِثَ تِسْعًا وَعِشْرِينَ فَقُلْتُ أَلَيْسَ قَدْ كُنْتَ آلَيْتَ شَهْرًا فَعَدَدْتُ الْأَيَّامَ تِسْعًا وَعِشْرِينَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ","id":"Telah mengabarkan kepada kami [Nashr bin 'Ali Al Jahdlami] dari ['Abdul A'la] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersumpah untuk tidak menemui istrinya selama satu bulan, lalu beliau tinggal (melalui) selama dua puluh sembilan hari! Aku kemudian bertanya; \"Bukankah engkau telah bersumpah -untuk tidak menemui istri-istri engkau- selama satu bulan? Padahal aku baru menghitung hari-hari itu sebanyak dua puluh sembilan hari!\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan dua puluh sembilan hari.\""},"2058":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ حَدَّثَهُ ح و أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ قَالَ أَنْبَأَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمْ أَزَلْ حَرِيصًا أَنْ أَسْأَلَ عُمَرَ بْنَ الْخَطَّابِ عَنْ الْمَرْأَتَيْنِ مِنْ أَزْوَاجِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَيْنِ قَالَ اللَّهُ لَهُمَا{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }وَسَاقَ الْحَدِيثَ وَقَالَ فِيهِ فَاعْتَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ مِنْ أَجْلِ ذَلِكَ الْحَدِيثِ حِينَ أَفْشَتْهُ حَفْصَةُ إِلَى عَائِشَةَ تِسْعًا وَعِشْرِينَ لَيْلَةً قَالَتْ عَائِشَةُ وَكَانَ قَالَ مَا أَنَا بِدَاخِلٍ عَلَيْهِنَّ شَهْرًا مِنْ شِدَّةِ مَوْجِدَتِهِ عَلَيْهِنَّ حِينَ حَدَّثَهُ اللَّهُ عَزَّ وَجَلَّ حَدِيثَهُنَّ فَلَمَّا مَضَتْ تِسْعٌ وَعِشْرُونَ لَيْلَةً دَخَلَ عَلَى عَائِشَةَ فَبَدَأَ بِهَا فَقَالَتْ لَهُ عَائِشَةُ إِنَّكَ قَدْ كُنْتَ آلَيْتَ يَا رَسُولَ اللَّهِ أَنْ لَا تَدْخُلَ عَلَيْنَا شَهْرًا وَإِنَّا أَصْبَحْنَا مِنْ تِسْعٍ وَعِشْرِينَ لَيْلَةً نَعُدُّهَا عَدَدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ لَيْلَةً","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; [bapakku] telah menceritakan kepada kami, dari [Shalih] dari [Ibnu Syihab] bahwasanya ['Ubaidullah bin 'Abdullah bin Abu Tsaur] menceritakan kepadanya. Demikian juga diriwayatkan dari jalur lain, dan telah mengabarkan kepada kami ['Amru bin Manshur] dia berkata; telah menceritakan kepada kami [Al Hakam bin Nafi'] dia berkata; telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin Abu Tsaur] dari [Ibnu 'Abbas] dia berkata; Aku masih tetap bersemangat untuk bertanya kepada [Umar bin Khaththab] tentang dua orang dari istri Rasulullah shallallahu 'alaihi wasallam yang Allah berfirman kepada keduanya: \"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong -untuk menerima kebaikan-.\" (Qs. At Tahrim 66: 4). Dan ia menyebutkan hadits ini. Ia berkata di dalam hadits tersebut; \"Maka Rasulullah shallallahu 'alaihi wasallam menjauh dari istri-istrinya karena pembicaraan itu; ketika Hafshah menyebarkannya kepada Aisyah, yaitu selama dua puluh Sembilan malam. Aisyah berkata; Beliau bersabda: \"Aku tidak akan menemui mereka selama satu bulan.\" Karena besarnya kemarahan beliau terhadap mereka, ketika Allah -Azza wa Jalla- menceritakan kepada beliau apa yang terjadi pada mereka. Setelah dua puluh Sembilan malam berlalu, beliau masuk menemui Aisyah, dan dengannyalah beliau memulainya, kemudian Aisyah berkata kepada beliau; \"Sesungguhnya engkau telah bersumpah wahai Rasulullah shallallahu 'alaihi wasallam, untuk tidak menemui kami selama satu bulan, dan kami memasuki pagi hari dari dua puluh sembilan malam, kami menghitungnya dari awal, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan itu ada dua puluh sembilan malam.\""},"2059":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ هُوَ أَبُو بُرَيْدٍ الْجَرْمِيُّ بَصْرِيٌّ عَنْ بَهْزٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ عَنْ أَبِي الْحَكَمِ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَانِي جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ يَوْمًا","id":"Telah mengabarkan kepada kami ['Amru bin Yazid Abu Buraid Al Jarmi Al Bashri] dari [Bahz] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Salamah] dari [Abul Hakam] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \" Jibril Alaihissalam menemuiku dan ia berkata sebulan itu ada dua puluh sembilan hari.\""},"2060":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ وَذَكَرَ كَلِمَةً مَعْنَاهَا حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ قَالَ سَلَمَةُ سَمِعْتُ أَبَا الْحَكَمِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ يَوْمًا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dari [Muhammad] -dan dia menyebutkan kalimat yang ma'nanya- telah menceritakan kepada kami [Syu'bah] dari [Salamah] dia berkata; aku mendengar [Abul Hakam] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan dua puluh sembilan hari.\""},"2061":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ مُحَمَّدِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ ضَرَبَ بِيَدِهِ عَلَى الْأُخْرَى وَقَالَ الشَّهْرُ هَكَذَا وَهَكَذَا وَهَكَذَا وَنَقَصَ فِي الثَّالِثَةِ إِصْبَعًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Isma'il bin Abu Khalid] dari [Muhammad bin Sa'd bin Abu Waqqash] dari [bapaknya] dari Nabi bahwasanya beliau mengisyaratkan dengan tangannya dan bersabda: \"Satu bulan itu seperti ini, seperti ini dan seperti ini, \" dan beliau mengurangi pada yang ketiga kali dengan satu jari (berjumlah dua puluh sembilan)."},"2062":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ إِسْمَعِيلَ عَنْ مُحَمَّدِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ هَكَذَا وَهَكَذَا وَهَكَذَا يَعْنِي تِسْعَةً وَعِشْرِينَرَوَاهُ يَحْيَى بْنُ سَعِيدٍ وَغَيْرُهُ عَنْ إِسْمَعِيلَ عَنْ مُحَمَّدِ بْنِ سَعْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Isma'il] dari [Muhammad bin Sa'd] dari [bapaknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan itu begini, begini dan begini.\" Yakni dua puluh sembilan. Yahya bin Sa'id dan yang lainnya telah meriwayatkannya dari Isma'il dari Muhammad bin Sa'd dari Nabi shallallahu 'alaihi wasallam."},"2063":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ مُحَمَّدِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ هَكَذَا وَهَكَذَا وَهَكَذَا وَصَفَّقَ مُحَمَّدُ بْنُ عُبَيْدٍ بِيَدَيْهِ يَنْعَتُهَا ثَلَاثًا ثُمَّ قَبَضَ فِي الثَّالِثَةِ الْإِبْهَامَ فِي الْيُسْرَىقَالَ يَحْيَى بْنُ سَعِيدٍ قُلْتُ لِإِسْمَعِيلَ عَنْ أَبِيهِ قَالَ لَا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Ubaid] dia berkata; telah menceritakan kepada kami [Isma'il] dari [Muhammad bin Sa'd bin Abu Waqqash] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan itu begini, begini dan begini.\" Muhammad bin Ubaid menepukkan tangannya untuk menggambarkannya tiga kali, kemudian yang ketiga kalinya ia menggenggam ibu jari tangan kirinya. Yahya bin Sa'id berkata; 'Aku bertanya kepada Isma'il, apakah dari bapaknya? Dia menjawab; 'Bukan'."},"2064":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا هَارُونُ قَالَ حَدَّثَنَا عَلِيٌّ هُوَ ابْنُ الْمُبَارَكِ قَالَ حَدَّثَنَا يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ يَكُونُ تِسْعَةً وَعِشْرِينَ وَيَكُونُ ثَلَاثِينَ فَإِذَا رَأَيْتُمُوهُ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ غُمَّ عَلَيْكُمْ فَأَكْمِلُوا الْعِدَّةَ","id":"Telah mengabarkan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Harun] dia berkata; telah menceritakan kepada kami ['Ali bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Yahya] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Satu bulan bisa dua puluh sembilan dan bisa tiga puluh hari, jika kalian melihatnya, maka berpuasalah dan jika kalian melihatnya maka berbukalah. Jika -hilal- tertutup dari pandangan kalian, maka sempurnakanlah bilangan -bulan- menjadi tiga puluh hari.\""},"2065":{"ar":"أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا مُعَاوِيَةُ ح و أَخْبَرَنِي أَحْمَدُ بْنُ مُحَمَّدِ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ سَعِيدٍ عَنْ مُعَاوِيَةَ وَاللَّفْظُ لَهُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ أَنَّ أَبَا سَلَمَةَ أَخْبَرَهُ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ وَهُوَ ابْنُ عُمَرَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الشَّهْرُ تِسْعٌ وَعِشْرُونَ","id":"Telah mengabarkan kepadaku ['Ubaidullah bin Fadlalah bin Ibrahim] dia berkata; telah memberitakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Mu'awiyah]. Dan diriwayatkan pula dari jalur lain, telah mengabarkan kepadaku [Ahmad bin Muhammad bin Al Mughirah] dia berkata; telah menceritakan kepada kami ['Utsman bin Sa'id] dari [Mu'awiyah] -dan lafazh ini miliknya- dari [Yahya bin Abu Katsir] bahwasanya [Abu Salamah] mengabarkan kepadanya, ia mendengar ['Abdullah bin 'Umar] berkata; 'Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan itu adalah dua puluh sembilan hari.\""},"2066":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ سَعِيدِ بْنِ عَمْرٍو عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّا أُمَّةٌ أُمِّيَّةٌ لَا نَكْتُبُ وَلَا نَحْسُبُ الشَّهْرُ هَكَذَا وَهَكَذَا وَهَكَذَا ثَلَاثًا حَتَّى ذَكَرَ تِسْعًا وَعِشْرِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Al Aswad bin Qais] dari [Sa'id bin 'Amru] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kita adalah umat yang ummi (buta huruf), kita tidak bisa menulis dan tidak bisa menghitung, satu bulan itu begini, begini dan begini -tiga kali-hingga beliau menyebutkan dua puluh sembilan hari.\""},"2067":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ عَنْ شُعْبَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ عَمْرِو بْنِ سَعِيدِ بْنِ أَبِي الْعَاصِ أَنَّهُ سَمِعَ ابْنَ عُمَرَ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّا أُمَّةٌ أُمِّيَّةٌ لَا نَحْسُبُ وَلَا نَكْتُبُ وَالشَّهْرُ هَكَذَا وَهَكَذَا وَهَكَذَا وَعَقَدَ الْإِبْهَامَ فِي الثَّالِثَةِ وَالشَّهْرُ هَكَذَا وَهَكَذَا وَهَكَذَا تَمَامَ الثَّلَاثِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] dari [Muhammad] dari [Syu'bah] dari [Al Aswad bin Qais] dia berkata; Aku mendengar [Sa'id bin 'Amru bin Sa'id bin Abu Waqqash] bahwasanya ia mendengar [Ibnu 'Umar] menceritakan dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kita adalah umat yang ummi (buta huruf), kita tidak bisa menghitung dan tidak bisa menulis, satu bulan itu begini, begini dan begini -dan beliau menggenggam ibu jari di saat menyebutkan yang ketiga kalinya- dalam satu bulan itu begini, begini dan begini, genap tiga puluh hari.\""},"2068":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ جَبَلَةَ بْنِ سُحَيْمٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشَّهْرُ هَكَذَا وَوَصَفَ شُعْبَةُ عَنْ صِفَةِ جَبَلَةَ عَنْ صِفَةِ ابْنِ عُمَرَ أَنَّهُ تِسْعٌ وَعِشْرُونَ فِيمَا حَكَى مِنْ صَنِيعِهِ مَرَّتَيْنِ بِأَصَابِعِ يَدَيْهِ وَنَقَصَ فِي الثَّالِثَةِ إِصْبَعًا مِنْ أَصَابِعِ يَدَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Jabalah bin Suhaim] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Satu bulan itu begini.\" Syu'bah menggambarkan dari gambaran Jabalah, dari gambaran Ibnu Umar, yaitu: dua puluh sembilan hari, sebagaimana diceritakan dari sabdanya shallallahu 'alaihi wasallam, dua kali dengan jari-jari kedua tangannya dan di saat yang ketiga kalinya beliau mengurangi satu jari dari jari-jari kedua tangannya.\""},"2069":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عُقْبَةَ يَعْنِي ابْنَ حُرَيْثٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Uqbah bin Huraits] dia berkata; Aku mendengar [Ibnu 'Umar] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan dua puluh sembilan hari.\""},"2070":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَحَّرُوا فَإِنَّ فِي السَّحُورِ بَرَكَةًوَقَفَهُ عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari ['Ashim] dari [Zirr] dari ['Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makan sahurlah kalian karena pada makan sahur terdapat berkah, \" Ubaidillah bin Said memauqufkannya."},"2071":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ أَبِي بَكْرِ بْنِ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ قَالَتَسَحَّرُواقَالَ عُبَيْدُ اللَّهِ لَا أَدْرِي كَيْفَ لَفْظُهُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Abu Bakr bin 'Ayyasy] dari ['Ashim] dari [Zirr] dari ['Abdullah] dia berkata; \"Makan sahurlah kalian.\" Ubaidullah berkata; 'Aku tidak tahu lafazhnya bagaimana.'"},"2072":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ وَعَبْدِ الْعَزِيزِ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَحَّرُوا فَإِنَّ فِي السَّحُورِ بَرَكَةً","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dan ['Abdul 'Aziz] dari [Anas] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Makan sahurlah kalian, karena sesungguhnya dalam sahur itu terdapat berkah.\""},"2073":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ سَعِيدِ بْنِ جَرِيرٍ نَسَائِيٌّ قَالَ حَدَّثَنَا أَبُو الرَّبِيعِ قَالَ حَدَّثَنَا مَنْصُورُ بْنُ أَبِي الْأَسْوَدِ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَحَّرُوا فَإِنَّ فِي السَّحُورِ بَرَكَةً","id":"Telah mengabarkan kepada kami ['Ali bin Sa'id bin Jarir An Nasa'i] dia berkata; telah menceritakan kepada kami [Abu Ar Rabi'] dia berkata; telah menceritakan kepada kami [Manshur bin Abul Aswad] dari ['Abdul Malik bin Abu Sulaiman] dari ['Atha'] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makan sahurlah kalian karena sesungguhnya dalam sahur itu terdapat berkah.\""},"2074":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَتَسَحَّرُوا فَإِنَّ فِي السَّحُورِ بَرَكَةًرَفَعَهُ ابْنُ أَبِي لَيْلَى","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Yazid] dia berkata; telah memberitakan kepada kami ['Abdul Malik bin Abu Sulaiman] dari ['Atha] dari [Abu Hurairah] dia berkata; \"Makan sahurlah kalian karena sesungguhnya dalam sahur itu terdapat berkah.\" Ibnu Abu Laila memarfu'kannya."},"2075":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ أَبِي لَيْلَى عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَسَحَّرُوا فَإِنَّ فِي السَّحُورِ بَرَكَةً","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Ibnu Abu Laila] dari ['Atha] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Makan sahurlah kalian karena sesungguhnya dalam sahur itu terdapat berkah.\""},"2076":{"ar":"أَخْبَرَنَا عَبْدُ الْأَعْلَى بْنُ وَاصِلِ بْنِ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَحَّرُوا فَإِنَّ فِي السَّحُورِ بَرَكَةً","id":"Telah mengabarkan kepada kami ['Abdul A'la bin Washil bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Sufyan] dari [Ibnu Abu Laila] dari ['Atha] dari [Abu Hurairah] dia berkata; dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Makan sahurlah kalian karena sesungguhnya dalam sahur itu terdapat berkah.\""},"2077":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَحَّرُوا فَإِنَّ فِي السَّحُورِ بَرَكَةًقَالَ أَبُو عَبْد الرَّحْمَنِ حَدِيثُ يَحْيَى بْنِ سَعِيدٍ هَذَا إِسْنَادُهُ حَسَنٌ وَهُوَ مُنْكَرٌ وَأَخَافُ أَنْ يَكُونَ الْغَلَطُ مِنْ مُحَمَّدِ بْنِ فُضَيْلٍ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami [Abu Bakr bin Khallad] dia berkata; telah menceritakan kepada kami [Muhammad bin Fudhail] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makan sahurlah kalian karena sesungguhnya dalam sahur itu terdapat berkah.\" Abu Abdurrahman berkata; 'Isnad Hadits Yahya bin Sa'id ini adalah hasan, tapi dianggap mungkar, aku khawatir kesalahannya dari Muhammad bin Fudlail.'"},"2078":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ أَيُّوبَ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ زِرٍّ قَالَقُلْنَا لِحُذَيْفَةَ أَيَّ سَاعَةٍ تَسَحَّرْتَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هُوَ النَّهَارُ إِلَّا أَنَّ الشَّمْسَ لَمْ تَطْلُعْ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Ayyub] dia berkata; telah memberitakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ashim] dari [Zirr] dia berkata; Kami bertanya kepada [Hudzaifah], \"Pada saat apakah engkau makan sahur bersama Rasulullah shallallahu 'alaihi wasallam? Ia menjawab, \"Yaitu diwaktu siang, hanya saja matahari belum terbit.\""},"2079":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيٍّ قَالَ سَمِعْتُ زِرَّ بْنَ حُبَيْشٍ قَالَتَسَحَّرْتُ مَعَ حُذَيْفَةَ ثُمَّ خَرَجْنَا إِلَى الصَّلَاةِ فَلَمَّا أَتَيْنَا الْمَسْجِدَ صَلَّيْنَا رَكْعَتَيْنِ وَأُقِيمَتْ الصَّلَاةُ وَلَيْسَ بَيْنَهُمَا إِلَّا هُنَيْهَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Adi] dia berkata; Aku mendengar [Zirr bin Hubaisy] dia berkata; \"Aku pernah makan sahur bersama [Hudzaifah], kemudian kami keluar untuk melaksanakan shalat, setelah sampai di masjid, kami shalat dua rakaat, lalu shalat didirikan dan tidak ada di antara keduanya kecuali waktu yang sangat pendek.\""},"2080":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ قَالَ حَدَّثَنَا أَبُو يَعْفُورٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ عَنْ صِلَةَ بْنِ زُفَرَ قَالَتَسَحَّرْتُ مَعَ حُذَيْفَةَ ثُمَّ خَرَجْنَا إِلَى الْمَسْجِدِ فَصَلَّيْنَا رَكْعَتَيْ الْفَجْرِ ثُمَّ أُقِيمَتْ الصَّلَاةُ فَصَلَّيْنَا","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Muhammad bin Fudhail] dia berkata; telah menceritakan kepada kami [Abu Ya'fur] dia berkata; telah menceritakan kepada kami [Ibrahim] dari [Shilah bin Zufar] dia berkata; \"Aku pernah makan sahur bersama [Hudzaifah], kemudian kami keluar ke masjid, lalu kami shalat dua rakaat, kemudian shalat didirikan, dan kamipun melaksanakan shalat.\""},"2081":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَتَسَحَّرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قُمْنَا إِلَى الصَّلَاةِ قُلْتُ كَمْ كَانَ بَيْنَهُمَا قَالَ قَدْرُ مَا يَقْرَأُ الرَّجُلُ خَمْسِينَ آيَةً","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] dari [Zaid bin Tsabit] dia berkata; \"Kami makan sahur bersama Rasulullah shallallahu 'alaihi wasallam, kemudian kami berdiri untuk melaksanakan shalat.\" Aku bertanya; \"Berapa jarak antara keduanya? Ia menjawab, \"Seukuran orang membaca lima puluh ayat.\""},"2082":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَتَسَحَّرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قُمْنَا إِلَى الصَّلَاةِ قُلْتُ زُعِمَ أَنَّ أَنَسًا الْقَائِلُ مَا كَانَ بَيْنَ ذَلِكَ قَالَ قَدْرُ مَا يَقْرَأُ الرَّجُلُ خَمْسِينَ آيَةً","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Hisyam] dia berkata; telah menceritakan kepada kami [Qatadah] dari [Anas] dari [Zaid bin Tsabit] dia berkata; \"Kami pernah makan sahur bersama Rasulullah Shalallahu 'Alaihi Wa Sallam, kemudian kami berdiri untuk melaksanakan shalat.\" Aku bertanya; (ada anggapan bahwa yang bertanya adalah Anas), 'Berapa jarak diantara hal tersebut? Ia menjawab; 'Seukuran orang membaca lima puluh ayat.'"},"2083":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَتَسَحَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَزَيْدُ بْنُ ثَابِتٍ ثُمَّ قَامَا فَدَخَلَا فِي صَلَاةِ الصُّبْحِ فَقُلْنَا لِأَنَسٍ كَمْ كَانَ بَيْنَ فَرَاغِهِمَا وَدُخُولِهِمَا فِي الصَّلَاةِ قَالَ قَدْرُ مَا يَقْرَأُ الْإِنْسَانُ خَمْسِينَ آيَةً","id":"Telah mengabarkan kepada kami [Abul Asy'ats] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas Radliallahu'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam makan sahur bersama Zaid bin Tsabit lalu mereka berdua berdiri dan melaksanakan shalat shubuh, kami berkata kepada Anas; 'Berapa waktu antara selesai sahur mereka dengan masuk waktu shalatnya, ia menjawab seukuran orang yang membaca limapuluh ayat."},"2084":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ خَيْثَمَةَ عَنْ أَبِي عَطِيَّةَ قَالَقُلْتُ لِعَائِشَةَ فِينَا رَجُلَانِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدُهُمَا يُعَجِّلُ الْإِفْطَارَ وَيُؤَخِّرُ السُّحُورَ وَالْآخَرُ يُؤَخِّرُ الْإِفْطَارَ وَيُعَجِّلُ السُّحُورَ قَالَتْ أَيُّهُمَا الَّذِي يُعَجِّلُ الْإِفْطَارَ وَيُؤَخِّرُ السُّحُورَ قُلْتُ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ قَالَتْ هَكَذَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Khaitsamah] dari [Abu 'Athiyyah] dia berkata; aku berkata kepada ['Aisyah]; \"Di antara kita ada dua orang dari sahabat Nabi shallallahu 'alaihi wasallam, salah seorang dari keduanya menyegerakan berbuka dan mengakhirkan bersahur, sedangkan yang lain mengakhirkan berbuka dan menyegerakan bersahur?\" ia bertanya; \"Siapakah di antara keduanya yang menyegerakan berbuka dan mengakhirkan sahur?\" Aku menjawab; \"Abdullah bin Mas'ud.\" Ia berkata, \"Demikianlah Rasulullah shallallahu 'alaihi wasallam melakukannya.\""},"2085":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ خَيْثَمَةَ عَنْ أَبِي عَطِيَّةَ قَالَقُلْتُ لِعَائِشَةَ فِينَا رَجُلَانِ أَحَدُهُمَا يُعَجِّلُ الْإِفْطَارَ وَيُؤَخِّرُ السُّحُورَ وَالْآخَرُ يُؤَخِّرُ الْفِطْرَ وَيُعَجِّلُ السُّحُورَ قَالَتْ أَيُّهُمَا الَّذِي يُعَجِّلُ الْإِفْطَارَ وَيُؤَخِّرُ السُّحُورَ قُلْتُ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ قَالَتْ هَكَذَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Khaitsamah] dari [Abu 'Athiyyah] dia berkata; Aku berkata kepada ['Aisyah]; \"Di antara kita ada dua orang, salah seorang dari keduanya menyegerakan berbuka dan mengakhirkan bersahur, sedangkan yang lain mengakhir berbuka dan menyegerakan bersahur?\" Ia bertanya; \"Siapakah di antara keduanya yang menyegerakan berbuka dan mengakhirkan sahur?\" Aku menjawab; \"Abdullah bin Mas'ud.\" Ia berkata; \"Demikianlah Rasulullah shallallahu 'alaihi wasallam melakukannya.\""},"2086":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ أَبِي عَطِيَّةَ قَالَدَخَلْتُ أَنَا وَمَسْرُوقٌ عَلَى عَائِشَةَ فَقَالَ لَهَا مَسْرُوقٌ رَجُلَانِ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِلَاهُمَا لَا يَأْلُو عَنْ الْخَيْرِ أَحَدُهُمَا يُؤَخِّرُ الصَّلَاةَ وَالْفِطْرَ وَالْآخَرُ يُعَجِّلُ الصَّلَاةَ وَالْفِطْرَ قَالَتْ عَائِشَةُ أَيُّهُمَا الَّذِي يُعَجِّلُ الصَّلَاةَ وَالْفِطْرَ قَالَ مَسْرُوقٌ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ فَقَالَتْ عَائِشَةُ هَكَذَا كَانَ يَصْنَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Husain] dari [Zaidah] dari [Al A'masy] dari ['Umarah] dari [Abu 'Athiyyah] dia berkata; Aku dan Masruq masuk menemui ['Aisyah], lalu Masruq berkata kepadanya; \"Ada dua sahabat Nabi shallallahu 'alaihi wasallam, keduanya tidak pernah ketinggalan melakukan kebaikan. Salah seorang dari keduanya menyegerakan shalat dan berbuka, sedangkan yang lain mengakhirkan shalat dan berbuka?\" Ia bertanya, \"Siapakah di antara keduanya yang menyegerakan shalat dan berbuka?\" Masruq menjawab; \"Abdullah bin Mas'ud.\" Aisyah berkata; \"Demikianlah Rasulullah shallallahu 'alaihi wasallam melakukannya.\""},"2087":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ أَبِي عَطِيَّةَ قَالَدَخَلْتُ أَنَا وَمَسْرُوقٌ عَلَى عَائِشَةَ فَقُلْنَا لَهَا يَا أُمَّ الْمُؤْمِنِينَ رَجُلَانِ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدُهُمَا يُعَجِّلُ الْإِفْطَارَ وَيُعَجِّلُ الصَّلَاةَ وَالْآخَرُ يُؤَخِّرُ الْإِفْطَارَ وَيُؤَخِّرُ الصَّلَاةَ فَقَالَتْ أَيُّهُمَا يُعَجِّلُ الْإِفْطَارَ وَيُعَجِّلُ الصَّلَاةَ قُلْنَا عَبْدُ اللَّهِ بْنُ مَسْعُودٍ قَالَتْ هَكَذَا كَانَ يَصْنَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْآخَرُ أَبُو مُوسَى رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Mu'awiyah] dari [Al A'masy] dari ['Umarah] dari [Abu 'Athiyyah] dia berkata; aku dan Masruq masuk menemui ['Aisyah] lalu kami berkata kepadanya; \"Wahai Ummul Mukminin, ada dua sahabat Nabi shallallahu 'alaihi wasallam; salah seorang dari keduanya menyegerakan berbuka dan menyegerakan shalat, sedangkan yang lain mengakhirkan berbuka dan mengakhirkan shalat?\" Ia bertanya; \"Siapakah di antara keduanya yang menyegerakan berbuka dan menyegerakan shalat?\" kami menjawab; \"Abdullah bin Mas'ud.\" Aisyah berkata; \"Demikianlah Rasulullah shallallahu 'alaihi wasallam melakukannya. Sedangkan yang lain ialah Abu Musa -radliallahu 'anhuma-.\""},"2088":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْحَمِيدِ صَاحِبِ الزِّيَادِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الْحَارِثِ يُحَدِّثُ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَسَحَّرُ فَقَالَ إِنَّهَا بَرَكَةٌ أَعْطَاكُمْ اللَّهُ إِيَّاهَا فَلَا تَدَعُوهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah memberitakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Abdul Hamid] -sahabat Az Ziyadi- dia berkata; aku mendengar ['Abdullah bin Al Harits] menceritakan dari [seorang sahabat Nabi shallallahu 'alaihi wasallam]; Aku pernah masuk menemui Nabi shallallahu 'alaihi wasallam saat beliau sedang makan sahur, lalu beliau bersabda: \"Sesungguhnya itu adalah berkah yang Allah berikan kepada kalian, maka janganlah kalian meninggalkannya.\""},"2089":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ بَصْرِيٌّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ يُونُسَ بْنِ سَيْفٍ عَنْ الْحَارِثِ بْنِ زِيَادٍ عَنْ أَبِي رُهْمٍ عَنْ الْعِرْبَاضِ بْنِ سَارِيَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَدْعُو إِلَى السَّحُورِ فِي شَهْرِ رَمَضَانَ وَقَالَ هَلُمُّوا إِلَى الْغَدَاءِ الْمُبَارَكِ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf Al Bashri] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Mu'awiyah bin Shalih] dari [Yunus bin Saif] dari [Al Harits bin Ziyad] dari [Abu Ruhm] dari [Al 'Irbadh bin Sariyah] dia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam di mana beliau mengajak makan sahur di bulan Ramadlan, beliau bersabda: \"Kemarilah kalian menuju makan yang diberkahi.\""},"2090":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ بَقِيَّةَ بْنِ الْوَلِيدِ قَالَ أَخْبَرَنِي بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ الْمِقْدَامِ بْنِ مَعْدِ يكَرِبَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَيْكُمْ بِغَدَاءِ السُّحُورِ فَإِنَّهُ هُوَ الْغَدَاءُ الْمُبَارَكُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Baqiyyah bin Al Walid] dia berkata; telah mengabarkan kepadaku [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'dikarib] dari Nabi bersabda: \"Hendaknya kalian makan sahur karena ia adalah makan yang diberkahi.\""},"2091":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ثَوْرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ هَلُمَّ إِلَى الْغَدَاءِ الْمُبَارَكِ يَعْنِي السَّحُورَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Tsaur] dari [Khalid bin Ma'dan] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada seseorang, \"Kemarilah kamu menuju makan yang diberkahi.\" -yaitu; sahur.-"},"2092":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ مُوسَى بْنِ عُلَيٍّ عَنْ أَبِيهِ عَنْ أَبِي قَيْسٍ عَنْ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فَصْلَ مَا بَيْنَ صِيَامِنَا وَصِيَامِ أَهْلِ الْكِتَابِ أَكْلَةُ السُّحُورِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Musa bin 'Ali] dari [bapaknya] dari [Abu Qais] dari ['Amru bin Al 'Ash] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perbedaan antara puasa kita dan puasa ahli kitab adalah makan sahur.\""},"2093":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَلِكَ عِنْدَ السُّحُورِ يَا أَنَسُ إِنِّي أُرِيدُ الصِّيَامَ أَطْعِمْنِي شَيْئًا فَأَتَيْتُهُ بِتَمْرٍ وَإِنَاءٍ فِيهِ مَاءٌ وَذَلِكَ بَعْدَ مَا أَذَّنَ بِلَالٌ فَقَالَ يَا أَنَسُ انْظُرْ رَجُلًا يَأْكُلْ مَعِي فَدَعَوْتُ زَيْدَ بْنَ ثَابِتٍ فَجَاءَ فَقَالَ إِنِّي قَدْ شَرِبْتُ شَرْبَةَ سَوِيقٍ وَأَنَا أُرِيدُ الصِّيَامَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أُرِيدُ الصِّيَامَ فَتَسَحَّرَ مَعَهُ ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Qatadah] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda -ketika sahur-: \"Wahai Anas, aku ingin berpuasa, berilah sedikit makanan.\" Lalu aku datang dengan membawa kurma dan wadah yang berisi air -yaitu setelah Bilal adzan-. Lalu beliau bersabda: \"Wahai Anas, lihatlah seorang yang -mau- makan bersamaku.\" Maka aku memenggil Zaid bin Tsabit, lalu ia datang dan berkata; \"Aku sudah minum seteguk minuman yang terbuat dari tepung dan aku ingin berpuasa.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku juga ingin berpuasa.\" Lalu beliau sahur bersamanya, kemudian berdiri lalu shalat dua rakaat, kemudian keluar untuk melaksanakan shalat.\""},"2094":{"ar":"أَخْبَرَنِي هِلَالُ بْنُ الْعَلَاءِ بْنِ هِلَالٍ قَالَ حَدَّثَنَا حُسَيْنُ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ أَحَدَهُمْ كَانَ إِذَا نَامَ قَبْلَ أَنْ يَتَعَشَّى لَمْ يَحِلَّ لَهُ أَنْ يَأْكُلَ شَيْئًا وَلَا يَشْرَبَ لَيْلَتَهُ وَيَوْمَهُ مِنْ الْغَدِ حَتَّى تَغْرُبَ الشَّمْسُ حَتَّى نَزَلَتْ هَذِهِ الْآيَةُ{ وَكُلُوا وَاشْرَبُوا إِلَى الْخَيْطِ الْأَسْوَدِ }قَالَ وَنَزَلَتْ فِي أَبِي قَيْسِ بْنِ عَمْرٍو أَتَى أَهْلَهُ وَهُوَ صَائِمٌ بَعْدَ الْمَغْرِبِ فَقَالَ هَلْ مِنْ شَيْءٍ فَقَالَتْ امْرَأَتُهُ مَا عِنْدَنَا شَيْءٌ وَلَكِنْ أَخْرُجُ أَلْتَمِسُ لَكَ عَشَاءً فَخَرَجَتْ وَوَضَعَ رَأْسَهُ فَنَامَ فَرَجَعَتْ إِلَيْهِ فَوَجَدَتْهُ نَائِمًا وَأَيْقَظَتْهُ فَلَمْ يَطْعَمْ شَيْئًا وَبَاتَ وَأَصْبَحَ صَائِمًا حَتَّى انْتَصَفَ ال��َّهَارُ فَغُشِيَ عَلَيْهِ وَذَلِكَ قَبْلَ أَنْ تَنْزِلَ هَذِهِ الْآيَةُ فَأَنْزَلَ اللَّهُ فِيهِ","id":"Telah mengabarkan kepadaku [Hilal bin Al 'Ala bin Hilal] dia berkata; telah menceritakan kepada kami [Husain bin 'Ayyasy] dia berkata; telah menceritakan kepada kami [Zuhair] dia berkata; telah menceritakan kepada kami [Abu Ishaq] dari [Al Barra' bin 'Azib] bahwa salah seorang dari mereka jika tidur sebelum makan malam, maka tidak boleh baginya makan apapun, dan tidak boleh minum pada malam itu serta pada hari itu, mulai pagi sampai matahari terbenam. Hingga turun ayat ini: \"Dan makan serta minumlah.\" Sampai firman Allah \"benang hitam.\" Dia mengatakan; \"Ayat ini turun berkenaan dengan masalah Abu Qais bin Amru, saat ia menemui istrinya setelah maghrib, sedangkan ia dalam keadaan berpuasa, lalu ia bertanya; \"Apakah ada sesuatu?\" Istrinya menjawab; \"Kita tidak memiliki apa-apa, tetapi aku keluar mencari makan malam untukmu\", lalu ia keluar, sementara Abu Qais merebahkan kepalanya lalu tidur. Kemudian istrinya pulang dan mendapatinya sedang tidur, lalu ia membangunkannya, namun ia tidak makan sedikitpun, ia melalui waktu malam dan pagi dalam keadaan berpuasa, hingga pertengahan siang, lalu ia pingsan. Kejadian tersebut sebelum ayat ini turun, lalu Allah menurunkan ayat tersebut tentang dirinya.\""},"2095":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ تَعَالَى{ حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }قَالَ هُوَ سَوَادُ اللَّيْلِ وَبَيَاضُ النَّهَارِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Jarir] dari [Mutharrif] dari [Asy Sya'bi] dari ['Adi bin Hatim] bahwa ia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang firman Allah Ta'ala: \" Hingga terang bagimu benang putih dan benang hitam.\" (Qs. Al Baqarah 2: 187) Beliau bersabda: \"Yaitu hitamnya malam dan putihnya siang.\""},"2096":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ ابْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ لِيُنَبِّهَ نَائِمَكُمْ وَيُرْجِعَ قَائِمَكُمْ وَلَيْسَ الْفَجْرُ أَنْ يَقُولَ هَكَذَا وَأَشَارَ بِكَفِّهِ وَلَكِنْ الْفَجْرُ أَنْ يَقُولَ هَكَذَا وَأَشَارَ بِالسَّبَّابَتَيْنِ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [At Taimi] dari [Abu 'Utsman] dari [Ibnu Mas'ud] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Bilal adzan di waktu malam untuk membangunkan orang yang tidur di antara kalian, dan mengembalikan orang yang sedang shalat di antara kalian -agar beristirahat dan mempersiapkan segala sesuatu sebelum masuknya waktu fajar-. Saat fajar bukanlah mengatakan begini -beliau mengisyaratkan dengan telapak tangannya, sebab kemunculan fajar tidak seperti itu- tetapi waktu fajar ialah dengan mengatakan begini -beliau mengisyaratkan dengan dua jari telunjuk-.\""},"2097":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ أَنْبَأَنَا سَوَادَةُ بْنُ حَنْظَلَةَ قَالَ سَمِعْتُ سَمُرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغُرَّنَّكُمْ أَذَانُ بِلَالٍ وَلَا هَذَا الْبَيَاضُ حَتَّى يَنْفَجِرَ الْفَجْرُ هَكَذَا وَهَكَذَا يَعْنِي مُعْتَرِضًاقَالَ أَبُو دَاوُدَ وَبَسَطَ بِيَدَيْهِ يَمِينًا وَشِمَالًا مَادًّا يَدَيْهِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Syu'bah]; telah memberitakan kepada kami [Sawadah bin Hanzhalah] dia berkata; aku mendengar [Samurah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian tertipu adzan Bilal dan juga warna putih ini, hingga fajar bersinar begini dan begini.\" Artinya: cahaya yang melintang.\" Abu Daud (salah seorang perawi hadits ini) berkata: \"Dan beliau membentangkan kedua tangannya ke arah kanan dan ke arah kiri dengan memenjangkan kedua tangannya.\""},"2098":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقَدَّمُوا قَبْلَ الشَّهْرِ بِصِيَامٍ إِلَّا رَجُلٌ كَانَ يَصُومُ صِيَامًا أَتَى ذَلِكَ الْيَوْمُ عَلَى صِيَامِهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Al Walid] dari [Al Auza'i] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian mendahului dengan berpuasa sebelum bulan (Ramadlan), kecuali orang yang biasa berpuasa dan hari itu bertepatan dengan waktu puasanya.\""},"2099":{"ar":"أَخْبَرَنِي عِمْرَانُ بْنُ يَزِيدَ بْنِ خَالِدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ قَالَ أَنْبَأَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى قَالَ حَدَّثَنِي أَبُو سَلَمَةَ قَالَ أَخْبَرَنِي أَبُو هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَقَدَّمَنَّ أَحَدٌ الشَّهْرَ بِيَوْمٍ وَلَا يَوْمَيْنِ إِلَّا أَحَدٌ كَانَ يَصُومُ صِيَامًا قَبْلَهُ فَلْيَصُمْهُ","id":"Telah mengabarkan kepadaku ['Imran bin Yazid bin Khalid] dia berkata; telah menceritakan kepada kami [Muhammad bin Syu'aib] dia berkata; telah memberitakan kepada kami [Al Auza'i] dari [Yahya] dia berkata; telah menceritakan kepadaku [Abu Salamah] dia berkata; telah mengabarkan kepadaku [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sekali-kali seseorang mendahului bulan (Ramadlan) dengan (berpuasa) sehari dan tidak pula dua hari, kecuali seseorang yang biasa berpuasa sebelumnya, maka berpuasalah.\""},"2100":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو خَالِدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَتَقَدَّمُوا الشَّهْرَ بِصِيَامِ يَوْمٍ أَوْ يَوْمَيْنِ إِلَّا أَنْ يُوَافِقَ ذَلِكَ يَوْمًا كَانَ يَصُومُهُ أَحَدُكُمْقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala] dia berkata; telah menceritakan kepada kami [Abu Khalid] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mendahului bulan Ramadlan dengan puasa sehari atau dua hari kecuali jika ia telah biasa berpuasa (sunnah) pada hari itu.\" Abdurrahman berkata ini adalah salah."},"2101":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ سَالِمٍ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ شَهْرَيْنِ مُتَتَابِعَيْنِ إِلَّا أَنَّهُ كَانَ يَصِلُ شَعْبَانَ بِرَمَضَانَ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf] dan [Muhammad bin Basysyar] -dan lafadz ini miliknya- mereka berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Salim] dari [Abu Salamah] dari [Ummu Salamah] dia berkata; \"Aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam berpuasa dua bulan berturut-turut, hanya saja beliau menyambung bulan Sya'ban dengan Ramadlan.\""},"2102":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا النَّضْرُ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ تَوْبَةَ الْعَنْبَرِيِّ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصِلُ شَعْبَانَ بِرَمَضَانَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [An Nadlr] dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Taubah Al 'Anbari] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Ummu Salamah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam menyambung bulan Sya'ban dengan Ramadlan.\""},"2103":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ أَنَّ مُحَمَّدَ بْنَ إِبْرَاهِيمَ حَدَّثَهُ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِأَنَّهُ سَأَلَ عَائِشَةَ عَنْ صِيَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ حَتَّى نَقُولَ لَا يُفْطِرُ وَيُفْطِرُ حَتَّى نَقُولَ لَا يَصُومُ وَكَانَ يَصُومُ شَعْبَانَ أَوْ عَامَّةَ شَعْبَانَ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Usamah bin Zaid] bahwasanya [Muhammad bin Ibrahim] menceritakan kepadanya dari [Abu Salamah bin 'Abdurrahman] bahwasanya ia bertanya kepada ['Aisyah] tentang puasa Rasulullah shallallahu 'alaihi wasallam? Maka ia menjawab; \"Rasulullah shallallahu 'alaihi wasallam berpuasa hingga kami mengatakan; 'Beliau tidak pernah berbuka' dan beliau berbuka hingga kami mengatakan; 'Beliau tidak pernah berpuasa', beliau berpuasa pada satu bulan penuh di bulan Sya'ban atau kebanyakan pada bulan Sya'ban.\""},"2104":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سَعْدِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا نَافِعُ بْنُ يَزِيدَ أَنَّ ابْنَ الْهَادِ حَدَّثَهُ أَنَّ مُحَمَّدَ بْنَ إِبْرَاهِيمَ حَدَّثَهُ عَنْ أَبِي سَلَمَةَ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْلَقَدْ كَانَتْ إِحْدَانَا تُفْطِرُ فِي رَمَضَانَ فَمَا تَقْدِرُ عَلَى أَنْ تَقْضِيَ حَتَّى يَدْخُلَ شَعْبَانُ وَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ فِي شَهْرٍ مَا يَصُومُ فِي شَعْبَانَ كَانَ يَصُومُهُ كُلَّهُ إِلَّا قَلِيلًا بَلْ كَانَ يَصُومُهُ كُلَّهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sa'd bin Al Hakam] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Nafi' bin Yazid], [Ibnul Had] menceritakan kepadanya, bahwasanya [Muhammad bin Ibrahim] menceritakan kepadanya dari [Abu Salamah bin 'Abdurrahman] dari ['Aisyah] dia berkata; \"Sungguh salah seorang dari kami pernah berbuka pada bulan Ramadlan, kemudian tidak sanggup untuk mengqadhanya hingga masuk bulan Sya'ban. Rasulullah shallallahu 'alaihi wasallam tidak pernah berpuasa satu bulan penuh seperti pada bulan Sya'ban; beliau berpuasa semuanya (satu bulan penuh) kecuali hanya sedikit (beberapa hari); bahkan beliau pernah berpuasa semuanya (satu bulan penuh).\""},"2105":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي لَبِيدٍ عَنْ أَبِي سَلَمَةَ قَالَسَأَلْتُ عَائِشَةَ فَقُلْتُ أَخْبِرِينِي عَنْ صِيَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ يَصُومُ حَتَّى نَقُولَ قَدْ صَامَ وَيُفْطِرُ حَتَّى نَقُولَ قَدْ أَفْطَرَ وَلَمْ يَكُنْ يَصُومُ شَهْرًا أَكْثَرَ مِنْ شَعْبَانَ كَانَ يَصُومُ شَعْبَانَ إِلَّا قَلِيلًا كَانَ يَصُومُ شَعْبَانَ كُلَّهُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Yazid] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Abdullah bin Abu Labid] dari [Abu Salamah] dia berkata; Aku bertanya kepada ['Aisyah], lalu aku katakana; \"Beritahukan kepadaku tentang puasa Rasulullah shallallahu 'alaihi wasallam?\" ia menjawab; \"Beliau berpuasa hingga kami katakan, 'Sungguh beliau -seakan-akan selalu- berpuasa dan beliau berbuka hingga kami katakan, 'Sungguh beliau -seakan-akan selalu- berbuka'. Dan beliau tidak pernah berpuasa selama satu bulan yang lebih banyak dari bulan Sya'ban; (pada satu tahun) beliau berpuasa penuh di bulan Sya'ban kecuali hanya sedikit (beberapa hari); -namun pada tahun yang lainnya- beliau berpuasa di bulan Sya'ban semuanya (sebulan penuh).\""},"2106":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَهْرٍ مِنْ السَّنَةِ أَكْثَرَ صِيَامًا مِنْهُ فِي شَعْبَانَ كَانَ يَصُومُ شَعْبَانَ كُلَّهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Mu'adz bin Hisyam] dia berkata; [bapakku] telah menceritakan kepadaku dari [Yahya bin Abu Katsir] dia berkata; telah menceritakan kepadaku [Abu Salamah bin 'Abdurrahman] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah berpuasa satu bulan dalam satu tahun yang lebih banyak dari puasa beliau di bulan Sya'ban. Beliau berpuasa di bulan Sya'ban semuanya (sebulan penuh).\""},"2107":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ خَالِدِ بْنِ سَعْدٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ شَعْبَانَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Abu Dawud] dari [Sufyan] dari [Manshur] dari [Khalid bin Sa'd] dari ['Aisyah] dia berkata; \"Nabi shallallahu 'alaihi wasallam berpuasa di bulan Sya'ban.\""},"2108":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ عَنْ عَبْدَةَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْلَا أَعْلَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ الْقُرْآنَ كُلَّهُ فِي لَيْلَةٍ وَلَا قَامَ لَيْلَةً حَتَّى الصَّبَاحِ وَلَا صَامَ شَهْرًا كَامِلًا قَطُّ غَيْرَ رَمَضَانَ","id":"Telah mengabarkan kepada kami [Harun bin Ishaq] dari ['Abdah] dari [Sa'id] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah] dia berkata; \"Aku tidak pernah mengetahui Rasulullah shallallahu 'alaihi wasallam membaca Al Qur'an semuanya (seluruh Al Qur'an) dalam satu malam, tidak pernah shalat malam hingga pagi dan tidak pula berpuasa satu bulan penuh sama sekali selain pada bulan Ramadlan.\""},"2109":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي يُوسُفَ الصَّيْدَلَانِيُّ حَرَّانِيٌّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَسَأَلْتُهَا عَنْ صِيَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ حَتَّى نَقُولَ قَدْ صَامَ وَيُفْطِرُ حَتَّى نَقُولَ قَدْ أَفْطَرَ وَلَمْ يَصُمْ شَهْرًا تَامًّا مُنْذُ أَتَى الْمَدِينَةَ إِلَّا أَنْ يَكُونَ رَمَضَانُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Yusuf Ash Shaidalani Al Harrani] dia berkata; telah menceritakan kepada kami [Muhammad bin Salamah] dari [Hisyam] dari [Ibnu Sirin] dari ['Abdullah bin Syaqiq] dari ['Aisyah] dia berkata; Aku pernah bertanya kepadanya tentang puasa Rasulullah shallallahu 'alaihi wasallam? ia menjawab; \"Rasulullah shallallahu 'alaihi wasallam berpuasa hingga kami katakan, 'Sungguh beliau -seakan-akan selalu- berpuasa' dan beliau berbuka hingga kami katakana; 'Sungguh beliau -seakan-akan selalu- berbuka'. Dan beliau tidak pernah berpuasa selama satu bulan penuh sejak beliau datang ke Madinah kecuali di bulan Ramadlan.\""},"2110":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ أَنْبَأَنَا خَالِدٌ وَهُوَ ابْنُ الْحَارِثِ عَنْ كَهْمَسٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَقُلْتُ لِعَائِشَةَ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي صَلَاةَ الضُّحَى قَالَتْ لَا إِلَّا أَنْ يَجِيءَ مِنْ مَغِيبِهِ قُلْتُ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ شَهْرًا كُلَّهُ قَالَتْ لَا مَا عَلِمْتُ صَامَ شَهْرًا كُلَّهُ إِلَّا رَمَضَانَ وَلَا أَفْطَرَ حَتَّى يَصُومَ مِنْهُ حَتَّى مَضَى لِسَبِيلِهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah memberitakan kepada kami [Khalid bin Al Harits] dari [Kahmas] dari ['Abdullah bin Syaqiq] dia berkata; Aku pernah bertanya kepada [Aisyah]; \"Apakah Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat Dluha?\" Ia menjawab; \"Tidak, kecuali jika beliau datang dari bepergian.\" Aku bertanya; \"Apakah Rasulullah shallallahu 'alaihi wasallam berpuasa satu bulan penuh?\" Ia menjawab; \"Tidak, aku tidak pernah mengetahui beliau berpuasa satu bulan penuh kecuali di bulan Ramadlan dan tidak pernah berbuka hingga berpuasa dari bulan itu sampai beliau melakukan pepergian.\""},"2111":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ عَنْ يَزِيدَ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَقُلْتُ لِعَائِشَةَ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي صَلَاةَ الضُّحَى قَالَتْ لَا إِلَّا أَنْ يَجِيءَ مِنْ مَغِيبِهِ قُلْتُ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ صَوْمٌ مَعْلُومٌ سِوَى رَمَضَانَ قَالَتْ وَاللَّهِ إِنْ صَامَ شَهْرًا مَعْلُومًا سِوَى رَمَضَانَ حَتَّى مَضَى لِوَجْهِهِ وَلَا أَفْطَرَ حَتَّى يَصُومَ مِنْهُ","id":"Telah mengabarkan kepada kami [Abul Asy'ats] dari [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Al Jurairi] dari ['Abdullah bin Syaqiq] dia berkata; Aku berkata kepada ['Aisyah] dia berkata; Aku pernah bertanya kepada Aisyah; \"Apakah Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat Dluha?\" Ia menjawab; \"Tidak, kecuali jika ia datang dari bepergian.\" Aku bertanya; \"Apakah Rasulullah shallallahu 'alaihi wasallam memiliki puasa tertentu selain Ramadlan?\" Ia menjawab; \"Demi Allah, beliau tidak pernah mengetahui beliau berpuasa tertentu selama satu bulan selain Ramadlan, hingga berlalu dan tidak berbuka hingga beliau berpuasa dari bulan itu'.\""},"2112":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ عَنْ بَقِيَّةَ قَالَ حَدَّثَنَا بَحِيرٌ عَنْ خَالِدٍ عَنْ جُبَيْرِ بْنِ نُفَيْرٍأَنَّ رَجُلًا سَأَلَ عَائِشَةَ عَنْ الصِّيَامِ فَقَالَتْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ شَعْبَانَ كُلَّهُ وَيَتَحَرَّى صِيَامَ الِاثْنَيْنِ وَالْخَمِيسِ","id":"Telah mengabarkan kepadaku ['Amr bin 'Utsman] dari [Baqiyyah] dia berkata; telah menceritakan kepada kami [Bahir] dari [Khalid] dari [Jubair bin Nufair] bahwasanya seorang lelaki bertanya kepada ['Aisyah] ia menjawab; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam berpuasa di bulan Sya'ban semuanya (satu bulan penuh) dan memilih berpuasa pada hari senin dan kamis.\""},"2113":{"ar":"أَخْبَرَنَا عَمْ��ُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ قَالَ حَدَّثَنَا ثَوْرٌ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ رَبِيعَةَ الْجُرَشِيِّ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ شَعْبَانَ وَرَمَضَانَ وَيَتَحَرَّى الِاثْنَيْنِ وَالْخَمِيسَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdullah bin Dawud] dia berkata; telah menceritakan kepada kami [Tsaur] dari [Khalid bin Ma'dan] dari [Rabi'ah Al Juraisyi] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam berpuasa di bulan Sya'ban dan Ramadlan serta memilih berpuasa pada hari senin dan kamis.\""},"2114":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْأَشَجُّ عَنْ أَبِي خَالِدٍ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ أَبِي إِسْحَقَ عَنْ صِلَةَ قَالَكُنَّا عِنْدَ عَمَّارٍ فَأُتِيَ بِشَاةٍ مَصْلِيَّةٍ فَقَالَ كُلُوا فَتَنَحَّى بَعْضُ الْقَوْمِ قَالَ إِنِّي صَائِمٌ فَقَالَ عَمَّارٌ مَنْ صَامَ الْيَوْمَ الَّذِي يُشَكُّ فِيهِ فَقَدْ عَصَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Abdullah bin Sa'id Al Asyja'i] dari [Abu Khalid] dari ['Amru bin Qais] dari [Abu Ishaq] dari [Shilah] dia berkata; kami berada di rumah Ammar, kemudian diberi kambing panggang, ia lalu berkata, \"Makanlah\", namun ada sebagian orang yang menjauh. Ia berkata, \"Aku sedang berpuasa.\" Maka [Ammar] berkata; \"Barangsiapa yang berpuasa di hari yang diragukan, maka sungguh ia telah mendurhakai Abul Qasim shallallahu 'alaihi wasallam.\""},"2115":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ أَبِي يُونُسَ عَنْ سِمَاكٍ قَالَدَخَلْتُ عَلَى عِكْرِمَةَ فِي يَوْمٍ قَدْ أُشْكِلَ مِنْ رَمَضَانَ هُوَ أَمْ مِنْ شَعْبَانَ وَهُوَ يَأْكُلُ خُبْزًا وَبَقْلًا وَلَبَنًا فَقَالَ لِي هَلُمَّ فَقُلْتُ إِنِّي صَائِمٌ قَالَ وَحَلَفَ بِاللَّهِ لَتُفْطِرَنَّ قُلْتُ سُبْحَانَ اللَّهِ مَرَّتَيْنِ فَلَمَّا رَأَيْتُهُ يَحْلِفُ لَا يَسْتَثْنِي تَقَدَّمْتُ قُلْتُ هَاتِ الْآنَ مَا عِنْدَكَ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ فَإِنْ حَالَ بَيْنَكُمْ وَبَيْنَهُ سَحَابَةٌ أَوْ ظُلْمَةٌ فَأَكْمِلُوا الْعِدَّةَ عِدَّةَ شَعْبَانَ وَلَا تَسْتَقْبِلُوا الشَّهْرَ اسْتِقْبَالًا وَلَا تَصِلُوا رَمَضَانَ بِيَوْمٍ مِنْ شَعْبَانَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Ibnu 'Adi] dari [Abu Yunus] dari [Simak] dia berkata; aku masuk menemui ['Ikrimah] di hari yang dipermasalahkan, 'Apakah hari itu ia berada di bulan Ramadlan atau masih berada di bulan Sya'ban?! ' Sementara saat ia sedang makan roti, sayur dan susu, lalu ia berkata kepadaku; \"Kemarilah.\" Aku berkata; \"Aku sedang berpuasa.\" Ia berkata dengan bersumpah atas nama Allah; sungguh kamu benar-benar akan berbuka.\" Aku berkata; \"Subhanallah\" -dua kali-, setelah aku melihatnya bersumpah dengan tidak ada pengecualian (tidak ada redaksi Insya Allah), maka aku maju seraya kukatakan; \"Sekarang berikan -hujjah- yang ada padamu!\" ia berkata; \"Aku mendengar [Ibnu Abbas] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berpuasalah kalian karena melihatnya dan berbukalah karena melihatnya. Jika ada mendung atau gelap yang menghalangi antara kalian dan hilal, maka sempurnakanlah bilangan -bulan-, yaitu bilangan bulan Sya'ban. Dan janganlah kalian menghadap bulan (Ramadlan) serta menyambung bulan Ramadlan dengan satu hari dari bulan Sya'ban.\""},"2116":{"ar":"أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ بْنِ سَعْدٍ قَالَ أَخْبَرَنِي أَبِي عَنْ جَدِّي قَالَ أَخْبَرَنِي شُعَيْبُ بْنُ إِسْحَقَ عَنْ الْأَوْزَاعِيِّ وَابْنُ أَبِي عَرُوبَةَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ أَلَا لَا تَقَدَّمُوا الشَّهْرَ بِيَوْمٍ أَوْ اثْنَيْنِ إِلَّا رَجُلٌ كَانَ يَصُومُ صِيَامًا فَلْيَصُمْهُ","id":"Telah mengabarkan kepada kami ['Abdul Malik bin Syu'aib bin Al Laits bin Sa'd] dia berkata; [bapakku] telah mengabarkan kepadaku dari [kakekku], dia berkata; telah mengabarkan kepadaku [Syu'aib bin Ishaq] dari [Al Auza'i] dan [Ibnu Abu 'Arubah] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Ketahuilah, janganlah kalian mendahului bulah (Ramadlan) dengan berpuasa sehari atau dua hari, kecuali seseorang yang biasa berpuasa, maka hendaknya ia berpuasa.\""},"2117":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ قَالَ أَنْبَأَنَا خَالِدٌ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul Hakim] dari [Syu'aib] dari [Al Laits] dia berkata; telah memberitakan kepada kami [Khalid] dari [Ibnu Abu Hilal] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang melakukan qiyamullail dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\""},"2118":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ جَبَلَةَ قَالَ حَدَّثَنَا الْمُعَافَى قَالَ حَدَّثَنَا مُوسَى عَنْ إِسْحَقَ بْنِ رَاشِدٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُرَغِّبُ النَّاسَ فِي قِيَامِ رَمَضَانَ مِنْ غَيْرِ أَنْ يَأْمُرَهُمْ بِعَزِيمَةِ أَمْرٍ فِيهِ فَيَقُولُ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Jabalah] dia berkata; telah menceritakan kepada kami [Al Mu'afa] dia berkata; telah menceritakan kepada kami [Musa] dari [Ishaq bin Rasyid] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair] dari ['Aisyah] istri Nabi shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam menganjurkan manusia untuk melakukan qiyamullail di bulan Ramadlan tanpa menyuruh mereka dengan perintah yang mengharuskan dalam hal itu, lalu bersabda: \"Barangsiapa yang melakukan qiyamullail dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\""},"2119":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ أَنْبَأَنَا إِسْحَقُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ عَنْ يُونُسَ الْأَيْلِيِّ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فِي جَوْفِ اللَّيْلِ يُصَلِّي فِي الْمَسْجِدِ فَصَلَّى بِالنَّاسِ وَسَاقَ الْحَدِيثَ وَفِيهِ قَالَتْ فَكَانَ يُرَغِّبُهُمْ فِي قِيَامِ رَمَضَانَ مِنْ غَيْرِ أَنْ يَأْمُرَهُمْ بِعَزِيمَةٍ وَيَقُولُ مَنْ قَامَ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ قَالَ فَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْأَمْرُ عَلَى ذَلِكَ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah memberitakan kepada kami [Ishaq] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al Harits] dari [Yunus Al Aili] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwasanya ['Aisyah] mengabarkan kepadanya; Rasulullah shallallahu 'alaihi wasallam keluar di tengah malam untuk melakukan shalat di masjid, lalu beliau shalat bersama orang banyak… dan ia menyebutkan hadits tersebut. Di dalamnya -terdapat redaksi-: Aisyah berkata; \"Beliau menganjurkan mereka untuk melakukan qiyamullail di bulan Ramadlan tanpa menyuruh mereka dengan perintah yang mengharuskan dan bersabda: \"Barangsiapa yang melakukan qiyamullail pada malam lailatul Qadar dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\" Ia berkata; \"Lalu Rasulullah shallallahu 'alaihi wasallam wafat dan perintah tetap sepeti itu.\""},"2120":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ جَوْفِ اللَّيْلِ فَصَلَّى فِي الْمَسْجِدِ وَسَاقَ الْحَدِيثَ وَقَالَ فِيهِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرَغِّبُهُمْ فِي قِيَامِ رَمَضَانَ مِنْ غَيْرِ أَنْ يَأْمُرَهُمْ بِعَزِيمَةِ أَمْرٍ فِيهِ فَيَقُولُ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepadaku [Muhammad bin Khalid] dia berkata; telah menceritakan kepada kami [Bisyr bin Syu'aib] dari [bapaknya] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwasanya ['Aisyah] mengabarkan kepadanya; Rasulullah shallallahu 'alaihi wasallam keluar di tengah malam lalu beliau melakukan shalat di masjid… dan ia menyebutkan hadits. Di dalam hadits tersebut, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menganjurkan mereka untuk melakukan qiyamullail di bulan Ramadlan tanpa menyuruh mereka dengan perintah yang mengharuskan lalu bersabda: \"Barangsiapa yang melakukan qiyamullail pada malam lailatul Qadar di bulan Ramadlan dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\""},"2121":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنَا أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِرَمَضَانَ مَنْ قَامَهُ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Khalid] dia berkata; telah menceritakan kepada kami [Bisyr bin Syu'aib] dari [bapaknya] dari [Az Zuhri] dia berkata; telah menceritakan kepada kami [Abu Salamah bin 'Abdurrahman] bahwasanya [Abu Hurairah] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda tentang Ramadlan: \"Barangsiapa yang melakukan qiyamullail di bulan itu dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\""},"2122":{"ar":"أَخْبَرَنَا نُوحُ بْنُ حَبِيبٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرَغِّبُ فِي قِيَامِ رَمَضَانَ مِنْ غَيْرِ أَنْ يَأْمُرَهُمْ بِعَزِيمَةٍ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Nuh bin Habib] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam menganjurkan untuk melakukan qiyamullail di bulan Ramadlan tanpa menyuruh mereka dengan perintah yang mengharuskan, beliau bersabda: \"Barangsiapa yang melakukan qiyamullail di bulan Ramadlan dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu."},"2123":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang melakukan qiyamullail di bulan Ramadlan dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\""},"2124":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnul Qasim] dari [Malik] dia berkata; telah menceritakan kepadaku [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang melakukan qiyamullail di bulan Ramadlan dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\""},"2125":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ رَمَضَانَ وَفِي حَدِيثِ قُتَيْبَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ شَهْرَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَنْ قَامَ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dan [Muhammad bin 'Abdullah bin Yazid] mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang berpuasa Ramadlan -dalam suatu lafazh yang \"Barangsiapa yang melakukan qiyamullail di bulan Ramadlan\"- dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu. Dan, barangsiapa yang melakukan qiyamullail pada malam lailatul Qadar dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\""},"2126":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berpuasa Ramadlan dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\""},"2127":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى وَمُحَمَّدُ بْنُ هِشَامٍ وَأَبُو الْأَشْعَثِ وَاللَّفْظُ لَهُ قَالُوا حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَنْ قَامَ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dan [Muhammad bin Hisyam] dan [Abul Asy'ats] dan lafazh ini miliknya, mereka berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin 'Abdurrahman] dia berkata; telah menceritakan kepadaku [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berpuasa Ramadlan dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah lalu. Dan, barangsiapa yang melakukan qiyamullail pada malam lailatul Qadar dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\""},"2128":{"ar":"أَخْبَرَنِي مَحْمُودُ بْنُ خَالِدٍ عَنْ مَرْوَانَ أَنْبَأَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَامَ شَهْرَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَنْ قَامَ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepadaku [Mahmud bin Khalid] dari [Marwan]; telah memberitakan kepada kami [Mu'awiyah bin Sallam] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam dari bersabda: \"Barangsiapa yang melakukan qiyamullail di bulan Ramadlan dengan penuh keimanan dan mengharap pahala, akan diampuni dari dosanya yang telah lalu. Dan barangsiapa yang melakukan qiyamullail pada malam lailatul Qadar dengan penuh keimanan dan mengharap pahala, maka akan diampuni dari dosanya yang telah berlalu.\""},"2129":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ قَالَ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنِي النَّضْرُ بْنُ شَيْبَانَ أَنَّهُ لَقِيَ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ فَقَالَ لَهُ حَدِّثْنِي بِأَفْضَلِ شَيْءٍ سَمِعْتَهُ يُذْكَرُ فِي شَهْرِ رَمَضَانَ فَقَالَ أَبُو سَلَمَةَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ ذَكَرَ شَهْرَ رَمَضَانَ فَفَضَّلَهُ عَلَى الشُّهُورِ وَقَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا خَرَجَ مِنْ ذُنُوبِهِ كَيَوْمِ وَلَدَتْهُ أُمُّهُقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ أَنْبَأَنَا الْقَاسِمُ بْنُ الْفَضْلِ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شَيْبَانَ عَنْ أَبِي سَلَمَةَ فَذَكَرَ مِثْلَهُ وَقَالَ مَنْ صَامَهُ وَقَامَهُ إِيمَانًا وَاحْتِسَابًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Al Fadhl bin Dukain] dia berkata; telah menceritakan kepada kami [Nashr bin 'Ali] dia berkata; telah menceritakan kepadaku [An Nadlr bin Syaiban] bahwasanya ia bertemu dengan [Abu Salamah bin 'Abdurrahman], lalu ia berkata; ceritakan kepadaku tentang hal yang paling utama yang pernah engkau dengar di bulan Ramadlan? Maka Abu Salamah berkata; telah menceritakan kepadaku ['Abdurrahman bin 'Auf] dari Rasulullah shallallahu 'alaihi wasallam bahwasanya beliau menyebutkan tentang bulan Ramadlan dan beliau mengutamakannya dari bulan yang lain, beliau bersabda: \"Barangsiapa yang shalat dimalam hari bulan Ramadlan dengan keimanan dan mengharapkan pahala maka dosa-dosanya akan keluar seperti hari dimana ia baru dilahirkan oleh ibunya, \" Abu Abdurrahman berkata; 'Ini adalah salah, yang benar adalah Abu Salamah dari Abu Hurairah Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Annadlr bin Syumail] dia berkata; Telah memberitakan kepada kami [Qasim bin Fadhl] dia berkata; Telah menceritakan kepada kami [Annadlr bin Syaiban] dari [Abu Salamah] lalu ia menyebutkan seperti itu juga dan dia berkata; 'Barangsiapa yang berpuasa dan shalat dimalamnya dengan keimanan dan mengharapkan pahala.'"},"2130":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو هِشَامٍ قَالَ حَدَّثَنَا الْقَاسِمُ بْنُ الْفَضْلِ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شَيْبَانَ قَالَ قُلْتُ لِأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ حَدِّثْنِي بِشَيْءٍ سَمِعْتَهُ مِنْ أَبِيكَ سَمِعَهُ أَبُوكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ بَيْنَ أَبِيكَ وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدٌ فِي شَهْرِ رَمَضَانَ قَالَ نَعَمْ حَدَّثَنِي أَبِي قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى فَرَضَ صِيَامَ رَمَضَانَ عَلَيْكُمْ وَسَنَنْتُ لَكُمْ قِيَامَهُ فَمَنْ صَامَهُ وَقَامَهُ إِيمَانًا وَاحْتِسَابًا خَرَجَ مِنْ ذُنُوبِهِ كَيَوْمِ وَلَدَتْهُ أُمُّهُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Abu Hisyam] dia berkata; telah menceritakan kepada kami [Al Qasim bin Al Fadl] dia berkata; telah menceritakan kepada kami [An Nadlr bin Syaiban] dia berkata; aku berkata kepada [Abu Salamah bin 'Abdurrahman]; \"Ceritakan kepadaku mengenai sesuatu tentang bulan Ramadlan yang kamu dengar dari Bapakmu, dari Rasulullah Shalallahu 'Alaihi Wa Sallam, yang mana antara Rasulullah Shalallahu 'Alaihi Wa Sallam dan Bapakmu tidak ada perantara seorangpun. Abu Salamah menjawab; 'Ya, ' Telah menceritakan kepadaku [Bapakku] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Sesungguhnya Allah Tabaaraka Wata'ala telah mewajibkan kepada kalian puasa di bulan Ramadlan, dan aku mensunnahkan shalat malamnya. Barang siapa berpuasa dibulan tersebut dan shalat di malamnya karena iman dan mengaharap pahala dariNya, maka dosa-dosanya akan keluar darinya sebagaimana hari dimana ia dilahirkan oleh ibunya.\""},"2131":{"ar":"أَخْبَرَنِي هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ زَيْدٍ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ الصَّوْمُ لِي وَأَنَا أَجْزِي بِهِ وَلِلصَّائِمِ فَرْحَتَانِ حِينَ يُفْطِرُ وَحِينَ يَلْقَى رَبَّهُ وَالَّذِي نَفْسِي بِيَدِهِ لَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah mengabarkan kepadaku [Hilal bin Al 'Ala] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Zaid] dari [Abu Ishaq] dari ['Abdullah bin Al Harits] dari ['Ali bin Abu Thalib] dari Rasulullah beliau bersabda: \"Sesungguhnya Allah Tabaraka wa Ta'ala berfirman: \"Puasa itu adalah untukku dan Aku yang akan memberinya pahala, dan bagi seorang yang berpuasa ia memiliki dua kebahagiaan yaitu ketika ia berbuka dan ketika ia bertemu dengan Rabbnya, demi yang jiwaku berada ditanganNya sungguh bau mulut seorang yang berpuasa itu lebih harum disisi Allah daripada aroma minyak kesturi.\""},"2132":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ قَالَ عَبْدُ اللَّهِقَالَ اللَّهُ عَزَّ وَجَلَّ الصَّوْمُ لِي وَأَنَا أَجْزِي بِهِ وَلِلصَّائِمِ فَرْحَتَانِ فَرْحَةٌ حِينَ يَلْقَى رَبَّهُ وَفَرْحَةٌ عِنْدَ إِفْطَارِهِ وَلَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Abul Ahwash] dia berkata; ['Abdullah] berkata; Allah -Azza wa Jalla- berfirman: \"Puasa itu untuk-Ku dan Aku yang akan membalasnya. Orang yang berpuasa itu mempunyai dua kegembiraan, kegembiraan ketika bertemu Rabb-nya dan ketika berbuka. Dan aroma mulut orang yang berpuasa sungguh lebih harum di sisi Allah daripada aroma minyak kesturi.\""},"2133":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حَرْبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ قَالَ حَدَّثَنَا أَبُو سِنَانٍ ضِرَارُ بْنُ مُرَّةَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ الصَّوْمُ لِي وَأَنَا أَجْزِي بِهِ وَلِلصَّائِمِ فَرْحَتَانِ إِذَا أَفْطَرَ فَرِحَ وَإِذَا لَقِيَ اللَّهَ فَجَزَاهُ فَرِحَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah mengabarkan kepada kami ['Ali bin Harb] dia berkata; telah menceritakan kepada kami [Muhammad bin Fudhail] dia berkata; telah menceritakan kepada kami [Abu Sinan Dhirar bin Murrah] dari [Abu Shalih] dari [Abu Sa'id] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah -Tabaraka wa Ta'ala- berfirman: 'Puasa itu untuk-Ku dan Aku akan membalasnya. Dan orang yang berpuasa itu mempunyai dua kegembiraan; ketika berbuka ia gembira dan ketika bertemu Rabb-nya, lalu Dia membalasnya, ia pun bergembira. Demi Dzat yang jiwa Muhammad berada di tangan-Nya, bau mulut orang yang berpuasa sungguh lebih harum di sisi Allah daripada aroma minyak kesturi.\""},"2134":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو أَنَّ الْمُنْذِرَ بْنَ عُبَيْدٍ حَدَّثَهُ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصِّيَامُ لِي وَأَنَا أَجْزِي بِهِ وَالصَّائِمُ يَفْرَحُ مَرَّتَيْنِ عِنْدَ فِطْرِهِ وَيَوْمَ يَلْقَى اللَّهَ وَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Dawud] dari [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku ['Amr] bahwasanya [Al Mudzir bin 'Ubaid] menceritakan kepadanya dari [Abu Shalih As Samman] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Puasa itu untuk-Ku dan Aku yang akan membalasnya. Orang yang berpuasa bergembira dua kali; ketika berbuka dan pada saat bertemu Allah. Dan aroma mulut orang yang berpuasa sungguh lebih harum di sisi Allah daripada aroma minyak kesturi.\""},"2135":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ حَسَنَةٍ عَمِلَهَا ابْنُ آدَمَ إِلَّا كُتِبَ لَهُ عَشْرُ حَسَنَاتٍ إِلَى سَبْعِ مِائَةِ ضِعْفٍ قَالَ اللَّهُ عَزَّ وَجَلَّ إِلَّا الصِّيَامَ فَإِنَّهُ لِي وَأَنَا أَجْزِي بِهِ يَدَعُ شَهْوَتَهُ وَطَعَامَهُ مِنْ أَجْلِي الصِّيَامُ جُنَّةٌ لِلصَّائِمِ فَرْحَتَانِ فَرْحَةٌ عِنْدَ فِطْرِهِ وَفَرْحَةٌ عِنْدَ لِقَاءِ رَبِّهِ وَلَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Tidak ada kebaikan yang dikerjakan anak Adam kecuali akan ditulis untuknya sepuluh kebaikan hingga tujuh ratus kali lipat. Allah -Azza wa Jalla- berfirman: 'Kecuali puasa, maka sesungguhnya puasa itu untuk-Ku dan Aku akan membalasnya, ia meninggalkan syahwat dan makanannya hanya karena Aku. Puasa itu perisai. Orang yang berpuasa mempunyai dua kegembiraan; satu kegembiraan ketika berbuka dan kegembiraan ketika bertemu Rabb-nya. Dan aroma mulut orang yang berpuasa sungguh lebih harum di sisi Allah daripada aroma minyak kesturi.\""},"2136":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ عَنْ حَجَّاجٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ عَنْ أَبِي صَالِحٍ الزَّيَّاتِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ عَمَلِ ابْنِ آدَمَ لَهُ إِلَّا الصِّيَامَ هُوَ لِي وَأَنَا أَجْزِي بِهِ وَالصِّيَامُ جُنَّةٌ إِذَا كَانَ يَوْمُ صِيَامِ أَحَدِكُمْ فَلَا يَرْفُثْ وَلَا يَصْخَبْ فَإِنْ شَاتَمَهُ أَحَدٌ أَوْ قَاتَلَهُ فَلْيَقُلْ إِنِّي صَائِمٌ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ يَوْمَ الْقِيَامَةِ مِنْ رِيحِ الْمِسْكِ لِلصَّائِمِ فَرْحَتَانِ يَفْرَحُهُمَا إِذَا أَفْطَرَ فَرِحَ بِفِطْرِهِ وَإِذَا لَقِيَ رَبَّهُ عَزَّ وَجَلَّ فَرِحَ بِصَوْمِهِ","id":"Telah mengabarkan kepadaku [Ibrahim bin Al Hasan] dari [Hajjaj] dia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku ['Atha] dari [Abu Shalih Az Ziyyat] bahwasanya ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semua amal perbuatan anak Adam adalah untuknya kecuali puasa, ia untuk-Ku dan Aku akan membalasnya. Dan puasa itu adalah perisai. Jika salah seorang dari kalian berada pada hari puasa, maka tidak boleh melakukan rafats (berbicara keji yang termasuk di dalamnya adalah jima) dan tidak boleh membuat kegaduhan. Jika seseorang mencacinya atau menyerangnya, maka hendaklah ia mengatakan; 'Sesungguhnya aku sedang berpuasa.' Demi Dzat yang jiwa Muhammad ada di tangan-Nya, sungguh aroma mulut orang yang berpuasa lebih harum di sisi Allah -pada hari Kiamat- dari pada aroma minyak kesturi. Orang yang berpuasa mempunyai dua kegembiraan, ia bergembira dengan keduanya; jika berbuka, ia bergenbira dengan berbukanya dan jika bertemu dengan Rabb-nya -Azza wa Jalla-, ia bergembira dengan puasanya.\""},"2137":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ جُرَيْجٍ قِرَاءَةً عَلَيْهِ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ قَالَ أَخْبَرَنِي عَطَاءٌ الزَّيَّاتُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ عَزَّ وَجَلَّ كُلُّ عَمَلِ ابْنِ آدَمَ لَهُ إِلَّا الصِّيَامَ هُوَ لِي وَأَنَا أَجْزِي بِهِ الصِّيَامُ جُنَّةٌ فَإِذَا كَانَ يَوْمُ صَوْمِ أَحَدِكُمْ فَلَا يَرْفُثْ وَلَا يَصْخَبْ فَإِنْ شَاتَمَهُ أَحَدٌ أَوْ قَاتَلَهُ فَلْيَقُلْ إِنِّي امْرُؤٌ صَائِمٌ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِوَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ أَبِي هُرَيْرَةَ وَسَعِيدِ بْنِ الْمُسَيَّبِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] dia berkata; telah memberitakan kepada kami [Suwaid] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Ibnu Juraij] -secara baca- dari ['Atha bin Abu Rabbah] dia berkata; telah mengabarkan kepadaku ['Atha Az Ziyyat] bahwasanya ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Azza wa Jalla berfirman: \"Semua amal perbuatan anak Adam adalah untuknya, kecuali puasa, ia untuk-Ku dan Aku akan membalasnya. Puasa itu adalah perisai. Jika salah seorang dari kalian berada pada hari puasa, maka tidak boleh melakukan rafats (berkata kotor dll) dan tidak boleh membuat kegaduhan. Jika seseorang mencacinya atau menyerangnya, maka hendaklah ia mengatakan; 'Sesungguhnya aku sedang berpuasa.' Dan, demi Dzat yang jiwa Muhammad ada di tangan-Nya, aroma mulut orang yang berpuasa lebih harum di sisi Allah -pada hari Kiamat- dari pada aroma minyak kesturi.\" Hadits ini telah diriwayatkan dari Abu Hurairah dan Sa'id Musayyab."},"2138":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ عَزَّ وَجَلَّ كُلُّ عَمَلِ ابْنِ آدَمَ لَهُ إِلَّا الصِّيَامَ هُوَ لِي وَأَنَا أَجْزِي بِهِ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَخُلْفَةُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; telah menceritakan kepadaku [Sa'id bin Al Musayyab] bahwasanya [Abu Hurairah] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Azza wa Jalla berfirman: 'Semua amal perbuatan anak Adam adalah untuknya, kecuali puasa, ia untuk-Ku dan Aku akan membalasnya. Demi Dzat yang jiwa Muhammad ada di tangan-Nya, sungguh aroma mulut orang yang berpuasa lebih harum di sisi Allah -pada hari Kiamat- dari pada aroma minyak kesturi.\""},"2139":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عِيسَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرٍو عَنْ بُكَيْرٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ حَسَنَةٍ يَعْمَلُهَا ابْنُ آدَمَ فَلَهُ عَشْرُ أَمْثَالِهَا إِلَّا الصِّيَامَ لِي وَأَنَا أَجْزِي بِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Isa] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari ['Amr] dari [Bukair] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Setiap kebaikan yang dilakukan oleh anak Adam, maka untuknya sepuluh kebaikan yang sama, kecuali puasa, (puasa itu) untuk-Ku dan Aku akan membalasnya.\""},"2140":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي جَرِيرُ بْنُ حَازِمٍ أَنَّ مُحَمَّدَ بْنَ عَبْدِ اللَّهِ بْنِ أَبِي يَعْقُوبَ الضَّبِّيَّ حَدَّثَهُ عَنْ رَجَاءِ بْنِ حَيْوَةَ قَالَ حَدَّثَنَا أَبُو أُمَامَةَ الْبَاهِلِيُّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مُرْنِي بِأَمْرٍ يَنْفَعُنِي اللَّهُ بِهِ قَالَ عَلَيْكَ بِالصِّيَامِ فَإِنَّهُ لَا مِثْلَ لَهُ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Jarir bin Hazim] bahwasanya [Muhammad bin 'Abdullah bin Abu Ya'qub Adl Dlabbi] menceritakan kepadanya dari [Raja' bin Haiwah] dia berkata; telah menceritakan kepada kami [Abu Umamah Al Bahili] dia berkata; \"Aku mengatakan; 'Wahai Rasulullah shallallahu 'alaihi wasallam, perintahlah aku dengan suatu perintah yang dengannya Allah memberikan manfaat kepadaku', beliau bersabda: \"Hendaklah kamu berpuasa, karena ia tidak ada bandingannya.\""},"2141":{"ar":"أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الضَّعِيفُ شَيْخٌ صَالِحٌ وَالضَّعِيفُ لَقَبٌ لِكَثْرَةِ عِبَادَتِهِ قَالَ أَخْبَرَنَا يَعْقُوبُ الْحَضْرَمِيُّ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي يَعْقُوبَ عَنْ أَبِي نَصْرٍ عَنْ رَجَاءِ بْنِ حَيْوَةَ عَنْ أَبِي أُمَامَةَأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْعَمَلِ أَفْضَلُ قَالَ عَلَيْكَ بِالصَّوْمِ فَإِنَّهُ لَا عِدْلَ لَهُ","id":"Telah mengabarkan kepadaku ['Abdullah bin Muhammad Adh Dha'if] -syaikh yang shalih dan lemah, digelari seperti ini karena banyaknya dia beribadah- dia berkata; telah mengabarkan kepada kami [Ya'qub Al Hadhrami] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin 'Abdullah bin Abu Ya'qub] dari [Abu Nashr] dari [Raja' bin Haiwah] dari [Abu Umamah] bahwa ia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, lalu aku berkata; \"Amal apa yang paling utama?\" Beliau bersabda: \"Hendaklah kamu berpuasa, karena ia tidak ada bandingannya.\""},"2142":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ مُحَمَّدٍ هُوَ ابْنُ السَّكَنِ أَبُو عُبَيْدِ اللَّهِ قَالَ حَدَّثَنَا يَحْيَى بْنُ كَثِيرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ أَبِي يَعْقُوبَ الضَّبِّيِّ عَنْ أَبِي نَصْرٍ الْهِلَالِيِّ عَنْ رَجَاءِ بْنِ حَيْوَةَ عَنْ أَبِي أُمَامَةَ قَالَ قُلْتُيَا رَسُولَ اللَّهِ مُرْنِي بِعَمَلٍ قَالَ عَلَيْكَ بِالصَّوْمِ فَإِنَّهُ لَا عَدْلَ لَهُ قُلْتُ يَا رَسُولَ اللَّهِ مُرْنِي بِعَمَلٍ قَالَ عَلَيْكَ بِالصَّوْمِ فَإِنَّهُ لَا عِدْلَ لَهُ","id":"Telah mengabarkan kepada kami [Yahya bin Muhammad bin As Sakan Abu 'Ubaidullah] dia berkata; telah menceritakan kepada kami [Yahya bin Katsir] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Abu Ya'qub Adl Dlabbi] dari [Abu Nashr Al Hilali] dari [Raja' bin Haiwah] dari [Abu Umamah] dia berkata; Aku berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, perintahlah aku dengan suatu amal.\" Beliau bersabda: \"Hendaklah kamu berpuasa, karena ia tidak ada bandingannya.\" Aku berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, perintahlah aku dengan suatu amal.\" Beliau bersabda: \"Hendaklah kamu berpuasa, karena ia tidak ada bandingannya.\""},"2143":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سُلَيْمَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ وَالْحَكَمِ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّوْمُ جُنَّةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Yahya bin Hammad] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Sulaiman] dari [Habib bin Abu Tsabit] dan [Al Hakam] dari [Maimun bin Abu Syabib] dari [Mu'adz bin Jabal] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa itu perisai.\""},"2144":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ عُرْوَةَ بْنَ النَّزَّالِ يُحَدِّثُ عَنْ مُعَاذٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّوْمُ جُنَّةٌأَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ عَنْ حَجَّاجٍ عَنْ شُعْبَةَ قَالَ لِي الْحَكَمُ سَمِعْتُهُ مِنْهُ مُنْذُ أَرْبَعِينَ سَنَةً ثُمَّ قَالَ الْحَكَمُ وَحَدَّثَنِي بِهِ مَيْمُونُ بْنُ أَبِي شَبِيبٍ عَنْ مُعَاذِ بْنِ جَبَلٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dia berkata; aku mendengar ['Urwah bin An Nazzal] menceritakan dari [Mu'adz] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa itu perisai.\" Telah mengabarkan kepadaku [Ibrahim bin Hasan] dari [Hajjaj] dari [Syu'bah], [Hakam] berkata kepadaku, Aku mendengar darinya sejak empat puluh tahun, kemudian Al Hakam berkata; 'Dan telah menceritakan kepadaku tentang hal itu, dari [Maimun bin Abu Syabib] dari [Mu'adz bin Jabal]."},"2145":{"ar":"و أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ أَنْبَأَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ جُرَيْجٍ قِرَاءَةً عَنْ عَطَاءٍ قَالَ أَنْبَأَنَا عَطَاءٌ الزَّيَّاتُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصِّيَامُ جُنَّةٌ","id":"Dan telah mengabarkan kepada kami [Muhammad bin Hatim]; telah memberitakan kepada kami [Suwaid] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Ibnu Juraij] secara baca dari ['Atha] dia berkata; telah memberitakan kepada kami ['Atha Az Zayyat] bahwasanya ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa itu perisai.\""},"2146":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ أَنَّ مُطَرِّفًا رَجُلًا مِنْ بَنِي عَامِرِ بْنِ صَعْصَعَةَ حَدَّثَهُأَنَّ عُثْمَانَ بْنَ أَبِي الْعَاصِ دَعَا لَهُ بِلَبَنٍ لِيَسْقِيَهُ فَقَالَ مُطَرِّفٌ إِنِّي صَائِمٌ فَقَالَ عُثْمَانُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الصِّيَامُ جُنَّةٌ كَجُنَّةِ أَحَدِكُمْ مِنْ الْقِتَالِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Sa'id bin Abu Hind] bahwasanya [Mutharrif] -seorang lelaki dari Bani 'Amir bin Sha'sha'ah- menceritakan kepadanya bahwasanya ['Utsman bin Abul 'Ash] meminta diambilkan susu untuk memberikan minum kepadanya, Mutharif berkata; \"Sesungguhnya aku sedang berpuasa.\" Lalu Utsman berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa itu perisai, seperti perisai salah seorang di antara kalian dari peperangan.\""},"2147":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ الْحُسَيْنِ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ مُطَرِّفٍ قَالَدَخَلْتُ عَلَى عُثْمَانَ بْنِ أَبِي الْعَاصِ فَدَعَا بِلَبَنٍ فَقُلْتُ إِنِّي صَائِمٌ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الصَّوْمُ جُنَّةٌ مِنْ النَّارِ كَجُنَّةِ أَحَدِكُمْ مِنْ الْقِتَالِأَخْبَرَنِي زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا أَبُو مُصْعَبٍ عَنْ الْمُغِيرَةِ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ قَالَ دَخَلَ مُطَرِّفٌ عَلَى عُثْمَانَ نَحْوَهُ مُرْسَلٌ","id":"Telah mengabarkan kepada kami ['Ali bin Al Hasan] dia berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Ibnu Ishaq] dari [Sa'id bin Abu Hind] dari [Mutharrif] dia berkata; \"Aku masuk menemui [Utsman bin Abu Al Ash], lalu ia minta diambilkan susu, maka aku berkata; \"Sesungguhnya aku sedang berpuasa.\" Lalu ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Puasa itu perisai, seperti perisai salah seorang di antara kalian dari peperangan'.\" Telah mengabarkan kepadaku [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami [Abu Mush'ab] dari [Al Mughirah] dari ['Abdullah bin Sa'id bin Abu Hind] dari [Muhammad bin Ishaq] dari [Sa'id bin Abu Hind] dia berkata; 'Mutharrif masuk menemui Utsman.... selanjutnya sebagaimana Hadits di atas secara mursal.'"},"2148":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الْآدَمِيُّ قَالَ حَدَّثَنَا مَعْنٌ عَنْ خَارِجَةَ بْنِ سُلَيْمَانَ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصِّيَامُ جُنَّةٌ مِنْ النَّارِ فَمَنْ أَصْبَحَ صَائِمًا فَلَا يَجْهَلْ يَوْمَئِذٍ وَإِنْ امْرُؤٌ جَهِلَ عَلَيْهِ فَلَا يَشْتُمْهُ وَلَا يَسُبَّهُ وَلْيَقُلْ إِنِّي صَائِمٌ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Al Adami] dia berkata; telah menceritakan kepada kami [Ma'n] dari [Kharijah bin Sulaiman] dari [Yazid bin Ruman] dari ['Urwah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Puasa itu adalah perisai dari api neraka, barangsiapa yang berpuasa, maka janganlah berbuat bodoh ketika itu, dan jika seseorang membodohinya, maka janganlah mencacinya dan jangan mencelanya, hendaklah ia mengatakan, ' aku sedang berpuasa, ' demi Dzat yang jiwa Muhammad ada di tangan-Nya, aroma mulut orang yang berpuasa lebih harum di sisi Allah -pada hari Kiamat- dari pada aroma minyak kesturi.\""},"2149":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حَبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مِسْعَرٍ عَنْ الْوَلِيدِ بْنِ أَبِي مَالِكٍ قَالَ حَدَّثَنَا أَصْحَابُنَا عَنْ أَبِي عُبَيْدَةَ قَالَالصِّيَامُ جُنَّةٌ مَا لَمْ يَخْرِقْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] dia berkata; telah memberitakan kepada kami [Habban] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Mis'ar] dari [Al Walid bin Abu Malik] dia berkata; telah menceritakan kepada kami [shahabat-shahabat kami] dari [Abu 'Ubaidah] dia berkata; \"Puasa itu adalah perisai, selagi ia tidak merusaknya -dengan maksiat-.\""},"2150":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَخْبَرَنِي أَنَسٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ زَحْزَحَ اللَّهُ وَجْهَهُ عَنْ النَّارِ بِذَلِكَ الْيَوْمِ سَبْعِينَ خَرِيفًا","id":"Telah mengabarkan kepada kami [Yunus bin 'Abdul A'la] dia berkata; telah mengabarkan kepadaku [Anas] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berpuasa sehari di jalan Allah -Azza wa Jalla-, Allah menjauhkan wajahnya dari api neraka selama tujuh puluh tahun karena hari itu.\""},"2151":{"ar":"أَخْبَرَنَا دَاوُدُ بْنُ سُلَيْمَانَ بْنِ حَفْصٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ الضَّرِيرُ عَنْ سُهَيْلٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ بَاعَدَ اللَّهُ بَيْنَهُ وَبَيْنَ النَّارِ بِذَلِكَ الْيَوْمِ سَبْعِينَ خَرِيفًا","id":"Telah mengabarkan kepada kami [Dawud bin Sulaiman bin Hafsh] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah Adl Dlarir] dari [Suhail] dari [Al Maqburi] dari [Abu Sa'id Al Khudri] dia berkata; dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa sehari dijalan Allah, Allah menjauhkan antara ia dan neraka selama tujuh puluh tahun karena hari itu.\""},"2152":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ أَخْبَرَنِي سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ بَاعَدَ اللَّهُ عَزَّ وَجَلَّ وَجْهَهُ عَنْ النَّارِ سَبْعِينَ خَرِيفًا","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami [Ibnu Abu Maryam] dia berkata; telah menceritakan kepada kami [Sa'id bin 'Abdurrahman] dia berkata; telah mengabarkan kepadaku [Suhail] dari [Bapaknya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa sehari di jalan Allah, Allah -Azza wa Jalla- menjauhkan wajahnya dari api neraka selama tujuh puluh tahun karena hari itu.\""},"2153":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُهَيْلٍ عَنْ صَفْوَانَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ بَاعَدَ اللَّهُ وَجْهَهُ مِنْ جَهَنَّمَ سَبْعِينَ عَامًا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Suhail] dari [Shafwan] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berpuasa sehari di jalan Allah -Azza wa Jalla-, Allah menjauhkan wajahnya dari neraka Jahanam selama tujuh puluh tahun.\""},"2154":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ ابْنِ الْهَادِ عَنْ سُهَيْلٍ عَنْ ابْنِ أَبِي عَيَّاشٍ عَنْ أَبِي سَعِيدٍأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَصُومُ يَوْمًا فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ إِلَّا بَعَّدَ اللَّهُ عَزَّ وَجَلَّ بِذَلِكَ الْيَوْمِ وَجْهَهُ عَنْ النَّارِ سَبْعِينَ خَرِيفًا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul Hakim] dari [Syu'aib] dia berkata; telah memberitakan kepada kami [Al Laits] dari [Ibnul Had] dari [Suhail] dari [Ibnu Abu 'Ayyasy] dari [Abu Sa'id] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba yang berpuasa sehari di jalan Allah -Azza wa Jalla-, melainkan Allah -Azza wa Jalla- menjauhkan wajahnya dari api neraka selama tujuh puluh tahun karena hari itu.\""},"2155":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ قَزَعَةَ عَنْ حُمَيْدِ بْنِ الْأَسْوَدِ قَالَ حَدَّثَنَا سُهَيْلٌ عَنْ النُّعْمَانِ بْنِ أَبِي عَيَّاشٍ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ بَاعَدَهُ اللَّهُ عَنْ النَّارِ سَبْعِينَ خَرِيفًا","id":"Telah mengabarkan kepada kami [Al Hasan bin Qaza'ah] dari [Humaid bin Al Aswad] dia berkata; telah menceritakan kepada kami [Suhail] dari [An Nu'man bin Abu 'Ayyasy] dia berkata; aku mendengar [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa sehari di jalan Allah -Azza wa Jalla-, Allah menjauhkan ia dari api neraka selama tujuh puluh tahun.\""},"2156":{"ar":"أَخْبَرَنَا مُؤَمَّلُ بْنُ إِهَابٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي يَحْيَى بْنُ سَعِيدٍ وَسُهَيْلُ بْنُ أَبِي صَالِحٍ سَمِعَا النُّعْمَانَ بْنَ أَبِي عَيَّاشٍ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ تَبَارَكَ وَتَعَالَى بَاعَدَ اللَّهُ وَجْهَهُ عَنْ النَّارِ سَبْعِينَ خَرِيفًا","id":"Telah mengabarkan kepada kami [Muammal bin Ihab] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku [Yahya bin Sa'id] dan [Suhail bin Abu Shalih], mereka mendengar dari [An Nu'man bin Abu 'Ayyasy] dia berkata; aku mendengar [Abu Sa'id Al Khudri] berkata; \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa sehari di jalan Allah -Tabaraka wa Ta'ala-, Allah menjauhkan wajahnya dari api neraka selama tujuh puluh tahun.\""},"2157":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ نَيْسَابُورِيٌّ قَالَ حَدَّثَنَا يَزِيدُ الْعَدَنِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ النُّعْمَانِ بْنِ أَبِي عَيَّاشٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَصُومُ عَبْدٌ يَوْمًا فِي سَبِيلِ اللَّهِ إِلَّا بَاعَدَ اللَّهُ تَعَالَى بِذَلِكَ الْيَوْمِ النَّارَ عَنْ وَجْهِهِ سَبْعِينَ خَرِيفًا","id":"Telah mengabarkan kepada kami ['Abdullah bin Munir An Naisaburi] dia berkata; telah menceritakan kepada kami [Yazid Al 'Adani] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Suhail bin Abu Shalih] dari [An Nu'man bin Abu 'Ayyasy] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba yang berpuasa sehari di jalan Allah, melainkan Allah -Ta'ala- akan jauhkan neraka dari wajahnya selama tujuh puluh tahun karena hari itu.\""},"2158":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا قَاسِمٌ عَنْ سُفْيَانَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ النُّعْمَانِ بْنِ أَبِي عَيَّاشٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ بَاعَدَ اللَّهُ بِذَلِكَ الْيَوْمِ حَرَّ جَهَنَّمَ عَنْ وَجْهِهِ سَبْعِينَ خَرِيفًا","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] dia berkata; telah menceritakan kepada kami [Qasim] dari [Sufyan] dari [Suhail bin Abu Shalih] dari [An Nu'man bin Abu 'Ayyasy] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa berpuasa sehari di jalan Allah, Allah menjauhkan panasnya neraka Jahanam dari wajahnya karena hari itu selama tujuh puluh tahun.\""},"2159":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ مُحَمَّدِ بْنِ حَنْبَلٍ قَالَ قَرَأْتُ عَلَى أَبِي حَدَّثَكُمْ ابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سُمَيٍّ عَنْ النُّعْمَانِ بْنِ أَبِي عَيَّاشٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ بَاعَدَ اللَّهُ بِذَلِكَ الْيَوْمِ النَّارَ عَنْ وَجْهِهِ سَبْعِينَ خَرِيفًا","id":"Telah mengabarkan kepada kami ['Abdullah bin Ahmad bin Muhammad bin Hanbal] dia berkata; aku membaca kitab [bapakku], telah menceritakan kepada kalian [Ibnu Numair] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Sumayyi] dari [An Nu'man bin Abu 'Ayyasy] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa sehari di jalan Allah, Allah menjauhkan neraka dari wajahnya selama tujuh puluh tahun karena hari itu.\""},"2160":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ عَنْ مُحَمَّدِ بْنِ شُعَيْبٍ قَالَ أَخْبَرَنِي يَحْيَى بْنُ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ أَنَّهُ حَدَّثَهُ عَنْ عُقْبَةَ بْنِ عَامِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ بَاعَدَ اللَّهُ مِنْهُ جَهَنَّمَ مَسِيرَةَ مِائَةِ عَامٍ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] dari [Muhammad bin Syu'aib] dia berkata; telah mengabarkan kepadaku [Yahya bin Al Harits] dari [Al Qasim Abu 'Abdurrahman] bahwasanya ia menceritakan kepadanya dari ['Uqbah bin 'Amir] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa yang berpuasa sehari dijalan Allah Azza wa Jalla maka Allah menjauhkan darinya neraka Jahannam sejauh perjalanan seratus tahun.\""},"2161":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ عَنْ أُمِّ الدَّرْدَاءِ عَنْ كَعْبِ بْنِ عَاصِمٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari [Shafwan bin 'Abdullah] dari [Ummu Ad Darda'] dari [Ka'b bin 'Ashim] dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk kebajikan berpuasa dalam perjalanan.\""},"2162":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ الَّذِي قَبْلَهُ لَا نَعْلَمُ أَحَدًا تَابَعَ ابْنَ كَثِيرٍ عَلَيْهِ","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami [Muhammad bin Katsir] dari [Al Auza'i] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk kebajikan berpuasa dalam perjalanan.\" Abu Abdurrahman berkata; 'Ini adalah salah dan yang benar adalah Hadits sebelumnya, kami tidak mengetahui seorang pun yang mengikuti Ibnu Katsir atas hal itu.'"},"2163":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا بَكْرٌ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نَاسًا مُجْتَمِعِينَ عَلَى رَجُلٍ فَسَأَلَ فَقَالُوا رَجُلٌ أَجْهَدَهُ الصَّوْمُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَ��ْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Bakr] dari ['Umarah bin Ghaziyyah] dari [Muhammad bin 'Abdurrahman] dari [Jabir bin 'Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah melihat sekelompok orang yang sedang berkumpul mengerumuni seseorang, lalu beliau bertanya? mereka menjawab; \"Ia adalah orang yang tertekan -karena- puasa.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk kebajikan berpuasa dalam perjalanan.\""},"2164":{"ar":"أَخْبَرَنِي شُعَيْبُ بْنُ شُعَيْبِ بْنِ إِسْحَقَ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ أَخْبَرَنِي جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِرَجُلٍ فِي ظِلِّ شَجَرَةٍ يُرَشُّ عَلَيْهِ الْمَاءُ قَالَ مَا بَالُ صَاحِبِكُمْ هَذَا قَالُوا يَا رَسُولَ اللَّهِ صَائِمٌ قَالَ إِنَّهُ لَيْسَ مِنْ الْبِرِّ أَنْ تَصُومُوا فِي السَّفَرِ وَعَلَيْكُمْ بِرُخْصَةِ اللَّهِ الَّتِي رَخَّصَ لَكُمْ فَاقْبَلُوهَاأَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا الْفِرْيَابِيُّ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي مَنْ سَمِعَ جَابِرًا نَحْوَهُ","id":"Telah mengabarkan kepadaku [Syu'aib bin Syu'aib bin Ishaq] dia berkata; telah menceritakan kepada kami ['Abdul Wahhab bin Sa'id] dia berkata; telah menceritakan kepada kami [Syu'aib] dia berkata; telah menceritakan kepada kami [Al Auza'i] dia berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir] dia berkata; telah mengabarkan kepadaku [Muhammad bin 'Abdurrahman] dia berkata; telah mengabarkan kepadaku [Jabir bin 'Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam melewati seseorang yang berada di bawah naungan pohon, dirinya disiram air, beliau bertanya: \"Apa yang telah terjadi pada teman kalian ini?!\" mereka menjawab; \"Wahai Rasulullah shallallahu 'alaihi wasallam, ia sedang berpuasa.\" Beliau bersabda: \"Bukan termasuk kebajikan jika kalian berpuasa dalam perjalanan dan hendaklah kalian mengambil keringanan yang Allah berikan kepada kalian, terimalah keringanan tersebut.\" Telah mengabarkan kepada kami [Mahmud bin Khalid] dia berkata; telah menceritakan kepada kami [Al Firyabi] dia berkata; telah menceritakan kepada kami [Al Auza'i] dia bekata; telah menceritakan kepadaku [Yahya] dia berkata; Telah mengabarkan kepadaku [Muhammad bin Abdurrahman] dia berkata; telah menceritakan kepadaku [orang yang mendengar Hadits] dari [Jabir]; mengenai Hadits yang serupa."},"2165":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ عَلَيْكُمْ بِرُخْصَةِ اللَّهِ عَزَّ وَجَلَّ فَاقْبَلُوهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami ['Ali bin Al Mubarak] dari [Yahya bin Abu Katsir] dari [Muhammad bin 'Abdurrahman bin Tsauban] dari [Jabir bin 'Abdullah Radliallahu? nhuma], dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Bukan termasuk kebajikan berpuasa dalam perjalanan. Hendaklah kalian mengambil keringanan yang diberikan Allah -Azza wa Jalla-, terimalah keringanan tersebut.\""},"2166":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ عُثْمَانَ بْنِ عُمَرَ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ رَجُلٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari ['Utsman bin 'Umar] dia berkata; telah memberitakan kepada kami ['Ali bin Al Mubarak] dari [Yahya] dari [Muhammad bin 'Abdurrahman] dari [seorang lelaki] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk kebajikan jika kalian berpuasa dalam perjalanan.\""},"2167":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَخَالِدُ بْنُ الْحَارِثِ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَسَنٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا قَدْ ظُلِّلَ عَلَيْهِ فِي السَّفَرِ فَقَالَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dan [Khalid bin Al Harits] dari [Syu'bah] dari [Muhammad bin 'Abdurrahman] dari [Muhammad bin 'Amr bin Hasan] dari [Jabir bin 'Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam melihat seseorang yang menaungi dirinya dengan sesuatu -karena panas dan dahaga- dalam perjalanan, maka beliau bersabda: \"Bukan termasuk kebajikan berpuasa dalam perjalanan.\""},"2168":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ ابْنِ الْهَادِ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَكَّةَ عَامَ الْفَتْحِ فِي رَمَضَانَ فَصَامَ حَتَّى بَلَغَ كُرَاعَ الْغَمِيمِ فَصَامَ النَّاسُ فَبَلَغَهُ أَنَّ النَّاسَ قَدْ شَقَّ عَلَيْهِمْ الصِّيَامُ فَدَعَا بِقَدَحٍ مِنْ الْمَاءِ بَعْدَ الْعَصْرِ فَشَرِبَ وَالنَّاسُ يَنْظُرُونَ فَأَفْطَرَ بَعْضُ النَّاسِ وَصَامَ بَعْضٌ فَبَلَغَهُ أَنَّ نَاسًا صَامُوا فَقَالَ أُولَئِكَ الْعُصَاةُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul Hakam] dari [Syu'aib] dia berkata; telah memberitakan kepada kami [Al Laits] dari [Ibnul Had] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam berangkat ke Mekkah pada tahun kemenangan kota Mekkah di bulan Ramadlan, lalu beliau berpuasa hingga sampai di Kura' Al Ghamim dan orang-orang ikut berpuasa, kemudian berita sampai kepada beliau, bahwa orang-orang merasa berat untuk berpuasa, lalu setelah Ashar beliau meminta segelas air, kemudian minum dan orang-orang melihatnya, maka sebagian orang berbuka dan sebagian lainnya berpuasa, setelah sampai berita kepada beliau bahwa -ada sebagian- orang yang berpuasa, beliau bersabda: \"Mereka adalah orang-orang yang durhaka.\""},"2169":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبدِ اللَّهِ وَعَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَا حَدَّثَنَا أَبُو دَاوُدَ عَنْ سُفْيَانَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِطَعَامٍ بِمَرِّ الظَّهْرَانِ فَقَالَ لِأَبِي بَكْرٍ وَعُمَرَ أَدْنِيَا فَكُلَا فَقَالَا إِنَّا صَائِمَانِ فَقَالَ ارْحَلُوا لِصَاحِبَيْكُمْ اعْمَلُوا لِصَاحِبَيْكُمْأَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ قَالَ أَخْبَرَنِي الْأَوْزَاعِيُّ عَنْ يَحْيَى أَنَّهُ حَدَّثَهُ عَنْ أَبِي سَلَمَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَغَدَّى بِمَرِّ الظَّهْرَانِ وَمَعَهُ أَبُو بَكْرٍ وَعُمَرُ فَقَالَ الْغَدَاءَ مُرْسَلٌ أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا عَلِيٌّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ كَانُوا بِمَرِّ الظَّهْرَانِ مُرْسَلٌ","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dan ['Abdurrahman bin Muhammad bin Sallam] mereka berkata; telah menceritakan kepada kami [Abu Dawud] dari [Sufyan] dari [Al Auza'i] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Nabi shallallahu 'alaihi wasallam diberi makanan di Marr Azh-Zhahran, maka beliau bersabda kepada Abu Bakar dan Umar: \"Mendekatlah kalian berdua dan makanlah.\" Lalu keduanya berkata; ' kami sedang berpuasa.' Maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Pergilah kalian untuk menemui dua sahabat kalian dan buatkan sesuatu untuk dua sahabat kalian.' Telah mengabarkan kepada kami [Imran bin Yazid] dia berkata; Telah menceritakan kepada kami [Muhammad bin Syu'aib] dia berkata; telah mengabarkan kepadakku [Al Auza'i] dari [Yahya] dia berkata kepadanya, dari [Abu Salamah] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda ketika Rasulullah shallallahu 'alaihi wasallam makan siang di Marr Azh-Zhahran, beliau bersama Abu Bakar dan Umar, beliau berkata: 'Makan sianglah'. Secara mursal. Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Utsman bin Umar] dia berkata; telah menceritakan kepada kami [Ali] dari [Yahya] dari [Abu Salamah] bahwasanya Rasulullah shallallahu 'alaihi wasallam, Abu Bakar dan Umar berada di Marr Azh-Zhahran. Secara mursal."},"2170":{"ar":"أَخْبَرَنِي عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ عَنْ مُحَمَّدِ بْنِ شُعَيْبٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ أَخْبَرَنِي عَمْرُو بْنُ أُمَيَّةَ الضَّمْرِيُّ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَفَرٍ فَقَالَ انْتَظِرْ الْغَدَاءَ يَا أَبَا أُمَيَّةَ فَقُلْتُ إِنِّي صَائِمٌ فَقَالَ تَعَالَ ادْنُ مِنِّي حَتَّى أُخْبِرَكَ عَنْ الْمُسَافِرِ إِنَّ اللَّهَ عَزَّ وَجَلَّ وَضَعَ عَنْهُ الصِّيَامَ وَنِصْفَ الصَّلَاةِ","id":"Telah mengabarkan kepadaku ['Abdah bin 'Abdurrahim] dari [Muhammad bin Syu'aib] dia berkata; telah menceritakan kepada kami [Al Auza'i] dari [Yahya] dari [Abu Salamah] dia berkata; telah mengabarkan kepadaku ['Amru bin Umayyah Adl Dlamri] dia berkata; Aku datang untuk menemui Rasulullah shallallahu 'alaihi wasallam dari bepergian, lalu beliau bersabda: \"Tunggulah makan siang wahai Abu Umayah!\" Kemudian aku berkata; \" aku sedang berpuasa.\" Maka beliau bersabda: \"Kemari, mendekatlah kepadaku hingga kuberitahukan kepadamu tentang -sesuatu yang berkenaan dengan- orang yang bepergian. Allah -Azza wa Jalla- telah membebaskan puasa dan setengah shalat darinya.\""},"2171":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو قِلَابَةَ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيُّ عَنْ أَبِيهِ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تَنْتَظِرُ الْغَدَاءَ يَا أَبَا أُمَيَّةَ قُلْتُ إِنِّي صَائِمٌ فَقَالَ تَعَالَ أُخْبِرْكَ عَنْ الْمُسَافِرِ إِنَّ اللَّهَ وَضَعَ عَنْهُ الصِّيَامَ وَنِصْفَ الصَّلَاةِ","id":"Telah mengabarkan kepadaku ['Amru bin 'Utsman] dia berkata; telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dia berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir] dia berkata; telah menceritakan kepadaku [Abu Qilabah] dia berkata; telah menceritakan kepadaku [Ja'far bin 'Amri bin Umayyah Adl Dlamri] dari [bapaknya], dia berkata; \"Aku pernah datang untuk menemui Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Tidakkah kamu menunggu makan siang wahai Abu Umayah?\" Aku berkata; \" aku sedang berpuasa.\" Maka beliau bersabda: \"Kemari, mendekatlah kepadaku hingga kuberitahukan kepadamu tentang -sesuatu yang berkenaan dengan- orang yang bepergian. Allah Azza Wa Jalla telah membebaskan puasa dan setengah shalat darinya.\""},"2172":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَاجِرِ عَنْ أَبِي أُمَيَّةَ الضَّمْرِيِّ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَفَرٍ فَسَلَّمْتُ عَلَيْهِ فَلَمَّا ذَهَبْتُ لِأَخْرُجَ قَالَ انْتَظِرْ الْغَدَاءَ يَا أَبَا أُمَيَّةَ قُلْتُ إِنِّي صَائِمٌ يَا نَبِيَّ اللَّهِ قَالَ تَعَالَ أُخْبِرْكَ عَنْ الْمُسَافِرِ إِنَّ اللَّهَ تَعَالَى وَضَعَ عَنْهُ الصِّيَامَ وَنِصْفَ الصَّلَاةِأَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُوسَى بْنُ مَرْوَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الْأَوْزَاعِيِّ قَالَ أَخْبَرَنِي يَحْيَى قَالَ حَدَّثَنِي أَبُو قِلَابَةَ قَالَ حَدَّثَنِي أَبُو الْمُهَاجِرِ قَالَ حَدَّثَنِي أَبُو أُمَيَّةَ يَعْنِي الضَّمْرِيَّ أَنَّهُ قَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah memberitakan kepada kami [Abul Mughirah] dia berkata; telah menceritakan kepada kami [Al Auza'i] dari [Yahya] dari [Abu Qilabah] dari [Abul Muhajir] dari [Abu Umayyah Adl Dlamri] dia berkata; Aku pernah datang untuk menemui Rasulullah shallallahu 'alaihi wasallam dari bepergian, lalu kuucapkan salam kepada beliau. Setelah aku beranjak keluar, beliau bersabda: \"Tunggulah makan siang wahai Abu Umayah.\" Aku berkata, \" Aku sedang berpuasa wahai Nabiyullah.\" Beliau bersabda: \"Kemarilah, kuberitahukan kepadamu tentang -sesuatu yang berkenaan dengan- orang yang bepergian. Allah telah membebaskan puasa dan setengah shalat darinya.\" Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Musa bin Marwan] dia berkata; telah menceritakan kepada kami [Muhammad bin Harb] dari [Al Auza'i] dia berkata; telah mengabarkan kepadaku [Yahya] dia berkata; telah menceritakan kepadaku [Abu Qilabah] dia berkata; telah menceritakan kepadaku [Abul Muhajir] dia berkata; telah menceritakan kepadaku [Abu Umayyah Adl Dlamri] bahwa dia datang menemui Rasulullah shallallahu 'alaihi wasallam, - kemudian dia menyebutkan Hadits diatas-."},"2173":{"ar":"أَخْبَرَنِي شُعَيْبُ بْنُ شُعَيْبِ بْنِ إِسْحَقَ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ حَدَّثَنِي الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى قَالَ حَدَّثَنِي أَبُو قِلَابَةَ الْجَرْمِيُّ أَنَّ أَبَا أُمَيَّةَ الضَّمْرِيَّ حَدَّثَهُمْأَنَّهُ قَدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَفَرٍ فَقَالَ انْتَظِرْ الْغَدَاءَ يَا أَبَا أُمَيَّةَ قُلْتُ إِنِّي صَائِمٌ قَالَ ادْنُ أُخْبِرْكَ عَنْ الْمُسَافِرِ إِنَّ اللَّهَ وَضَعَ عَنْهُ الصِّيَامَ وَنِصْفَ الصَّلَاةِ","id":"Telah mengabarkan kepadaku [Syu'aib bin Syu'aib bin Ishaq] dia berkata; telah menceritakan kepada kami ['Abdul Wahhab] dia berkata; telah menceritakan kepada kami [Syu'aib] dia berkata; telah menceritakan kepadaku [Al Auza'i] dia berkata; telah menceritakan kepadaku [Yahya] dia berkata; telah menceritakan kepadaku [Abu Qilabah Al Jarmi] bahwasanya [Abu Umayyah Adl Dlamri] menceritakan kepada mereka, ia datang untuk menemui Rasulullah shallallahu 'alaihi wasallam dari bepergian, lalu beliau bersabda: \"Tunggulah makan siang, wahai Abu Umayah!\" Aku berkata; \" aku sedang berpuasa.\" Maka beliau bersabda: \"Kemari, mendekatlah kepadaku hingga kuberitahukan kepadamu tentang -sesuatu yang berkenaan dengan- orang yang bepergian. Allah Azza Wa Jalla telah membebaskan puasa dan setengah shalat darinya.\""},"2174":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ بْنِ يَزِيدَ بْنِ إِبْرَاهِيمَ الْحَرَّانِيُّ قَالَ حَدَّثَنَا عُثْمَانُ قَالَ حَدَّثَنَا مُعَاوِيَةُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ أَنَّ أَبَا أُمَيَّةَ الضَّمْرِيَّ أَخْبَرَهُأَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَفَرٍ وَهُوَ صَائِمٌ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تَنْتَظِرْ الْغَدَاءَ قَالَ إِنِّي صَائِمٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَالَ أُخْبِرْكَ عَنْ الصِّيَامِ إِنَّ اللَّهَ عَزَّ وَجَلَّ وَضَعَ عَنْ الْمُسَافِرِ الصِّيَامَ وَنِصْفَ الصَّلَاةِأَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَنْبَأَنَا عَلِيٌّ عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ رَجُلٍ أَنَّ أَبَا أُمَيَّةَ أَخْبَرَهُ أَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَفَرٍ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaidullah bin Yazid bin Ibrahim Al Harrani] dia berkata; telah menceritakan kepada kami ['Utsman] dia berkata; telah menceritakan kepada kami [Mu'awiyah] dari [Yahya bin Abu Katsir] dari [Abu Qilabah] bahwasanya [Abu Umayyah Adl Dlamri] menceritakan kepada mereka, ia datang untuk menemui Rasulullah shallallahu 'alaihi wasallam dari bepergian, lalu beliau bersabda: \"Tunggulah makan siang, wahai Abu Umayah!\" Aku berkata; \" aku sedang berpuasa.\" Maka beliau bersabda: \"Kemari, mendekatlah kepadaku hingga kuberitahukan kepadamu tentang -sesuatu yang berkenaan dengan- orang yang bepergian. Allah telah membebaskan puasa dan setengah shalat darinya.\" Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Utsman bin Umar] dia berkata; telah memberitakan kepada kami [Ali] dari [Yahya] dari [Abu Qilabah] dari [seseorang], bahwa [Abu Umayyah] mengabarkan kepadanya, ia datang menemui Rasulullah shallallahu 'alaihi wasallam dari pepergian sebagaimana hadits diatas."},"2175":{"ar":"أَخْبَرَنَا عُمَرُ بْنُ مُحَمَّدِ بْنِ الْحَسَنِ بْنِ التَّلِّ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ وَضَعَ عَنْ الْمُسَافِرِ نِصْفَ الصَّلَاةِ وَالصَّوْمَ وَعَنْ الْحُبْلَى وَالْمُرْضِعِ","id":"Telah mengabarkan kepada kami ['Umar bin Muhammad bin Al Hasan bin At Tall] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Ayyub] dari [Abu Qilabah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Allah telah membebaskan setengah shalat dan puasa dari orang-orang yang bepergian dan dari wanita yang hamil serta menyusui.\""},"2176":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ حَدَّثَنَا حِبَّانُ قَالَ أَنْبَأَن��ا عَبْدُ اللَّهِ عَنْ ابْنِ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ شَيْخٍ مِنْ قُشَيْرٍ عَنْ عَمِّهِ حَدَّثَنَاثُمَّ أَلْفَيْنَاهُ فِي إِبِلٍ لَهُ فَقَالَ لَهُ أَبُو قِلَابَةَ حَدِّثْهُ فَقَالَ الشَّيْخُ حَدَّثَنِي عَمِّي أَنَّهُ ذَهَبَ فِي إِبِلٍ لَهُ فَانْتَهَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَأْكُلُ أَوْ قَالَ يَطْعَمُ فَقَالَ ادْنُ فَكُلْ أَوْ قَالَ ادْنُ فَاطْعَمْ فَقُلْتُ إِنِّي صَائِمٌ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ وَضَعَ عَنْ الْمُسَافِرِ شَطْرَ الصَّلَاةِ وَالصِّيَامَ وَعَنْ الْحَامِلِ وَالْمُرْضِعِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] dia berkata; telah menceritakan kepada kami [Habban] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Ibnu 'Uyainah] dari [Ayyub] dari [seorang Syaikh yang berasal dari Qusyair], dari [pamannya], dia menceritakan kepada kami, -kemudian kami mengikutinya yang pada waktu itu dia berada diatas untanya-, Maka Abu Qilabah berkata kepadanya; Ceritakanlah kepadanya, syaikh itu berkata; 'Pamanku telah menceritakan kepadaku bahwa ia pernah pergi dengan menaiki untanya yang berakhir di tempat Nabi shallallahu 'alaihi wasallam sedangkan beliau sedang makan -atau ia mengatakan, \"Beliau sedang makan\"-. Maka beliau bersabda: \"Kemari dan makanlah\", atau beliau bersabda: \"Kemari dan makanlah.\" Aku berkata; \" aku sedang berpuasa!\" lalu beliau bersabda: \" Allah -Azza Wa Jalla- telah membebaskan setengah shalat dan puasa dari orang yang bepergian dan dari wanita yang sedang hamil serta menyusui.\""},"2177":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا سُرَيْجٌ قَالَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ قَالَ حَدَّثَنِي أَبُو قِلَابَةَ هَذَا الْحَدِيثَ ثُمَّ قَالَ هَلْ لَكَ فِي صَاحِبِ الْحَدِيثِ فَدَلَّنِي عَلَيْهِ فَلَقِيتُهُ فَقَالَ حَدَّثَنِي قَرِيبٌ لِي يُقَالُ لَهُ أَنَسُ بْنُ مَالِكٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِبِلٍ كَانَتْ لِي أُخِذَتْ فَوَافَقْتُهُ وَهُوَ يَأْكُلُ فَدَعَانِي إِلَى طَعَامِهِ فَقُلْتُ إِنِّي صَائِمٌ فَقَالَ ادْنُ أُخْبِرْكَ عَنْ ذَلِكَ إِنَّ اللَّهَ وَضَعَ عَنْ الْمُسَافِرِ الصَّوْمَ وَشَطْرَ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Abu Bakr bin 'Ali] dia berkata; telah menceritakan kepada kami [Suraij] dia berkata; telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Ayyub] dia berkata; telah menceritakan kepadaku [Abu Qilabah] tentang Hadits ini, kemudian dia berkata; 'Apakah kamu tahu [siapa yang membawakan Hadits] ini? Lalu ia menunjukannya, kemudian aku menemuinya, ia berkata; telah menceritakan kepadaku orang yang dekat denganku, yaitu [Anas bin Malik] dia berkata; \"Aku pernah menemui Rasulullah shallallahu 'alaihi wasallam dengan menaiki unta milikku, lalu aku mendapati beliau sedang makan, maka beliau mengajakku makan bersamanya. Aku berkata; \" aku sedang berpuasa.\" Lalu beliau bersabda: \"Kemarilah, kuberitahukan kepadamu tentang hal itu, Allah telah membebaskan puasa dan setengah shalat dari orang yang bepergian.\""},"2178":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ رَجُلٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَةٍ فَإِذَا هُوَ يَتَغَدَّى قَالَ هَلُمَّ إِلَى الْغَدَاءِ فَقُلْتُ إِنِّي صَائِمٌ قَالَ هَلُمَّ أُخْبِرْكَ عَنْ الصَّوْمِ إِنَّ اللَّهَ وَضَعَ عَنْ الْمُسَافِرِ نِصْفَ الصَّلَاةِ وَالصَّوْمَ وَرَخَّصَ لِلْحُبْلَى وَالْمُرْضِعِأَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي الْعَلَاءِ بْنِ الشِّخِّيرِ عَنْ رَجُلٍ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Khalid Al Hadza'] dari [Abu Qilabah] dari [seseorang], ia berkata: \"Aku pernah menemui Rasulullah shallallahu 'alaihi wasallam karena suatu kebutuhan, ternyata beliau sedang makan siang, beliau bersabda: \"Marilah makan siang.\" Maka aku berkata, \" aku sedang berpuasa.\" Beliau bersabda: \"Kemarilah, kuberitahukan kepadamu tentang puasa, Allah telah membebaskan setengah shalat dan puasa dari orang yang bepergian memberikan keringanan kepada wanita hamil yang sedang menyusui.\" Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Khalid Al Hadza'] dari [Abu Al 'Allaa'i bin As Syakhir] dari [seseorang] seperti itu juga."},"2179":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ هَانِئِ بْنِ الشِّخِّيرِ عَنْ رَجُلٍ مِنْ بَلْحَرِيشٍ عَنْ أَبِيهِ قَالَكُنْتُ مُسَافِرًا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا صَائِمٌ وَهُوَ يَأْكُلُ قَالَ هَلُمَّ قُلْتُ إِنِّي صَائِمٌ قَالَ تَعَالَ أَلَمْ تَعْلَمْ مَا وَضَعَ اللَّهُ عَنْ الْمُسَافِرِ قُلْتُ وَمَا وَضَعَ عَنْ الْمُسَافِرِ قَالَ الصَّوْمَ وَنِصْفَ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Hani' bin Asy Syikhkhir] dari seseorang yang berasal dari Balharisy, dari [Bapaknya] dia berkata: Aku pernah bepergian, lalu aku menemui Rasulullah shallallahu 'alaihi wasallam, dan -saat itu- aku sedang berpuasa, sedangkan beliau sedang makan. Beliau bersabda: \"Kemarilah.\" Aku berkata; \" aku sedang berpuasa.\" Beliau bersabda: \"Kemarilah, tidakkah kamu mengetahui apa yang telah Allah bebaskan dari orang yang bepergian?\" Aku berkata; \"Apa yang Allah bebaskan dari orang yang bepergian?\" beliau bersabda: \"Puasa dan shalat.\""},"2180":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ هَانِئِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ رَجُلٍ مِنْ بَلْحَرِيشٍ عَنْ أَبِيهِ قَالَكُنَّا نُسَافِرُ مَا شَاءَ اللَّهُ فَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَطْعَمُ فَقَالَ هَلُمَّ فَاطْعَمْ فَقُلْتُ إِنِّي صَائِمٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُحَدِّثُكُمْ عَنْ الصِّيَامِ إِنَّ اللَّهَ وَضَعَ عَنْ الْمُسَافِرِ الصَّوْمَ وَشَطْرَ الصَّلَاةِ","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Muhammad bin Sallam] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Hani' bin 'Abdullah bin Asy Syikhkhir] dari seorang lelaki yang berasal dari Balharisy, dari [bapaknya], dia berkata; \"Kami pernah bepergian sesuai yang dikehendaki Allah, lalu kami menemui Rasulullah shallallahu 'alaihi wasallam, dan -saat itu- beliau sedang makan. Maka beliau bersabda: \"Mari, makanlah.\" Aku berkata; \" aku sedang berpuasa.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kuceritakan kepada kalian tentang puasa, Allah telah membebaskan puasa dan setengah shalat bagi orang yang bepergian.\""},"2181":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْكَرِيمِ قَالَ حَدَّثَنَا سَهْلُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ هَانِئِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِيهِ قَالَكُنْتُ مُسَافِرًا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَأْكُلُ وَأَنَا صَائِمٌ فَقَالَ هَلُمَّ قُلْتُ إِنِّي صَائِمٌ قَالَ أَتَدْرِي مَا وَضَعَ اللَّهُ عَنْ الْمُسَافِرِ قُلْتُ وَمَا وَضَعَ اللَّهُ عَنْ الْمُسَافِرِ قَالَ الصَّوْمَ وَشَطْرَ الصَّلَاةِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin 'Abdul Karim] dia berkata; telah menceritakan kepada kami [Sahl bin Bakkar] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Hani' bin 'Abdullah bin Asy Syakhkhir] dari [bapaknya] dia berkata; \"Aku pernah bepergian, lalu aku menemui Nabi shallallahu 'alaihi wasallam dan -saat itu- beliau sedang makan dan aku sedang berpuasa. Beliau bersabda: \"Kemarilah.\" Aku berkata, \" aku sedang berpuasa.\" Beliau bertanya: \"Apakah kamu tahu apa yang Allah bebaskan dari orang yang bepergian?\" Aku bertanya; Apa yang telah Allah bebaskan bagi orang yang bebepergian? Beliau bersabda: \"Puasa dan setengah shalat.\""},"2182":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ مُوسَى هُوَ ابْنُ أَبِي عَائِشَةَ عَنْ غَيْلَانَ قَالَخَرَجْتُ مَعَ أَبِي قِلَابَةَ فِي سَفَرٍ فَقَرَّبَ طَعَامًا فَقُلْتُ إِنِّي صَائِمٌ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فِي سَفَرٍ فَقَرَّبَ طَعَامًا فَقَالَ لِرَجُلٍ ادْنُ فَاطْعَمْ قَالَ إِنِّي صَائِمٌ قَالَ إِنَّ اللَّهَ وَضَعَ عَنْ الْمُسَافِرِ نِصْفَ الصَّلَاةِ وَالصِّيَامَ فِي السَّفَرِ فَادْنُ فَاطْعَمْ فَدَنَوْتُ فَطَعِمْتُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dia berkata; telah memberitakan kepada kami [Israil] dari [Musa bin Abu 'Aisyah] dari [Ghailan] dia berkata; \"Aku pernah keluar bersama [Abu Qilabah] dalam suatu perjalanan, lalu ia menyuguhkan makanan, kemudian aku berkata; \" aku berpuasa.\" Ia berkata; \" Rasulullah shallallahu 'alaihi wasallam pernah berangkat dalam suatu perjalanan, lalu menyuguhkan makanan seraya berkata kepada seseorang: \"Mari, makanlah.\" Orang itu berkata; \" Aku sedang berpuasa.\" Beliau bersabda: \"Allah telah membebaskan setengah shalat dan puasa dalam perjalanan, dari orang yang sedang bepergian, maka kemari dan makanlah.\" Lalu aku mendekat dan makan.\""},"2183":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ مُوَرِّقٍ الْعِجْلِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السَّفَرِ فَمِنَّا الصَّائِمُ وَمِنَّا الْمُفْطِرُ فَنَزَلْنَا فِي يَوْمٍ حَارٍّ وَاتَّخَذْنَا ظِلَالًا فَسَقَطَ الصُّوَّامُ وَقَامَ الْمُفْطِرُونَ فَسَقَوْا الرِّكَابَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَهَبَ الْمُفْطِرُونَ الْيَوْمَ بِالْأَجْرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dia berkata; telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Muwarriq Al 'Ijli] dari [Anas bin Malik] dia berkata; \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, di antara kami ada yang berpuasa dan ada yang berbuka. Lalu kami singgah di hari yang panas dan kami membuat tempat untuk berteduh, orang-orang yang berpuasa tidak dapat melakukan aktivitas, sedangkan orang-orang yang berbuka mereka dapat melakukannya, lalu mereka memberi minum hewan tunggangannya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang yang berbuka pada hari ini telah pergi dengan membawa pahala.\""},"2184":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ أَبَانَ الْبَلْخِيُّ قَالَ حَدَّثَنَا مَعْنٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَيُقَالُ الصِّيَامُ فِي السَّفَرِ كَالْإِفْطَارِ فِي الْحَضَرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Aban Al Balkhi] dia berkata; telah menceritakan kepada kami [Ma'n] dari [Ibnu Abu Dzi'b] dari [Az Zuhri] dari [Abu Salamah bin 'Abdurrahman] dari ['Abdurrahman bin 'Auf] dia berkata; \"Dikatakan bahwa puasa pada waktu safar seperti halnya berbuka pada waktu mukim (tidak bersafar).\""},"2185":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ أَيُّوبَ قَالَ حَدَّثَنَا حَمَّادُ الْخَيَّاطِ وَأَبُو عَامِرٍ قَالَا حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَالصَّائِمُ فِي السَّفَرِ كَالْمُفْطِرِ فِي الْحَضَرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Ayyub] dia berkata; telah menceritakan kepada kami [Hammad Al Khayyath] dan [Abu 'Amir] mereka berkata; telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az Zuhri] dari [Abu Salamah] dari ['Abdurrahman bin 'Auf] dia berkata; \"Orang yang berpuasa pada waktu safar seperti halnya orang yang berbuka pada waktu mukim (tidak bersafar).\""},"2186":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ أَيُّوبَ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِيهِ قَالَالصَّائِمُ فِي السَّفَرِ كَالْمُفْطِرِ فِي الْحَضَرِ","id":"Telah mengabarkan kepadaku [Muhammad bin Yahya bin Ayyub] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dia berkata; telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az Zuhri] dari [Humaid bin 'Abdurrahman bin 'Auf] dari [Bapaknya] dia berkata; \"Orang yang berpuasa pada waktu safar seperti halnya orang yang berbuka pada waktu mukim (tidak bersafar).\""},"2187":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا سُوَيْدٌ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فِي رَمَضَانَ فَصَامَ حَتَّى أَتَى قُدَيْدًا ثُمَّ أُتِيَ بِقَدَحٍ مِنْ لَبَنٍ فَشَرِبَ وَأَفْطَرَ هُوَ وَأَصْحَابُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] dia berkata; telah memberitakan kepada kami [Suwaid] dia berkata; telah mengabarkan kepada kami ['Abdullah] dari [Syu'bah] dari [Al Hakam] dari [Miqsam] dari [Ibnu 'Abbas], bahwa Nabi shallallahu 'alaihi wasallam keluar pada -bulan- Ramadlan, lalu beliau berpuasa hingga sampai di Qudaid, kemudian diberi segelas susu, lalu meminumnya. Maka beliau dan para sahabatnya berbuka."},"2188":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا عَبْثَرٌ عَنْ الْعَلَاءِ بْنِ الْمُسَيَّبِ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَصَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ حَتَّى أَتَى قُدَيْدًا ثُمَّ أَفْطَرَ حَتَّى أَتَى مَكَّةَ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakaria] dia berkata; telah menceritakan kepada kami [Sa'id bin 'Amr] dia berkata; telah menceritakan kepada kami ['Abtsar] dari [Al 'Ala bin Al Musayyab] dari [Al Hakam bin 'Utaibah] dari [Mujahid] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam berpuasa sejak dari Madinah hingga ke Qudaid, kemudian berbuka hingga sampai di Makkah.\""},"2189":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ أَنْبَأَنَا الْحَسَنُ بْنُ عِيسَى قَالَ أَنْبَأَنَا ابْنُ الْمُبَارَكِ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَامَ فِي السَّفَرِ حَتَّى أَتَى قُدَيْدًا ثُمَّ دَعَا بِقَدَحٍ مِنْ لَبَنٍ فَشَرِبَ فَأَفْطَرَ هُوَ وَأَصْحَابُهُ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah memberitakan kepada kami [Al Hasan bin 'Isa] dia berkata; telah memberitakan kepada kami [Ibnul Mubarak] dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Al Hakam] dari [Miqsam] dari [Ibnu 'Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam berpuasa dalam perjalanan hingga sampai Qudaid, kemudian beliau meminta segelas susu, lalu meminumnya, maka beliau dan para sahabatnya berbuka.\""},"2190":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَكَّةَ فَصَامَ حَتَّى أَتَى عُسْفَانَ فَدَعَا بِقَدَحٍ فَشَرِبَ قَالَ شُعْبَةُ فِي رَمَضَانَفَكَانَ ابْنُ عَبَّاسٍ يَقُولُ مَنْ شَاءَ صَامَ وَمَنْ شَاءَ أَفْطَرَ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Manshur] dari [Mujahid] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah keluar ke Makkah, lalu beliau berpuasa hingga sampai Usfan, kemudian beliau meminta segelas susu dan meminumnya pada -bulan- Ramadlan. Ibnu Abbas berkata; \"Barangsiapa yang ingih (berpuasa), boleh berpuasa dan barangsiapa yang ingin (berbuka), boleh berbuka.\""},"2191":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَسَافَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ فَصَامَ حَتَّى بَلَغَ عُسْفَانَ ثُمَّ دَعَا بِإِنَاءٍ فَشَرِبَ نَهَارًا يَرَاهُ النَّاسُ ثُمَّ أَفْطَرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dari [Jarir] dari [Manshur] dari [Mujahid] dari [Thawus] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bepergian pada -bulan- Ramadlan, lalu ia berpuasa hingga sampai Usfan, kemudian meminta segelas (susu) lalu meminum di siang hari yang dilihat oleh orang banyak, kemudian berbuka.\""},"2192":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْعَوَّامِ بْنِ حَوْشَبٍ قَالَ قُلْتُ لِمُجَاهِدٍالصَّوْمُ فِي السَّفَرِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ وَيُفْطِرُ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Al 'Awwam bin Hausyab] dia berkata; \"Aku bertanya kepada [Mujahid], \"Tentang berpuasa dalam bepergian?\" ia menjawab; \"Rasulullah shallallahu 'alaihi wasallam berpuasa dan berbuka.\""},"2193":{"ar":"أَخْبَرَنِي هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا حُسَيْنٌ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ قَالَ أَخْبَرَنِي مُجَاهِدٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَامَ فِي شَهْرِ رَمَضَانَ وَأَفْطَرَ فِي السَّفَرِ","id":"Telah mengabarkan kepadaku [Hilal bin Al 'Ala] dia berkata; telah menceritakan kepada kami [Husain] dia berkata; telah menceritakan kepada kami [Zuhair] dia berkata; telah menceritakan kepada kami [Abu Ishaq] dia berkata; telah mengabarkan kepadaku [Mujahid] bahwa Rasulullah shallallahu 'alaihi wasallam berpuasa di bulan Ramadlan dan berbuka dalam perjalanan.\""},"2194":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا أَزْهَرُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ حَمْزَةَ بْنِ عَمْرٍو الْأَسْلَمِيِّأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فِي السَّفَرِ قَالَ إِنْ ثُمَّ ذَكَرَ كَلِمَةً مَعْنَاهَا إِنْ شِئْتَ صُمْتَ وَإِنْ شِئْتَ أَفْطَرْتَأَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ بُكَيْرٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ أَنَّ حَمْزَةَ بْنَ عَمْرٍو قَالَ يَا رَسُولَ اللَّهِ مِثْلَهُ مُرْسَلٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Azhar bin Al Qasim] dia berkata; telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Sulaiman bin Yasar] dari [Hamzah bin 'Amru Al Aslami], bahwa ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang puasa dalam perjalanan? Beliau bersabda: \"Jika -kemudian beliau menyebutkan kalimat yang artinya- engkau ingin berpuasa, boleh berpuasa dan jika engkau ingin berbuka, boleh berbuka.\" Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al Laits] dari [Bukair] dari [Sulaiman bin Yasar] bahwa [Hamzah bin Amru] berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam... seperti Hadits diatas secara mursal.\" "},"2195":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ حَمْزَةَ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فِي السَّفَرِ قَالَ إِنْ شِئْتَ أَنْ تَصُومَ فَصُمْ وَإِنْ شِئْتَ أَنْ تُفْطِرَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari ['Abdul Hamid bin Ja'far] dari ['Imran bin Abu Ansa] dari [Sulaiman bin Yasar] dari [Hamzah] dia berkata; \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang puasa dalam perjalanan, beliau bersabda: \"Jika engkau ingin berpuasa, maka berpuasalah dan jika engkau ingin berbuka, maka berbukalah.\""},"2196":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا أَبُو بَكْرٍ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ حَمْزَةَ بْنِ عَمْرٍو قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فِي السَّفَرِ فَقَالَ إِنْ شِئْتَ أَنْ تَصُومَ فَصُمْ وَإِنْ شِئْتَ أَنْ تُفْطِرَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Abu Bakr] dia berkata; telah menceritakan kepada kami ['Abdul Hamid bin Ja'far] dari ['Imran bin Abu Anas] dari [Sulaiman bin Yasar] dari [Hamzah bin 'Amr] dia berkata; \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang puasa dalam perjalanan? Beliau bersabda: 'Jika engkau ingin berpuasa, berpuasalah dan jika engkau ingin berbuka, berbukalah'.\""},"2197":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ وَاللَّيْثُ فَذَكَرَ آخَرَ عَنْ بُكَيْرٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ حَمْزَةَ بْنِ عَمْرٍو الْأَسْلَمِيِّ قَالَيَا رَسُولَ اللَّهِ إِنِّي أَجِدُ قُوَّةً عَلَى الصِّيَامِ فِي السَّفَرِ قَالَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku ['Amr bin Al Harits] dan [Al Laits] kemudian dia menyebutkan yang selainnya, dari [Bukair] dari [Sulaiman bin Yasar] dari [Hamzah bin 'Amru Al Aslami] dia berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, sungguh aku mampu untuk puasa dalam perjalanan.\" Beliau bersabda: \"Jika engkau ingin berpuasa, berpuasalah dan jika engkau ingin berbuka, berbukalah.\""},"2198":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ أَنْبَأَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي عِمْرَانُ بْنُ أَبِي أَنَسٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَمْزَةَ بْنِ عَمْرٍوأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فِي السَّفَرِ قَالَ إِنْ شِئْتَ أَنْ تَصُومَ فَصُمْ وَإِنْ شِئْتَ أَنْ تُفْطِرَ فَأَفْطِرْ","id":"Telah mengabarkan kepadaku [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Muhammad bin Bakr] dia berkata; telah memberitakan kepada kami ['Abdul Hamid bin Ja'far] dia berkata; telah mengabarkan kepadaku ['Imran bin Abu Anas] dari [Abu Salamah bin 'Abdurrahman] dari [Hamzah bin 'Amru] bahwa ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang puasa dalam perjalanan? Beliau bersabda: \"Jika engkau ingin berpuasa, berpuasalah dan jika engkau ingin berbuka, maka berbukalah.\""},"2199":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا مُحَمَّدٌ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ وَحَنْظَلَةَ بْنِ عَلِيٍّ قَالَ حَدَّثَانِي جَمِيعًا عَنْ حَمْزَةَ بْنِ عَمْرٍو قَالَكُنْتُ أَسْرُدُ الصِّيَامَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَسْرُدُ الصِّيَامَ فِي السَّفَرِ فَقَالَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami ['Imran bin Bakkar] dia berkata; telah menceritakan kepada kami [Ahmad bin Khalid] dia berkata; telah menceritakan kepada kami [Muhammad] dari ['Imran bin Abu Anas] dari [Sulaiman bin Yasar] dan [Hanzhalah bin 'Ali] dia berkata; keduanya telah menceritakan kepadaku dari [Hamzah bin 'Amru] dia berkata; \"Di masa Rasulullah shallallahu 'alaihi wasallam aku berpuasa terus-menerus. Lalu aku bertanya; \"Wahai Rasulullah shallallahu 'alaihi wasallam, aku puasa terus-menerus dalam perjalanan? Maka beliau bersabda: \"Jika engkau ingin berpuasa, maka berpuasalah dan jika engkau ingin berbuka, maka berbukalah.\""},"2200":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ حَنْظَلَةَ بْنِ عَلِيٍّ عَنْ حَمْزَةَ قَالَقُلْتُ يَا نَبِيَّ اللَّهِ إِنِّي رَجُلٌ أَسْرُدُ الصِّيَامَ أَفَأَصُومُ فِي السَّفَرِ قَالَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; [bapakku] telah menceritakan kepada kami, dari [Ibnu Ishaq] dari ['Imran bin Abu Anas] dari [Hanzhalah bin 'Ali] dari [Hamzah] dia berkata; Aku bertanya; \"Wahai Nabi Allah, aku sering berpuasa dalam perjalanan?\" Beliau bersabda: \"Jika engkau ingin berpuasa, maka berpuasalah dan jika engkau ingin berbuka, maka berbukalah.\""},"2201":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي عِمْرَانُ بْنُ أَبِي أَنَسٍ أَنَّ سُلَيْمَانَ بْنَ يَسَارٍ حَدَّثَهُ أَنَّ أَبَا مُرَاوِحٍ حَدَّثَهُ أَنَّ حَمْزَةَ بْنَ عَمْرٍو حَدَّثَهُأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَجُلًا يَصُومُ فِي السَّفَرِ فَقَالَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; [bapakku] telah menceritakan kepada kami, dari [Ibnu Ishaq] dia berkata; telah menceritakan kepadaku ['Imran bin Abu Anas] bahwasanya [Sulaiman bin Yasar] menceritakan kepadanya dari [Abu Murawih] dari [Hamzah bin 'Amru] bahwa ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam -ia adalah orang yang selalu berpuasa dalam perjalanan-, maka beliau bersabda: \"Jika engkau ingin berpuasa, maka berpuasalah dan jika engkau ingin berbuka, berbukalah.\""},"2202":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَنْبَأَنَا عَمْرٌو وَذَكَرَ آخَرَ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ أَبِي مُرَاوِحٍ عَنْ حَمْزَةَ بْنِ عَمْرٍوأَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجِدُ فِيَّ قُوَّةً عَلَى الصِّيَامِ فِي السَّفَرِ فَهَلْ عَلَيَّ جُنَاحٌ قَالَ هِيَ رُخْصَةٌ مِنْ اللَّهِ عَزَّ وَجَلَّ فَمَنْ أَخَذَ بِهَا فَحَسَنٌ وَمَنْ أَحَبَّ أَنْ يَصُومَ فَلَا جُنَاحَ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah memberitakan kepada kami ['Amru] -dan dia menyebutkan selainnya- dari [Abul Aswad] dari ['Urwah] dari [Abu Murawih] dari [Hamzah bin 'Amru] bahwa ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam; \"Aku mampu untuk berpuasa dalam perjalanan, apakah aku berdosa?\" Beliau bersabda: \"Itu adalah keringanan dari Allah -Azza Wa Jalla-, barangsiapa mengambilnya, itu baik dan barangsiapa ingin berpuasa, tidak ada dosa atas dirinya.\""},"2203":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ عَنْ مُحَمَّدِ بْنِ بِشْرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ حَمْزَةَ بْنِ عَمْرٍو الْأَسْلَمِيِّأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصُومُ فِي السَّفَرِ قَالَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dari [Muhammad bin Bisyr] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Hamzah bin 'Amru Al Aslami] bahwa ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam; \"Apakah aku boleh berpuasa dalam perjalanan? Beliau bersabda: \"Jika engkau ingin berpuasa, maka berpuasalah dan jika engkau ingin berbuka, berbukalah.\""},"2204":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ الْحَسَنِ اللَّانِيُّ بِالْكُوفَةِ قَالَ حَدَّثَنَا عَبْدُ الرَّحِيمِ الرَّازِيُّ عَنْ هِشَامٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ حَمْزَةَ بْنِ عَمْرٍو أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ أَصُومُ أَفَأَصُومُ فِي السَّفَرِ قَالَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami ['Ali bin Al Hasan Al Lani] -seorang dari Kufah- dia berkata; telah menceritakan kepada kami ['Abdurrahim Ar Razi] dari [Hisyam] dari ['Urwah] dari ['Aisyah] dari [Hamzah bin 'Amru] bahwasanya dia berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, aku sering berpuasa, apakah aku boleh berpuasa dalam perjalanan?\" Beliau bersabda: \"Jika engkau ingin berpuasa, berpuasalah dan jika engkau ingin berbuka, berbukalah.\""},"2205":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْإِنَّ حَمْزَةَ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ أَصُومُ فِي السَّفَرِ وَكَانَ كَثِيرَ الصِّيَامِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah memberitakan kepada kami [Ibnul Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] dia berkata; bahwasanya Hamzah bertanya kepada Rasulullah shallallahu 'alaihi wasallam: \"Wahai Rasulullah shallallahu 'alaihi wasallam, aku berpuasa dalam perjalanan -ia sering berpuasa-? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika engkau ingin berpuasa, berpuasalah dan jika engkau ingin berbuka, berbukalah.\""},"2206":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ هِشَامٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ عَجْلَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْإِنَّ حَمْزَةَ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَصُومُ فِي السَّفَرِ فَقَالَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah mengabarkan kepadali ['Amr bin Hisyam] dia berkata; telah menceritakan kepada kami [Muhammad bin Salamah] dari [Ibnu 'Ajlan] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] dia berkata; bahwasanya Hamzah pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, lalu ia berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, apakah aku boleh berpuasa dalam perjalanan?\" beliau bersabda: \"Jika engkau ingin berpuasa, a berpuasalah dan jika engkau ingin berbuka, berbukalah.\""},"2207":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدَةُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ حَمْزَةَ الْأَسْلَمِيَّ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فِي السَّفَرِ وَكَانَ رَجُلًا يَسْرُدُ الصِّيَامَ فَقَالَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdah bin Sulaiman] dia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] bahwasanya Hamzah Al Aslami pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang berpuasa dalam perjalanan -ia adalah orang yang sering berpuasa-. Maka beliau bersabda: \"Jika engkau ingin berpuasa, maka berpuasalah dan jika engkau ingin berbuka, maka berbukalah.\""},"2208":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ قَالَ حَدَّثَنَا أَبُو سَعِيدٍ قَالَكُنَّا نُسَافِرُ فِي رَمَضَانَ فَمِنَّا الصَّائِمُ وَمِنَّا الْمُفْطِرُ لَا يَعِيبُ الصَّائِمُ عَلَى الْمُفْطِرِ وَلَا يَعِيبُ الْمُفْطِرُ عَلَى الصَّائِمِ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dia berkata; telah menceritakan kepada kami [Hammad] dari [Sa'id Al Jurairi] dari [Abu Nadlrah] dia berkata; telah menceritakan kepada kami [Abu Sa'id] dia berkata; \"Kami pernah bepergian pada -bulan- Ramadlan, lalu di antara kami ada yang berpuasa dan ada yang berbuka, orang yang berpuasa tidak mencela orang yang berbuka dan orang yang berbuka tidak mencela orang yang berpuasa.\""},"2209":{"ar":"أَخْبَرَنَا سَعِيدُ بْنُ يَعْقُوبَ الطَّالْقَانِيُّ قَالَ حَدَّثَنَا خَالِدٌ وَهُوَ ابْنُ عَبْدِ اللَّهِ الْوَاسِطِيُّ عَنْ أَبِي مَسْلَمَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَكُنَّا نُسَافِرُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمِنَّا الصَّائِمُ وَمِنَّا الْمُفْطِرُ وَلَا يَعِيبُ الصَّائِمُ عَلَى الْمُفْطِرِ وَلَا يَعِيبُ الْمُفْطِرُ عَلَى الصَّائِمِ","id":"Telah mengabarkan kepada kami [Sa'id bin Ya'qub Ath Thalqani] dia berkata; telah menceritakan kepada kami [Khalid bin 'Abdullah Al Wasithi] dari [Abu Maslamah] dari [Abu Nadlrah] dari [Abu Sa'id] dia berkata; \"Kami pernah melakukan perjalanan bersama Nabi shallallahu 'alaihi wasallam, lalu di antara kami ada yang berpuasa dan ada yang tidak dan orang yang berpuasa tidak mencela orang yang tidak puasa.\""},"2210":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا الْقَوَارِيرِيُّ قَالَ حَدَّثَنَا بِشْرُ بْنُ مَنْصُورٍ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي نَضْرَةَ عَنْ جَابِرٍ قَالَسَافَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَامَ بَعْضُنَا وَأَفْطَرَ بَعْضُنَا","id":"Telah mengabarkan kepada kami [Abu Bakr bin 'Ali] dia berkata; telah menceritakan kepada kami [Al Qawariri] dia berkata; telah menceritakan kepada kami [Bisyr bin Manshur] dari ['Ashim Al Ahwal] dari [Abu Nadlrah] dari [Jabir] dia berkata; \"Kami pernah bepergian bersama Rasulullah shallallahu 'alaihi wasallam, lalu sebagian kami ada yang berpuasa dan ada yang tidak.\""},"2211":{"ar":"أَخْبَرَنِي أَيُّوبُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَرْوَانُ قَالَ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي نَضْرَةَ الْمُنْذِرِ عَنْ أَبِي سَعِيدٍ وَجَابِرِ بْنِ عَبْدِ اللَّهِأَنَّهُمَا سَافَرَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَصُومُ الصَّائِمُ وَيُفْطِرُ الْمُفْطِرُ وَلَا يَعِيبُ الصَّائِمُ عَلَى الْمُفْطِرِ وَلَا الْمُفْطِرُ عَلَى الصَّائِمِ","id":"Telah mengabarkan kepadaku [Ayyub bin Muhammad] dia berkata; telah menceritakan kepada kami [Marwan] dia berkata; telah menceritakan kepada kami ['Ashim] dari [Abu Nadlrah Al Mundzir] dari [Abu Sa'id] dan [Jabir bin 'Abdullah] bahwasanya keduanya bersama Rasulullah shallallahu 'alaihi wasallam, maka yang ingin berpuasa, berpuasa, dan yang ingin berbuka, berbuka. Orang yang berpuasa tidak mencela orang yang berbuka dan orang yang berbuka tidak mencela orang yang berpuasa.\""},"2212":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ صَائِمًا فِي رَمَضَانَ حَتَّى إِذَا كَانَ بِالْكَدِيدِ أَفْطَرَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah keluar pada tahun Fathu Makkah (pembukaan atas kota Makkah) dalam keadaan berpuasa pada -bulan- Ramadlan, hingga ketika sampai di Kadid, beliau berbuka.\""},"2213":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مُفَضَّلٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَسَافَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَامَ حَتَّى بَلَغَ عُسْفَانَ ثُمَّ دَعَا بِإِنَاءٍ فَشَرِبَ نَهَارًا لِيَرَاهُ النَّاسُ ثُمَّ أَفْطَرَ حَتَّى دَخَلَ مَكَّةَ فَافْتَتَحَ مَكَّةَ فِي رَمَضَانَ قَالَ ابْنُ عَبَّاسٍ فَصَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السَّفَرِ وَأَفْطَرَ فَمَنْ شَاءَ صَامَ وَمَنْ شَاءَ أَفْطَرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Mufadhdhal] dari [Manshur] dari [Mujahid] dari [Thawus] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah bepergian, dan berpuasa hingga sampai Usfan, kemudian meminta segelas -air- dan meminumnya di siang hari agar dilihat orang banyak, lalu beliau berbuka hingga sampai Makkah, kemudian menaklukan Makkah pada -bulan Ramadlan.\" Ibnu Abbas berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah berpuasa dalam perjalanan dan -pernah juga- berbuka, barangsiapa yang ingin berpuasa, boleh berpuasa dan barangsiapa yang ingin berbuka, boleh berbuka.\""},"2214":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ عَنْ وُهَيْبِ بْنِ خَالِدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَوَادَةَ الْقُشَيْرِيُّ عَنْ أَبِيهِ عَنْ أَنَسِ بْنِ مَالِكٍ رَجُلٌ مِنْهُمْأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ وَهُوَ يَتَغَدَّى فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلُمَّ إِلَى الْغَدَاءِ فَقَالَ إِنِّي صَائِمٌ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ وَضَعَ لِلْمُسَافِرِ الصَّوْمَ وَشَطْرَ الصَّلَاةِ وَعَنْ الْحُبْلَى وَالْمُرْضِعِ","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] dia berkata; telah menceritakan kepada kami [Muslim bin Ibrahim] dari [Wuhaib bin Khalid] dia berkata; telah menceritakan kepada kami ['Abdullah bin Suwadah Al Qusyairi] dari [Bapaknya] dari [Anas bin Malik] -salah seorang dari mereka- ia datang menemui Nabi shallallahu 'alaihi wasallam di Madinah, saat beliau sedang makan siang, lalu Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Marilah, makan siang.\" Lalu ia berkata; \"Aku sedang berpuasa.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \" Allah -Azza wa Jalla- membebaskan berpuasa dan setengah shalat dari orang yang bepergian dan dari wanita yang sedang hamil dan yang menyusui.\""},"2215":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ أَنْبَأَنَا بَكْرٌ وَهُوَ ابْنُ مُضَرَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرٍ عَنْ يَزِيدَ مَوْلَى سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَعَلَى الَّذِينَ يُطِيقُونَهُ فِدْيَةٌ طَعَامُ مِسْكِينٍ }كَانَ مَنْ أَرَادَ مِنَّا أَنْ يُفْطِرَ وَيَفْتَدِيَ حَتَّى نَزَلَتْ الْآيَةُ الَّتِي بَعْدَهَا فَنَسَخَتْهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah memberitakan kepada kami [Bakr bin Mudlar] dari ['Amru bin Al Harits] dari [Bukair] dari [Yazid] -budak Salamah bin Al Akwa'- dari [Salamah bin Al Akwa'] dia berkata; \"Ketika ayat ini turun \"Dan wajib bagi orang-orang yang berat menjalankannya (jika mereka tidak puasa) membayar fidyah, (yaitu): memberi makan seorang miskin \" di antara kami ada yang ingin berbuka dan membayar fidyah, hingga turun ayat selanjutnya, lalu ayat tersebut menghapusnya.\""},"2216":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا وَرْقَاءُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَعَلَى الَّذِينَ يُطِيقُونَهُ فِدْيَةٌ طَعَامُ مِسْكِينٍ }يُطِيقُونَهُ يُكَلَّفُونَهُ فِدْيَةٌ طَعَامُ مِسْكِينٍ وَاحِدٍ{ فَمَنْ تَطَوَّعَ خَيْرًا }طَعَامُ مِسْكِينٍ آخَرَ لَيْسَتْ بِمَنْسُوخَةٍ{ فَهُوَ خَيْرٌ لَهُ وَأَنْ تَصُومُوا خَيْرٌ لَكُمْ }لَا يُرَخَّصُ فِي هَذَا إِلَّا لِلَّذِي لَا يُطِيقُ الصِّيَامَ أَوْ مَرِيضٍ لَا يُشْفَى","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yazid] dia berkata; telah memberitakan kepada kami [Warqa'] dari ['Amr bin Dinar] dari ['Atha] dari [Ibnu 'Abbas] tentang firman Allah Azza wa Jalla: \"Dan wajib bagi orang-orang yang berat menjalankannya (jika mereka tidak berpuasa) membayar fidyah, (yaitu): memberi makan seorang miskin.\" Berat menjalankannya artinya: dibebani membayar fidyah, memberi makan satu orang miskin.\"Barangsiapa yang dengan kerelaan mengerjakan kebajikan.\" Memberi makan seorang miskin yang lain, bukanlah ayat yang mansukh, \"tapi itulah yang baik baginya. Dan berpuasa lebih baik bagimu\" dalam hal ini tidak diberikan keringanan kecuali bagi orang yang tidak mampu berpuasa atau sakit yang tidak diharapkan sembuhnya.\""},"2217":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا عَلِيٌّ يَعْنِي ابْنَ مُسْهِرٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ مُعَاذَةَ الْعَدَوِيَّةِأَنَّ امْرَأَةً سَأَلَتْ عَائِشَةَ أَتَقْضِي الْحَائِضُ الصَّلَاةَ إِذَا طَهُرَتْ قَالَتْ أَحَرُورِيَّةٌ أَنْتِ كُنَّا نَحِيضُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ نَطْهُرُ فَيَأْمُرُنَا بِقَضَاءِ الصَّوْمِ وَلَا يَأْمُرُنَا بِقَضَاءِ الصَّلَاةِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami ['Ali bin Mushir] dari [Sa'id] dari [Qatadah] dari [Mu'adzah Al 'Adawiyyah] bahwasanya seorang wanita bertanya kepada ['Aisyah], \"Apakah seorang wanita yang haidl boleh mengqadla shalat jika telah suci?\" Aisyah berkata; \"Apakah kamu berpaham Haruriyah (golongan Khawarij)? Kami pernah mengalami haidl pada masa Rasulullah shallallahu 'alaihi wasallam, setelah suci, beliau menyuruh kami untuk mengganti puasa dan tidak menyuruh kami untuk mengqadla shalat.\" "},"2218":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ يُحَدِّثُ عَنْ عَائِشَةَ قَالَتْإِنْ كَانَ لَيَكُونُ عَلَيَّ الصِّيَامُ مِنْ رَمَضَانَ فَمَا أَقْضِيهِ حَتَّى يَجِيءَ شَعْبَانُ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; Aku mendengar [Abu Salamah] menceritakan dari ['Aisyah] dia berkata; \"Jika saya harus melaksanakan puasa Ramadlan, maka saya tidak mengqadlanya hingga datang -bulan- Sya'ban.\""},"2219":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ عَبْدِ اللَّهِ بْنِ يُونُسَ أَبُو حَصِينٍ قَالَ حَدَّثَنَا عَبْثَرٌ قَالَ حَدَّثَنَا حُصَيْنٌ عَنْ الشَّعْبِيِّ عَنْ مُحَمَّدِ بْنِ صَيْفِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَاشُورَاءَ أَمِنْكُمْ أَحَدٌ أَكَلَ الْيَوْمَ فَقَالُوا مِنَّا مَنْ صَامَ وَمِنَّا مَنْ لَمْ يَصُمْ قَالَ فَأَتِمُّوا بَقِيَّةَ يَوْمِكُمْ وَابْعَثُوا إِلَى أَهْلِ الْعَرُوضِ فَلْيُتِمُّوا بَقِيَّةَ يَوْمِهِمْ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Ahmad bin 'Abdullah bin Yunus Abu Hashin] dia berkata; telah menceritakan kepada kami ['Abtsar] dia berkata; telah menceritakan kepada kami [Hushain] dari [Asy Sya'bi] dari [Muhammad bin Shaifi] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda pada hari Asyura: \"Apakah ada salah seorang di antara kalian yang makan pada hari ini?\" Mereka menjawab; \"Di antara kami ada yang berpuasa dan ada yang tidak berpuasa.\" Beliau bersabda: \"Maka sempurnakanlah waktu yang tersisa dari hari kalian ini dan pergilah kepada penduduk (Makkah dan Madinah serta sekitarnya) hendaklah mereka menyempurnakan waktu yang masih tersisa dari hari mereka.\""},"2220":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى عَنْ يَزِيدَ قَالَ حَدَّثَنَا سَلَمَةُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ أَذِّنْ يَوْمَ عَاشُورَاءَ مَنْ كَانَ أَكَلَ فَلْيُتِمَّ بَقِيَّةَ يَوْمِهِ وَمَنْ لَمْ يَكُنْ أَكَلَ فَلْيَصُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Yahya] dari [Yazid] dia berkata; telah menceritakan kepada kami [Salamah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada seseorang: \"Beritahukanlah dengan -adanya- hari Asyura: Barangsiapa yang makan, maka hendaklah ia menyempurnakan waktu yang masih tersisa dari harinya dan barangsiapa yang belum makan, hendaklah ia berpuasa.\""},"2221":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَاصِمُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ طَلْحَةَ بْنِ يَحْيَى بْنِ طَلْحَةَ عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَقَالَ هَلْ عِنْدَكُمْ شَيْءٌ فَقُلْتُ لَا قَالَ فَإِنِّي صَائِمٌ ثُمَّ مَرَّ بِي بَعْدَ ذَلِكَ الْيَوْمِ وَقَدْ أُهْدِيَ إِلَيَّ حَيْسٌ فَخَبَأْتُ لَهُ مِنْهُ وَكَانَ يُحِبُّ الْحَيْسَ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّهُ أُهْدِيَ لَنَا حَيْسٌ فَخَبَأْتُ لَكَ مِنْهُ قَالَ أَدْنِيهِ أَمَا إِنِّي قَدْ أَصْبَحْتُ وَأَنَا صَائِمٌ فَأَكَلَ مِنْهُ ثُمَّ قَالَ إِنَّمَا مَثَلُ صَوْمِ الْمُتَطَوِّعِ مَثَلُ الرَّجُلِ يُخْرِجُ مِنْ مَالِهِ الصَّدَقَةَ فَإِنْ شَاءَ أَمْضَاهَا وَإِنْ شَاءَ حَبَسَهَا","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dia berkata; telah menceritakan kepada kami ['Ashim bin Yusuf] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Thalhah bin Yahya bin Thalhah] dari [Mujahid] dari ['Aisyah] dia berkata; \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam masuk menemuiku lalu bersabda: \"Apakah kamu memiliki sesuatu?\" Aku menjawab; \"Tidak.\" Beliau bersabda: \" Maka aku berpuasa.\" Kemudian beliau menemuiku lagi setelah hari itu dan telah dihadiahkan hais (makanan yang terbuat dari kurma) untukku, maka kusimpan makanan itu untuk beliau-padahal beliau menyukai hais-. Ia berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, kita diberi hadiah hais, lalu kusimpan makanan itu untukmu.\" Beliau bersabda: \"Bawalah kemari, pagi tadi aku berniat untuk berpuasa.\" Lalu beliau memakannya, kemudian bersabda: ', perumpamaan puasa sunnah seperti seorang yang mengeluarkan hartanya untuk bersedekah, jika ia ingin bersedekah, maka boleh menyedekahkannya dan jika ia ingin manahannya, boleh menahannya.'"},"2222":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَزِيدُ أَنْبَأَنَا شَرِيكٌ عَنْ طَلْحَةَ بْنِ يَحْيَى بْنِ طَلْحَةَ عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ قَالَتْدَارَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَوْرَةً قَالَ أَعِنْدَكِ شَيْءٌ قَالَتْ لَيْسَ عِنْدِي شَيْءٌ قَالَ فَأَنَا صَائِمٌ قَالَتْ ثُمَّ دَارَ عَلَيَّ الثَّانِيَةَ وَقَدْ أُهْدِيَ لَنَا حَيْسٌ فَجِئْتُ بِهِ فَأَكَلَ فَعَجِبْتُ مِنْهُ فَقُلْتُ يَا رَسُولَ اللَّهِ دَخَلْتَ عَلَيَّ وَأَنْتَ صَائِمٌ ثُمَّ أَكَلْتَ حَيْسًا قَالَ نَعَمْ يَا عَائِشَةُ إِنَّمَا مَنْزِلَةُ مَنْ صَامَ فِي غَيْرِ رَمَضَانَ أَوْ غَيْرِ قَضَاءِ رَمَضَانَ أَوْ فِي التَّطَوُّعِ بِمَنْزِلَةِ رَجُلٍ أَخْرَجَ صَدَقَةَ مَالِهِ فَجَادَ مِنْهَا بِمَا شَاءَ فَأَمْضَاهُ وَبَخِلَ مِنْهَا بِمَا بَقِيَ فَأَمْسَكَهُ","id":"Telah mengabarkan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Yazid]; telah memberitakan kepada kami [Syarik] dari [Thalhah bin Yahya bin Thalhah] dari [Mujahid] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah memeriksaku (bertanya kepadaku) sekali, beliau bersabda: \"Apakah kamu memiliki sesuatu?\" Ia menjawab; \"Aku tidak memiliki sesuatu pun.\" Beliau bersabda: \"Maka aku berpuasa.\" Ia berkata, \"Kemudian beliau memeriksaku (bertanya kepadaku) untuk kedua kalinya, dan telah dihadiahkan hais (makanan yang terbuat dari korma) untuk kami, lalu aku datang dengan membawa makanan tersebut, kemudian beliau memakannya, maka aku heran karenanya! Aku bertanya; \"Wahai Rasulullah shallallahu 'alaihi wasallam, engkau masuk menemuiku dalam keadaan berpuasa, kemudian engkau makan hais?\" beliau bersabda: \"Ya, wahai Aisyah, kedudukan orang yang berpuasa selain Ramadlan atau selain mengqadha puasa Ramadlan, atau puasa sunnah, seperti seorang yang mengeluarkan sedekah hartanya, lalu ia menjadi orang yang dermawan dengan keinginannya, lalu ia meneruskannya dan menjadi kikir dengan -sesuatu- yang masih tersisa, lalu ia menahannya.\""},"2223":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْهَيْثَمِ قَالَ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجِيءُ وَيَقُولُ هَلْ عِنْدَكُمْ غَدَاءٌ فَنَقُولُ لَا فَيَقُولُ إِنِّي صَائِمٌ فَأَتَانَا يَوْمًا وَقَدْ أُهْدِيَ لَنَا حَيْسٌ فَقَالَ هَلْ عِنْدَكُمْ شَيْءٌ قُلْنَا نَعَمْ أُهْدِيَ لَنَا حَيْسٌ قَالَ أَمَا إِنِّي قَدْ أَصْبَحْتُ أُرِيدُ الصَّوْمَ فَأَكَلَخَالَفَهُ قَاسِمُ بْنُ يَزِيدَ","id":"Telah mengabarkan kepada kami ['Abdullah bin Al Haitsam] dia berkata; telah menceritakan kepada kami [Abu Bakr Al Hanafi] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Thalhah bin Yahya] dari [Mujahid] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah datang seraya bertanya: \"Apakah kamu memiliki makanan?\" Kami menjawab; \"Tidak.\" Beliau bersabda: \" aku berpuasa.\" Lalu pada suatu hari beliau datang menemui kami dan telah dihadiahkan hais untuk kami, lalu beliau bertanya: \"Apakah kamu memiliki sesuatu?\" Kami menjawab; \"Ya, telah dihadiahkan hais untuk kami.\" Beliau bersabda: \" pagi tadi aku berniat untuk berpuasa.\" Lalu beliau makan.\" Qasim bin Yazid menyelisihinya."},"2224":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا قَاسِمٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ عَائِشَةَ بِنْتِ طَلْحَةَ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ قَالَتْأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَقُلْنَا أُهْدِيَ لَنَا حَيْسٌ قَدْ جَعَلْنَا لَكَ مِنْهُ نَصِيبًا فَقَالَ إِنِّي صَائِمٌ فَأَفْطَرَ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] dia berkata; telah menceritakan kepada kami [Qasim] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Thalhah bin Yahya] dari ['Aisyah binti Thalhah] dari ['Aisyah] dia berkata; Pada suatu hari Rasulullah shallallahu 'alaihi wasallam datang menemui kami, lalu kami berkata; \"Telah dihadiahkan hais untuk kami, dan kami sisakan sebagian untuk engkau.\" Maka beliau bersabda: \" aku sedang berpuasa.\" Lalu beliau berbuka.\""},"2225":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا طَلْحَةُ بْنُ يَحْيَى قَالَ حَدَّثَتْنِي عَائِشَةُ بِنْتُ طَلْحَةَ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْتِيهَا وَهُوَ صَائِمٌ فَقَالَ أَصْبَحَ عِنْدَكُمْ شَيْءٌ تُطْعِمِينِيهِ فَنَقُولُ لَا فَيَقُولُ إِنِّي صَائِمٌ ثُمَّ جَاءَهَا بَعْدَ ذَلِكَ فَقَالَتْ أُهْدِيَتْ لَنَا هَدِيَّةٌ فَقَالَ مَا هِيَ قَالَتْ حَيْسٌ قَالَ قَدْ أَصْبَحْتُ صَائِمًا فَأَكَلَ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Thalhah bin Yahya] dia berkata; telah menceritakan kepadaku ['Aisyah bintu Thalhah] dari ['Aisyah] -Ummul Mukminin-, bahwa Nabi shallallahu 'alaihi wasallam datang menemuinya, saat itu beliau sedang berpuasa, lalu bersabda: \"Pagi ini apakah kamu memiliki sesuatu yang dengannya kamu memberiku makan?\" Ia manjawab; \"Tidak.\" Beliau bersabda: \" aku berpuasa.\" Setelah itu beliau datang lagi menemui Aisyah, lalu Aisyah berkata; \"Sesuatu telah dihadiahkan kepada kita.\" Beliau bertanya: \"Apa itu?\" Ia menjawab; \"Hais.\" Beliau bersabda: \"Pagi tadi aku berniat untuk berpuasa.\" Lalu beliau makan.\""},"2226":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنَا طَلْحَةُ بْنُ يَحْيَى عَنْ عَمَّتِهِ عَائِشَةَ بِنْتِ طَلْحَةَ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ فَقَالَ هَلْ عِنْدَكُمْ شَيْءٌ قُلْنَا لَا قَالَ فَإِنِّي صَائِمٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Thalhah bin Yahya] dari ['Aisyah bintu Thalhah] dari ['Aisyah] Ummul Mukminin, dia berkata: Pada suatu hari Rasulullah shallallahu 'alaihi wasallam masuk menemuiku lalu bersabda: \"Apakah kamu memiliki sesuatu?\" Kami menjawab, \"Tidak.\" Beliau bersabda: \"Maka aku berpuasa.\""},"2227":{"ar":"أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ أَخْبَرَنِي أَبِي عَنْ الْقَاسِمِ بْنِ مَعْنٍ عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ عَائِشَةَ بِنْتِ طَلْحَةَ وَمُجَاهِدٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاهَا فَقَالَ هَلْ عِنْدَكُمْ طَعَامٌ فَقُلْتُ لَا قَالَ إِنِّي صَائِمٌ ثُمَّ جَاءَ يَوْمًا آخَرَ فَقَالَتْ عَائِشَةُ يَا رَسُولَ اللَّهِ إِنَّا قَدْ أُهْدِيَ لَنَا حَيْسٌ فَدَعَا بِهِ فَقَالَ أَمَا إِنِّي قَدْ أَصْبَحْتُ صَائِمًا فَأَكَلَأَخْبَرَنِي عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا الْمُعَافَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا الْقَاسِمُ عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ مُجَاهِدٍ وَأُمِّ كُلْثُومٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى عَائِشَةَ فَقَالَ هَلْ عِنْدَكُمْ طَعَامٌ نَحْوَهُ قَالَ أَبُو عَبْد الرَّحْمَنِ وَقَدْ رَوَاهُ سِمَاكُ بْنُ حَرْبٍ قَالَ حَدَّثَنِي رَجُلٌ عَنْ عَائِشَةَ بِنْتِ طَلْحَةَ","id":"Telah mengabarkan kepadaku [Abu Bakr bin 'Ali] dia berkata; telah menceritakan kepada kami [Nashr bin 'Ali] dia berkata; [bapakku] telah mengabarkan kepadaku dari [Al Qasim bin Ma'n] dari [Thalhah bin Yahya] dari ['Aisyah bintu Thalhah] dan [Mujahid] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam datang menemuinya lalu bersabda: \"Apakah kalian memiliki makanan?\" Aku menjawab, \"Tidak.\" Beliau bersabda: ' aku berpuasa.' Kemudian di hari yang lain beliau datang menemuinya, lalu Aisyah berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, telah dihadiahkan hais untuk kita, maka beliau memintanya dan bersabda: \" pagi tadi aku berniat untuk berpuasa.\" Lalu beliau makan.\" Telah mengabarkan kepadaku ['Amru bin Yahya bin Al Harits] dia berkata; Telah menceritakan kepadaku [Al Mu'afa bin Sulaiman] dia berkata; telah menceritakan kepada kami [Al Qasim] dari [Thalhah bin Yahya] dari [Mujahid] dari [Ummu Kultsum] bahwa Rasulullah shallallahu 'alaihi wasallam menemui Aisyah beliau berkata: 'Apakah kamu memiliki makanan?, -seperti Hadist diatas-. Abu Abdurrahman berkata; dan Simak bin Harb telah meriwayatkannya dia berkata; Telah menceritakan kepadaku seorang laki-laki, dari Aisyah binti Thalhah. "},"2228":{"ar":"أَخْبَرَنِي صَفْوَانُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكِ بْنِ حَرْبٍ قَالَ حَدَّثَنِي رَجُلٌ عَنْ عَائِشَةَ بِنْتِ طَلْحَةَ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ قَالَتْجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَقَالَ هَلْ عِنْدَكُمْ مِنْ طَعَامٍ قُلْتُ لَا قَالَ إِذًا أَصُومُ قَالَتْ وَدَخَلَ عَلَيَّ مَرَّةً أُخْرَى فَقُلْتُ يَا رَسُولَ اللَّهِ قَدْ أُهْدِيَ لَنَا حَيْسٌ فَقَالَ إِذًا أُفْطِرُ الْيَوْمَ وَقَدْ فَرَضْتُ الصَّوْمَ","id":"Telah mengabarkan kepadaku [Shafwan bin 'Amr] dia berkata; telah menceritakan kepada kami [Ahmad bin Khalid] dia berkata; telah menceritakan kepada kami [Israil] dari [Simak bin Harb] dia berkata; telah menceritakan kepadaku [seorang lelaki] dari ['Aisyah bintu Thalhah] dari ['Aisyah] -Ummul Mukminin-, dia berkata; Pada suatu hari Rasulullah shallallahu 'alaihi wasallam datang seraya berkata: \"Apakah kalian memiliki makanan?\" Aku menjawab, \"Tidak.\" Beliau bersabda: \"Jika demikian, aku berpuasa.\" Aisyah berkata; \"Beliau masuk menemuiku lagi, lalu aku berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, telah dihadiahkan hais untuk kita, \" maka beliau bersabda: \"Jika demikian, hari ini aku berbuka, walaupun aku telah berniat berpuasa.\""},"2229":{"ar":"أَخْبَرَنِي الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ شُرَحْبِيلَ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ حَفْصَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يُبَيِّتْ الصِّيَامَ قَبْلَ الْفَجْرِ فَلَا صِيَامَ لَهُ","id":"Telah mengabarkan kepadaku [Al Qasim bin Zakaria bin Dinar] dia berkata; telah menceritakan kepada kami [Sa'id bin Syurahbil] dia berkata; telah memberitakan kepada kami [Al Laits] dari [Yahya bin Ayyub] dari ['Abdullah bin Abu Bakr] dari [Salim bin 'Abdullah] dari ['Abdullah bin 'Umar] dari [Hafshah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang tidak berniat puasa pada malam hari sebelum terbit fajar, tidak ada puasa baginya.\""},"2230":{"ar":"أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ بْنِ سَعْدٍ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَ حَدَّثَنِي يَحْيَى بْنُ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ عَنْ حَفْصَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يُبَيِّتْ الصِّيَامَ قَبْلَ الْفَجْرِ فَلَا صِيَامَ لَهُ","id":"Telah mengabarkan kepada kami ['Abdul Malik bin Syu'aib bin Al Laits bin Sa'd] dia berkata; [bapakku] telah menceritakan kepadaku dari [kakekku], dia berkata; telah menceritakan kepadaku [Yahya bin Ayyub] dari ['Abdullah bin Abu Bakr] dari [Ibnu Syihab] dari [Salim] dari ['Abdullah] dari [Hafshah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang tidak berniat puasa pada malam hari sebelum terbit fajar, tidak ada puasa baginya.\""},"2231":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ أَشْهَبَ قَالَ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ وَذَكَرَ آخَرَ أَنَّ عَبْدَ اللَّهِ بْنَ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ حَدَّثَهُمَا عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ حَفْصَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يُجْمِعْ الصِّيَامَ قَبْلَ طُلُوعِ الْفَجْرِ فَلَا يَصُومُ","id":"Telah mengabarkan kepadaku [Muhammad bin 'Abdullah bin 'Abdul Hakim] dari [Asyhab] dia berkata; telah mengabarkan kepadaku [Yahya bin Ayyub] -dan dia menyebutkan selainnya- bahwasanya ['Abdullah bin Abu Bakr bin Muhammad bin 'Amr bin Hazm] menceritakan kepada keduanya dari [Ibnu Syihab] dari [Salim bin 'Abdullah] dari [Bapaknya] dari [Hafshah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang tidak berniat puasa sebelum terbit fajar, maka ia -dianggap- tidak berpuasa.\""},"2232":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ الْأَزْهَرِ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يُبَيِّتْ الصِّيَامَ مِنْ اللَّيْلِ فَلَا صِيَامَ لَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Al Azhar] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dari [Ibnu Juraij] dari [Ibnu Syihab] dari [Salim] dari [Ibnu 'Umar] dari [Hafshah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang tidak berniat puasa dari waktu malam, tidak ada puasa baginya.\""},"2233":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ عُبَيْدَ اللَّهِ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ عَنْ حَفْصَةَأَنَّهَا كَانَتْ تَقُولُ مَنْ لَمْ يُجْمِعْ الصِّيَامَ مِنْ اللَّيْلِ فَلَا يَصُومُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Mu'tamir] dia berkata; aku mendengar ['Ubaidullah] dari [Ibnu Syihab] dari [Salim] dari ['Abdullah] dari [Hafshah] bahwa ia berkata; \"Barangsiapa yang tidak berniat puasa diwaktu malam, ia -dianggap- tidak berpuasa.\""},"2234":{"ar":"أَخْبَرَنِي زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا الْحَسَنُ بْنُ عِيسَى قَالَ أَنْبَأَنَا ابْنُ الْمُبَارَكِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ حَمْزَةَ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ حَفْصَةَ قَالَتْلَا صِيَامَ لِمَنْ لَمْ يُجْمِعْ قَبْلَ الْفَجْرِ","id":"Telah mengabarkan kepadaku [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami [Al Hasan bin 'Isa] dia berkata; telah memberitakan kepada kami [Ibnul Mubarak] dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Hamzah bin 'Abdullah] dari ['Abdullah bin 'Umar] dari [Hafshah] dia berkata; \"Tidak ada puasa bagi orang yang tidak berniat sebelum terbit fajar.\""},"2235":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حَبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ وَمَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ حَمْزَةَ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ عَنْ حَفْصَةَ قَالَتْلَا صِيَامَ لِمَنْ لَمْ يُجْمِعْ الصِّيَامَ قَبْلَ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] dia berkata; telah memberitakan kepada kami [Habban] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Sufyan bin 'Uyainah] dan [Ma'mar] dari [Az Zuhri] dari [Hamzah bin 'Abdullah bin 'Umar] dari [bapaknya] dari [Hafshah] dia berkata; \"Tidak ada puasa bagi orang yang tidak berniat sebelum terbit fajar.\""},"2236":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ حَمْزَةَ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ حَفْصَةَ قَالَتْلَا صِيَامَ لِمَنْ لَمْ يُجْمِعْ الصِّيَامَ قَبْلَ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari [Hamzah bin 'Abdullah bin 'Umar] dari [Hafshah] dia berkata; \"Tidak ada puasa bagi orang yang tidak berniat sebelum terbit fajar.\""},"2237":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عَائِشَةَ وَحَفْصَةَ مِثْلَهُلَا يَصُومُ إِلَّا مَنْ أَجْمَعَ الصِّيَامَ قَبْلَ الْفَجْرِ","id":"Berkata [Al Harits bin Miskin] secara baca dan aku mendengarnya dari [Ibnul Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari ['Aisyah] dan [Hafshah] dengan hadits yang sama; \"Tidak -dianggap- berpuasa kecuali orang yang berniat puasa sebelum terbit fajar.\""},"2238":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ عُبَيْدَ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَإِذَا لَمْ يُجْمِعْ الرَّجُلُ الصَّوْمَ مِنْ اللَّيْلِ فَلَا يَصُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Al Mu'tamir] dia berkata; aku mendengar ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Jika seseorang belum berniat puasa dari waktu malam, ia tidak boleh berpuasa.\""},"2239":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَمْرِو بْنِ أَوْسٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ الصِّيَامِ إِلَى اللَّهِ عَزَّ وَجَلَّ صِيَامُ دَاوُدَ عَلَيْهِ السَّلَام كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا وَأَحَبُّ الصَّلَاةِ إِلَى اللَّهِ عَزَّ وَجَلَّ صَلَاةُ دَاوُدَ عَلَيْهِ السَّلَام كَانَ يَنَامُ نِصْفَ اللَّيْلِ وَيَقُومُ ثُلُثَهُ وَيَنَامُ سُدُسَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari ['Amru bin Aus] bahwasanya ia mendengar ['Abdullah bin 'Amru bin Al 'Ash] berkata; \"Puasa yang paling dicintai oleh Allah -Azza wa Jalla- yaitu puasa Nabi Daud Alaihis Salam, ia berpuasa sehari dan berbuka sehari, dan shalat yang paling dicintai oleh Allah -Azza wa Jalla- yaitu shalat Nabi Daud Alaihis Salam, ia tidur setengah malamnya, bangun sepertiganya dan tidur seperenamnya.\""},"2240":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ حَدَّثَنَا يَعْقُوبُ عَنْ جَعْفَرٍ عَنْ سَعِيدٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُفْطِرُ أَيَّامَ الْبِيضِ فِي حَضَرٍ وَلَا سَفَرٍ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakaria] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dia berkata; telah menceritakan kepada kami [Ya'qub] dari [Ja'far] dari [Sa'id] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah Shallallahu'alaihi wa Sallam tidak berbuka pada hari Bidl (tiga belas, empat belas dan lima belas setiap bulan hijriyah) baik ketika mukim maupun ketika safar.\""},"2241":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ حَتَّى نَقُولَ لَا يُفْطِرُ وَيُفْطِرُ حَتَّى نَقُولَ مَا يُرِيدُ أَنْ يَصُومَ وَمَا صَامَ شَهْرًا مُتَتَابِعًا غَيْرَ رَمَضَانَ مُنْذُ قَدِمَ الْمَدِينَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam membiasakan berpuasa hingga kita mengatakan; \"Beliau tidak pernah berbuka.\" Dan beliau sering tidak puasa hingga kita mengatakan; \"Beliau tidak ingin berpuasa, dan tidak berpuasa satu bulan berturut-turut selain Ramadlan sejak tiba di Madinah.\""},"2242":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ خَالِدٍ قَالَ حَدَّثَنَا سَعِيدٌ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْلَا أَعْلَمُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ الْقُرْآنَ كُلَّهُ فِي لَيْلَةٍ وَلَا قَامَ لَيْلَةً حَتَّى الصَّبَاحِ وَلَا صَامَ شَهْرًا قَطُّ كَامِلًا غَيْرَ رَمَضَانَ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dari [Khalid] dia berkata; telah menceritakan kepada kami [Sa'id] dia berkata; telah menceritakan kepada kami [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah] dia berkata; \"Aku tidak pernah mengetahui Nabi shallallahu 'alaihi wasallam membaca Al Qur'an semuanya dalam semalam, tidak pernah melakukan shalat malam hingga menjelang pagi dan tidak pula berpuasa sama sekali sebulan penuh kecuali di bulan Ramadlan.\""},"2243":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَسَأَلْتُ عَائِشَةَ عَنْ صِيَامِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ يَصُومُ حَتَّى نَقُولَ قَدْ صَامَ وَيُفْطِرُ حَتَّى نَقُولَ قَدْ أَفْطَرَ وَمَا صَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا كَامِلًا مُنْذُ قَدِمَ الْمَدِينَةَ إِلَّا رَمَضَانَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari ['Abdullah bin Syaqiq] dia berkata; Aku bertanya kepada ['Aisyah] mengenai puasa Nabi shallallahu 'alaihi wasallam, dia berkata; \"Beliau sering berpuasa hingga kami mengatakan; 'Sungguh beliau telah berpuasa, dan beliau sering berbuka hingga kami mengatakan; 'Sungguh beliau telah berbuka, ' Rasulullah shallallahu 'alaihi wasallam tidak pernah berpuasa sebulan penuh sejak tiba di Madinah kecuali di bulan Ramadlan.\""},"2244":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَالِكٌ وَعَمْرُو بْنُ الْحَارِثِ وَذَكَرَ آخَرَ قَبْلَهُمَا أَنَّ أَبَا النَّضْرِ حَدَّثَهُمْ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ حَتَّى نَقُولَ مَا يُفْطِرُ وَيُفْطِرُ حَتَّى نَقُولَ مَا يَصُومُ وَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَهْرٍ أَكْثَرَ صِيَامًا مِنْهُ فِي شَعْبَانَ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman bin Dawud] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Malik] dan ['Amru bin Al Harits] dan menyebutkan yang lainnya sebelum mereka berdua, bahwasanya [Abu An Nadhr] menceritakan kepada mereka dari [Abu Salamah] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam berpuasa hingga kami mengatakan; \"Beliau sering tidak berbuka, \" dan beliau sering berbuka hingga kami mengatakan; \"Beliau tidak berpuasa, \" dan tidak pula aku melihat Rasulullah shallallahu 'alaihi wasallam dalam sebulan yang paling banyak puasanya dibanding bulan Sya'ban.\""},"2245":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ سَالِمَ بْنَ أَبِي الْجَعْدِ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَصُومُ شَهْرَيْنِ مُتَتَابِعَيْنِ إِلَّا شَعْبَانَ وَرَمَضَانَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Manshur] dia berkata; Aku mendengar [Salim bin Abul Ja'dari] dari [Abu Salamah] dari [Ummu Salamah] bahwa Rasulullah shallallahu 'alaihi wasallam tidak pernah berpuasa dua bulan berturut-turut kecuali bulan Sya'ban dan Ramadlan.\""},"2246":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ تَوْبَةَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَمْ يَكُنْ يَصُومُ مِنْ السَّنَةِ شَهْرًا تَامًّا إِلَّا شَعْبَانَ وَيَصِلُ بِهِ رَمَضَانَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Walid] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Taubah] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau tidak berpuasa sebulan penuh dalam setahun, kecuali bulan Sya'ban dan beliau menyambungnya dengan bulan Ramadlan.\""},"2247":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ هِشَامٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ إِسْحَقَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ شَعْبَانَ إِلَّا قَلِيلًا","id":"Telah mengabarkan kepadaku ['Amr bin Hisyam] dia berkata; telah menceritakan kepada kami [Muhammad bin Salamah] dari [Ibnu Ishaq] dari [Yahya bin Sa'id] dari [Abu Salamah] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam berpuasa di bulan Sya'ban hanya beberapa hari.\""},"2248":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنَا بَحِيرٌ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ أَنَّ عَائِشَةَ قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ شَعْبَانَ كُلَّهُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Utsman] dia berkata; telah menceritakan kepada kami [Baqiyyah] dia berkata; telah menceritakan kepada kami [Bahir] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair] bahwasanya ['Aisyah] berkata; \" Rasulullah shallallahu 'alaihi wasallam berpuasa di bulan Sya'ban satu bulan penuh.\""},"2249":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا ثَابِتُ بْنُ قَيْسٍ أَبُو الْغُصْنِ شَيْخٌ مِنْ أَهْلِ الْمَدِينَةِ قَالَ حَدَّثَنِي أَبُو سَعِيدٍ الْمَقْبُرِيُّ قَالَ حَدَّثَنِي أُسَامَةُ بْنُ زَيْدٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّكَ تَصُومُ حَتَّى لَا تَكَادَ تُفْطِرُ وَتُفْطِرُ حَتَّى لَا تَكَادَ أَنْ تَصُومَ إِلَّا يَوْمَيْنِ إِنْ دَخَلَا فِي صِيَامِكَ وَإِلَّا صُمْتَهُمَا قَالَ أَيُّ يَوْمَيْنِ قُلْتُ يَوْمَ الِاثْنَيْنِ وَيَوْمَ الْخَمِيسِ قَالَ ذَانِكَ يَوْمَانِ تُعْرَضُ فِيهِمَا الْأَعْمَالُ عَلَى رَبِّ الْعَالَمِينَ فَأُحِبُّ أَنْ يُعْرَضَ عَمَلِي وَأَنَا صَائِمٌ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dari ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Tsabit bin Qais Abu Al Ghushn] - seorang Syaikh dari penduduk Madinah - dia berkata; telah menceritakan kepadaku [Abu Sa'id Al Maqburi] dia berkata; telah menceritakan kepadaku [Usamah bin Zaid] dia berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, sering engkau berpuasa hingga hampir tidak berbuka dan sering juga engkau berbuka hingga hampir tidak berpuasa, kecuali dua hari, jika keduanya telah masuk dalam puasamu, jika tidak, engkau berpuasa di dua hari itu.\" Beliau bertanya: \"Dua hari yang mana?\" Aku menjawab; \"Hari senin dan hari kamis.\" Beliau bersabda: \"Itu adalah dua hari yang dalam keduanya amal perbuatan diperlihatkan kepada Rabb semesta alam, aku senang amalku diperlihatkan ketika aku sedang berpuasa.\""},"2250":{"ar":"أَخْبَرَنِي حَاجِبُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا الْحَارِثُ بْنُ عَطِيَّةَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُ��لُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ الْأَبَدَ فَلَا صَامَ","id":"Telah mengabarkan kepadaku [Hajib bin Sulaiman] dia berkata; telah menceritakan kepada kami [Al Harits bin 'Athiyyah] dia berkata; telah menceritakan kepada kami [Al Auza'i] dari ['Atha bin Abu Rabah] dari ['Abdullah bin 'Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berpuasa selama-lamanya, ia -dianggap- tidak berpuasa.\""},"2251":{"ar":"حَدَّثَنَا عِيسَى بْنُ مُسَاوِرٍ عَنْ الْوَلِيدِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ عَبْدِ اللَّهِ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنَا عَطَاءٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ الْأَبَدَ فَلَا صَامَ وَلَا أَفْطَرَ","id":"Telah mengabarkan kepada kami ['Isa bin Musawir] dari [Al Walid] dia berkata; telah menceritakan kepada kami [Al Auza'i] dia berkata; telah mengabarkan kepadaku ['Atha] dari ['Abdullah] demikian juga diriwayatkan dari jalur lainnya, dan telah memberitakan kepada kami [Muhammad bin 'Abdullah] dia berkata; telah menceritakan kepadaku [Al Walid] dari [Al Auza'i] dia berkata; telah menceritakan kepada kami ['Atha] dari ['Abdullah bin 'Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berpuasa selama-lamanya, ia -dianggap- tidak berpuasa dan tidak juga berbuka.\""},"2252":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنَا أَبِي وَعُقْبَةُ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي عَطَاءٌ قَالَ حَدَّثَنِي مَنْ سَمِعَ ابْنَ عُمَرَ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ الْأَبَدَ فَلَا صَامَ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin Al Walid] dia berkata; [bapakku] dan ['Uqbah] telah menceritakan kepada kami dari [Al Auza'i] dia berkata; telah menceritakan kepadaku ['Atha] dia berkata; telah menceritakan kepadaku [orang yang telah mendengar] [Ibnu 'Umar] berkata; bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berpuasa selama-lamanya, ia -dianggap- tidak berpuasa.\""},"2253":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى قَالَ حَدَّثَنَا أَبِي عَنْ الْأَوْزَاعِيِّ عَنْ عَطَاءٍ قَالَ حَدَّثَنِي مَنْ سَمِعَ ابْنَ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ الْأَبَدَ فَلَا صَامَ","id":"Telah mengabarkan kepada kami [Isma'il bin Ya'qub] dia berkata; telah menceritakan kepada kami [Muhammad bin Musa] dia berkata; [bapakku] telah menceritakan kepada kami, dari [Al Auza'i] dari ['Atha] dia berkata; telah menceritakan kepadaku [orang] yang mendengar [Ibnu 'Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berpuasa selama-lamanya, ia -dianggap- tidak berpuasa.\""},"2254":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا ابْنُ عَائِذٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ الْأَوْزَاعِيِّ عَنْ عَطَاءٍ أَنَّهُ حَدَّثَهُ قَالَ حَدَّثَنِي مَنْ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ الْأَبَدَ فَلَا صَامَ وَلَا أَفْطَرَأَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ سَمِعْتُ عَطَاءً أَنَّ أَبَا الْعَبَّاسِ الشَّاعِرَ أَخْبَرَهُ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ قَالَ بَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي أَصُومُ أَسْرُدُ الصَّوْمَ وَسَاقَ الْحَدِيثَ قَالَ قَالَ عَطَاءٌ لَا أَدْرِي كَيْفَ ذَكَرَ صِيَامَ الْأَبَدِ لَا صَامَ مَنْ صَامَ الْأَبَدَ","id":"Telah mengabarkan kepada kami [Ahmad bin Ibrahim bin Muhammad] dia berkata; telah menceritakan kepada kami [Ibnu 'Aidz] dia berkata; telah menceritakan kepada kami [Yahya] dari [Al Auza'i] dari ['Atha] bahwasanya ia menceritakan kepadanya dia berkata; telah menceritakan kepadaku [orang] yang mendengar ['Abdullah bin 'Amr bin Al 'Ash] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berpuasa selama-lamanya, ia -dianggap- tidak berpuasa dan tidak juga berbuka.\" Telah mengabarkan kepadaku [Ibrahim bin Al Hasan] dia berkata; Telah menceritakan kepada kami [Hajjaj bin Muhammad] dia berkata; [Ibnu Juraij] berkata; Aku mendengar [Atha'], - [Al Abbas ahli sya'ir] telah mengabarkan kepadanya- bahwa dia mendengar [Abdullah bin Amru bin Al Ash] berkata; \"Telah sampai berita kepada Nabi shallallahu 'alaihi wasallam bahwa aku berpuasa, berpuasa terus-menerus. Ia menyebutkan hadits tersebut. Ia berkata; Atha' mengatakan; \"Aku tidak tahu bagaimana ia menyebutkan puasa selama-lamanya, 'Tidak dianggap puasa bagi orang yang berpuasa selama-lamanya.\""},"2255":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ الْجُرَيْرِيِّ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَخِيهِ مُطَرِّفٍ عَنْ عِمْرَانَ قَالَقِيلَ يَا رَسُولَ اللَّهِ إِنَّ فُلَانًا لَا يُفْطِرُ نَهَارًا الدَّهْرَ قَالَ لَا صَامَ وَلَا أَفْطَرَ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Isma'il] dari [Al Jurairi] dari [Yazid bin 'Abdullah bin Asy Syakhkhir] dari saudaranya [Mutharrif] dari ['Imran] dia berkata; seseorang bertanya; \"Wahai Rasulullah shallallahu 'alaihi wasallam, si fulan tidak berbuka di siang hari terus-menerus sepanjang masa?\" Beliau bersabda: \"Ia -dianggap- tidak berpuasa dan tidak berbuka.\""},"2256":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ هِشَامٍ قَالَ حَدَّثَنَا مَخْلَدٌ عَنْ الْأَوْزَاعِيِّ عَنْ قَتَادَةَ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ أَخْبَرَنِي أَبِيأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذُكِرَ عِنْدَهُ رَجُلٌ يَصُومُ الدَّهْرَ قَالَ لَا صَامَ وَلَا أَفْطَرَ","id":"Telah mengabarkan kepadaku ['Amr bin Hisyam] dia berkata; telah menceritakan kepada kami [Makhlad] dari [Al Auza'i] dari [Qatadah] dari [Mutharrif bin 'Abdullah bin Asy Syakhkhir]; [bapakku] telah mengabarkan kepadaku bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam ketika disebutkan kepadanya tentang seseorang yang berpuasa sepanjang masa, beliau bersabda: \"Ia -dianggap- tidak berpuasa dan tidak berbuka.\""},"2257":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ مُطَرِّفَ بْنَ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ يُحَدِّثُ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي صَوْمِ الدَّهْرِ لَا صَامَ وَلَا أَفْطَرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; aku mendengar [Mutharrif bin 'Abdullah bin Asy Syakhkhir] menceritakan dari [bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda tentang puasa Dahr (puasa sepanjang masa): \"Dia tidak dihitung berpuasa dan tidak berbuka.\""},"2258":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى قَالَ أَنْبَأَنَا أَبُو هِلَالٍ قَالَ حَدَّثَنَا غَيْلَانُ وَهُوَ ابْنُ جَرِيرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ وَهُوَ ابْنُ مَعْبَدٍ الزِّمَّانِيُّ عَنْ أَبِي قَتَادَةَ عَنْ عُمَرَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرَرْنَا بِرَجُلٍ فَقَالُوا يَا نَبِيَّ اللَّهِ هَذَا لَا يُفْطِرُ مُنْذُ كَذَا وَكَذَا فَقَالَ لَا صَامَ وَلَا أَفْطَرَ","id":"Telah mengabarkan kepadaku [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Al Hasan bin Musa] dia berkata; telah memberitakan kepada kami [Abu Hilal] dia berkata; telah menceritakan kepada kami [Ghailan bin Jarir] dia berkata; telah menceritakan kepada kami ['Abdullah bin Ma'bad Az Zamani] dari [Abu Qatadah] dari ['Umar] dia berkata; Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam, lalu kami melewati seseorang. Kemudian mereka berkata; \"Wahai Nabi Allah, orang ini tidak berbuka sejak hari ini dan ini?\" beliau bersabda: \"Ia -dianggap- tidak berpuasa dan tidak berbuka.\""},"2259":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ غَيْلَانَ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ مَعْبَدٍ الزِّمَّانِيَّ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ صَوْمِهِ فَغَضِبَ فَقَالَ عُمَرُ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ رَسُولًا وَسُئِلَ عَمَّنْ صَامَ الدَّهْرَ فَقَالَ لَا صَامَ وَلَا أَفْطَرَ أَوْ مَا صَامَ وَمَا أَفْطَرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Ghailan] bahwasanya ia mendengar ['Abdullah bin Ma'bad Az Zamani] dari [Abu Qatadah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang puasa beliau. Beliau marah. Lalu Umar berkata; \"Kami rela Allah sebagai Rabb, Islam sebagai agama dan Muhammad sebagai Rasul\", lalu beliau ditanya tentang orang yang berpuasa dahr, beliau menjawab: \"Dia -dianggap- tidak berpuasa dan tidak berbuka. Atau ia tidak berpuasa dan tidak berbuka.\""},"2260":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ حَمْزَةَ بْنَ عَمْرٍو الْأَسْلَمِيَّ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ أَسْرُدُ الصَّوْمَ أَفَأَصُومُ فِي السَّفَرِ قَالَ صُمْ إِنْ شِئْتَ أَوْ أَفْطِرْ إِنْ شِئْتَ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dia berkata; telah menceritakan kepada kami [Hammad] dari [Hisyam] dari [bapaknya] dari ['Aisyah] bahwasanya Hamzah bin 'Amru Al Aslami bertanya kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, aku adalah orang yang terus-menerus berpuasa, apakah aku -boleh- berpuasa saat dalam bepergian?\" Beliau bersabda: \"Berpuasalah jika engkau menghendaki dan berbukalah jika engkau menghendaki.\""},"2261":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي عَمَّارٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ يَصُومُ الدَّهْرَ قَالَ وَدِدْتُ أَنَّهُ لَمْ يَطْعَمْ الدَّهْرَ قَالُوا فَثُلُثَيْهِ قَالَ أَكْثَرَ قَالُوا فَنِصْفَهُ قَالَ أَكْثَرَ ثُمَّ قَالَ أَلَا أُخْبِرُكُمْ بِمَا يُذْهِبُ وَحَرَ الصَّدْرِ صَوْمُ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu 'Ammar] dari ['Amru bin Syurahbil] dari [salah seorang sahabat Nabi shallallahu 'alaihi wasallam], ia berkata; Dikatakan kepada Nabi shallallahu 'alaihi wasallam bahwa ada seseorang berpuasa Dahr (puasa sepanjang waktu) \" Beliau bersabda: \"Aku senang jika ia puasa tidak selamanya.\" Mereka bertanya; \"Dua pertiganya?\" Beliau menjawab: \"Masih terlalu banyak.\" Mereka bertanya; \"Setengahnya.\" Beliau menjawab: \"Masih terlalu banyak.\" Kemudian beliau bersabda: \"Maukah kuberitahukan kepada kalian dengan sesuatu yang bisa menghilangkan kemarahan dada? Puasa tiga hari setiap bulan.\""},"2262":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي عَمَّارٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ قَالَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَا تَقُولُ فِي رَجُلٍ صَامَ الدَّهْرَ كُلَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدِدْتُ أَنَّهُ لَمْ يَطْعَمْ الدَّهْرَ شَيْئًا قَالَ فَثُلُثَيْهِ قَالَ أَكْثَرَ قَالَ فَنِصْفَهُ قَالَ أَكْثَرَ قَالَ أَفَلَا أُخْبِرُكُمْ بِمَا يُذْهِبُ وَحَرَ الصَّدْرِ قَا��ُوا بَلَى قَالَ صِيَامُ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala'] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dia berkata; telah menceritakan kepada kami [Al A'masy] dari [Abu 'Ammar] dari ['Amru bin Syurahbil] dia berkata; Seseorang datang menemui Rasulullah shallallahu 'alaihi wasallam, lalu ia bertanya; \"Wahai Rasulullah shallallahu 'alaihi wasallam, bagaimana pendapat engkau tentang orang yang berpuasa Dahr (puasa setiap hari)?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malah aku senang jika ia tidak makan sedikitpun selamanya.\" Ia bertanya; \"Dua pertiganya?\" Beliau menjawab: \"Masih terlalu banyak.\" Ia bertanya; \"Setengahnya.\" Beliau menjawab: \"Masih terlalu banyak.\" Beliau bersabda: \"Maukah kuberitahukan kepada kalian dengan sesuatu yang bisa menghilangkan kemarahan dada?\" Mereka menjawab; \"Ya.\" Beliau bersabda: \"Puasa tiga hari setiap bulan.\""},"2263":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ الزِّمَّانِيِّ عَنْ أَبِي قَتَادَةَ قَالَ قَالَ عُمَرُيَا رَسُولَ اللَّهِ كَيْفَ بِمَنْ يَصُومُ الدَّهْرَ كُلَّهُ قَالَ لَا صَامَ وَلَا أَفْطَرَ أَوْ لَمْ يَصُمْ وَلَمْ يُفْطِرْ قَالَ يَا رَسُولَ اللَّهِ كَيْفَ بِمَنْ يَصُومُ يَوْمَيْنِ وَيُفْطِرُ يَوْمًا قَالَ أَوَ يُطِيقُ ذَلِكَ أَحَدٌ قَالَ فَكَيْفَ بِمَنْ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا قَالَ ذَلِكَ صَوْمُ دَاوُدَ عَلَيْهِ السَّلَام قَالَ فَكَيْفَ بِمَنْ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمَيْنِ قَالَ وَدِدْتُ أَنِّي أُطِيقُ ذَلِكَ قَالَ ثُمَّ قَالَ ثَلَاثٌ مِنْ كُلِّ شَهْرٍ وَرَمَضَانُ إِلَى رَمَضَانَ هَذَا صِيَامُ الدَّهْرِ كُلِّهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Ghailan bin Jarir] dari ['Abdullah bin Ma'bad Az Zamani] dari [Abu Qatadah] dia berkata; [Umar] bertanya; \"Wahai Rasulullah shallallahu 'alaihi wasallam, bagaimana dengan orang yang berpuasa Dahr (puasa sepanjang hari)?\" Beliau Nabi shallallahu 'alaihi wasallam menjawab: \"Ia -dianggap- tidak berpuasa dan tidak berbuka, atau belum berpuasa dan belum berbuka.\" Ia bertanya; \"Bagaimana dengan orang yang berpuasa dua hari dan berbuka sehari?\" Beliau menjawab: \"Apakah ada seorang yang mampu melakukan hal itu?\" Ia bertanya; \"Lalu bagaimana dengan orang yang berpuasa sehari dan berbuka sehari?\" Beliau menjawab: \"Itu adalah puasa Nabi Daud -alahissalam-.\" Ia bertanya; \"Bagaimana orang yang berpuasa sehari dan berbuka dua hari?\" Beliau menjawab: \"Aku senang jika aku mampu melakukan hal itu.\" Ia berkata; \"Kemudian beliau bersabda: \"Tiga hari setiap bulan dan Ramadlan hingga Ramadlan berikutnya, ini adalah -sama dengan- puasa Dahr.\""},"2264":{"ar":"قَالَ وَفِيمَا قَرَأَ عَلَيْنَا أَحْمَدُ بْنُ مَنِيعٍ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا حُصَيْنٌ وَمُغِيرَةُ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الصِّيَامِ صِيَامُ دَاوُدَ عَلَيْهِ السَّلَام كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا","id":"Telah berkata -dan sebagaimana yang telah dibacakan kepada kami oleh [Ahmad bin Mani'] - dia berkata; telah menceritakan kepada kami [Husyaim] dia berkata; telah memberitakan kepada kami [Hushain] dan [Mughirah] dari [Mujahid] dari ['Abdullah bin 'Amr] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa yang paling utama ialah pasa Nabi Daud -alaihissalam-, ia berpuasa sehari dan berbuka sehari.\""},"2265":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ مُجَاهِدٍ قَالَ قَالَ لِي عَبْدُ اللَّهِ بْنُ عَمْرٍوأَنْكَحَنِي أَبِي امْرَأَةً ذَاتَ حَسَبٍ فَكَانَ يَأْتِيهَا فَيَسْأَلُهَا عَنْ بَعْلِهَا فَقَالَتْ نِعْمَ الرَّجُلُ مِنْ رَجُلٍ لَمْ يَطَأْ لَنَا فِرَاشًا وَلَمْ يُفَتِّشْ لَنَا كَنَفًا مُنْذُ أَتَيْنَاهُ فَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ائْتِنِي بِهِ فَأَتَيْتُهُ مَعَهُ فَقَالَ كَيْفَ تَصُومُ قُلْتُ كُلَّ يَوْمٍ قَالَ صُمْ مِنْ كُلِّ جُمُعَةٍ ثَلَاثَةَ أَيَّامٍ قُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ صُمْ يَوْمَيْنِ وَأَفْطِرْ يَوْمًا قَالَ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ صُمْ أَفْضَلَ الصِّيَامِ صِيَامَ دَاوُدَ عَلَيْهِ السَّلَام صَوْمُ يَوْمٍ وَفِطْرُ يَوْمٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] dia berkata; telah menceritakan kepada kami [Yahya bin Hammad] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari [Mujahid] dia berkata; ['Abdullah bin 'Amr] berkata kepadaku; \"Bapakku menikahkan diriku dengan wanita yang memiliki keturunan yang mulia. Suatu kali bapakku menemuinya dan bertanya tentang suaminya. Wanita itu mengatakan; Sebaik laki-laki adalah yang tidak pernah menggauli kami di tempat tidur dan tidak pernah meneliti dada kami (mencumbui atau berdekatan) sejak kami datang kepadanya'.\" Lalu ia menuturkan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bawalah ia kemari.\" Lalu aku datang bersamanya, lalu beliau bertanya: \"Bagaimana cara engkau berpuasa?\" Aku menjawab; \"Setiap hari.\" Beliau bersabda: \"Berpuasalah setiap Jum'at tiga hari.\" Aku berkata; \" aku mampu dari itu!\" Beliau bersabda: \"Berpuasalah dua hari dan berbukalah sehari.\" Ia berkata; \" aku mampu lebih dari itu!\" Beliau bersabda: \"Berpuasalah dengan puasa yang paling utama, puasa Nabi Daud -alaihissalam-, berpuasa sehari dan berbuka sehari.\""},"2266":{"ar":"أَخْبَرَنَا أَبُو حَصِينٍ عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ عَبْدِ اللَّهِ بْنِ يُونُسَ قَالَ حَدَّثَنَا عَبْثَرٌ قَالَ حَدَّثَنَا حُصَيْنٌ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَزَوَّجَنِي أَبِي امْرَأَةً فَجَاءَ يَزُورُهَا فَقَالَ كَيْفَ تَرَيْنَ بَعْلَكِ فَقَالَتْ نِعْمَ الرَّجُلُ مِنْ رَجُلٍ لَا يَنَامُ اللَّيْلَ وَلَا يُفْطِرُ النَّهَارَ فَوَقَعَ بِي وَقَالَ زَوَّجْتُكَ امْرَأَةً مِنْ الْمُسْلِمِينَ فَعَضَلْتَهَا قَالَ فَجَعَلْتُ لَا أَلْتَفِتُ إِلَى قَوْلِهِ مِمَّا أَرَى عِنْدِي مِنْ الْقُوَّةِ وَالِاجْتِهَادِ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَكِنِّي أَنَا أَقُومُ وَأَنَامُ وَأَصُومُ وَأُفْطِرُ فَقُمْ وَنَمْ وَصُمْ وَأَفْطِرْ قَالَ صُمْ مِنْ كُلِّ شَهْرٍ ثَلَاثَةَ أَيَّامٍ فَقُلْتُ أَنَا أَقْوَى مِنْ ذَلِكَ قَالَ صُمْ صَوْمَ دَاوُدَ عَلَيْهِ السَّلَام صُمْ يَوْمًا وَأَفْطِرْ يَوْمًا قُلْتُ أَنَا أَقْوَى مِنْ ذَلِكَ قَالَ اقْرَأْ الْقُرْآنَ فِي كُلِّ شَهْرٍ ثُمَّ انْتَهَى إِلَى خَمْسَ عَشْرَةَ وَأَنَا أَقُولُ أَنَا أَقْوَى مِنْ ذَلِكَ","id":"Telah mengabarkan kepada kami [Abu Hushain 'Abdullah bin Ahmad bin 'Abdullah bin Yunus] dia berkata; telah menceritakan kepada kami ['Abtsar] dia berkata; telah menceritakan kepada kami [Hushain] dari [Mujahid] dari ['Abdullah bin 'Amru] dia berkata; Bapakku menikahkanku dengan seorang wanita, lalu ia datang mengunjunginya (wanita itu), kemudian ia bertanya; \"Bagaimana pendapatmu tentang suamimu?\" Wanita itu menjawab; \"Sebaik-baik laki-laki adalah dari seorang laki-laki yang ia tidak pernah tidur malam dan tidak pernah berbuka di siang hari.\" Lalu ia berbicara dengan suara tinggi kepadaku. Ia berkata; \"Aku nikahkan kamu dengan seorang wanita dari kaum muslimin, namun kamu menyepelekan -tidak menggauli layaknya seorang istri-.\" Ia berkata; \"Kemudian aku tidak memperhatikan perkataannya, karena aku melihat kekuatan dan kesungguhan pada diriku. Lalu berita itu sampai kepada Nabi shallallahu 'alaihi wasallam, hingga beliau menegur seraya bersabda: \"Tetapi aku bangun malam dan tidur, berpuasa dan berbuka, bangun malam dan tidurlah, berpuasa dan berbukalah.\" Beliau bersabda: \"Berpuasalah tiga hari setiap bulan.\" Aku berkata; \"Aku masih kuat -melakukan- lebih dari itu.\" Beliau bersabda: \"Berpuasalah seperti puasanya Nabi Daud -alaihis-salam-, berpuasalah sehari dan berbukalah sehari.\" Aku berkata; \"Aku masih kuat -melakukan- lebih dari itu!\" Beliau bersabda: \"Bacalah Al Qur'an setiap bulan.\" Kemudian selepas dari lima belas hari aku berkata; \"Aku masih kuat melakukan lebih dari itu.\""},"2267":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ أَبَا سَلَمَةَ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُجْرَتِي فَقَالَ أَلَمْ أُخْبَرْ أَنَّكَ تَقُومُ اللَّيْلَ وَتَصُومُ النَّهَارَ قَالَ بَلَى قَالَ فَلَا تَفْعَلَنَّ نَمْ وَقُمْ وَصُمْ وَأَفْطِرْ فَإِنَّ لِعَيْنِكَ عَلَيْكَ حَقًّا وَإِنَّ لِجَسَدِكَ عَلَيْكَ حَقًّا وَإِنَّ لِزَوْجَتِكَ عَلَيْكَ حَقًّا وَإِنَّ لِضَيْفِكَ عَلَيْكَ حَقًّا وَإِنَّ لِصَدِيقِكَ عَلَيْكَ حَقًّا وَإِنَّهُ عَسَى أَنْ يَطُولَ بِكَ عُمُرٌ وَإِنَّهُ حَسْبُكَ أَنْ تَصُومَ مِنْ كُلِّ شَهْرٍ ثَلَاثًا فَذَلِكَ صِيَامُ الدَّهْرِ كُلِّهِ وَالْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا قُلْتُ إِنِّي أَجِدُ قُوَّةً فَشَدَّدْتُ فَشُدِّدَ عَلَيَّ قَالَ صُمْ مِنْ كُلِّ جُمُعَةٍ ثَلَاثَةَ أَيَّامٍ قُلْتُ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ فَشَدَّدْتُ فَشُدِّدَ عَلَيَّ قَالَ صُمْ صَوْمَ نَبِيِّ اللَّهِ دَاوُدَ عَلَيْهِ السَّلَام قُلْتُ وَمَا كَانَ صَوْمُ دَاوُدَ قَالَ نِصْفُ الدَّهْرِ","id":"Telah mengabarkan kepada kami [Yahya bin Durusta] dia berkata; telah menceritakan kepada kami [Abu Isma'il] dia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] bahwasanya [Abu Salamah] menceritakan kepadanya bahwasanya ['Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam masuk ke kamarku, lalu beliau bersabda: \"Aku memperoleh berita bahwa kamu bangun di malam hari dan berpuasa di siang hari, benar?\" Ia menjawab; \"Benar.\" Beliau bersabda: \"Janganlah sekali-kali kamu lakukan -hal itu-; namun tidur dan bangunlah, berpuasa dan berbukalah. Karena kedua matamu memiliki hak atas dirimu, tubuhmu memiliki hak atas dirimu, istrimu memiliki hak atas dirimu, tamumu memiliki hak atas dirimu dan temanmu memiliki hak atas dirimu. Sungguh, semoga umurmu akan panjang dan cukup bagimu berpuasa tiga hari dalam setiap bulan, itulah puasa Dahr dan suatu kebaikan akan dibalas dengan sepuluh kali lipatnya.\" Aku berkata; \"Sungguh aku masih kuat - melakukan lebih dari itu-?\" Aku bersikap keras dan beliau pun bersikap keras kepadaku. Beliau bersabda: \"Berpuasalah tiga hari setiap Jum'at.\" Aku berkata; \" aku masih kuat melakukan lebih banyak dari itu!\" Aku bersikap keras dan beliau pun bersikap keras kepadaku. Beliau bersabda: \"Berpuasalah seperti puasanya Nabi Daud -Alaihissalam-.\" Aku berkata; \"Bagaimana puasa Nabi Daud?\" Beliau bersabda: \"Itu sama artinya dengan puasa setengah jaman.\""},"2268":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ قَالَذُكِرَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ يَقُولُ لَأَقُومَنَّ اللَّيْلَ وَلَأَصُومَنَّ النَّهَارَ مَا عِشْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْتَ الَّذِي تَقُولُ ذَلِكَ فَقُلْتُ لَهُ قَدْ قُلْتُهُ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّكَ لَا تَسْتَطِيعُ ذَلِكَ فَصُمْ وَأَفْطِرْ وَنَمْ وَقُمْ وَصُمْ مِنْ الشَّهْرِ ثَلَاثَةَ أَيَّامٍ فَإِنَّ الْحَسَنَةَ بِعَشْرِ أَمْثَالِهَا وَذَلِكَ مِثْلُ صِيَامِ الدَّهْرِ قُلْتُ فَإِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ صُمْ يَوْمًا وَأَفْطِرْ يَوْمَيْنِ فَقُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ يَا رَسُولَ اللَّهِ قَالَ فَصُمْ يَوْمًا وَأَفْطِرْ يَوْمًا وَذَلِكَ صِيَامُ دَاوُدَ وَهُوَ أَعْدَلُ الصِّيَامِ قُلْتُ فَإِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَفْضَلَ مِنْ ذَلِكَقَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍو لَأَنْ أَكُونَ قَبِلْتُ الثَّلَاثَةَ الْأَيَّامَ الَّتِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَي��هِ وَسَلَّمَ أَحَبُّ إِلَيَّ مِنْ أَهْلِي وَمَالِي","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] bahwasanya ['Abdullah bin 'Amr bin Al 'Ash] berkata; Diberitahukan kepada Nabi shallallahu 'alaihi wasallam bahwa ia berkata; \"Sungguh aku benar-benar akan bangun di malam hari -untuk beribadah- dan sungguh aku benar-benar akan berpuasa di siang hari selama aku masih hidup.\" beliau bersabda: 'Apakah kamu yang mengatakan hal itu? ' Aku katakan kepada beliau; 'Sungguh akulah yang telah mengatakannya, wahai Rasulullah shallallahu 'alaihi wasallam! ' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sungguh engkau tidak akan mampu melakukan hal itu, berpuasa dan berbukalah, tidur dan bangunlah dan berpuasalah tiga hari dalam sebulan, karena kebaikan akan dibalas dengan sepuluh kali lipatnya dan hal itu seperti berpuasa sepanjang masa.' Aku berkata; 'Sungguh aku masih mampu melakukan lebih dari itu, wahai Rasulullah shallallahu 'alaihi wasallam! ' Beliau bersabda: 'Berpuasalah sehari dan berbukalah dua hari.' Aku berkata; 'Sungguh aku mampu melakukan lebih dari itu, wahai Rasulullah shallallahu 'alaihi wasallam! ' Beliau bersabda: 'Berpuasalah sehari dan berbukalah sehari, itu adalah puasa Nabi Daud dan itu adalah puasa yang lebih adil.' 'Sungguh aku mampu melakukan lebih dari itu.' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidak ada yang lebih utama daripada itu.' Abdullah bin Amru berkata; 'Sungguh aku menerima tiga hari yang Rasulullah shallallahu 'alaihi wasallam sabdakan lebih aku cintai dari keluarga dan hartaku! '"},"2269":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ سَلَمَةَ عَنْ ابْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَدَخَلْتُ عَلَى عَبْدِ اللَّهِ بْنِ عَمْرٍو قُلْتُ أَيْ عَمِّ حَدِّثْنِي عَمَّا قَالَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا ابْنَ أَخِي إِنِّي قَدْ كُنْتُ أَجْمَعْتُ عَلَى أَنْ أَجْتَهِدَ اجْتِهَادًا شَدِيدًا حَتَّى قُلْتُ لَأَصُومَنَّ الدَّهْرَ وَلَأَقْرَأَنَّ الْقُرْآنَ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ فَسَمِعَ بِذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَانِي حَتَّى دَخَلَ عَلَيَّ فِي دَارِي فَقَالَ بَلَغَنِي أَنَّكَ قُلْتَ لَأَصُومَنَّ الدَّهْرَ وَلَأَقْرَأَنَّ الْقُرْآنَ فَقُلْتُ قَدْ قُلْتُ ذَلِكَ يَا رَسُولَ اللَّهِ قَالَ فَلَا تَفْعَلْ صُمْ مِنْ كُلِّ شَهْرٍ ثَلَاثَةَ أَيَّامٍ قُلْتُ إِنِّي أَقْوَى عَلَى أَكْثَرَ مِنْ ذَلِكَ قَالَ فَصُمْ مِنْ الْجُمُعَةِ يَوْمَيْنِ الِاثْنَيْنِ وَالْخَمِيسَ قُلْتُ فَإِنِّي أَقْوَى عَلَى أَكْثَرَ مِنْ ذَلِكِ قَالَ فَصُمْ صِيَامَ دَاوُدَ عَلَيْهِ السَّلَام فَإِنَّهُ أَعْدَلُ الصِّيَامِ عِنْدَ اللَّهِ يَوْمًا صَائِمًا وَيَوْمًا مُفْطِرًا وَإِنَّهُ كَانَ إِذَا وَعَدَ لَمْ يُخْلِفْ وَإِذَا لَاقَى لَمْ يَفِرَّ","id":"Telah mengabarkan kepadaku [Ahmad bin Bakkar] dia berkata; telah menceritakan kepada kami [Muhammad bin Salamah] dari [Ibnu Ishaq] dari [Muhammad bin Ibrahim] dari [Abu Salamah bin 'Abdurrahman] dia berkata; aku masuk menemui ['Abdullah bin 'Amru] aku berkata; \"Wahai pamanku ceritakan kepadaku apa yang telah Rasulullah shallallahu'alaihiwasallam sabdakan kepadamu! Dia menjawab; 'Wahai keponakanku, sungguh aku telah berniat untuk bersungguh-sungguh hingga aku mengatakan; Sungguh aku benar-benar akan berpuasa Dahr (sepanjang masa), dan sungguh aku akan membaca Al Qur'an setiap hari dan malam. Lalu Rasulullah Shallallahu 'Alahi Wa Sallam mendengar hal itu, kemudian beliau datang menemuiku di rumah dan berkata: 'Telah sampai kepadaku bahwa kamu mengatakan sungguh akan berpuasa sepanjang masa, dan membaca Al Qur'an. Aku katakan kepada beliau; 'Sungguh akulah yang telah mengatakannya, wahai Rasulullah shallallahu 'alaihi wasallam! ' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Jangan kamu lakukan!, berpuasalah tiga hari dalam setiap bulan.' Aku berkata; 'Sungguh aku masih mampu melakukan lebih dari itu.' Beliau bersabda: 'Berpuasalah dua hari dalam seminggu yaitu hari senin dan kamis.' Aku berkata; 'Sungguh aku mampu melakukan lebih dari itu! ' Beliau bersabda: 'Berpuasalah dengan puasa Nabi Daud dan itu adalah puasa yang lebih adil di sisi Allah, yaitu berpuasa sehari dan berbuka sehari, apabila berjanji tidak pernah mengingkari, dan apabila bertemu musuh tidak pernah lari.'"},"2270":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ زِيَادِ بْنِ فَيَّاضٍ سَمِعْتُ أَبَا عِيَاضٍ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ صُمْ يَوْمًا وَلَكَ أَجْرُ مَا بَقِيَ قَالَ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ صُمْ يَوْمَيْنِ وَلَكَ أَجْرُ مَا بَقِيَ قَالَ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ صُمْ ثَلَاثَةَ أَيَّامٍ وَلَكَ أَجْرُ مَا بَقِيَ قَالَ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ صُمْ أَرْبَعَةَ أَيَّامٍ وَلَكَ أَجْرُ مَا بَقِيَ قَالَ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ صُمْ أَفْضَلَ الصِّيَامِ عِنْدَ اللَّهِ صَوْمَ دَاوُدَ عَلَيْهِ السَّلَام كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah memberitakan kepada kami [Muhammad] dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Ziyad bin Fayyadl]; aku mendengar [Abu 'Iyadl] menceritakan dari ['Abdullah bin 'Amru] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya; \"Berpuasalah sehari dan bagimu pahala hari yang tersisa.\" Dia berkata; ' aku masih mampu melakukan lebih dari itu! ' Beliau bersabda: 'Berpuasalah dua hari dan bagimu pahala yang tersisa.' Dia berkata; ' aku masih mampu melakukan lebih dari itu! ' Beliau bersabda: 'Berpuasalah tiga hari dan bagimu pahala yang tersisa.' Dia berkata; ' aku mampu melakukan lebih dari itu.' Beliau bersabda: 'Berpuasalah empat hari dan bagimu pahala hari yang tersisa.' Dia berkata; ' aku mampu melakukan lebih dari itu.' Beliau bersabda: 'Berpuasalah dengan berpuasa yang paling utama di sisi Allah; puasa Nabi Daud -alaihissalam-, ia berpuasa sehari dan berbuka sehari.'"},"2271":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ قَالَ حَدَّثَنَا أَبُو الْعَلَاءِ عَنْ مُطَرِّفٍ عَنْ ابْنِ أَبِي رَبِيعَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَذَكَرْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّوْمَ فَقَالَ صُمْ مِنْ كُلِّ عَشَرَةِ أَيَّامٍ يَوْمًا وَلَكَ أَجْرُ تِلْكَ التِّسْعَةِ فَقُلْتُ إِنِّي أَقْوَى مِنْ ذَلِكَ قَالَ صُمْ مِنْ كُلِّ تِسْعَةِ أَيَّامٍ يَوْمًا وَلَكَ أَجْرُ تِلْكَ الثَّمَانِيَةِ قُلْتُ إِنِّي أَقْوَى مَنْ ذَلِكَ قَالَ فَصُمْ مِنْ كُلِّ ثَمَانِيَةِ أَيَّامٍ يَوْمًا وَلَكَ أَجْرُ تِلْكَ السَّبْعَةِ قُلْتُ إِنِّي أَقْوَى مِنْ ذَلِكَ قَالَ فَلَمْ يَزَلْ حَتَّى قَالَ صُمْ يَوْمًا وَأَفْطِرْ يَوْمًا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Al Mu'tamir] dari [bapaknya], dia berkata; telah menceritakan kepada kami [Abul 'Ala] dari [Mutharrif] dari [Ibnu Abu Rabi'ah] dari ['Abdullah bin 'Amru] dia berkata; Aku menyebutkan kepada Nabi shallallahu 'alaihi wasallam tentang puasa, lalu beliau bersabda: \"Dari sepuluh hari berpuasalah sehari dan bagimu pahala sembilan hari yang tersisa.\" Aku berkata; 'Aku mampu melakukan lebih dari itu.' Beliau bersabda: 'Dari sembilan hari berpuasalah sehari dan bagimu pahala delapan hari yang tersisa.' Aku berkata; 'aku mampu melakukan lebih dari itu.' Beliau bersabda: 'Dari delapan hari berpuasalah sehari dan bagimu pahala tujuh hari yang tersisa.' Aku berkata; 'aku mampu melakukan lebih dari itu.' Dia mengatakan, beliau tetap seperti hingga beliau bersabda: \"Berpuasalah sehari dan berbukalah sehari.\""},"2272":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا حَمَّادٌ ح و أَخْبَرَنِي زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ شُعَيْبِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِيهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُمْ يَوْمًا وَلَكَ أَجْرُ عَشَرَةِ فَقُلْتُ زِدْنِي فَقَالَ صُمْ يَوْمَيْنِ وَلَكَ أَجْرُ تِسْعَةٍ قُلْتُ زِدْنِي قَالَ صُمْ ثَلَاثَةَ أَيَّامٍ وَلَكَ أَجْرُ ثَمَانِيَةٍقَالَ ثَابِتٌ فَذَكَرْتُ ذَلِكَ لِمُطَرِّفٍ فَقَالَ مَا أُرَاهُ إِلَّا يَزْدَادُ فِي الْعَمَلِ وَيَنْقُصُ مِنْ الْأَجْرِ وَاللَّفْظُ لِمُحَمَّدٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yazid] dia berkata; telah menceritakan kepada kami [Hammad]. Demikian juga telah diriwayatkan dari jalur yang lainnya, dan telah mengabarkan kepadaku [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami ['Abdul A'la] dia berkata; telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Syu'aib bin 'Abdullah bin 'Amru] dari [bapaknya], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku; \"Berpuasalah sehari dan bagimu pahala sepuluh hari.\" Aku berkata; 'Tambahkanlah untukku.' beliau bersabda: 'Berpuasalah dua hari dan bagimu pahala sembilan hari yang tersisa.' Aku berkata; 'Berpuasalah tiga hari, dan bagimu pahala delapan hari.' Tsabit berkata; Lalu hal itu diberitahukan kepada Mutharrif, ia berkata; \"Tidaklah aku melihatnya kecuali amalan yang bertambah namun pahalanya berkurang.\" Dan lafadz ini pada Imam Muhammad."},"2273":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ أَسْبَاطٍ عَنْ مُطَرِّفٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي الْعَبَّاسِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ بَلَغَنِي أَنَّكَ تَقُومُ اللَّيْلَ وَتَصُومُ النَّهَارَ قُلْتُ يَا رَسُولَ اللَّهِ مَا أَرَدْتُ بِذَلِكَ إِلَّا الْخَيْرَ قَالَ لَا صَامَ مَنْ صَامَ الْأَبَدَ وَلَكِنْ أَدُلُّكَ عَلَى صَوْمِ الدَّهْرِ ثَلَاثَةُ أَيَّامٍ مِنْ الشَّهْرِ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ صُمْ خَمْسَةَ أَيَّامٍ قُلْتُ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ فَصُمْ عَشْرًا فَقُلْتُ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ صُمْ صَوْمَ دَاوُدَ عَلَيْهِ السَّلَام كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًاأَخْبَرَنَا عَلِيُّ بْنُ الْحُسَيْنِ قَالَ حَدَّثَنَا أُمَيَّةُ عَنْ شُعْبَةَ عَنْ حَبِيبٍ قَالَ حَدَّثَنِي أَبُو الْعَبَّاسِ وَكَانَ رَجُلًا مِنْ أَهْلِ الشَّامِ وَكَانَ شَاعِرًا وَكَانَ صَدُوقًا عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaid] dari [Asbath] dari [Mutharrif] dari [Habib bin Abu Tsabit] dari [Abul 'Abbas] dari ['Abdullah bin 'Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Telah sampai berita kepadaku bahwa kamu bangun di malam hari -untuk beribadah- dan berpuasa di siang hari?\" Aku berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam, tidak ada yang kumaksud dari hal itu kecuali kebaikan! ' Beliau bersabda: 'Tidak -dianggap- berpuasa bagi orang yang berpuasa selamanya, tetapi aku tunjukkan kepadamu tentang puasa Dahr; yaitu tiga hari dalam sebulan.' Aku berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam, ' aku mampu melakukan lebih dari itu! ' Beliau bersabda: 'Berpuasalah lima hari.' Aku berkata; ' aku mampu melakukan lebih dari itu.' Beliau bersabda: 'Berpuasalah sepuluh hari.' Aku berkata; ' aku mampu melakukan lebih dari itu.' Beliau bersabda: 'Berpuasalah seperti puasa Nabi Daud -alaihissalam-, ia berpuasa sehari dan berbuka sehari.' Telah mengabarkan kepada kami [Ali bin Al Husain] ia berkata; telah menceritakan kepada kami [Umayyah] dari [Syu'bah] dari [Habib] ia berkata; telah menceritakan kepadaku [Abu Al Abbas] dia adalah salah satu penduduk Syam, ahli sya'ir, dan ia adalah orang yang terpercaya dari [Abdullah bin Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku; -kemudian dia menyebutkan hadits di atas.-"},"2274":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي حَبِيبُ بْنُ أَبِي ثَابِتٍ قَالَ سَمِعْتُ أَبَا الْعَبَّاسِ هُوَ الشَّاعِرُ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ لِي رَ��ُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ اللَّهِ بْنَ عَمْرٍو إِنَّكَ تَصُومُ الدَّهْرَ وَتَقُومُ اللَّيْلَ وَإِنَّكَ إِذَا فَعَلْتَ ذَلِكَ هَجَمَتْ الْعَيْنُ وَنَفِهَتْ لَهُ النَّفْسُ لَا صَامَ مَنْ صَامَ الْأَبَدَ صَوْمُ الدَّهْرِ ثَلَاثَةُ أَيَّامٍ مِنْ الشَّهْرِ صَوْمُ الدَّهْرِ كُلِّهِ قُلْتُ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ صُمْ صَوْمَ دَاوُدَ كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا وَلَا يَفِرُّ إِذَا لَاقَى","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Habib bin Abu Tsabit] dia berkata; aku mendengar [Abul 'Abbas Asy Sya'ir] menceritakan dari ['Abdullah bin 'Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai Abdullah bin Amru, kamu berpuasa Dahr dan bangun di malam hari -untuk beribadah-. jika kamu melakukan hal itu, mata akan bertambah rusak dan jiwa akan lemah. Tidak -dianggap- berpuasa orang yang melakukan puasa abad (selamanya), puasa Dahr yaitu tiga hari dalam sebulan, hal itu sama dengan puasa Dahr seluruhnya.\" Aku berkata; ' aku mampu melakukan lebih dari itu.' Beliau bersabda: 'Berpuasalah seperti puasa Nabi Daud, ia berpuasa sehari dan berbuka sehari dan dia tidak lari jika berjumpa musuh.'"},"2275":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الْعَبَّاسِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ الْقُرْآنَ فِي شَهْرٍ قُلْتُ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ فَلَمْ أَزَلْ أَطْلُبُ إِلَيْهِ حَتَّى قَالَ فِي خَمْسَةِ أَيَّامٍ وَقَالَ صُمْ ثَلَاثَةَ أَيَّامٍ مِنْ الشَّهْرِ قُلْتُ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكِ فَلَمْ أَزَلْ أَطْلُبُ إِلَيْهِ حَتَّى قَالَ صُمْ أَحَبَّ الصِّيَامِ إِلَى اللَّهِ عَزَّ وَجَلَّ صَوْمَ دَاوُدَ كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Dinar] dari [Abul 'Abbas] dari ['Abdullah bin 'Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacalah Al Qur'an dalam sebulan.\" Aku berkata; ' aku mampu melakukan lebih dari itu.' Aku selalu meminta kepada beliau, hingga beliau bersabda setelah lima hari, beliau bersabda: 'Berpuasalah tiga hari dalam sebulan.' Aku meminta kepada beliau, hingga akhirnya beliau bersabda: 'Berpuasalah dengan puasa yang paling dicintai oleh Allah -Azza wa Jalla-; yaitu puasa Nabi Daud, ia berpuasa sehari dan berbuka sehari.'"},"2276":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ سَمِعْتُ عَطَاءً يَقُولُ إِنَّ أَبَا الْعَبَّاسِ الشَّاعِرَ أَخْبَرَهُ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ قَالَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي أَصُومُ أَسْرُدُ الصَّوْمَ وَأُصَلِّي اللَّيْلَ فَأَرْسَلَ إِلَيْهِ وَإِمَّا لَقِيَهُ قَالَ أَلَمْ أُخْبَرْ أَنَّكَ تَصُومُ وَلَا تُفْطِرُ وَتُصَلِّي اللَّيْلَ فَلَا تَفْعَلْ فَإِنَّ لِعَيْنِكَ حَظًّا وَلِنَفْسِكَ حَظًّا وَلِأَهْلِكَ حَظًّا وَصُمْ وَأَفْطِرْ وَصَلِّ وَنَمْ وَصُمْ مِنْ كُلِّ عَشَرَةِ أَيَّامٍ يَوْمًا وَلَكَ أَجْرُ تِسْعَةٍ قَالَ إِنِّي أَقْوَى لِذَلِكَ يَا رَسُولَ اللَّهِ قَالَ صُمْ صِيَامَ دَاوُدَ إِذًا قَالَ وَكَيْفَ كَانَ صِيَامُ دَاوُدَ يَا نَبِيَّ اللَّهِ قَالَ كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا وَلَا يَفِرُّ إِذَا لَاقَى قَالَ وَمَنْ لِي بِهَذَا يَا نَبِيَّ اللَّهِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan] dia berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; [Ibnu Juraij] berkata; aku mendengar ['Atha] berkata; [Abul 'Abbas Asy Sya'ir] mengabarkan kepadanya bahwasanya ia mendengar ['Abdullah bin 'Amru bin Al 'Ash] berkata; \"Telah sampai berita kepada Nabi shallallahu 'alaihi wasallam bahwa aku berpuasa terus-menerus dan melakukan shalat malam.\" (Abbas assyair katakan), Beliau lantas mengutus seseorang untuk menemuinya -atau beliau bertemu dengannya-, dan bertanya: 'Aku peroleh kabar bahwa kamu berpuasa dan tidak berbuka serta melaksanakan shalat malam? Janganlah engkau lakukan, sungguh matamu memiliki bagian, jiwamu memiliki bagian dan keluargamu memiliki bagian; berpuasa dan berbukalah, shalat dan tidurlah, berpuasalah setiap sepuluh hari sekali dan bagimu pahala sembilan harinya.' Ia berkata; 'Sungguh aku mampu melakukan lebih dari itu, wahai Rasulullah shallallahu 'alaihi wasallam! ' Beliau bersabda: '-Jika begitu- berpuasalah seperti puasa Nabi Daud.' Ia bertanya; 'Bagaimana puasa Nabi Daud, wahai Nabi Allah? ' Beliau bersabda: 'Ia berpuasa sehari dan berbuka sehari dan tidak lari jika berjumpa dengan musuh.' Abdullah berkata; 'Siapakah aku dihadapan hal ini, wahai Nabi Allah? '"},"2277":{"ar":"أَخْبَرَنَا زَكَرِيَّاءُ بْنُ يَحْيَى قَالَ حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ قَالَ أَنْبَأَنَا خَالِدٌ عَنْ خَالِدٍ وَهُوَ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمَلِيحِ قَالَ دَخَلْتُ مَعَ أَبِيكَ زَيْدٍ عَلَى عَبْدِ اللَّهِ بْنِ عَمْرٍو فَحَدَّثَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذُكِرَ لَهُ صَوْمِي فَدَخَلَ عَلَيَّ فَأَلْقَيْتُ لَهُ وِسَادَةَ أَدَمٍ رَبْعَةً حَشْوُهَا لِيفٌ فَجَلَسَ عَلَى الْأَرْضِ وَصَارَتْ الْوِسَادَةُ فِيمَا بَيْنِي وَبَيْنَهُ قَالَ أَمَا يَكْفِيكَ مِنْ كُلِّ شَهْرٍ ثَلَاثَةُ أَيَّامٍ قُلْتُ يَا رَسُولَ اللَّهِ قَالَ خَمْسًا قُلْتُ يَا رَسُولَ اللَّهِ قَالَ سَبْعًا قُلْتُ يَا رَسُولَ اللَّهِ قَالَ تِسْعًا قُلْتُ يَا رَسُولَ اللَّهِ قَالَ إِحْدَى عَشْرَةَ قُلْتُ يَا رَسُولَ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَوْمَ فَوْقَ صَوْمِ دَاوُدَ شَطْرَ الدَّهْرِ صِيَامُ يَوْمٍ وَفِطْرُ يَوْمٍ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami [Wahb bin Baqiyyah] dia berkata; telah memberitakan kepada kami [Khalid] dari [Khalid Al Hadza'] dari [Abu Qilabah] dari [Abu Al Malih] dia berkata; aku masuk bersama bapakmu yaitu Zaid menemui ['Abdullah bin 'Amru]. Lalu ia bercerita bahwa Rasulullah shallallahu 'alaihi wasallam telah diberitahu tentang puasaku. Lalu beliau masuk menemuiku, kemudian kuberikan bantal kulit yang berukuran sedang dan berisi sabut. Beliau duduk di atas tanah sedangkan bantal tersebut berada di antara diriku dan beliau. Beliau bersabda: \"Tidakkah cukup bagimu (berpuasa) tiga hari dalam sebulan?\" Aku berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam! ' Beliau bersabda: 'Lima hari? ' Aku berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam! ' Beliau bersabda: 'Tujuh hari.' Aku berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam! ' Beliau bersabda: 'Sembilan.' Aku berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam! ' Beliau bersabda: 'Sebelas.' Aku berkata: 'Wahai Rasulullah shallallahu 'alaihi wasallam! ' Nabi shallallahu 'alaihi wasallam bersabda: 'Tidak ada puasa -yang kebaikannya- melebihi puasa Nabi Daud, Itu dihitung setengah masa, berpuasa sehari dan berbuka sehari.'"},"2278":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي شُعْبَةُ عَنْ زِيَادِ بْنِ فَيَّاضٍ قَالَ سَمِعْتُ أَبَا عِيَاضٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍوقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُمْ مِنْ الشَّهْرِ يَوْمًا وَلَكَ أَجْرُ مَا بَقِيَ قُلْتُ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ فَصُمْ يَوْمَيْنِ وَلَكَ أَجْرُ مَا بَقِيَ قُلْتُ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ فَصُمْ ثَلَاثَةَ أَيَّامٍ وَلَكَ أَجْرُ مَا بَقِيَ قُلْتُ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ صُمْ أَرْبَعَةَ أَيَّامٍ وَلَكَ أَجْرُ مَا بَقِيَ قُلْتُ إِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الصَّوْمِ صَوْمُ دَاوُدَ كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan] dia berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] dia berkata; telah menceritakan kepadaku [Syu'bah] dari [Ziyad bin Fayyadl] dia berkata; Aku mendengar [Abu 'Iyadl] berkata; ['Abdullah bin 'Amru] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: 'Berpuasalah sehari dalam sebulan, dan bagimu pahala hari-hari yang tersisa.' Aku berkata; ' aku masih kuat melakukan dari itu.' Beliau bersabda: 'Berpuasalah dua hari -dalam sebulan- dan bagimu pahala hari-hari yang tersisa.' Aku berkata; ' aku mampu melakukan lebih dari itu.' Beliau bersabda: 'Berpuasalah tiga hari, dan bagimu pahala hari yang tersisa.' Aku berkata; ' aku masih kuat lebih dari itu.' Beliau bersabda: 'Berpuasalah empat hari, dan bagimu pahala hari-hari yang tersisa.' Aku berkata; ' aku masih kuat lebih dari itu.' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Puasa yang paling utama adalah puasa Nabi Daud, ia berpuasa sehari dan berbuka sehari.'"},"2279":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حَرْمَلَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي ذَرٍّ قَالَأَوْصَانِي حَبِيبِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَلَاثَةٍ لَا أَدَعُهُنَّ إِنْ شَاءَ اللَّهُ تَعَالَى أَبَدًا أَوْصَانِي بِصَلَاةِ الضُّحَى وَبِالْوَتْرِ قَبْلَ النَّوْمِ وَبِصِيَامِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Muhammad bin Abu Harmalah] dari ['Atha bin Yasar] dari [Abu Dzar] dia berkata; \"Kekasihku shallallahu 'alaihi wasallam berwasiat tiga hal kepadaku -insya Allah Ta'ala tidak akan ku tinggalkan selamanya-. Beliau berwasiat kepadaku agar melakukan shalat Dluha, shalat witir sebelum tidur dan puasa tiga hari setiap bulan.\""},"2280":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ الْحَسَنِ قَالَ سَمِعْتُ أَبِي قَالَ أَنْبَأَنَا أَبُو حَمْزَةَ عَنْ عَاصِمٍ عَنْ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ أَبِي هُرَيْرَةَ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَلَاثٍ بِنَوْمٍ عَلَى وِتْرٍ وَالْغُسْلِ يَوْمَ الْجُمُعَةِ وَصَوْمِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ali bin Al Hasan] dia berkata; aku mendengar [bapakku] berkata; telah memberitakan kepada kami [Abu Hamzah] dari ['Ashim] dari [Al Aswad bin Hilal] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkanku dalam tiga hal: Tidur setelah melakukan shalat witir, mandi pada hari jum'at dan puasa tiga hari setiap bulan.\""},"2281":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا أَبُو كَامِلٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ رَجُلٍ عَنْ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ أَبِي هُرَيْرَةَ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَكْعَتَيْ الضُّحَى وَأَنْ لَا أَنَامَ إِلَّا عَلَى وِتْرٍ وَصِيَامِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami [Abu Kamil] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari ['Ashim bin Bahdalah] dari [seorang laki-laki], dari [Al Aswad bin Hilal] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkanku dalam tiga hal: Tidur setelah melakukan shalat witir, mandi pada hari jum'at dan puasa tiga hari setiap bulan.\""},"2282":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عَاصِمٍ عَنْ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَوْمٍ عَلَى وَتْرٍ وَالْغُسْلِ يَوْمَ الْجُمُعَةِ وَصِيَامِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi']; telah menceritakan kepada kami [Abu An Nadhr]; telah menceritakan kepada kami [Abu Mu'awiyah] dari ['Ashim] dari [Al Aswad bin Hilal] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkanku dalam tiga hal: Tidur setelah melakukan shalat witir, mandi pada hari jum'at dan puasa tiga hari setiap bulan.\""},"2283":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَبِي عُثْمَانَ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ شَهْرُ الصَّبْرِ وَثَلَاثَةُ أَيَّامٍ مِنْ كُلِّ شَهْرٍ صَوْمُ الدَّهْرِ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah menceritakan kepada kami ['Abdul A'la] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Abu 'Utsman] bahwasanya [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bulan kesabaran (puasa Ramadlan) dan -berpuasa- tiga hari dalam sebulan; -sama dengan- puasa Dahr.\""},"2284":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ الْحَسَنِ اللَّانِيُّ بِالْكُوفَةِ عَنْ عَبْدِ الرَّحِيمِ وَهُوَ ابْنُ سُلَيْمَانَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ ثَلَاثَةَ أَيَّامٍ مِنْ الشَّهْرِ فَقَدْ صَامَ الدَّهْرَ كُلَّهُ ثُمَّ قَالَ صَدَقَ اللَّهُ فِي كِتَابِهِ{ مَنْ جَاءَ بِالْحَسَنَةِ فَلَهُ عَشْرُ أَمْثَالِهَا }","id":"Telah mengabarkan kepada kami ['Ali bin Al Hasan Al Laniy] di Kufah, dari ['Abdurrahim bin Sulaiman] dari ['Ashim Al Ahwal] dari [Abu 'Utsman] dari [Abu Dzarr] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berpuasa tiga hari setiap bulan, sungguh ia -sama dengan- telah berpuasa Dahr seluruhnya.\" Kemudian ia berkata; 'Maha benar Allah -terhadap apa yang ada- di dalam kitab-Nya, Barangsiapa membawa amal yang baik, baginya (pahala) sepuluh kali lipat amalnya.' (Qs. Al An'am 6: 160)."},"2285":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ رَجُلٍ قَالَ أَبُو ذَرٍّسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَامَ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ فَقَدْ تَمَّ صَوْمُ الشَّهْرِ أَوْ فَلَهُ صَوْمُ الشَّهْرِ شَكَّ عَاصِمٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] dia berkata; telah memberitakan kepada kami [Hibban] dia berkata; telah memberitakan kepada kami ['Abdullah] dari ['Ashim] dari [Abu 'Utsman] dari [seorang laki-laki], dia berkata; [Abu Dzarr] berkata; \"Barangsiapa berpuasa tiga hari dalam setiap bulan, telah sempurna puasanya dalam sebulan, atau ia telah mendapatkan pahala puasa sebulan.\" Ashim merasa ragu."},"2286":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ أَنَّ مُطَرِّفًا حَدَّثَهُ أَنَّ عُثْمَانَ بْنَ أَبِي الْعَاصِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ صِيَامٌ حَسَنٌ ثَلَاثَةُ أَيَّامٍ مِنْ الشَّهْرِأَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ أَنْبَأَنَا أَبُو مُصْعَبٍ عَنْ مُغِيرَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ قَالَ عُثْمَانُ بْنُ أَبِي الْعَاصِ نَحْوَهُ مُرْسَلٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Sa'id bin Abu Hind] bahwasanya [Mutharrif] menceritakan kepadanya, bahwasanya ['Utsman bin Abul 'Ash] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Puasa yang baik adalah tiga hari dalam sebulan'.\" Telah mengabarkan kepada kami [Zakaria bin Yahya] dia berkata; telah memberitakan kepada kami [Abu Mush'ab] dari [Mughirah bin Abdurrahman] dari [Abdullah bin Sa'id bin Abu Hindun] dari [Muhammad bin Ishaq] dari [Sa'id bin Abu Hindun] berkata; [Utsman bin Abul Ash] seperti itu juga secara mursal."},"2287":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ شَرِيكٍ عَنْ الْحُرِّ بْنِ صَيَّاحٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Syarik] dari [Al Hurr bin Shayyah] dia berkata; aku mendengar [Ibnu 'Umar] berkata; \"Nabi shallallahu 'alaihi wasallam berpuasa tiga hari setiap bulan.\""},"2288":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ قَالَ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ شَرِيكٍ عَنْ الْحُرِّ بْنِ صَيَّاحٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ يَوْمَ الِاثْنَيْنِ مِنْ أَوَّلِ الشَّهْرِ وَالْخَمِيسِ الَّذِي يَلِيهِ ثُمَّ الْخَمِيسِ الَّذِي يَلِيهِ","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad Az Za'farani] dia berkata; telah menceritakan kepada kami [Sa'id bin Sulaiman] dari [Syarik] dari [Al Hurr bin Shayyah] dari [Ibnu 'Umar] bahwasanya Rasulullah shallallahu 'alaihi wasallam berpuasa tiga hari dalam sebulan; hari Senin di awal bulan, hari Kamis berikutnya, kemudian hari Kamis berikutnya lagi."},"2289":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ قَالَ حَدَّثَنَا خَلَفُ بْنُ تَمِيمٍ عَنْ زُهَيْرٍ عَنْ الْحُرِّ بْنِ الصَّيَّاحِ قَالَ سَمِعْتُ هُنَيْدَةَ الْخُزَاعِيَّ قَالَدَخَلْتُ عَلَى أُمِّ الْمُؤْمِنِينَ سَمِعْتُهَا تَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ مِنْ كُلِّ شَهْرٍ ثَلَاثَةَ أَيَّامٍ أَوَّلَ اثْنَيْنِ مِنْ الشَّهْرِ ثُمَّ الْخَمِيسَ ثُمَّ الْخَمِيسَ الَّذِي يَلِيهِ","id":"Telah mengabarkan kepada kami ['Ali bin Muhammad bin 'Ali] dia berkata; telah menceritakan kepada kami [Khalaf bin Tamim] dari [Zuhair] dari [Al Hurr bin Shayyah] dia berkata; aku mendengar [Hunaidah Al Khuza'i] berkata; aku masuk menemui [Ummul Mu'minin], dan aku mendengar ia berkata; \"Rasulullah shallallahu 'alaihi wasallam berpuasa tiga hari setiap bulan; hari Senin pertama dari bulan itu, kemudian hari Kamis, kemudian hari Kamis berikutnya.\""},"2290":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ أَبِي النَّضْرِ قَالَ حَدَّثَنِي أَبُو النَّضْرِ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ الْأَشْجَعِيُّ كُوفِيٌّ عَنْ عَمْرِو بْنِ قَيْسٍ الْمُلَائِيِّ عَنْ الْحُرِّ بْنِ الصَّيَّاحِ عَنْ هُنَيْدَةَ بْنِ خَالِدٍ الْخُزَاعِيِّ عَنْ حَفْصَةَ قَالَتْأَرْبَعٌ لَمْ يَكُنْ يَدَعُهُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صِيَامَ عَاشُورَاءَ وَالْعَشْرَ وَثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ وَرَكْعَتَيْنِ قَبْلَ الْغَدَاةِ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Abu An Nadhr] dia berkata; telah menceritakan kepadaku [Abu An Nadhr] dia berkata; telah menceritakan kepada kami [Abu Ishaq Al Asyja'i Al Kufi] dari ['Amr bin Qais Al Mula'i] dari [Al Hurr bin Ash-Shayyah] dari [Hunaidah bin Khalid Al Khuza'i] dari [Hafshah] dia berkata; \"Empat hal yang tidak pernah ditinggalkan oleh Rasulullah shallallahu 'alaihi wasallam; puasa 'Asyura, puasa sepuluh hari, puasa tiga hari dalam setiap bulan dan dua raka'at sebelum Subuh.\""},"2291":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ يَحْيَى عَنْ أَبِي نُعَيْمٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْحُرِّ بْنِ الصَّيَّاحِ عَنْ هُنَيْدَةَ بْنِ خَالِدٍ عَنْ امْرَأَتِهِ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ تِسْعًا مِنْ ذِي الْحِجَّةِ وَيَوْمَ عَاشُورَاءَ وَثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ أَوَّلَ اثْنَيْنِ مِنْ الشَّهْرِ وَخَمِيسَيْنِ","id":"Telah mengabarkan kepadaku [Ahmad bin Yahya] dari [Abu Nu'aim] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Al Hurr bin Ash-Shayyah] dari [Hunaidah bin Khalid] dari [istrinya], dari sebagian istri Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam berpuasa sembilan hari dari bulan Dzulhijjah, hari 'Asyura dan tiga hari dalam setiap bulan, yaitu hari Senin pertama dari bulan itu dan dua hari kamis (berikutnya)."},"2292":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ أَبِي صَفْوَانَ الثَّقَفِيُّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْحُرِّ بْنِ الصَّيَّاحِ عَنْ هُنَيْدَةَ بْنِ خَالِدٍ عَنْ امْرَأَتِهِ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ الْعَشْرَ وَثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ الِاثْنَيْنِ وَالْخَمِيسَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Utsman bin Abu Shafwan Ats-Tsaqafi] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Al Hurr bin Ash-Shayyah] dari [Hunaidah bin Khalid] dari [istrinya], dari [sebagian istri] Nabi shallallahu 'alaihi wasallam, mereka berkata; \"Nabi shallallahu 'alaihi wasallam berpuasa sepuluh hari dan tiga hari dalam setiap bulan, yaitu hari Senin dan Kamis.\""},"2293":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ هُنَيْدَةَ الْخُزَاعِيِّ عَنْ أُمِّهِ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِصِيَامِ ثَلَاثَةِ أَيَّامٍ أَوَّلِ خَمِيسٍ وَالِاثْنَيْنِ وَالِاثْنَيْنِ","id":"Telah mengabarkan kepada kami [Isma'il bin Sa'id Al Jauhari] dia berkata; telah menceritakan kepada kami [Muhammad bin Fudhail] dari [Al Hasan bin 'Abdullah] dari [Hunaidah Al Khuza'i] dari [ibunya] dari [Ummu Salamah] dia berkata; Rasulullah shallallahu 'alaihi wasallam menyuruh berpuasa tiga hari yaitu Kamis pertama kemudian hari Senin dan hari Senin berikutnya."},"2294":{"ar":"أَخْبَرَنَا مَخْلَدُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ أَبِي إِسْحَقَ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صِيَامُ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ صِيَامُ الدَّهْرِ وَأَيَّامُ الْبِيضِ صَبِيحَةَ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Makhlad bin Al Hasan] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Zaid bin Abu Unaisah] dari [Abu Ishaq] dari [Jarir bin 'Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Puasa tiga hari setiap bulan adalah puasa Dahr dan puasa hari-hari Bidh (putih cerah karena sinar rembulan), adalah waktu pagi tanggal tiga belas, empat belas dan lima belas.\""},"2295":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ أَعْرَابِيٌّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَرْنَبٍ قَدْ شَوَاهَا فَوَضَعَهَا بَيْنَ يَدَيْهِ فَأَمْسَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَأْكُلْ وَأَمَرَ الْقَوْمَ أَنْ يَأْكُلُوا وَأَمْسَكَ الْأَعْرَابِيُّ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَمْنَعُكَ أَنْ تَأْكُلَ قَالَ إِنِّي صَائِمٌ ثَلَاثَةَ أَيَّامٍ مِنْ الشَّهْرِ قَالَ إِنْ كُنْتَ صَائِمًا فَصُمْ الْغُرَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] dia berkata; telah menceritakan kepada kami [Habban] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari ['Abdul Malik bin 'Umair] dari [Musa bin Thalhah] dari [Abu Hurairah] dia berkata; \"Seorang Badui datang kepada Nabi Shallallahu 'Alahi Wa Sallam dengan membawa seekor kelinci yang di panggang, dia meletakkannya di hadapan Rasulullah Shallallahu 'Alahi Wa Sallam, namun Rasulullah Shallallahu 'Alahi Wa Sallam diam dan tidak memakannya, beliau menyuruh orang-orang untuk memakannya, demikian juga orang badui itu tidak memakannya. Kemudian Rasulullah Shallallahu 'Alahi Wa Sallam bersabda kepadanya: 'Apa yang melarang kamu untuk memakannya? Dia menjdawab; 'Aku sedang berpuasa tiga hari dalam sebulan.' Beliau bersabda: 'Apabila kamu berpuasa berpuasalah pada hari - hari Bidl (tanggal 13, 14, 15)."},"2296":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى عَنْ فِطْرٍ عَنْ يَحْيَى بْنِ سَامٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِي ذَرٍّ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَصُومَ مِنْ الشَّهْرِ ثَلَاثَةَ أَيَّامٍ الْبِيضَ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul 'Aziz] dia berkata; telah memberitakan kepada kami [Al Fudhail bin Musa] dari [Fithr] dari [Yahya bin Sam] dari [Musa bin Thalhah] dari [Abu Dzarr] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar berpuasa tiga hari Bidh dalam sebulan; yaitu -tanggal- tiga belas, empat belas dan lima belas.\""},"2297":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَامٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِي ذَرٍّ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَصُومَ مِنْ الشَّهْرِ ثَلَاثَةَ أَيَّامٍ الْبِيضَ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami ['Amr bin Yazid] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dia berkata; aku mendengar [Yahya bin Sam] dari [Musa bin Thalhah] dari [Abu Dzarr] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar berpuasa tiga hari Bidl dalam sebulan; yaitu -tanggal- tiga belas, empat belas dan lima belas.\""},"2298":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَامٍ عَنْ مُوسَى بْنِ طَلْحَةَ قَالَسَمِعْتُ أَبَا ذَرٍّ بِالرَّبَذَةِ قَالَ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صُمْتَ شَيْئًا مِنْ الشَّهْرِ فَصُمْ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami ['Amr bin Yazid] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dia berkata; aku mendengar [Yahya bin Sam] dari [Musa bin Thalhah] dia berkata; aku mendengar [Abu Dzarr] di Ar Rabdzah berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: 'Jika engkau ingin berpuasa beberapa dalam sebulan, berpuasalah -tanggal- tiga belas, empat belas dan lima belas'.\""},"2299":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ عَنْ بَيَانِ بْنِ بِشْرٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ ابْنِ الْحَوْتَكِيَّةِ عَنْ أَبِي ذَرٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ عَلَيْكَ بِصِيَامِ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ لَيْسَ مِنْ حَدِيثِ بَيَانٍ وَلَعَلَّ سُفْيَانَ قَالَ حَدَّثَنَا اثْنَانِ فَسَقَطَ الْأَلِفُ فَصَارَ بَيَانٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] dari [Bayan bin Bisyr] dari [Musa bin Thalhah] dari [Ibnul Hautakiyyah] dari [Abu Dzarr] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada seseorang: \"Hendaklah kamu berpuasa -tanggal- tiga belas, empat belas dan lima belas.\" Abu Abdurrahman berkata; (Sanad) ini salah, Hadits ini bukan dari Bayan, Mungkin Sufyan berkata; Telah menceritakan kepada kami (dua orang), namun Alifnya hilang, menjadi Bayan."},"2300":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا رَجُلَانِ مُحَمَّدٌ وَحَكِيمٌ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ ابْنِ الْحَوْتَكِيَّةِ عَنْ أَبِي ذَرٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ رَجُلًا بِصِيَامِ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami dua orang laki-laki - [Muhammad] dan [Hakim] - dari [Musa bin Thalhah] dari [Ibnul Hautakiyyah] dari [Abu Dzarr] bahwa Nabi shallallahu 'alaihi wasallam memerintahkan seseorang agar berpuasa -tanggal- tiga belas, empat belas dan lima belas.\""},"2301":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ عَنْ بَكْرٍ عَنْ عِيسَى عَنْ مُحَمَّدٍ عَنْ الْحَكَمِ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ ابْنِ الْحَوْتَكِيَّةِ قَالَ قَالَ أَبِيجَاءَ أَعْرَابِيٌّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ أَرْنَبٌ قَدْ شَوَاهَا وَخُبْزٌ فَوَضَعَهَا بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ إِنِّي وَجَدْتُهَا تَدْمَى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ لَا يَضُرُّ كُلُوا وَقَالَ لِلْأَعْرَابِيِّ كُلْ قَالَ إِنِّي صَائِمٌ قَالَ صَوْمُ مَاذَا قَالَ صَوْمُ ثَلَاثَةِ أَيَّامٍ مِنْ الشَّهْرِ قَالَ إِنْ كُنْتَ صَائِمًا فَعَلَيْكَ بِالْغُرِّ الْبِيضِ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَقَالَ أَبُو عَبْد الرَّحْمَنِ الصَّوَابُ عَنْ أَبِي ذَرٍّ وَيُشْبِهُ أَنْ يَكُونَ وَقَعَ مِنْ الْكُتَّابِ ذَرٌّ فَقِيلَ أَبِي","id":"Telah mengabarkan kepada kami [Ahmad bin 'Utsman bin Hakim] dari [Bakr] dari ['Isa] dari [Muhammad] dari [Al Hakam] dari [Musa bin Thalhah] dari [Ibnul Hautakiyyah] dia berkata; [bapakku] berkata; \"Seorang Badui datang kepada Nabi Shallallahu 'Alahi Wa Sallam dengan membawa seekor kelinci yang telah di panggang dan roti, lalu dia meletakkannya di hadapan Rasulullah Shallallahu 'Alahi Wa Sallam sambil berkata; 'Aku mendapatkannya dalam keadaan berdarah, kemudian Rasulullah Shallallahu 'Alahi Wa Sallam bersabda kepada para sahabatnya, tidak mengapa, makanlah oleh kalian semua, juga beliau berkata kepada orang badui: 'makanlah' dia berkata; 'Aku sedang puasa.' Beliau bertanya: 'Puasa apa? ' dia menjawab; 'Puasa tiga hari dalam sebulan. Beliau bersabda: \"Apabila kamu berpuasa, berpuasalah pada hari-hari Bidl yaitu tanggal 13, 14, dan 15.\" Abu Abdurrahman berkata; 'Yang benar adalah dari Abu Dzar, sepertinya telah jatuh dari para juru tulis kalimat Dzar, menjadi (Bapakku)."},"2302":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَعْلَى عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ مُوسَى بْنِ طَلْحَةَ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَرْنَبٍ قَدْ شَوَاهَا رَجُلٌ فَلَمَّا قَدَّمَهَا إِلَيْهِ قَالَ يَا رَسُولَ اللَّهِ إِنِّي قَدْ رَأَيْتُ بِهَا دَمًا فَتَرَكَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَأْكُلْهَا وَقَالَ لِمَنْ عِنْدَهُ كُلُوا فَإِنِّي لَوْ اشْتَهَيْتُهَا أَكَلْتُهَا وَرَجُلٌ جَالِسٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْنُ فَكُلْ مَعَ الْقَوْمِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي صَائِمٌ قَالَ فَهَلَّا صُمْتَ الْبِيضَ قَالَ وَمَا هُنَّ قَالَ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dia berkata; telah menceritakan kepada kami [Ya'la] dari [Thalhah bin Yahya] dari [Musa bin Thalhah] dia berkata; \"Nabi Shallallahu 'Alahi Wa Sallam diberi seekor kelinci yang di panggang oleh seseorang.\" Tatkala kelinci itu dihidangkan kepada beliau, orang yang membawanya tadi berkata; 'Aku melihat kelinci itu berdarah, Nabi pun tidak jadi memakannya, beliau berkata: 'Siapa saja yang mau makan, silahkan, jika aku berselera aku pun sudah memakannya. Diantara mereka ada seseorang yang duduk saja. Kemudian Nabi shallallahu 'alaihi wasallam berkata: 'Mendekatlah kamu dan makanlah bersama orang-orang! ' Dia berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam Aku sedang puasa'. Nabi shallallahu 'alaihi wasallam bersabda kepadanya: 'Kalau begitu berpuasalah pada hari - hari Bidl. Dia bertanya: Apakah hari-hari Bidl itu? Beliau menjawab: Tanggal 13, 14, dan 15.'"},"2303":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ قَالَ أَنْبَأَنَا أَنَسُ بْنُ سِيرِينَ عَنْ رَجُلٍ يُقَالُ لَهُ عَبْدُ الْمَلِكِ يُحَدِّثُ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ بِهَذِهِ الْأَيَّامِ الثَّلَاثِ الْبِيضِ وَيَقُولُ هُنَّ صِيَامُ الشَّهْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dia berkata; telah memberitakan kepada kami [Anas bin Sirin] dari seorang lelaki yang bernama ['Abdul Malik] dia menceritakan dari [bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam telah menyuruh berpuasa pada tiga hari Bidl ini, dan beliau bersabda: 'Itu adalah puasa sebulan.'"},"2304":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا أَنَسُ بْنُ سِيرِينَ قَالَ حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ قُدَامَةَ بْنِ مِلْحَانَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا بِصَوْمِ أَيَّامِ اللَّيَالِي الْغُرِّ الْبِيضِ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] dia berkata; telah menceritakan kepada kami [Habban] dia berkata; telah menceritakan kepada kami [Hammam] dia berkata; telah menceritakan kepada kami [Anas bin Sirin] dia berkata; telah menceritakan kepadaku ['Abdul Malik bin Qudamah bin Milhan] dari [bapaknya], dia berkata; bahwa Nabi shallallahu 'alaihi wasallam menyuruh kami berpuasa pada tiga hari Bidl. Yaitu tanggal 13, 14, 15."},"2305":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنِي سَيْفُ بْنُ عُبَيْدِ اللَّهِ مِنْ خِيَارِ الْخَلْقِ قَالَ حَدَّثَنَا الْأَسْوَدُ بْنُ شَيْبَانَ عَنْ أَبِي نَوْفَلِ بْنِ أَبِي عَقْرَبٍ عَنْ أَبِيهِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فَقَالَ صُمْ يَوْمًا مِنْ الشَّهْرِ قُلْتُ يَا رَسُولَ اللَّهِ زِدْنِي زِدْنِي قَالَ تَقُولُ يَا رَسُولَ اللَّهِ زِدْنِي زِدْنِي يَوْمَيْنِ مِنْ كُلِّ شَهْرٍ قُلْتُ يَا رَسُولَ اللَّهِ زِدْنِي زِدْنِي إِنِّي أَجِدُنِي قَوِيًّا فَقَالَ زِدْنِي زِدْنِي أَجِدُنِي قَوِيًّا فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى ظَنَنْتُ أَنَّهُ لَيَرُدُّنِي قَالَ صُمْ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepadaku [Saif bin 'Ubaidullah] dari orang yang ahlaknya baik, dia berkata; telah menceritakan kepada kami [Al Aswad bin Syaiban] dari [Abu Naufal bin Abu 'Aqrab] dari [bapaknya] dia berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang puasa? Lalu beliau menjawab: \"Puasalah sehari dalam sebulan.\" Aku berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam, tambahkanlah untukku, tambahkanlah untukku! ' Beliau bersabda: 'Kamu mengatakan, 'Wahai Rasulullah, tambahkanlah untukku, tambahkanlah untukku? ', Dua hari setiap bulan.' Aku berkata; 'Wahai Rasulullah, tambahkanlah untukku, tambahkanlah untukku, sungguh aku masih kuat.' Beliau bersabda: 'Kamu mengatakan tambahkanlah untukku, tambahkanlah untukku, sungguh aku masih kuat.' Lalu Rasulullah diam hingga aku mengira bahwa beliau menolak -permintaan- ku. Kemudian beliau bersabda: 'Berpuasalah tiga hari pada setiap bulan.'"},"2306":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا الْأَسْوَدُ بْنُ شَيْبَانَ عَنْ أَبِي نَوْفَلِ بْنِ أَبِي عَقْرَبٍ عَنْ أَبِيهِأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فَقَالَ صُمْ يَوْمًا مِنْ كُلِّ شَهْرٍ وَاسْتَزَادَهُ قَالَ بِأَبِي أَنْتَ وَأُمِّي أَجِدُنِي قَوِيًّا فَزَادَهُ قَالَ صُمْ يَوْمَيْ��ِ مِنْ كُلِّ شَهْرٍ فَقَالَ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ إِنِّي أَجِدُنِي قَوِيًّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أَجِدُنِي قَوِيًّا إِنِّي أَجِدُنِي قَوِيًّا فَمَا كَادَ أَنْ يَزِيدَهُ فَلَمَّا أَلَحَّ عَلَيْهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُمْ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Muhammad bin Sallam] dia berkata; telah menceritakan kepada kami [Yazid bin Harun] dia berkata; telah memberitakan kepada kami [Al Aswad bin Syaiban] dari [Abu Naufal bin Abu 'Aqrab] dari [bapaknya], ia bertanya kepada Nabi shallallahu 'alaihi wasallam tentang puasa, beliau bersabda: \"Berpuasalah sehari setiap bulan.\" Namun ia minta tambah, seraya berkata; 'Bapak dan ibuku sebagai tebusannya, aku masih kuat -melakukan lebih dari itu-.' Lalu beliau menambahinya seraya bersabda: 'Berpuasalah dua hari setiap bulan.' ia berkata; 'Bapak dan ibuku sebagai tebusannya, wahai Rasulullah, sungguh aku masih kuat! ' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sungguh aku masih kuat, sungguh aku masih kuat.' Hampir saja beliau tidak menambahkan untuknya. Setelah ia mendesak terus, Rasulullah shallallahu 'alaihi wasallam bersabda: 'Berpuasalah tiga hari setiap bulan.'"},"2307":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَمَّارٍ الْمَوْصِلِيُّ عَنْ الْمُعَافَى عَنْ زَكَرِيَّا بْنِ إِسْحَقَ الْمَكِّيِّ قَالَ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ بْنِ صَيْفِىٍّ عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمُعَاذٍ حِينَ بَعَثَهُ إِلَى الْيَمَنِ إِنَّكَ تَأْتِي قَوْمًا أَهْلَ كِتَابٍ فَإِذَا جِئْتَهُمْ فَادْعُهُمْ إِلَى أَنْ يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَإِنْ هُمْ أَطَاعُوكَ بِذَلِكَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ عَزَّ وَجَلَّ فَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي يَوْمٍ وَلَيْلَةٍ فَإِنْ هُمْ يَعْنِي أَطَاعُوكَ بِذَلِكَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ عَزَّ وَجَلَّ فَرَضَ عَلَيْهِمْ صَدَقَةً تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ فَتُرَدُّ عَلَى فُقَرَائِهِمْ فَإِنْ هُمْ أَطَاعُوكَ بِذَلِكَ فَاتَّقِ دَعْوَةَ الْمَظْلُومِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Ammar Al Maushuli] dari [Al Mu'afa] dari [Zakariy bin Ishaq Al Makki] dia berkata; telah menceritakan kepada kami [Yahya bin 'Abdullah bin Shafiy] dari [Abu Ma'bad] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Mu'adz ketika beliau mengutusnya ke Yaman: \"Engkau akan menemui kaum ahli kitab. Jika engkau datang kepada mereka, serulah agar mereka bersaksi bahwa tiada ilah (sesembahan) yang berhak disembah kecuali Allah dan Muhammad adalah utusan Allah. Jika mereka menaati dalam hal itu, beritahukanlah kepada mereka bahwa Allah -Azza wa Jalla- telah mewajibkan atas mereka shalat lima waktu dalam sehari semalam. Jika mereka -artinya: menaatimu- dalam hal itu, beritahukanlah bahwa Allah -Azza wa Jalla- telah mewajibkan atas mereka sedekah yang diambil dari orang-orang kaya di antara mereka, lalu diberikan kepada orang-orang fakir di antara mereka. Jika mereka menaati dalam hal itu, takutlah terhadap doa orang yang dizhalimi.\""},"2308":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ بَهْزَ بْنَ حَكِيمٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقُلْتُ يَا نَبِيَّ اللَّهِ مَا أَتَيْتُكَ حَتَّى حَلَفْتُ أَكْثَرَ مِنْ عَدَدِهِنَّ لِأَصَابِعِ يَدَيْهِ أَنْ لَا آتِيَكَ وَلَا آتِيَ دِينَكَ وَإِنِّي كُنْتُ امْرَأً لَا أَعْقِلُ شَيْئًا إِلَّا مَا عَلَّمَنِي اللَّهُ عَزَّ وَجَلَّ وَرَسُولُهُ وَإِنِّي أَسْأَلُكَ بِوَحْيِ اللَّهِ بِمَا بَعَثَكَ رَبُّكَ إِلَيْنَا قَالَ بِالْإِسْلَامِ قُلْتُ وَمَا آيَاتُ الْإِسْلَامِ قَالَ أَنْ تَقُولَ أَسْلَمْتُ وَجْهِي إِلَى اللَّهِ وَتَخَلَّيْتُ وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Mu'tamir] dia berkata; Aku mendengar [Bahz bin Hakim] menceritakan dari [bapaknya] dari [kakeknya], dia berkata; Aku berkata; \"Wahai Nabi Allah, tidaklah aku datang menemuimu hingga aku bersumpah lebih dari bilangan mereka (jari-jari tangannya), untuk tidak mendatangimu dan tidak memeluk agamamu. Sungguh, dahulu aku adalah seorang yang tidak mengetahui sedikit pun kecuali apa yang Allah -Azza wa Jalla- dan Rasul-Nya ajarkan kepadaku, dan sungguh aku bertanya kepadamu atas nama wahyu Allah, dengan apa Rabbmu mengutusmu kepada kami?\" Beliau menjawab: 'Dengan Islam.' Aku bertanya; 'Apakah tanda-tanda Islam? ' Beliau bersabda: 'Hendaklah engkau mengucapkan; 'Aku menyerahkan wajahku kepada Allah dan membuang semua bentuk sesembahan selain kepada-Nya', mendirikan shalat dan menunaikan zakat.'"},"2309":{"ar":"أَخْبَرَنَا عِيسَى بْنُ مُسَاوِرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبِ بْنِ شَابُورَ عَنْ مُعَاوِيَةَ بْنِ سَلَّامٍ عَنْ أَخِيهِ زَيْدِ بْنِ سَلَّامٍ أَنَّهُ أَخْبَرَهُ عَنْ جَدِّهِ أَبِي سَلَّامٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غُنْمٍ أَنَّ أَبَا مَالِكٍ الْأَشْعَرِيَّ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِسْبَاغُ الْوُضُوءِ شَطْرُ الْإِيمَانِ وَالْحَمْدُ لِلَّهِ تَمْلَأُ الْمِيزَانَ وَالتَّسْبِيحُ وَالتَّكْبِيرُ يَمْلَأُ السَّمَوَاتِ وَالْأَرْضَ وَالصَّلَاةُ نُورٌ وَالزَّكَاةُ بُرْهَانٌ وَالصَّبْرُ ضِيَاءٌ وَالْقُرْآنُ حُجَّةٌ لَكَ أَوْ عَلَيْكَ","id":"Telah mengabarkan kepada kami ['Isa bin Musawir] dia berkata; telah menceritakan kepada kami [Muhammad bin Syu'aib bin Syabur] dari [Mu'awiyah bin Sallam] dari saudaranya [Zaid bin Sallam] bahwasanya ia telah mengabarkan kepadanya, dari kakeknya [Abu Sallam] dari ['Abdurrahman bin Ghunam], [Abu Malik Al Asy'ari] menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menyempurnakan wudlu adalah separuh dari iman, kalimat Alhamdulillah mengisi -penuh- timbangan, tasbih dan takbir mengisi -penuh- langit dan bumi, shalat adalah cahaya, zakat adalah bukti, kesabaran adalah cahaya dan Al Qur'an adalah hujjah yang membela atau justeru hujjah yang menuntut dirimu.\""},"2310":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ قَالَ أَنْبَأَنَا خَالِدٌ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ نُعَيْمٍ الْمُجْمِرِ أَبِي عَبْدِ اللَّهِ قَالَ أَخْبَرَنِي صُهَيْبٌ أَنَّهُ سَمِعَ مِنْ أَبِي هُرَيْرَةَ وَمِنْ أَبِي سَعِيدٍ يَقُولَانِخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ ثَلَاثَ مَرَّاتٍ ثُمَّ أَكَبَّ فَأَكَبَّ كُلُّ رَجُلٍ مِنَّا يَبْكِي لَا نَدْرِي عَلَى مَاذَا حَلَفَ ثُمَّ رَفَعَ رَأْسَهُ فِي وَجْهِهِ الْبُشْرَى فَكَانَتْ أَحَبَّ إِلَيْنَا مِنْ حُمْرِ النَّعَمِ ثُمَّ قَالَ مَا مِنْ عَبْدٍ يُصَلِّي الصَّلَوَاتِ الْخَمْسَ وَيَصُومُ رَمَضَانَ وَيُخْرِجُ الزَّكَاةَ وَيَجْتَنِبُ الْكَبَائِرَ السَّبْعَ إِلَّا فُتِّحَتْ لَهُ أَبْوَابُ الْجَنَّةِ فَقِيلَ لَهُ ادْخُلْ بِسَلَامٍ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul Hakim] dari [Syu'aib] dari [Al Laits] dia berkata; telah memberitakan kepada kami [Khalid] dari [Ibnu Abu Hilal] dari [Nu'aim Al Mujmir Abu 'Abdullah] dia berkata; telah mengabarkan kepadaku [Shuhaib] bahwasanya ia mendengar dari [Abu Hurairah] dan [Abu Sa'id] mereka berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah pada suatu hari, beliau bersabda: \"Demi jiwaku yang berada ditanganNya, \" sebanyak tiga kali, lalu beliau mengisak tangis, dan diantara kami pun mulai menangis, kami tidak mengetahui atas apa beliau bersumpah lalu beliau mengangkat kepalanya dan tampak di wajahnya kegembiraan, hal itu lebih kami sukai daripada unta merah (harta terbaik), kemudian beliau bersabda: 'Tidaklah seorang hamba melaksanakan shalat lima waktu, berpuasa Ramadlan, mengeluarkan zakat dan ia menjauhi tujuh buah dosa besar kecuali akan dibukakan untuknya pintu-pintu surga dan dikatakan padanya masuklah dengan keselamatan.'"},"2311":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرٍ قَالَ حَدَّثَنَا أَبِي عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَنْفَقَ زَوْجَيْنِ مِنْ شَيْءٍ مِنْ الْأَشْيَاءِ فِي سَبِيلِ اللَّهِ دُعِيَ مِنْ أَبْوَابِ الْجَنَّةِ يَا عَبْدَ اللَّهِ هَذَا خَيْرٌ لَكَ وَلِلْجَنَّةِ أَبْوَابٌ فَمَنْ كَانَ مِنْ أَهْلِ الصَّلَاةِ دُعِيَ مِنْ بَابِ الصَّلَاةِ وَمَنْ كَانَ مِنْ أَهْلِ الْجِهَادِ دُعِيَ مِنْ بَابِ الْجِهَادِ وَمَنْ كَانَ مِنْ أَهْلِ الصَّدَقَةِ دُعِيَ مِنْ بَابِ الصَّدَقَةِ وَمَنْ كَانَ مِنْ أَهْلِ الصِّيَامِ دُعِيَ مِنْ بَابِ الرَّيَّانِ قَالَ أَبُو بَكْرٍ هَلْ عَلَى مَنْ يُدْعَى مِنْ تِلْكَ الْأَبْوَابِ مِنْ ضَرُورَةٍ فَهَلْ يُدْعَى مِنْهَا كُلِّهَا أَحَدٌ يَا رَسُولَ اللَّهِ قَالَ نَعَمْ وَإِنِّي أَرْجُو أَنْ تَكُونَ مِنْهُمْ يَعْنِي أَبَا بَكْرٍ","id":"Telah mengabarkan kepadaku ['Amr bin 'Utsman bin Sa'id bin Katsir] dia berkata; [bapakku] telah menceritakan kepada kami dari [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Humaid bin 'Abdurrahman] bahwasanya [Abu Hurairah] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menafkahkan sesuatu yaang berpasang-pasangan di jalan Allah, akan dipanggil dari pintu-pintu surga, 'Wahai hamba Allah, ini lebih baik bagimu'. Dan surga memiliki pintu-pintu; barangsiapa yang termasuk rajin mengerjakan shalat, akan dipanggil dari pintu shalat; barangsiapa yang termasuk rajin jihad, akan dipanggil dari pintu jihad; barangsiapa yang termasuk rajin bersedekah, akan dipanggil dari pintu sedekah; dan barangsiapa yang termasuk rajin berpuasa, akan dipanggil dari pintu Ar-Rayyan.\" Abu Bakar Ash-Shidiq berkata; 'Jika seseorang dipanggil dari salah satu diantara pintu-pintu itu, itu sebuah kepastian (tidak aneh), namun apakah ada seseorang yang dipanggil dari semua pintu-pintu itu, Wahai Rasulullah? ' Beliau bersabda: 'Ya, dan aku berharap agar engkau termasuk di antara mereka.'"},"2312":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ فِي حَدِيثِهِ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ قَالَجِئْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ جَالِسٌ فِي ظِلِّ الْكَعْبَةِ فَلَمَّا رَآنِي مُقْبِلًا قَالَ هُمْ الْأَخْسَرُونَ وَرَبِّ الْكَعْبَةِ فَقُلْتُ مَا لِي لَعَلِّي أُنْزِلَ فِيَّ شَيْءٌ قُلْتُ مَنْ هُمْ فِدَاكَ أَبِي وَأُمِّي قَالَ الْأَكْثَرُونَ أَمْوَالًا إِلَّا مَنْ قَالَ هَكَذَا وَهَكَذَا وَهَكَذَا حَتَّى بَيْنَ يَدَيْهِ وَعَنْ يَمِينِهِ وَعَنْ شِمَالِهِ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَا يَمُوتُ رَجُلٌ فَيَدَعُ إِبِلًا أَوْ بَقَرًا لَمْ يُؤَدِّ زَكَاتَهَا إِلَّا جَاءَتْ يَوْمَ الْقِيَامَةِ أَعْظَمَ مَا كَانَتْ وَأَسْمَنَهُ تَطَؤُهُ بِأَخْفَافِهَا وَتَنْطَحُهُ بِقُرُونِهَا كُلَّمَا نَفِدَتْ أُخْرَاهَا أُعِيدَتْ أُولَاهَا حَتَّى يُقْضَى بَيْنَ النَّاسِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dalam haditsnya dari [Abu Mu'awiyah] dari [Al A'masy] dari [Al Ma'rur bin Suwaid] dari [Abu Dzarr] dia berkata; Aku pernah datang menemui Nabi shallallahu 'alaihi wasallam dan beliau sedang duduk di bawah naungan Ka'bah. Setelah melihatku datang, beliau bersabda: \"Mereka adalah orang-orang yang merugi, demi Pemelihara Ka'bah.\" aku bertanya-tanya; 'Apa yang terjadi padaku? Barangkali telah diturunkan sesuatu tentang diriku! ' Aku bertanya; 'Siapakah mereka, sungguh bapak dan ibuku sebagai tebusannya? ' Beliau bersabda: 'Orang yang banyak hartanya, kecuali orang yang mengatakan begini, begini dan begini, hingga di hadapannya, samping kanan dan samping kirinya.' Kemudian beliau bersabda: 'Demi Dzat yang jiwaku berada di tangan-Nya. Tidaklah seorang meninggal, lalu ia meninggalkan unta atau sapi yang belum ditunaikan zakatnya, kecuali akan datang pada hari Kiamat lebih besar dan lebih gemuk dari sebelumnya, menginjakkan dengan tapak kakinya dan menyeruduknya dengan tanduknya. Setiap kali yang terakhir selesai, diulang lagi yang pertama, hingga diputuskan perkara di hadapan manusia.'"},"2313":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى قَالَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ جَامِعِ بْنِ أَبِي رَاشِدٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ رَجُلٍ لَهُ مَالٌ لَا يُؤَدِّي حَقَّ مَالِهِ إِلَّا جُعِلَ لَهُ طَوْقًا فِي عُنُقِهِ شُجَاعٌ أَقْرَعُ وَهُوَ يَفِرُّ مِنْهُ وَهُوَ يَتْبَعُهُ ثُمَّ قَرَأَ مِصْدَاقَهُ مِنْ كِتَابِ اللَّهِ عَزَّ وَجَلَّ{ مُحَمَّد بْن مَاجَةَ وَلَا تَحْسَبَنَّ مُحَمَّد بْن مَاجَةَ الَّذِينَ يَبْخَلُونَ بِمَا آتَاهُمْ اللَّهُ مِنْ فَضْلِهِ هُوَ خَيْرًا لَهُمْ بَلْ هُوَ شَرٌّ لَهُمْ سَيُطَوَّقُونَ مَا بَخِلُوا بِهِ يَوْمَ الْقِيَامَةِ }الْآيَةَ","id":"Telah mengabarkan kepada kami [Mujahid bin Musa] dia berkata; telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Jami' bin Abu Rasyid] dari [Abu Wa'il] dari ['Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang memiliki harta yang ia tidak menunaikan hak hartanya, melainkan akan dijadikan untuknya ular botak sebagai kalung di lehernya, ia berlari terbirit-birit darinya namun ular tersebut terus mengikutinya.\" Kemudian beliau membaca pembenarannya dari Kitabullah -Azza wa Jalla-, 'Sekali-kali janganlah orang-orang yang bakhil dengan harta yang Allah berikan kepada mereka dari karunia-Nya menyangka bahwa kebakhilan baik bagi mereka. Sebenarnya kebakhilan itu adalah buruk bagi mereka. Harta yang mereka bakhilkan itu dikalungkan kelak di lehernya di hari kiamat...\". (QS. Ali Imraan 3: 180)"},"2314":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي عَمْرٍو الْغُدَانِيِّ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا رَجُلٍ كَانَتْ لَهُ إِبِلٌ لَا يُعْطِي حَقَّهَا فِي نَجْدَتِهَا وَرِسْلِهَا قَالُوا يَا رَسُولَ اللَّهِ مَا نَجْدَتُهَا وَرِسْلُهَا قَالَ فِي عُسْرِهَا وَيُسْرِهَا فَإِنَّهَا تَأْتِي يَوْمَ الْقِيَامَةِ كَأَغَذِّ مَا كَانَتْ وَأَسْمَنِهِ وَآشَرِهِ يُبْطَحُ لَهَا بِقَاعٍ قَرْقَرٍ فَتَطَؤُهُ بِأَخْفَافِهَا إِذَا جَاءَتْ أُخْرَاهَا أُعِيدَتْ عَلَيْهِ أُولَاهَا فِي يَوْمٍ كَانَ مِقْدَارُهُ خَمْسِينَ أَلْفَ سَنَةٍ حَتَّى يُقْضَى بَيْنَ النَّاسِ فَيَرَى سَبِيلَهُ وَأَيُّمَا رَجُلٍ كَانَتْ لَهُ بَقَرٌ لَا يُعْطِي حَقَّهَا فِي نَجْدَتِهَا وَرِسْلِهَا فَإِنَّهَا تَأْتِي يَوْمَ الْقِيَامَةِ أَغَذَّ مَا كَانَتْ وَأَسْمَنَهُ وَآشَرَهُ يُبْطَحُ لَهَا بِقَاعٍ قَرْقَرٍ فَتَنْطَحُهُ كُلُّ ذَاتِ قَرْنٍ بِقَرْنِهَا وَتَطَؤُهُ كُلُّ ذَاتِ ظِلْفٍ بِظِلْفِهَا إِذَا جَاوَزَتْهُ أُخْرَاهَا أُعِيدَتْ عَلَيْهِ أُولَاهَا فِي يَوْمٍ كَانَ مِقْدَارُهُ خَمْسِينَ أَلْفَ سَنَةٍ حَتَّى يُقْضَى بَيْنَ النَّاسِ فَيَرَى سَبِيلَهُ وَأَيُّمَا رَجُلٍ كَانَتْ لَهُ غَنَمٌ لَا يُعْطِي حَقَّهَا فِي نَجْدَتِهَا وَرِسْلِهَا فَإِنَّهَا تَأْتِي يَوْمَ الْقِيَامَةِ كَأَغَذِّ مَا كَانَتْ وَأَكْثَرِهِ وَأَسْمَنِهِ وَآشَرِهِ ثُمَّ يُبْطَحُ لَهَا بِقَاعٍ قَرْقَرٍ فَتَطَؤُهُ كُلُّ ذَاتِ ظِلْفٍ بِظِلْفِهَا وَتَنْطَحُهُ كُلُّ ذَاتِ قَرْنٍ بِقَرْنِهَا لَيْسَ فِيهَا عَقْصَاءُ وَلَا عَضْبَاءُ إِذَا جَاوَزَتْهُ أُخْرَاهَا أُعِيدَتْ عَلَيْهِ أُولَاهَا فِي يَوْمٍ كَانَ مِقْدَارُهُ خَمْسِينَ أَلْفَ سَنَةٍ حَتَّى يُقْضَى بَيْنَ النَّاسِ فَيَرَى سَبِيلَهُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dia berkata; telah menceritakan kepada kami [Qatadah] dari [Abu 'Amru Al Ghudani] bahwasanya [Abu Hurairah] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah orangnya yang memiliki unta, ia tidak memberikan haknya saat najdah-nya dan rislah-nya?\" -Mereka bertanya; 'Wahai Rasulullah! Apa itu najdah dan rislah?\" Beliau menjawab: 'Saat sulitnya dan saat lapangnya.'- sungguh akan datang pada hari Kiamat, lebih cepat dari sebelumnya, lebih gemuk dan lebih runcing. Ia (si pemilik) ditelungkupkan di tempat yang luas, lalu diinjak dengan tapak kakinya. Jika yang terakhir telah datang gilirannya, diulang lagi mulai yang pertamanya, dalam sehari yang kadarnya lima puluh ribu tahun, hingga diputuskan perkara di hadapan manusia, lalu ia melihat jalannya. Siapakah orangnya yang memiliki sapi, ia tidak memberikan haknya saat najdahnya dan rislahnya, akan datang pada hari kiamat lebih cepat dari sebelumnya, lebih gemuk dan lebih runcing. Ia ditelungkupkan di tempat yang luas, lalu setiap yang memiliki tanduk menyeruduknya dengan tanduknya dan setiap yang memiliki kuku telapak kaki menginjaknya dengan kuku telapak kakinya. Jika yang terakhir telah melewatinya diulang lagi yang pertamanya dalam sehari yang kadarnya lima puluh ribu tahun, hingga diputuskan perkara di hadapan manusia, lalu ia melihat jalannya. Dan siapakah orang yang memiliki kambing, ia tidak memberikan haknya dalam najdah dan rislah, sungguh akan datang pada hari Kiamat lebih cepat dari sebelumnya, lebih banyak, lebih gemuk dan lebih runcing. Ia ditelungkupkan di tempat yang luas, lalu setiap yang memiliki kuku menginjaknya dengan kukunya dan setiap yang memiliki tanduk menyeruduknya dengan tanduknya. Tidak ada yang bengkok tanduknya dan tidak ada yang pecah. Jika yang terakhir telah melewatinya diulang lagi yang pertamanya dalam sehari yang kadarnya lima puluh ribu tahun, hingga diputuskan perkara di hadapan manusia, lalu ia melihat jalannya.'"},"2315":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتُخْلِفَ أَبُو بَكْرٍ بَعْدَهُ وَكَفَرَ مَنْ كَفَرَ مِنْ الْعَرَبِ قَالَ عُمَرُ لِأَبِي بَكْرٍ كَيْفَ تُقَاتِلُ النَّاسَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَمَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ عَصَمَ مِنِّي مَالَهُ وَنَفْسَهُ إِلَّا بِحَقِّهِ وَحِسَابُهُ عَلَى اللَّهِ فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ لَأُقَاتِلَنَّ مَنْ فَرَّقَ بَيْنَ الصَّلَاةِ وَالزَّكَاةِ فَإِنَّ الزَّكَاةَ حَقُّ الْمَالِ وَاللَّهِ لَوْ مَنَعُونِي عِقَالًا كَانُوا يُؤَدُّونَهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَاتَلْتُهُمْ عَلَى مَنْعِهِقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ رَأَيْتُ اللَّهَ شَرَحَ صَدْرَ أَبِي بَكْرٍ لِلْقِتَالِ فَعَرَفْتُ أَنَّهُ الْحَقُّ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] dari [Abu Hurairah] dia berkata; Setelah Rasulullah shallallahu 'alaihi wasallam wafat, lalu -kekhalifahan- sesudahnya digantikan oleh Abu Bakar, namun orang kafir dari bangsa Arab mengingkarinya. [Umar] berkata kepada Abu Bakar; \"Bagaimana caramu memerangi manusia, sedangkan Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Aku diperintahkan untuk memerangi manusia hingga mereka mengatakan, La Ilaaha Ilallah (tidak ada Ilah yang berhak disembah kecuali Allah) '. Barangsiapa yang mengatakan, 'La Ilaaha Ilallah', berarti ia telah memelihara harta dan jiwanya dariku kecuali dengan haknya dan hisabnya atas Allah'.' [Abu Bakar] -radliallahu 'anhu- berkata; 'Sungguh benar-benar aku akan perangi orang yang memisahkan antara shalat dan zakat. zakat adalah hak harta. Demi Allah, andaikata mereka menghalangiku untuk mengambil zakat unta yang dahulu mereka berikan kepada Rasulullah shallallahu 'alaihi wasallam, niscaya akan aku perangi mereka karena hal itu.' Umar -radliallahu 'anhu- berkata; 'Demi Allah, tidak ada hal lain kecuali aku melihat Allah telah melapangkan dada Abu Bakar untuk berperang, aku mengetahui bahwa hal itu adalah suatu kebenaran.'"},"2316":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا بَهْزُ بْنُ حَكِيمٍ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي كُلِّ إِبِلٍ سَائِمَةٍ فِي كُلِّ أَرْبَعِينَ ابْنَةُ لَبُونٍ لَا يُفَرَّقُ إِبِلٌ عَنْ حِسَابِهَا مَنْ أَعْطَاهَا مُؤْتَجِرًا فَلَهُ أَجْرُهَا وَمَنْ أَبَى فَإِنَّا آخِذُوهَا وَشَطْرَ إِبِلِهِ عَزْمَةٌ مِنْ عَزَمَاتِ رَبِّنَا لَا يَحِلُّ لِآلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا شَيْءٌ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; Telah menceritakan kepada kami [Yahya] dia berkata; Telah menceritakan kepada kami [Bahz bin Hakim] dia berkata; [Bapakku] telah menceritakan kepadaku dari [kakekku], dia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Pada setiap empat puluh ekor unta yang dilepas, (mencari makan sendiri), zakatnya satu ekor unta Ibnatu labun (unta yang umurnya memasuki tahun ketiga). Tidak boleh dipisahkan unta itu untuk mengurangi perhitungan zakat. Barangsiapa memberinya karena mengharap pahala, ia akan mendapat pahalanya. Barangsiapa menolak untuk mengeluarkannya, kami akan mengambilnya beserta setengah hartanya, karena keputusan Rabb kami. Tidak halal bagi keluarga Muhammad memakan harta (zakat) sedikitpun.\""},"2317":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي عَمْرُو بْنُ يَحْيَى ح و أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ عَنْ عَبْدِ الرَّحْمَنِ عَنْ سُفْيَانَ وَشُعْبَةَ وَمَالِكٍ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ صَدَقَةٌ وَلَا فِيمَا دُونَ خَمْسِ ذَوْدٍ صَدَقَةٌ وَلَا فِيمَا دُونَ خَمْسَةِ أَوَاقٍ صَدَقَةٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Sufyan] dia berkata; Telah menceritakan kepadaku ['Amru bin Yahya], demikian juga diriwayatkan dari jalur lainnya, dan telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] dari ['Abdurrahman] dari [Sufyan] dan [Syu'bah] dan [Malik] dari ['Amru bin Yahya] dari [bapaknya] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat pada biji-bijian yang kurang dari lima wasaq, tidak ada zakat pada unta yang kurang dari lima dzaud (ekor) dan tidak ada zakat pada perak yang kurang dari lima uqiyah.\""},"2318":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرِو بْنِ يَحْيَى بْنِ عُمَارَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ فِيمَا دُونَ خَمْسَةِ ذَوْدٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسَةِ أَوَاقٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ صَدَقَةٌ","id":"Telah mengabarkan kepada kami ['Isa bin Hammad] dia berkata; Telah memberitakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari ['Amru bin Yahya bin 'Umarah] dari [bapaknya] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat pada unta yang kurang dari lima dzaud (ekor), tidak ada zakat pada perak yang kurang dari lima uqiyah dan tidak ada zakat pada biji-bijian yang kurang dari lima wasaq.\""},"2319":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا الْمُظَفَّرُ بْنُ مُدْرِكٍ أَبُو كَامِلٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَخَذْتُ هَذَا الْكِتَابَ مِنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَنَسِ بْنِ مَالِكٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ أَبَا بَكْرٍكَتَبَ لَهُمْ إِنَّ هَذِهِ فَرَائِضُ الصَّدَقَةِ الَّتِي فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمُسْلِمِينَ الَّتِي أَمَرَ اللَّهُ عَزَّ وَجَلَّ بِهَا رَسُولَهُ ��َلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ سُئِلَهَا مِنْ الْمُسْلِمِينَ عَلَى وَجْهِهَا فَلْيُعْطِ وَمَنْ سُئِلَ فَوْقَ ذَلِكَ فَلَا يُعْطِ فِيمَا دُونَ خَمْسٍ وَعِشْرِينَ مِنْ الْإِبِلِ فِي كُلِّ خَمْسِ ذَوْدٍ شَاةٌ فَإِذَا بَلَغَتْ خَمْسًا وَعِشْرِينَ فَفِيهَا بِنْتُ مَخَاضٍ إِلَى خَمْسٍ وَثَلَاثِينَ فَإِنْ لَمْ تَكُنْ بِنْتُ مَخَاضٍ فَابْنُ لَبُونٍ ذَكَرٌ فَإِذَا بَلَغَتْ سِتًّا وَثَلَاثِينَ فَفِيهَا بِنْتُ لَبُونٍ إِلَى خَمْسٍ وَأَرْبَعِينَ فَإِذَا بَلَغَتْ سِتَّةً وَأَرْبَعِينَ فَفِيهَا حِقَّةٌ طَرُوقَةُ الْفَحْلِ إِلَى سِتِّينَ فَإِذَا بَلَغَتْ إِحْدَى وَسِتِّينَ فَفِيهَا جَذَعَةٌ إِلَى خَمْسٍ وَسَبْعِينَ فَإِذَا بَلَغَتْ سِتًّا وَسَبْعِينَ فَفِيهَا بِنْتَا لَبُونٍ إِلَى تِسْعِينَ فَإِذَا بَلَغَتْ إِحْدَى وَتِسْعِينَ فَفِيهَا حِقَّتَانِ طَرُوقَتَا الْفَحْلِ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ عَلَى عِشْرِينَ وَمِائَةٍ فَفِي كُلِّ أَرْبَعِينَ بِنْتُ لَبُونٍ وَفِي كُلِّ خَمْسِينَ حِقَّةٌ فَإِذَا تَبَايَنَ أَسْنَانُ الْإِبِلِ فِي فَرَائِضِ الصَّدَقَاتِ فَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْجَذَعَةِ وَلَيْسَتْ عِنْدَهُ جَذَعَةٌ وَعِنْدَهُ حِقَّةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ الْحِقَّةُ وَيَجْعَلُ مَعَهَا شَاتَيْنِ إِنْ اسْتَيْسَرَتَا لَهُ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْحِقَّةِ وَلَيْسَتْ عِنْدَهُ حِقَّةٌ وَعِنْدَهُ جَذَعَةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ وَيُعْطِيهِ الْمُصَّدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ إِنْ اسْتَيْسَرَتَا لَهُ وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْحِقَّةِ وَلَيْسَتْ عِنْدَهُ وَعِنْدَهُ بِنْتُ لَبُونٍ فَإِنَّهَا تُقْبَلُ مِنْهُ وَيَجْعَلُ مَعَهَا شَاتَيْنِ إِنْ اسْتَيْسَرَتَا لَهُ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ ابْنَةِ لَبُونٍ وَلَيْسَتْ عِنْدَهُ إِلَّا حِقَّةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ وَيُعْطِيهِ الْمُصَّدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ ابْنَةِ لَبُونٍ وَلَيْسَتْ عِنْدَهُ بِنْتُ لَبُونٍ وَعِنْدَهُ بِنْتُ مَخَاضٍ فَإِنَّهَا تُقْبَلُ مِنْهُ وَيَجْعَلُ مَعَهَا شَاتَيْنِ إِنْ اسْتَيْسَرَتَا لَهُ أَوْ عِشْرِينَ دِرْهَمَا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ ابْنَةِ مَخَاضٍ وَلَيْسَ عِنْدَهُ إِلَّا ابْنُ لَبُونٍ ذَكَرٌ فَإِنَّهُ يُقْبَلُ مِنْهُ وَلَيْسَ مَعَهُ شَيْءٌ وَمَنْ لَمْ يَكُنْ عِنْدَهُ إِلَّا أَرْبَعٌ مِنْ الْإِبِلِ فَلَيْسَ فِيهَا شَيْءٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا وَفِي صَدَقَةِ الْغَنَمِ فِي سَائِمَتِهَا إِذَا كَانَتْ أَرْبَعِينَ فَفِيهَا شَاةٌ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا شَاتَانِ إِلَى مِائَتَيْنِ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا ثَلَاثُ شِيَاهٍ إِلَى ثَلَاثِ مِائَةٍ فَإِذَا زَادَتْ فَفِي كُلِّ مِائَةٍ شَاةٌ وَلَا يُؤْخَذُ فِي الصَّدَقَةِ هَرِمَةٌ وَلَا ذَاتُ عَوَارٍ وَلَا تَيْسُ الْغَنَمِ إِلَّا أَنْ يَشَاءَ الْمُصَّدِّقُ وَلَا يُجْمَعُ بَيْنَ مُتَفَرِّقٍ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ خَشْيَةَ الصَّدَقَةِ وَمَا كَانَ مِنْ خَلِيطَيْنِ فَإِنَّهُمَا يَتَرَاجَعَانِ بَيْنَهُمَا بِالسَّوِيَّةِ فَإِذَا كَانَتْ سَائِمَةُ الرَّجُلِ نَاقِصَةً مِنْ أَرْبَعِينَ شَاةً وَاحِدَةٌ فَلَيْسَ فِيهَا شَيْءٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا وَفِي الرِّقَةِ رُبْعُ الْعُشْرِ فَإِنْ لَمْ تَكُنْ إِلَّا تِسْعِينَ وَمِائَةَ دِرْهَمٍ فَلَيْسَ فِيهَا شَيْءٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; Telah menceritakan kepada kami [Al Muzhaffar bin Mudrik Abu Kamil] dia berkata; Telah menceritakan kepada kami [Hammad bin Salamah] dia berkata; Aku mengambil kitab ini dari [Tsumamah bin 'Abdullah bin Anas bin Malik] dari [Anas bin Malik] bahwasanya [Abu Bakr] menulis untuk mereka; \" Ini adalah kewajiban zakat yang Rasulullah shallallahu 'alaihi wasallam wajibkan atas kaum muslimin, Allah -Azza wa Jalla- perintahkan Rasul-Nya shallallahu 'alaihi wasallam untuk menunaikannya. Barangsiapa di antara kaum muslimin dimintai zakat tersebut berdasarkan aturannya, hendaklah ia memberikannya; dan barangsiapa yang dimintai lebih dari itu, maka janganlah ia memberikannya. Unta yang kurang dari dua puluh lima ekor, pada setiap kelipatan lima ekor zakatnya satu ekor kambing. Jika mencapai dua puluh lima ekor hingga tiga puluh lima ekor unta, zakatnya seekor unta betina yang umurnya telah menginjak tahun kedua. Jika tidak ada, zakatnya seekor unta jantan yang umurnya telah menginjak tahun ketiga. Jika mencapai tiga puluh enam hingga empat puluh lima ekor unta, zakatnya seekor anak unta betina yang umurnya telah menginjak tahun ketiga. Jika telah mencapai empat puluh enam sampai enam puluh ekor unta, zakatnya seekor anak unta betina yang umurnya telah masuk tahun keempat dan bisa dikawini unta jantan. Jika telah mencapai enampuluh satu hingga tujuh puluh lima ekor unta, zakatnya seekor unta betina yang umurnya telah masuk tahun kelima. Jika mencapai tujuh puluh enam hingga sembilan puluh ekor unta, zakatnya dua ekor anak unta betina yang umurnya telah menginjak tahun kedua. Jika telah mencapai sembilan puluh satu hingga seratus dua puluh ekor unta, zakatnya dua ekor unta betina yang umurnya telah masuk tahun keempat dan dapat dikawini unta jantan. Jika telah melebihi seratus dua puluh ekor unta, maka setiap empat puluh ekor zakatnya seekor anak unta betina yang umurnya masuk tahun ketiga dan setiap lima puluh ekor, zakatnya seekor unta betina yang umurnya masuk tahun keempat. Jika umur unta-unta yang menjadi kewajiban zakat berbeda-beda, maka barangsiapa yang jumlah untanya telah mewajibkannya untuk mengeluarkan seekor unta betina yang umurnya masuk tahun kelima, padahal ia tidak memilikinya dan yang ia miliki adalah unta betina yang umurnya masuk tahun keempat, maka ia boleh mengeluarkan seekor anak unta yang umurnya masuk tahun keempat ditambah dua ekor kambing jika hal itu -dirasa- mudah baginya, atau ditambah dua puluh dirham. Barangsiapa yang jumlah untanya telah wajib mengeluarkan seekor unta betina yang umurnya masuk tahun keempat, padahal ia tidak memilikinya dan ia memiliki unta betina yang umurnya masuk tahun kelima, maka ia boleh mengeluarkan seekor anak unta yang umurnya masuk tahun kelima, dan petugas zakat memberikan kepadanya dua puluh dirham atau dua kambing jika hal itu -dirasa- mudah baginya. Barangsiapa yang jumlah untanya telah mewajibkannya mengeluarkan seekor unta betina yang umurnya masuk tahun keempat, padahal ia tidak memilikinya dan ia hanya memiliki unta betina yang umurnya masuk tahun ketiga, maka ia boleh mengeluarkan seekor anak unta yang umurnya masuk tahun ketiga ditambah dua ekor kambing, jika hal itu -dirasa- mudah baginya, atau ditambah dua puluh dirham. Barangsiapa yang jumlah untanya telah mewajibkannya mengeluarkan seekor unta betina yang umurnya masuk tahun ketiga, padahal ia tidak memilikinya dan ia memilikinya dan ia memiliki unta betina yang umurnya masuk tahun keempat, maka ia boleh mengeluarkan seekor anak unta yang umurnya masuk tahun keempat dan petugas zakat memberikan kepadanya dua puluh dirham atau dua ekor kambing. Barangsiapa yang jumlah untanya telah mewajibkannya mengeluarkan seekor unta betina yang umurnya masuk tahun ketiga, padahal ia tidak memilikinya dan ia hanya memiliki unta betina yang umurnya masuk tahun kedua, maka ia boleh mengeluarkan seekor unta yang umurnya masuk tahun kedua ditambah dua ekor kambing jika hal itu -dirasa- mudah baginya, atau ditambah dua puluh dirham. Barangsiapa yang jumlah untanya telah mewajibkannya mengeluarkan seekor unta betina yang umurnya masuk tahun kedua, padahal ia tidak memilikinya dan ia memiliki unta jantan yang umurnya masuk tahun ketiga, maka ia boleh mengeluarkan seekor anak unta jantan yang umurnya masuk tahun ketiga dan tidak perlu ditambah yang lain. Barangsiapa yang tidak memiliki unta kecuali hanya empat ekor, tidak wajib atasnya zakat kecuali bila pemiliknya menginginkan. Mengenai zakat kambing yang dilepas mencari makan sendiri, jika mencapai empat puluh ekor hingga seratus dua puluh ekor kambing, zakatnya satu ekor kambing. Jika lebih dari seratus dua puluh hingga dua ratus ekor kambing, zakatnya dua ekor kambing. Jika lebih dari dua ratus hingga tiga ratus ekor kambing, zakatnya tiga ekor kambing. Jika lebih dari tiga ratus ekor kambing, maka setiap seratus ekor zakatnya seekor kambing. Tidak boleh dikeluarkan untuk zakat hewan yang tua dan yang cacat dan tidak boleh dikeluarkan yang jantan kecuali jika pemiliknya menghendaki. Tidak boleh dikumpulkan antara hewan-hewan ternak yang terpisah dan tidak boleh dipisahkan antara hewan-hewan ternak yang terkumpul karena takut mengeluarkan zakat. Hewan ternak kumpulan dari dua orang, pada waktu zakat harus kembali dibagi rata antara keduanya. Jika kambing yang dilepas mencari makan sendiri kurang satu ekor dari empat puluh ekor, maka tidak ada zakatnya, kecuali jika pemiliknya menghendakinya. Tentang zakat perak, setiap dua ratus dirham zakatnya seperempat puluhnya (dua setengah persen). Jika hanya seratus sembilan puluh dirham, maka tidak ada zakatnya, kecuali jika pemiliknya menghendakinya.\""},"2320":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ حَدَّثَنِي أَبُو الزِّنَادِ مِمَّا حَدَّثَهُ عَبْدُ الرَّحْمَنِ الْأَعْرَجُ مِمَّا ذَكَرَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يُحَدِّثُ بِهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَأْتِي الْإِبِلُ عَلَى رَبِّهَا عَلَى خَيْرِ مَا كَانَتْ إِذَا هِيَ لَمْ يُعْطِ فِيهَا حَقَّهَا تَطَؤُهُ بِأَخْفَافِهَا وَتَأْتِي الْغَنَمُ عَلَى رَبِّهَا عَلَى خَيْرِ مَا كَانَتْ إِذَا لَمْ يُعْطِ فِيهَا حَقَّهَا تَطَؤُهُ بِأَظْلَافِهَا وَتَنْطَحُهُ بِقُرُونِهَا قَالَ وَمِنْ حَقِّهَا أَنْ تُحْلَبَ عَلَى الْمَاءِ أَلَا لَا يَأْتِيَنَّ أَحَدُكُمْ يَوْمَ الْقِيَامَةِ بِبَعِيرٍ يَحْمِلُهُ عَلَى رَقَبَتِهِ لَهُ رُغَاءٌ فَيَقُولُ يَا مُحَمَّدُ فَأَقُولُ لَا أَمْلِكُ لَكَ شَيْئًا قَدْ بَلَّغْتُ أَلَا لَا يَأْتِيَنَّ أَحَدُكُمْ يَوْمَ الْقِيَامَةِ بِشَاةٍ يَحْمِلُهَا عَلَى رَقَبَتِهِ لَهَا يُعَارٌ فَيَقُولُ يَا مُحَمَّدُ فَأَقُولُ لَا أَمْلِكُ لَكَ شَيْئًا قَدْ بَلَّغْتُ قَالَ وَيَكُونُ كَنْزُ أَحَدِهِمْ يَوْمَ الْقِيَامَةِ شُجَاعًا أَقْرَعَ يَفِرُّ مِنْهُ صَاحِبُهُ وَيَطْلُبُهُ أَنَا كَنْزُكَ فَلَا يَزَالُ حَتَّى يُلْقِمَهُ أُصْبُعَهُ","id":"Telah mengabarkan kepada kami ['Imran bin Bukair] dia berkata; Telah menceritakan kepada kami ['Ali bin 'Abbas] dia berkata; Telah menceritakan kepada kami [Syu'aib] dia berkata; Telah menceritakan kepadaku [Abu Az Zinad] dari apa-apa yang diceritakan oleh ['Abdurrahman Al A'raj] dari apa-apa yang disebutkan, bahwasanya ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Unta akan mendatangi pemiliknya -pada hari Kiamat- dengan kondisi yang lebih baik dari sebelumnya. Jika ia tidak memberikan haknya, unta itu menginjaknya dengan tapak kakinya dan kambing mendatangi pemiliknya dengan kondisi yang lebih baik dari sebelumnya. Jika dia tidak memberikan haknya, kambing itu menginjaknya dengan kuku-kuku telapak kakinya dan menyeruduknya dengan tanduknya, -Beliau bersabda: - Di antara haknya ialah agar ia dibawa ke tempat air. Ketahuilah, janganlah sekali-kali salah seorang di antara kalian datang pada hari Kiamat dengan membawa seekor unta yang dibawa di atas lehernya, unta itu memiliki suara keras, lalu ia berkata; 'Wahai Muhammad'. Maka kukatakan; 'Aku tidak memiliki suatu tanggungan pun untukmu, sungguh telah kusampaikan'. Ketahuilah, janganlah sekali-kali salah seorang di antara kalian datang pada hari Kiamat dengan membawa seekor kambing yang ia bawa di atas lehernya. Kambing itu memiliki suara keras, lalu ia berkata; 'Wahai Muhammad'. Maka kukatakan; 'Aku tidak memiliki suatu tanggungan pun untukmu, sungguh telah kusampaikan'. Beliau bersabda: 'Harta simpanan salah seorang di antara mereka (jika tidak dikeluarkan zakatnya), pada hari Kiamat adalah ular yang berkepala putih (karena banyak racunnya), pemiliknya lari darinya dan ular itu menuntutnya; 'Akulah harta simpananmu', hal tersebut terus seperti itu hingga ular itu menelan jari-jarinya.'"},"2321":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ بَهْزَ بْنَ حَكِيمٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي كُلِّ إِبِلٍ سَائِمَةٍ مِنْ كُلِّ أَرْبَعِينَ ابْنَةُ لَبُونٍ لَا تُفَرَّقُ إِبِلٌ عَنْ حِسَابِهَا مَنْ أَعْطَاهَا مُؤْتَجِرًا لَهُ أَجْرُهَا وَمَنْ مَنَعَهَا فَإِنَّا آخِذُوهَا وَشَطْرَ إِبِلِهِ عَزْمَةً مِنْ عَزَمَاتِ رَب��ِنَا لَا يَحِلُّ لِآلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا شَيْءٌ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul A'la] dia berkata; Telah menceritakan kepada kami [Mu'tamir] dia berkata; Aku mendengar [Bahaz bin Hakim] menceritakan dari [bapaknya] dari [kakeknya], dia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Pada setiap unta yang dilepas mencari makan sendiri, setiap empat puluh ekor zakatnya satu ekor unta betina yang umurnya masuk tahun ketiga. Unta tidak boleh dipisahkan untuk mengurangi perhitungan zakat. Barangsiapa memberinya karena mengharap pahala, ia akan mendapat pahalanya. Barangsiapa menolak untuk mengeluarkannya, kami akan mengambilnya beserta setengah hartanya karena keputusan Rabb kami. Tidak halal bagi keluarga Muhammad shallallahu 'alaihi wasallam darinya sedikitpun.\""},"2322":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مُفَضَّلٌ وَهُوَ ابْنُ مُهَلْهَلٍ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ مُعَاذٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ إِلَى الْيَمَنِ وَأَمَرَهُ أَنْ يَأْخُذَ مِنْ كُلِّ حَالِمٍ دِينَارًا أَوْ عِدْلَهُ مَعَافِرَ وَمِنْ الْبَقَرِ مِنْ ثَلَاثِينَ تَبِيعًا أَوْ تَبِيعَةً وَمِنْ كُلِّ أَرْبَعِينَ مُسِنَّةً","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; Telah menceritakan kepada kami [Yahya bin Adam] dia berkata; Telah menceritakan kepada kami [Mufadldlal bin Muhalhal] dari [Al A'masy] dari [Syaqiq] dari [Masruq] dari [Mu'adz] bahwa Rasulullah shallallahu 'alaihi wasallam mengutusnya ke negeri Yaman, dan memerintahkannya untuk mengambil (zakat) dari setiap orang yang telah baligh sebesar satu dinar, atau yang sebanding dengan nilai itu berupa kain dari Yaman, dan dari setiap tiga puluh ekor sapi -zakatnya- seekor sapi yang berumur satu tahun lebih yang jantan atau betina, dan setiap empat puluh ekor sapi -zakatnya- seekor sapi betina berumur dua tahun lebih."},"2323":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَعْلَى وَهُوَ ابْنُ عُبَيْدٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ وَالْأَعْمَشُ عَنْ إِبْرَاهِيمَ قَالَا قَالَ مُعَاذٌبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ فَأَمَرَنِي أَنْ آخُذَ مِنْ كُلِّ أَرْبَعِينَ بَقَرَةً ثَنِيَّةً وَمِنْ كُلِّ ثَلَاثِينَ تَبِيعًا وَمِنْ كُلِّ حَالِمٍ دِينَارًا أَوْ عِدْلَهُ مَعَافِرَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Ya'la bin 'Ubaid] dia berkata; Telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Masruq] dan [Al A'masy] dari [Ibrahim] mereka berdua berkata; [Mu'adz] berkata; \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke negeri Yaman, lalu beliau memerintahku untuk mengambil dari setiap empat puluh ekor sapi -zakatnya- seekor anak sapi betina berumur dua tahun lebih, dari setiap tiga puluh ekor sapi -zakatnya- seekor sapi jantan yang berumur setahun lebih, serta dari setiap orang yang baligh diambil (jizyah) satu dinar atau yang sebanding dengan nilai pakaian dari Yaman.\""},"2324":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ عَنْ مُعَاذٍ قَالَلَمَّا بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ أَمَرَهُ أَنْ يَأْخُذَ مِنْ كُلِّ ثَلَاثِينَ مِنْ الْبَقَرِ تَبِيعًا أَوْ تَبِيعَةً وَمِنْ كُلِّ أَرْبَعِينَ مُسِنَّةً وَمِنْ كُلِّ حَالِمٍ دِينَارًا أَوْ عِدْلَهُ مَعَافِرَ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] dia berkata; Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Masruq] dari [Mu'adz] dia berkata; \"Setelah Rasulullah shallallahu 'alaihi wasallam mengutusnya ke negeri Yaman, beliau memerintahnya untuk mengambil (zakat) dari setiap tiga puluh ekor sapi seekor anak sapi yang berumur setahun lebih yang jantan atau yang betina, dan setiap empat puluh ekor sapi, seekor sapi betina berumur dua tahun lebih serta dari setiap orang yang telah baligh diambil (jizyah) satu dinar atau yang sebanding dengan nilai pakaian dari Yaman.\""},"2325":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ الطُّوسِيُّ قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي سُلَيْمَانُ الْأَعْمَشُ عَنْ أَبِي وَائِلِ بْنِ سَلَمَةَ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ بَعَثَنِي إِلَى الْيَمَنِ أَنْ لَا آخُذَ مِنْ الْبَقَرِ شَيْئًا حَتَّى تَبْلُغَ ثَلَاثِينَ فَإِذَا بَلَغَتْ ثَلَاثِينَ فَفِيهَا عِجْلٌ تَابِعٌ جَذَعٌ أَوْ جَذَعَةٌ حَتَّى تَبْلُغَ أَرْبَعِينَ فَإِذَا بَلَغَتْ أَرْبَعِينَ فَفِيهَا بَقَرَةٌ مُسِنَّةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur Ath Thusi] dia berkata; Telah menceritakan kepada kami [Ya'qub] dia berkata; [Bapakku] telah menceritakan kepada kami dari [Ibnu Ishaq] dia berkata; Telah menceritakan kepadaku [Sulaiman Al A'masy] dari [Abu Wa'il bin Salamah] dari [Mu'adz bin Jabal] dia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam mengutusku ke negeri Yaman, beliau menyuruhku untuk tidak mengambil (zakat) dari sapi sedikitpun hingga mencapai tiga puluh ekor. Jika sudah mencapai tiga puluh ekor, maka zakatnya seekor anak sapi yang berumur satu tahun lebih, baik yang jantan atau betina. Apabila mencapai empat puluh, maka zakatnya satu ekor sapi yang sudah berumur dua tahun lebih.\""},"2326":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى عَنْ ابْنِ فُضَيْلٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ صَاحِبِ إِبِلٍ وَلَا بَقَرٍ وَلَا غَنَمٍ لَا يُؤَدِّي حَقَّهَا إِلَّا وُقِفَ لَهَا يَوْمَ الْقِيَامَةِ بِقَاعٍ قَرْقَرٍ تَطَؤُهُ ذَاتُ الْأَظْلَافِ بِأَظْلَافِهَا وَتَنْطَحُهُ ذَاتُ الْقُرُونِ بِقُرُونِهَا لَيْسَ فِيهَا يَوْمَئِذٍ جَمَّاءُ وَلَا مَكْسُورَةُ الْقَرْنِ قُلْنَا يَا رَسُولَ اللَّهِ وَمَاذَا حَقُّهَا قَالَ إِطْرَاقُ فَحْلِهَا وَإِعَارَةُ دَلْوِهَا وَحَمْلٌ عَلَيْهَا فِي سَبِيلِ اللَّهِ وَلَا صَاحِبِ مَالٍ لَا يُؤَدِّي حَقَّهُ إِلَّا يُخَيَّلُ لَهُ يَوْمَ الْقِيَامَةِ شُجَاعٌ أَقْرَعُ يَفِرُّ مِنْهُ صَاحِبُهُ وَهُوَ يَتَّبِعُهُ يَقُولُ لَهُ هَذَا كَنْزُكَ الَّذِي كُنْتَ تَبْخَلُ بِهِ فَإِذَا رَأَى أَنَّهُ لَا بُدَّ لَهُ مِنْهُ أَدْخَلَ يَدَهُ فِي فِيهِ فَجَعَلَ يَقْضَمُهَا كَمَا يَقْضَمُ الْفَحْلُ","id":"Telah mengabarkan kepada kami [Washil bin 'Abdul A'la] dari [Ibnu Fudhail] dari ['Abdul Malik bin Abu Sulaiman] dari [Abu Az Zubair] dari [Jabir bin 'Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang pun dari pemilik unta, sapi dan kambing yang tidak menunaikan haknya melainkan akan dibangkitkan pada hari Kiamat, ditelungkupkan di tempat yang luas. Setiap yang memiliki kuku telapak kaki akan menginjaknya dengan kuku-kuku telapak kakinya dan setiap yang memiliki tanduk akan menyeruduk dengan tanduknya. Di antara binatang-binatang tersebut tidak ada yang bengkok dan tidak ada yang pecah tanduknya.\" Kami bertanya; 'Wahai Rasulullah shallallahu 'alaihi wasallam! Apa haknya? ' Beliau menjawab: 'Meminjamkan pejantannya, meminjamkan untuk mengambil air dari sumur dan membawa muatan di atasnya pada jalan Allah. Dan tidak ada pemilik harta yang tidak menunaikan haknya melainkan akan dibuatkan untuk dirinya pada hari Kiamat seperti ular yang berkepala putih (karena banyak racunnya), yang pemiliknya lari darinya namun ular tersebut terus mengikutinya seraya mengatakan; 'Inilah harta simpananmu yang kamu bakhil dengannya'. Ketika ia melihat bahwa hal itu sudah menjadi keharusan untuknya, ia memasukkan tangan ke mulutnya, lalu ia segera menggigitnya seperti hewan pejantan menggigit.'"},"2327":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ النَّسَائِيُّ قَالَ أَنْبَأَنَا شُرَيْحُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَنَسِ بْنِ مَالِكٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ كَتَبَ لَهُ أَنَّ هَذِهِ فَرَائِضُ الصَّدَقَةِ الَّتِي فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمُسْلِمِينَ الَّتِي أَمَرَ اللَّهُ بِهَا رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ سُئِلَهَا مِنْ الْمُسْلِمِينَ عَلَى وَجْهِهَا فَلْيُعْطِهَا وَمَنْ سُئِلَ فَوْقَهَا فَلَا يُعْطِهِ فِيمَا دُونَ خَمْسٍ وَعِشْرِينَ مِنْ الْإِبِلِ فِي خَمْسِ ذَوْدٍ شَاةٌ فَإِذَا بَلَغَتْ خَمْسًا وَعِشْرِينَ فَفِيهَا بِنْتُ مَخَاضٍ إِلَى خَمْسٍ وَثَلَاثِينَ فَإِنْ لَمْ تَكُنِ ابْنَةُ مَخَاضٍ فَابْنُ لَبُونٍ ذَكَرٌ فَإِذَا بَلَغَتْ سِتَّةً وَثَلَاثِينَ فَفِيهَا بِنْتُ لَبُونٍ إِلَى خَمْسٍ وَأَرْبَعِينَ فَإِذَا بَلَغَتْ سِتَّةً وَأَرْبَعِينَ فَفِيهَا حِقَّةٌ طَرُوقَةُ الْفَحْلِ إِلَى سِتِّينَ فَإِذَا بَلَغَتْ إِحْدَى وَسِتِّينَ فَفِيهَا جَذَعَةٌ إِلَى خَمْسَةٍ وَسَبْعِينَ فَإِذَا بَلَغَتْ سِتَّةً وَسَبْعِينَ فَفِيهَا ابْنَتَا لَبُونٍ إِلَى تِسْعِينَ فَإِذَا بَلَغَتْ إِحْدَى وَتِسْعِينَ فَفِيهَا حِقَّتَانِ طَرُوقَتَا الْفَحْلِ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ عَلَى عِشْرِينَ وَمِائَةٍ فَفِي كُلِّ أَرْبَعِينَ ابْنَةُ لَبُونٍ وَفِي كُلِّ خَمْسِينَ حِقَّةٌ فَإِذَا تَبَايَنَ أَسْنَانُ الْإِبِلِ فِي فَرَائِضِ الصَّدَقَاتِ فَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْجَذَعَةِ وَلَيْسَتْ عِنْدَهُ جَذَعَةٌ وَعِنْدَهُ حِقَّةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ الْحِقَّةُ وَيَجْعَلُ مَعَهَا شَاتَيْنِ إِنْ اسْتَيْسَرَتَا لَهُ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْحِقَّةِ وَلَيْسَتْ عِنْدَهُ إِلَّا جَذَعَةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ وَيُعْطِيهِ الْمُصَّدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْحِقَّةِ وَلَيْسَتْ عِنْدَهُ وَعِنْدَهُ ابْنَةُ لَبُونٍ فَإِنَّهَا تُقْبَلُ مِنْهُ وَيَجْعَلُ مَعَهَا شَاتَيْنِ إِنْ اسْتَيْسَرَتَا لَهُ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ بِنْتِ لَبُونٍ وَلَيْسَتْ عِنْدَهُ إِلَّا حِقَّةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ وَيُعْطِيهِ الْمُصَّدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ بِنْتِ لَبُونٍ وَلَيْسَتْ عِنْدَهُ بِنْتُ لَبُونٍ وَعِنْدَهُ بِنْتُ مَخَاضٍ فَإِنَّهَا تُقْبَلُ مِنْهُ وَيَجْعَلُ مَعَهَا شَاتَيْنِ إِنْ اسْتَيْسَرَتَا لَهُ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ ابْنَةِ مَخَاضٍ وَلَيْسَتْ عِنْدَهُ إِلَّا ابْنُ لَبُونٍ ذَكَرٌ فَإِنَّهُ يُقْبَلُ مِنْهُ وَلَيْسَ مَعَهُ شَيْءٌ وَمَنْ لَمْ يَكُنْ عِنْدَهُ إِلَّا أَرْبَعَةٌ مِنْ الْإِبِلِ فَلَيْسَ فِيهَا شَيْءٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا وَفِي صَدَقَةِ الْغَنَمِ فِي سَائِمَتِهَا إِذَا كَانَتْ أَرْبَعِينَ فَفِيهَا شَاةٌ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا شَاتَانِ إِلَى مِائَتَيْنِ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا ثَلَاثُ شِيَاهٍ إِلَى ثَلَاثِ مِائَةٍ فَإِذَا زَادَتْ وَاحِدَةً فَفِي كُلِّ مِائَةٍ شَاةٌ وَلَا تُؤْخَذُ فِي الصَّدَقَةِ هَرِمَةٌ وَلَا ذَاتُ عَوَارٍ وَلَا تَيْسُ الْغَنَمِ إِلَّا أَنْ يَشَاءَ الْمُصَّدِّقُ وَلَا يُجْمَعُ بَيْنَ مُتَفَرِّقٍ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ خَشْيَةَ الصَّدَقَةِ وَمَا كَانَ مِنْ خَلِيطَيْنِ فَإِنَّهُمَا يَتَرَاجَعَانِ بَيْنَهُمَا بِالسَّوِيَّةِ وَإِذَا كَانَتْ سَائِمَةُ الرَّجُلِ نَاقِصَةً مِنْ أَرْبَعِينَ شَاةً وَاحِدَةً فَلَيْسَ فِيهَا شَيْءٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا وَفِي الرِّقَةِ رُبْعُ الْعُشْرِ فَإِنْ لَمْ يَكُنْ الْمَالُ إِلَّا تِسْعِينَ وَمِائَةً فَلَيْسَ فِيهِ شَيْءٌ إِلَّا أَنْ يَشَاءَ رَبُّهَا","id":"Telah mengabarkan kepada kami ['Abdullah bin Fadhalah bin Ibrahim An Nasaa'i] dia berkata; Telah memberitakan kepada kami [Syuraih bin An Nu'man] dia berkata; Telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsumamah bin 'Abdullah bin Anas bin Malik] dari [Anas bin Malik] bahwasanya [Abu Bakr] -radliallahu 'anhu- menulis untuknya; \" ini adalah kewajiban zakat yang Rasulullah shallallahu 'alaihi wasallam wajibkan atas kaum muslimin, yang Allah perintahkan Rasul-Nya shallallahu 'alaihi wasallam untuk menunaikannya. Barangsiapa di antara kaum muslimin yang dimintai zakat tersebut berdasarkan aturannya, hendaklah ia memberikannya; dan barangsiapa yang dimintai lebih dari itu, janganlah ia memberikannya: Unta yang kurang dari dua puluh lima ekor, pada setiap kelipatan lima ekor zakatnya satu ekor kambing. Jika mencapai dua puluh lima ekor hingga tiga puluh lima ekor, zakatnya seekor unta betina yang umurnya telah menginjak tahun kedua. Jika tidak ada, zakatnya seekor unta jantan yang umurnya telah menginjak tahun ketiga. Jika mencapai tiga puluh enam hingga empat puluh lima ekor unta, zakatnya seekor anak unta betina yang umurnya telah menginjak tahun ketiga. Jika telah mencapai empat puluh enam sampai enam puluh ekor unta, zakatnya seekor anak unta betina yang umurnya telah masuk tahun keempat dan bisa dikawini unta jantan. Jika telah mencapai enam puluh satu hingga tujuh puluh lima ekor unta, zakatnya seekor unta betina yang umurnya telah masuk tahun kelima. Jika telah mencapai tujuh puluh enam hingga sembilan puluh ekor unta, zakatnya dua ekor anak unta betina yang umurnya telah menginjak tahun kedua. Jika telah mencapai sembilan puluh satu hingga seratus dua puluh ekor unta, zakatnya dua ekor unta betina yang umurnya telah masuk tahun keempat dan dapat dikawini unta jantan. Jika telah melebihi seratus dua puluh ekor unta, maka setiap empat puluh ekor zakatnya seekor anak unta betina yang umurnya masuk tahun ketiga; dan setiap lima puluh ekor, zakatnya seekor unta betina yang umurnya masuk tahun keempat. Jika umur unta-unta yang menjadi kewajiban zakat berbeda-beda, barangsiapa yang jumlah untanya telah wajib mengeluarkan seekor unta betina yang umurnya masuk tahun kelima, namun ia tidak memilikinya dan ia hanya memiliki unta betina yang umurnya masuk tahun keempat, maka ia boleh mengeluarkan seekor anak unta yang umurnya masuk tahun keempat ditambah dua ekor kambing jika hal itu -dirasa- mudah baginya, atau ditambah dua puluh dirham. Barangsiapa yang jumlah untanya telah wajib mengeluarkan seekor unta betina yang umurnya masuk tahun keempat, padahal ia tidak memilikinya dan ia memiliki unta betina yang umurnya masuk tahun kelima, maka ia boleh mengeluarkan seekor anak unta yang umurnya masuk tahun kelima dan petugas zakat memberikan kepadanya dua puluh dirham atau dua ekor kambing jika hal itu -dirasa- mudah baginya. Barangsiapa yang jumlah untanya telah wajib mengeluarkan zakat seekor unta betina yang umurnya masuk tahun keempat, namun ia tidak memilikinya dan ia memiliki unta betina yang umurnya masuk tahun ketiga, maka ia boleh mengeluarkan seekor anak unta yang umurnya masuk tahun ketiga ditambah dua ekor kambing jika hal itu -dirasa- mudah baginya, atau ditambah dua puluh dirham. Barangsiapa yang jumlah untanya telah wajib mengeluarkan zakat seekor unta betina yang umurnya masuk tahun ketiga, padahal ia tidak memilikinya dan ia memiliki unta betina yang umurnya masuk tahun keempat, maka ia boleh mengeluarkan seekor anak unta yang umurnya masuk tahun keempat dan petugas zakat memberikan kepadanya dua puluh dirham atau dua ekor kambing. Barangsiapa yang jumlah untanya telah mewajibkan mengeluarkan seekor unta betina yang umurnya masuk tahun ketiga, padahal ia tidak memilikinya dan ia memiliki unta betina yang umurnya masuk tahun kedua, maka ia boleh mengeluarkan seekor unta yang umurnya masuk tahun kedua ditambah dua ekor kambing jika hal itu -dirasa- mudah baginya, atau ditambah dua puluh dirham. Barangsiapa yang jumlah untanya telah mewajibkannya mengeluarkan seekor unta betina yang umurnya masuk tahun kedua, padahal ia tidak memilikinya dan ia memiliki unta jantan yang umurnya masuk tahun ketiga, maka ia boleh mengeluarkan seekor unta jantan yang umurnya masuk tahun ketiga dan tidak perlu ditambah yang lain. Barangsiapa yang tidak memiliki unta kecuali hanya empat ekor, tidak wajib atasnya zakat kecuali bila pemiliknya. Mengenai zakat kambing yang dilepas mencari makan sendiri, jika mencapai empat puluh ekor hingga seratus dua puluh ekor kambing, zakatnya satu ekor kambing. Jika lebih dari seratus dua puluh hingga dua ratus ekor kambing, zakatnya dua ekor kambing. Jika lebih dua ratus hingga tiga ratus ekor kambing, zakatnya tiga ekor kambing. Jika lebih dari tiga ratus ekor kambing, maka setiap seratus ekor zakatnya seekor kambing. Tidak boleh dikeluarkan untuk zakat hewan yang tua dan cacat dan tidak boleh dikeluarkan yang jantan, kecuali jika pemiliknya menghendaki. Tidak boleh dikumpulkan antara hewan-hewan ternak yang terpisah dan tidak boleh dipisahkan antara hewan-hewan ternak yang terkumpul karena takut mengeluarkan zakat. Hewan ternak kumpulan dari dua orang, pada waktu zakat haru kembali di bagi rata antara keduanya. Jika kambing yang dilepas mencari makan sendiri kurang satu ekor dari empat puluh ekor, maka tidak ada zakatnya, kecuali jika pemiliknya menghendaki. Tentang zakat perak, setiap dua ratus dirham zakatnya seperempat puluhnya (dua setengah persen). Jika hanya seratus sembilan ratus dirham, maka tidak ada zakatnya, kecuali jika pemiliknya menghendakinya.\""},"2328":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ صَاحِبِ إِبِلٍ وَلَا بَقَرٍ وَلَا غَنَمٍ لَا يُؤَدِّي زَكَاتَهَا إِلَّا جَاءَتْ يَوْمَ الْقِيَامَةِ أَعْظَمَ مَا كَانَتْ وَأَسْمَنَهُ تَنْطَحُهُ بِقُرُونِهَا وَتَطَؤُهُ بِأَخْفَافِهَا كُلَّمَا نَفِدَتْ أُخْرَاهَا أَعَادَتْ عَلَيْهِ أُولَاهَا حَتَّى يُقْضَى بَيْنَ النَّاسِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; Telah menceritakan kepada kami [Waki'] dia berkata; Telah menceritakan kepada kami [Al A'masy] dari [Al Ma'rur bin Suwaid] dari [Abu Dzarr] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang pun dari pemilik unta, sapi dan kambing yang tidak mau menunaikan zakatnya, kecuali akan datang pada hari Kiamat binatang itu lebih besar dan lebih gemuk dari sebelumnya, ia menyeruduknya dengan tanduknya dan menginjak orang itu dengan tapak kakinya. Setiap kali yang terakhir selesai diulang lagi yang pertamanya, hingga perkaranya diputuskan di hadapan manusia.\""},"2329":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ هُشَيْمٍ عَنْ هِلَالِ بْنِ خَبَّابٍ عَنْ مَيْسَرَةَ أَبِي صَالِحٍ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَأَتَانَا مُصَدِّقُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ فَجَلَسْتُ إِلَيْهِ فَسَمِعْتُهُ يَقُولُ إِنَّ فِي عَهْدِي أَنْ لَا نَأْخُذَ رَاضِعَ لَبَنٍ وَلَا نَجْمَعَ بَيْنَ مُتَفَرِّقٍ وَلَا نُفَرِّقَ بَيْنَ مُجْتَمِعٍ فَأَتَاهُ رَجُلٌ بِنَاقَةٍ كَوْمَاءَ فَقَالَ خُذْهَا فَأَبَى","id":"Telah mengabarkan kepada kami [Hannad bin As Sariy] dari [Husyaim] dari [Hilal bin Khabbab] dari [Maisarah Abu Shalih] dari [Suwaid bin Ghaflah] dia berkata; [Petugas pengambil zakat utusan Nabi shallallahu 'alaihi wasallam] datang kepada kami, lalu aku menemuinya, duduk di sampingnya dan mendengarkan ia berkata; \" Dalam perjanjianku agar kita tidak mengambil hewan yang masih menyusu dari induknya, tidak mengumpulkan antara hewan-hewan ternak yang terpisah dan memisahkan antara hewan-hewan ternak yang terkumpul.\" Lalu datang kepadanya seseorang dengan membawa unta yang besar punuknya seraya berkata; 'Ambillah unta ini! ' namun petugas zakat itu menolak.\""},"2330":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ زَيْدِ بْنِ يَزِيدَ يَعْنِي ابْنَ أَبِي الزَّرْقَاءِ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ سَاعِيًا فَأَتَى رَجُلًا فَآتَاهُ فَصِيلًا مَخْلُولًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثْنَا مُصَدِّقَ اللَّهِ وَرَسُولِهِ وَإِنَّ فُلَانًا أَعْطَاهُ فَصِيلًا مَخْلُولًا اللَّهُمَّ لَا تُبَارِكْ فِيهِ وَلَا فِي إِبِلِهِ فَبَلَغَ ذَلِكَ الرَّجُلَ فَجَاءَ بِنَاقَةٍ حَسْنَاءَ فَقَالَ أَتُوبُ إِلَى اللَّهِ عَزَّ وَجَلَّ وَإِلَى نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَارِكْ فِيهِ وَفِي إِبِلِهِ","id":"Telah mengabarkan kepada kami [Harun bin Zaid bin Yazid bin Abu Az Zarqa'] dia berkata; [Bapakku] telah menceritakan kepada kami, dia berkata; Telah menceritakan kepada kami [Sufyan] dari ['Ashim bin Kulaib] dari [bapaknya] dari [Wail bin Hujr] bahwa Nabi shallallahu 'alaihi wasallam mengutus seorang petugas pengambil zakat, lalu ia mendatangi seseorang dan orang itu memberikan seekor anak unta sapihan yang kurus, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kami telah mengutus seorang petugas pengambil zakat utusan Allah dan Rasul-Nya, dan sungguh si fulan telah memberikan kepadanya seekor anak unta sapihan yang kurus. Ya Allah, janganlah Engkau berikan berkah kepadanya dan jangan pula kepada untanya.\" Lalu berita itu sampai kepada orang tersebut, maka ia datang dengan membawa unta yang baik seraya berkata; 'Aku bertaubat kepada Allah -Azza wa Jalla- dan kepada Nabi-Nya shallallahu 'alaihi wasallam, ' Nabi shallallahu 'alaihi wasallam bersabda: 'Ya Allah, berikan berkah kepadanya dan kepada untanya.'"},"2331":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ عَمْرُو بْنُ مُرَّةَ أَخْبَرَنِي قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَاهُ قَوْمٌ بِصَدَقَتِهِمْ قَالَ اللَّهُمَّ صَلِّ عَلَى آلِ فُلَانٍ فَأَتَاهُ أَبِي بِصَدَقَتِهِ فَقَالَ اللَّهُمَّ صَلِّ عَلَى آلِ أَبِي أَوْفَى","id":"Telah mengabarkan kepada kami ['Amru bin Yazid] dia berkata; telah menceritakan kepada kami [Bahz bin Asad] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; ['Amru bin Murrah] telah mengabarkan kepadaku, dia berkata; Aku mendengar ['Abdullah bin Abu Aufa] berkata; Rasulullah shallallahu 'alaihi wasallam ketika didatangi oleh suatu kaum dengan mambawa zakat mereka, beliau berdo'a: \"Ya Allah berilah rahmat atas keluarga si fulan.\" Lalu Abu Aufa datang kepada beliau dengan membawa zakatnya, maka beliau berdo'a: 'Ya Allah berilah rahmat kepada keluarga Abu Aufa.'"},"2332":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا يَحْيَى عَنْ مُحَمَّدِ بْنِ أَبِي إِسْمَعِيلَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هِلَالٍ قَالَ قَالَ جَرِيرٌأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاسٌ مِنْ الْأَعْرَابِ فَقَالُوا يَا رَسُولَ اللَّهِ يَأْتِينَا نَاسٌ مِنْ مُصَدِّقِيكَ يَظْلِمُونَ قَالَ أَرْضُوا مُصَدِّقِيكُمْ قَالُوا وَإِنْ ظَلَمَ قَالَ أَرْضُوا مُصَدِّقِيكُمْ ثُمَّ قَالُوا وَإِنْ ظَلَمَ قَالَ أَرْضُوا مُصَدِّقِيكُمْقَالَ جَرِيرٌ فَمَا صَدَرَ عَنِّي مُصَدِّقٌ مُنْذُ سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا وَهُوَ رَاضٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] - dan lafadz ini miliknya - mereka berdua berkata; telah menceritakan kepada kami [Yahya] dari [Muhammad bin Isma'il] dari ['Abdurrahman bin Hilal] dia berkata; [Jarir] berkata; Sekelompok orang dari Arab badui datang menemui Nabi shallallahu 'alaihi wasallam, lalu mereka berkata; \"Wahai Rasulullah! Sekelompok orang datang dari petugas pengambil zakat utusanmu berbuat zhalim.\" Beliau bersabda: 'Buatlah para petugas pengambil zakat yang mengambil zakat kalian merasa ridla.' Mereka bertanya; 'Meskipun berbuat zhalim? ' Beliau bersabda: 'Buatlah para petugas pengambil zakat yang mengambil zakat kalian, merasa ridla.' Mereka bertanya; 'Meskipun berbuat zhalim? ' Beliau bersabda: 'Buatlah para petugas pengambil zakat yang mengambil zakat kalian merasa ridla.' Jarir berkata; 'Tidak pernah seorang petugas pengambil zakat kembali dari tempatku sejak aku mendengar Rasulullah shallallahu 'alaihi wasallam kecuali dia merasa ridla.'"},"2333":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا إِسْمَعِيلُ هُوَ ابْنُ عُلَيَّةَ قَالَ أَنْبَأَنَا دَاوُدُ عَنْ الشَّعْبِيِّ قَالَ قَالَ جَرِيرٌقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَاكُمْ الْمُصَّدِّقُ فَلْيَصْدُرْ وَهُوَ عَنْكُمْ رَاضٍ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] dia berkata; telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dia berkata; telah memberitakan kepada kami [Dawud] dari [Asy Sya'bi] dia berkata; [Jarir] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika datang kepada kalian petugas pengambil zakat, jadikanlah ia kembali dalam keadaan ridla terhadap kalian.\""},"2334":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ ب��نِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَقَ عَنْ عَمْرِو بْنِ أَبِي سُفْيَانَ عَنْ مُسْلِمِ بْنِ ثَفِنَةَ قَالَاسْتَعْمَلَ ابْنُ عَلْقَمَةَ أَبِي عَلَى عِرَافَةِ قَوْمِهِ وَأَمَرَهُ أَنْ يُصَدِّقَهُمْ فَبَعَثَنِي أَبِي إِلَى طَائِفَةٍ مِنْهُمْ لِآتِيَهُ بِصَدَقَتِهِمْ فَخَرَجْتُ حَتَّى أَتَيْتُ عَلَى شَيْخٍ كَبِيرٍ يُقَالُ لَهُ سَعْرٌ فَقُلْتُ إِنَّ أَبِي بَعَثَنِي إِلَيْكَ لِتُؤَدِّيَ صَدَقَةَ غَنَمِكَ قَالَ ابْنَ أَخِي وَأَيُّ نَحْوٍ تَأْخُذُونَ قُلْتُ نَخْتَارُ حَتَّى إِنَّا لَنَشْبُرُ ضُرُوعَ الْغَنَمِ قَالَ ابْنَ أَخِي فَإِنِّي أُحَدِّثُكَ أَنِّي كُنْتُ فِي شِعْبٍ مِنْ هَذِهِ الشِّعَابِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَنَمٍ لِي فَجَاءَنِي رَجُلَانِ عَلَى بَعِيرٍ فَقَالَا إِنَّا رَسُولَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْكَ لِتُؤَدِّيَ صَدَقَةَ غَنَمِكَ قَالَ قُلْتُ وَمَا عَلَيَّ فِيهَا قَالَا شَاةٌ فَأَعْمِدُ إِلَى شَاةٍ قَدْ عَرَفْتُ مَكَانَهَا مُمْتَلِئَةٍ مَحْضًا وَشَحْمًا فَأَخْرَجْتُهَا إِلَيْهِمَا فَقَالَ هَذِهِ الشَّافِعُ وَالشَّافِعُ الْحَائِلُ وَقَدْ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَأْخُذَ شَافِعًا قَالَ فَأَعْمِدُ إِلَى عَنَاقٍ مُعْتَاطٍ وَالْمُعْتَاطُ الَّتِي لَمْ تَلِدْ وَلَدًا وَقَدْ حَانَ وِلَادُهَا فَأَخْرَجْتُهَا إِلَيْهِمَا فَقَالَا نَاوِلْنَاهَا فَرَفَعْتُهَا إِلَيْهِمَا فَجَعَلَاهَا مَعَهُمَا عَلَى بَعِيرِهِمَا ثُمَّ انْطَلَقَاأَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَقَ قَالَ حَدَّثَنِي عَمْرُو بْنُ أَبِي سُفْيَانَ قَالَ حَدَّثَنِي مُسْلِمُ بْنُ ثَفِنَةَ أَنَّ ابْنَ عَلْقَمَةَ اسْتَعْمَلَ أَبَاهُ عَلَى صَدَقَةِ قَوْمِهِ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Zakariya bin Ishaq] dari ['Amru bin Abu Sufyan] dari [Muslim bin Tsafinah] dia berkata; Ibnu Al Qomah menugaskan bapakku untuk menjadi pemimpin kaumnya dan menyuruhnya untuk mengambil zakat mereka. Muslim berkata; 'Lalu ayahku mengutusku kepada sebuah kaum agar aku mengambil zakat mereka.' Kemudian aku keluar hingga menemui seorang yang telah tua bernama [Si'ir], aku katakan; ayahku mengutusku kepadamu agar kamu menunaikan zakat kambingmu. (orang tua itu) berkata; wahai anak saudaraku! kambing seperti apa yang akan kalian ambil? aku berkata; Biarkan aku memilih sampai aku bisa mengukur susu kambingmu. Dia berkata; 'Wahai anak saudaraku, aku akan memberitahumu bahwa ketika aku berada di sebuah bukit bersama kambing-kambingku pada masa Nabi shallallahu 'alaihi wasallam, tiba-tiba datang kepadaku dua orang laki-laki yang mengendarai unta dan berkata; 'Kami adalah utusan Nabi shallallahu 'alaihi wasallam yang datang kepadamu agar kamu menunaikan zakat kambingmu, aku berkata; 'Apa yang wajib aku keluarkan darinya? ' (Keduanya) berkata; 'Seekor kambing.' Lalu aku pergi menuju seekor kambing, yang aku melihatnya telah mengandung dan gemuk, lalu aku mengeluarkannya kepada mereka. [Keduanya] berkata; 'Ini adalah kambing yang sedang hamil, padahal Rasulullah shallallahu 'alaihi wasallam melarang kami untuk mengambil kambing yang hamil. (orang tua itu) berkata; 'Lalu aku menuju 'anaq (kambing betina yang berumur enam bulan hingga satu tahun) yang mu'tath, dia berkata; Mu'tath adalah kambing yang tidak bisa melahirkan anak (karena gemuk) padahal sudah masanya untuk bisa melahirkan anak, lalu aku mengeluarkannya kepada mereka dan keduanya berkata; 'Berikan kepada kami, maka aku memberikannya kepada mereka hingga keduanya menaikkannya ke atas unta mereka lalu keduanya pergi. Telah mengabarkan kepada kami [Harun bin Abdullah] dia berkata; Telah menceritakan kepada kami [Rauh] dia berkata; telah menceritakan kepada kami [Zakaria bin Ishaq] dia berkata; Telah menceritakan kepadaku [Amru bin Abu Sufyan] dia berkata; Telah menceritakan kepadaku [Muslim bin Tsafinah] bahwa Ibnu Al Qomah menugaskan bapakku untuk menjadi pemimpin kaumnya dan menyuruhnya untuk mengambil zakat mereka.- kemudian dia menyampaikan hadits diatas.-"},"2335":{"ar":"أَخْبَرَنِي عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ حَدَّثَنِي أَبُو الزِّنَادِ مِمَّا حَدَّثَهُ عَبْدُ الرَّحْمَنِ الْأَعْرَجُ مِمَّا ذَكَرَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يُحَدِّثُ قَالَ وَقَالَ عُمَرُأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَدَقَةٍ فَقِيلَ مَنَعَ ابْنُ جَمِيلٍ وَخَالِدُ بْنُ الْوَلِيدِ وَعَبَّاسُ بْنُ عَبْدِ الْمُطَّلِبِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَنْقِمُ ابْنُ جَمِيلٍ إِلَّا أَنَّهُ كَانَ فَقِيرًا فَأَغْنَاهُ اللَّهُ وَأَمَّا خَالِدُ بْنُ الْوَلِيدِ فَإِنَّكُمْ تَظْلِمُونَ خَالِدًا قَدْ احْتَبَسَ أَدْرَاعَهُ وَأَعْتُدَهُ فِي سَبِيلِ اللَّهِ وَأَمَّا الْعَبَّاسُ بْنُ عَبْدِ الْمُطَّلِبِ عَمُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهِيَ عَلَيْهِ صَدَقَةٌ وَمِثْلُهَا مَعَهَاأَخْبَرَنَا أَحْمَدُ بْنُ حَفْصٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ مُوسَى قَالَ حَدَّثَنِي أَبُو الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَدَقَةٍ مِثْلَهُ سَوَاءً","id":"Telah mengabarkan kepadaku ['Imran bin Bakkar] dia berkata; telah menceritakan kepada kami ['Ali bin 'Ayyasy] dia berkata; telah menceritakan kepada kami [Syu'aib] dia berkata; telah menceritakan kepadaku [Abu Az Zinad] dari apa-apa yang diceritakan kepadanya oleh ['Abdurrahman Al A'raj] disebutkan bahwasanya ia mendengar [Abu Hurairah] berkata; [Umar] berkata Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk mengambil zakat, lalu dikatakan; \"Ibnu Jamil, Khalid bin Al Walid dan Abbas bin Abdul Muthalib tidak mau memberikannya.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidaklah Ibnu Jamil merasa enggan untuk membayarnya, hanya saja dahulu ia fakir lalu Allah menjadikan ia kaya. Sedangkan Khalid bin Al Walid, sungguh kalian telah menzhalimi Khalid, ia telah mewakafkan baju besi dan peralatan perangnya di jalan Allah. Sedangkan Al Abbas bin Abdul Muthalib, paman Rasulullah shallallahu 'alaihi wasallam, dia berkewajiban membayar zakat dan zakat yang sama bersamaan dengannya.' Telah mengabarkan kepada kami [Ahmad bin Hafsh] dia berkata; Telah menceritakan kepada kami [Bapakku] dia berkata; Telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Musa] dia berkata; Telah menceritakan kepadaku [Abu Zinad] dari [Abdurrahman] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk mengambil zakat sama seperti diatas."},"2336":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ بْنِ هِلَالٍ الثَّقَفِيِّ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كِدْتُ أُقْتَلُ بَعْدَكَ فِي عَنَاقٍ أَوْ شَاةٍ مِنْ الصَّدَقَةِ فَقَالَ لَوْلَا أَنَّهَا تُعْطَى فُقَرَاءَ الْمُهَاجِرِينَ مَا أَخَذْتُهَا","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] dan [Mahmud bin Ghailan] mereka berdua berkata; Telah menceritakan kepada kami [Abu Nu'aim] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] dari ['Utsman bin 'Abdullah bin Al Aswad] dari ['Abdullah bin Hilal Ats Tsaqafi] dia berkata; Seseorang datang kepada Nabi shallallahu 'alaihi wasallam lalu ia berkata hampir saja aku terbunuh setelahmu karena zakat seekor kambing betina, lalu beliau bersabda: \"Kalau bukan karena (untuk diberikan) orang-orang Muhajirin yang fakir maka aku tidak akan mengambilnya.\""},"2337":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ وَسُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى الْمُسْلِمِ فِي عَبْدِهِ وَلَا فَرَسِهِ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Waki'] dari [Syu'bah] dan [Sufyan] dari ['Abdullah bin Dinar] dari [Sulaiman bin Yasar] dari ['Irak bin Malik] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidak wajib zakat atas seorang muslim pada budak dan kudanya'.\""},"2338":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ حَرْبٍ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا مُحْرِزُ بْنُ الْوَضَّاحِ عَنْ إِسْمَعِيلَ وَهُوَ ابْنُ أُمَيَّةَ عَنْ مَكْحُولٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا زَكَاةَ عَلَى الرَّجُلِ الْمُسْلِمِ فِي عَبْدِهِ وَلَا فَرَسِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ali bin Harb Al Marwazi] dia berkata; telah menceritakan kepada kami [Muhriz bin Al Wadldlah] dari [Isma'il bin Umayyah] dari [Makhul] dari ['Irak bin Malik] dari [Abu Hurairah] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak wajib zakat atas seorang muslim pada budak dan kudanya.\""},"2339":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَيُّوبُ بْنُ مُوسَى عَنْ مَكْحُولٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَيَرْفَعُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ عَلَى الْمُسْلِمِ فِي عَبْدِهِ وَلَا فِي فَرَسِهِ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; Telah menceritakan kepada kami [Sufyan] dia berkata; Telah menceritakan kepada kami [Ayyub bin Musa] dari [Makhul] dari [Sulaiman bin Yasar] dari ['Irak bin Malik] dari [Abu Hurairah] dia menyandarkannya kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak wajib zakat atas seseorang muslim pada budak dan kudanya.\""},"2340":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ خُثَيْمٍ قَالَ حَدَّثَنَا أَبِي عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ عَلَى الْمَرْءِ فِي فَرَسِهِ وَلَا فِي مَمْلُوكِهِ صَدَقَةٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Khutsaim] dia berkata; [bapakku] telah menceritakan kepada kami dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak wajib zakat atas seseorang pada kuda dan budaknya.\""},"2341":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ عَلَى الْمُسْلِمِ فِي عَبْدِهِ وَلَا فِي فَرَسِهِ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] secara baca, dan aku mendengarnya, lafazh ini miliknya, dari [Ibnul Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari ['Abdullah bin Dinar] dari [Sulaiman bin Yasar] dari ['Irak bin Malik] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak wajib zakat atas seseorang pada kuda dan budaknya.\""},"2342":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ خُثَيْمِ بْنِ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ عَلَى الْمُسْلِمِ صَدَقَةٌ فِي غُلَامِهِ وَلَا فِي فَرَسِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Khutsaim bin 'Irak bin Malik] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak wajib zakat atas seseorang pada kuda dan budaknya.\""},"2343":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ عَنْ حَمَّادٍ قَالَ حَدَّثَنَا يَحْيَى وَهُوَ ابْنُ سَعِيدٍ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيمَا دُونَ خَمْسَةِ أَوَاقٍ صَدَقَةٌ وَلَا فِيمَا دُونَ خَمْسِ ذَوْدٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ أَوْسُقٍ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dari [Hammad] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Amru bin Yahya] dari [bapaknya] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat pada perak yang kurang dari lima ekor uqiyah, tidak ada zakat pada unta yang kurang dari lima ekor dan tidak ada zakat pada (biji-bijian) yang kurang dari lima wasaq.\""},"2344":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ الْمَازِنِيُّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ فِيمَا دُونَ خَمْسِ أَوْسُقٍ مِنْ التَّمْرِ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ مِنْ الْوَرِقِ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ ذَوْدٍ مِنْ الْإِبِلِ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah memberitakan kepada kami [Ibnul Qasim] dari [Malik] dia berkata; telah menceritakan kepadaku [Muhammad bin 'Abdullah bin 'Abdurrahman bin Abu Sha'sha'ah Al Mazini] dari [bapaknya] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat pada kurma yang kurang dari lima wasaq, tidak ada zakat pada perak yang kurang dari lima uqiyah dan tidak ada zakat pada unta yang kurang dari lima ekor.\""},"2345":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ يَحْيَى بْنِ عُمَارَةَ وَعَبَّادِ بْنِ تَمِيمٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا صَدَقَةَ فِيمَا دُونَ خَمْسِ أَوْسَاقٍ مِنْ التَّمْرِ وَلَا فِيمَا دُونَ خَمْسِ أَوَاقٍ مِنْ الْوَرِقِ صَدَقَةٌ وَلَا فِيمَا دُونَ خَمْسِ ذَوْدٍ مِنْ الْإِبِلِ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Abu Usamah] dari [Al Walid bin Katsir] dari [Muhammad bin 'Abdurrahman bin Abu Sha'sha'ah] dari [Yahya bin 'Umarah] dan ['Abbad bin Tamim] dari [Abu Sa'id Al Khudri] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat pada kurma yang kurang dari lima wasaq, tidak ada zakat pada perak yang kurang dari lima uqiyah dan tidak ada zakat pada unta yang kurang dari lima ekor.\" "},"2346":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ الطُّوسِيُّ قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا ابْنُ إِسْحَقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ حِبَّانَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ وَكَانَا ثِقَةً عَنْ يَحْيَى بْنِ عُمَارَةَ بْنِ أَبِي حَسَنٍ وَعَبَّادِ بْنِ تَمِيمٍ وَكَانَا ثِقَةً عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ مِنْ الْوَرِقِ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسٍ مِنْ الْإِبِلِ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur Ath-Thusi] dia berkata; telah menceritakan kepada kami [Ya'qub] dia berkata; [Bapakku] telah menceritakan kepada kami, dia berkata; Telah menceritakan kepada kami [Ibnu Ishaq] dia berkata; Telah menceritakan kepadaku [Muhammad bin Yahya bin Hibban] dan [Muhammad bin 'Abdullah bin 'Abdurrahman bin Abu Sha'sha'ah] -dan mereka berdua adalah tsiqah- dari [Yahya bin 'Umarah bin Abu Hasan] dan ['Abbad bin Tamim] -dan mereka berdua adalah tsiqah- dari [Abu Sa'id Al Khudri] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat pada perak yang kurang dari lima uqiyah dan tidak ada zakat pada unta yang kurang dari lima ekor dan tidak ada zakat pada (biji-bijian) yang kurang dari lima wasaq.\""},"2347":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ عَفَوْتُ عَنْ الْخَيْلِ وَالرَّقِيقِ فَأَدُّوا زَكَاةَ أَمْوَالِكُمْ مِنْ كُلِّ مِائَتَيْنِ خَمْسَةً","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Abu Usamah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari ['Ashim bin Dhamrah] dari ['Ali] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku telah membebaskan diri dari -kewajiban mengeluarkan sedekah- kuda dan budak, maka tunaikanlah zakat harta kalian dari setiap dua ratus (dirham) lima dirham.\""},"2348":{"ar":"أَخْبَرَنَا حُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ عَفَوْتُ عَنْ الْخَيْلِ وَالرَّقِيقِ وَلَيْسَ فِيمَا دُونَ مِائَتَيْنِ زَكَاةٌ","id":"Telah mengabarkan kepada kami [Husain bin Manshur] dia berkata; telah menceritakan kepada kami [Ibnu Numair] dia berkata; telah menceritakan kepada kami [Al A'masy] dari [Abu Ishaq] dari ['Ashim bin Dhamrah] dari ['Ali] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku telah membebaskan diri dari -kewajiban mengeluarkan sedekah- kuda dan budak, dan tidak ada zakat pada harta yang kurang dari dua ratus dirham.\""},"2349":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ حُسَيْنٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ امْرَأَةً مِنْ أَهْلِ الْيَمَنِ أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِنْتٌ لَهَا فِي يَدِ ابْنَتِهَا مَسَكَتَانِ غَلِيظَتَانِ مِنْ ذَهَبٍ فَقَالَ أَتُؤَدِّينَ زَكَاةَ هَذَا قَالَتْ لَا قَالَ أَيَسُرُّكِ أَنْ يُسَوِّرَكِ اللَّهُ عَزَّ وَجَلَّ بِهِمَا يَوْمَ الْقِيَامَةِ سِوَارَيْنِ مِنْ نَارٍ قَالَ فَخَلَعَتْهُمَا فَأَلْقَتْهُمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ هُمَا لِلَّهِ وَلِرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ حُسَيْنًا قَالَ حَدَّثَنِي عَمْرُو بْنُ شُعَيْبٍ قَالَ جَاءَتْ امْرَأَةٌ وَمَعَهَا بِنْتٌ لَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي يَدِ ابْنَتِهَا مَسَكَتَانِ نَحْوَهُ مُرْسَلٌ قَالَ أَبُو عَبْد الرَّحْمَنِ خَالِدٌ أَثْبَتُ مِنْ الْمُعْتَمِرِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dari [Husain] dari ['Amru bin Syu'aib] dari [bapaknya] dari [kakeknya] bahwa seorang wanita dari negeri Yaman datang kepada Rasulullah shallallahu 'alaihi wasallam bersama puterinya yang mengenakan dua gelang ditangannya berukuran besar terbuat dari emas, lalu beliau bertanya: \"Apakah kamu telah mengeluarkan zakat gelang ini?\" Ia menjawab; 'Tidak.' Beliau bersabda: 'Apakah kamu senang pada hari Kiamat nanti Allah -Azza wa Jalla- akan menggelangimu dengan dua gelang dari api neraka? ' Ibnu Amru berkata; 'Maka ia segera melepas kedua gelang tersebut dan melemparkannya kepada Rasulullah shallallahu 'alaihi wasallam, seraya berkata; 'Kedua gelang itu untuk Allah dan Rasul-Nya.' Telah mengabarkan kepada kami Muhammad bin Abdul A'la dia berkata; telah menceritakan kepada kami Al Mu'tamir bin Sulaiman dia berkata; Aku mendengar Husain berkata; Telah menceritakan kepada kami Amru bin Syu'aib dia berkata; Telah datang kepada Rasulullah shallallahu 'alaihi wasallam seorang wanita bersama puterinya yang mengenakan dua gelang ditangannya, -sebagaimana Hadits di atas secara mursal. Abu Abdurrahman berkata; Khalid lebih kuat dibanding Al Mu'tamir."},"2350":{"ar":"أَخْبَرَنَا الْفَضْلُ بْنُ سَهْلٍ قَالَ حَدَّثَنَا أَبُو النَّضْرِ هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الَّذِي لَا يُؤَدِّي زَكَاةَ مَالِهِ يُخَيَّلُ إِلَيْهِ مَالُهُ يَوْمَ الْقِيَامَةِ شُجَاعًا أَقْرَعَ لَهُ زَبِيبَتَانِ قَالَ فَيَلْتَزِمُهُ أَوْ يُطَوِّقُهُ قَالَ يَقُولُ أَنَا كَنْزُكَ أَنَا كَنْزُكَ","id":"Telah mengabarkan kepada kami [Al Fadhl bin Sahl] dia berkata; Telah menceritakan kepada kami [Abu An Nadhr Hasyim bin Al Qasim] dia berkata; Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah bin Abu Salamah] dari ['Abdullah bin Dinar] dari [Ibnu 'Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Orang yang tidak mau menunaikan zakat hartanya, pada hari Kiamat hartanya itu diubah seperti ular berkepala putih (karena banyak racunnya) yang memiliki dua titik hitam di atas matanya atau dua taringnya.\" -Ibnu Umar berkata- Lalu ular itu mengikutinya -atau mengulanginya, ia menuturkan-, ular itu berkata; 'Akulah harta simpananmu, akulah harta simpananmu'.'"},"2351":{"ar":"أَخْبَرَنَا الْفَضْلُ بْنُ سَهْلٍ قَالَ حَدَّثَنَا حَسَنُ بْنُ مُوسَى الْأَشْيَبُ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ الْمَدَنِيُّ عَنْ أَبِيهِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ آتَاهُ اللَّهُ عَزَّ وَجَلَّ مَالًا فَلَمْ يُؤَدِّ زَكَاتَهُ مُثِّلَ لَهُ مَالُهُ يَوْمَ الْقِيَامَةِ شُجَاعًا أَقْرَعَ لَهُ زَبِيبَتَانِ يَأْخُذُ بِلِهْزِمَتَيْهِ يَوْمَ الْقِيَامَةِ فَيَقُولُ أَنَا مَالُكَ أَنَا كَنْزُكَ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَلَا يَحْسَبَنَّ الَّذِينَ يَبْخَلُونَ بِمَا آتَاهُمْ اللَّهُ مِنْ فَضْلِهِ }الْآيَةَ","id":"Telah mengabarkan kepada kami [Al Fadhl bin Sahl] dia berkata; Telah menceritakan kepada kami [Hasan bin Musa Al Asyyab] dia berkata; Telah menceritakan kepada kami ['Abdurrahman bin 'Abdullah bin Dinar Al Madani] dari [bapaknya] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang diberi harta oleh Allah -Azza wa Jalla-, lalu ia tidak menunaikan zakatnya, maka hartanya akan diubah pada hari Kiamat seperti seekor ular berkepala putih (karena banyak racunnya) serta memiliki dua titik hitam di atas matanya atau dua taring, memangsa dengan kedua tulang rahangnya pada hari Kiamat, lalu mengatakan, 'Akulah harta simpananmu, akulah harta simpananmu'.\" Kemudian membaca ayat ini: 'Janganlah sekali-kali orang-orang yang bakhil dengan harta yang Allah berikan kepada mereka dari karunia-Nya menyangka....' dan seterusnya."},"2352":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ يَحْيَى بْنِ عُمَارَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسَاقٍ مِنْ حَبٍّ أَوْ تَمْرٍ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Isma'il bin Umayyah] dari [Muhammad bin Yahya bin Habban] dari [Yahya bin 'Umarah] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat pada biji-bijian atau kurma yang kurang dari lima wasaq.\""},"2353":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا رَوْحُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنِي عَمْرُو بْنُ يَحْيَى بْنِ عُمَارَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ فِي الْبُرِّ وَالتَّمْرِ زَكَاةٌ حَتَّى تَبْلُغَ خَمْسَةَ أَوْسُقٍ وَلَا يَحِلُّ فِي الْوَرِقِ زَكَاةٌ حَتَّى تَبْلُغَ خَمْسَةَ أَوَاقٍ وَلَا يَحِلُّ فِي إِبِلٍ زَكَاةٌ حَتَّى تَبْلُغَ خَمْسَ ذَوْدٍ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; Telah menceritakan kepada kami [Rauh bin Al Qasim] dia berkata; Telah menceritakan kepadaku ['Amru bin Yahya bin 'Umarah] dari [bapaknya] dari [Abu Sa'id Al Khudri] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak halal mengeluarkan zakat pada gandum dan kurma hingga mencapai lima wasaq, tidak halal mengeluarkan zakat pada perak hingga mencapai lima uqiyah dan tidak halal mengeluarkan zakat pada unta hingga mencapai lima ekor.\""},"2354":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ يَحْيَى بْنِ عُمَارَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ فِي حَبٍّ وَلَا تَمْرٍ صَدَقَةٌ حَتَّى تَبْلُغَ خَمْسَةَ أَوْسُقٍ وَلَا فِيمَا دُونَ خَمْسٍ ذَوْدٍ وَلَا فِيمَا دُونَ خَمْسِ أَوَاقٍ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Umayyah] dari [Muhammad bin Yahya bin Habban] dari [Yahya bin 'Umarah] dari [Abu Sa'id Al Khudri] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat pada biji-bijian dan kurma hingga mencapai lima wasaq, tidak ada zakat pada unta yang kurang dari lima ekor dan tidak ada pula zakat pada perak yang kurang dari lima uqiyah.\""},"2355":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا إِدْرِيسُ الْأَوْدِيُّ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Idris Al Audi] dari ['Amru bin Murrah] dari [Abu Al Bukhtari] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat pada perak yang kurang dari lima uqiyah.\""},"2356":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدَةَ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ يَحْيَى بْنِ سَعِيدٍ وَعُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ صَدَقَةٌ وَلَا فِيمَا دُونَ خَمْسِ ذَوْدٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Abdah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Yahya bin Sa'id] dan ['Ubaidullah bin 'Umar] dari ['Amru bin Yahya] dari [bapaknya] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada zakat pada perak yang kurang dari lima uqiyah, tidak ada zakat pada unta yang kurang dari lima ekor dan tidak ada zakat pada biji-bijian yang kurang dari lima wasaq.\""},"2357":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ سَعِيدِ بْنِ الْهَيْثَمِ أَبُو جَعْفَرٍ الْأَيْلِيُّ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِيمَا سَقَتْ السَّمَاءُ وَالْأَنْهَارُ وَالْعُيُونُ أَوْ كَانَ بَعْلًا الْعُشْرُ وَمَا سُقِيَ بِالسَّوَانِي وَالنَّضْحِ نِصْفُ الْعُشْرِ","id":"Telah mengabarkan kepada kami [Harun bin Sa'id bin Al Haitsam Abu Ja'far Al Aili] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim] dari [bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tanaman yang disiram dengan air hujan, sungai dan mata air atau tanaman yang hanya hidup dengan air hujan, zakatnya sepersepuluh; dan tanaman yang disiram dengan tenaga manusia atau binatang zakatnya separuh dari sepersepuluh (seperduapuluh).\""},"2358":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو وَأَحْمَدُ بْنُ عَمْرٍو وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ أَنَّ أَبَا الزُّبَيْرِ حَدَّثَهُ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِيمَا سَقَتْ السَّمَاءُ وَالْأَنْهَارُ وَالْعُيُونُ الْعُشْرُ وَفِيمَا سُقِيَ بِالسَّانِيَةِ نِصْفُ الْعُشْرِ","id":"Telah mengabarkan kepadaku ['Amr bin Sawwad bin Al Aswad bin 'Amr] dan [Ahmad bin 'Amru] dan [Al Harits bin Miskin] secara baca dan aku mendengarnya dari [Ibnu Wahb] dia berkata; Telah menceritakan kepada kami ['Amru bin Al Harits] bahwasanya [Abu Az Zubair] menceritakan kepadanya bahwasanya dia mendengar [Jabir bin 'Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tanaman yang disiram dengan air hujan, sungai dan mata air atau tanaman yang hanya hidup dengan air hujan, zakatnya sepersepuluh; dan tanaman yang disiram dengan tenaga manusia atau binatang zakatnya separuh dari sepersepuluh (seperduapuluh).\""},"2359":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي بَكْرٍ وَهُوَ ابْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ مُعَاذٍ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ فَأَمَرَنِي أَنْ آخُذَ مِمَّا سَقَتْ السَّمَاءُ الْعُشْرَ وَفِيمَا سُقِيَ بِالدَّوَالِي نِصْفَ الْعُشْرِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Bakr bin 'Ayyasy] dari ['Ashim] dari [Abu Wa'il] dari [Mu'adz] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke negeri Yaman, lalu beliau memerintahkanku untuk mengambil sepersepuluh hasil tanaman yang disiram dengan air hujan dan separuh dari sepersepuluh (seperduapuluh) hasil tanaman yang disiram dengan tenaga manusia.\""},"2360":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ خُبَيْبَ بْنَ عَبْدِ الرَّحْمَنِ يُحَدِّثُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَسْعُودِ بْنِ نِيَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَ أَتَانَا وَنَحْنُ فِي السُّوقِ فَقَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَصْتُمْ فَخُذُوا وَدَعُوا الثُّلُثَ فَإِنْ لَمْ تَأْخُذُوا أَوْ تَدَعُوا الثُّلُثَ شَكَّ شُعْبَةُ فَدَعُوا الرُّبُعَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dan [Muhammad bin Ja'far] mereka berdua berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; Aku mendengar [Khubaib bin 'Abdurrahman] menceritakan dari ['Abdurrahman bin Mas'ud bin Niyar] dia berkata; [Sahl bin Abu Hatsmah] datang kepada kami, sedangkan kami sedang berada di pasar, lalu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian memperkirakan buah yang masih berada di atas pohon dengan taksiran, maka ambillah dan sisakanlah sepertiganya. Jika kalian tidak meninggalkan sepertiganya -Syu'bah merasa ragu- maka tinggalkanlah seperempatnya.\""},"2361":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ قَالَ حَدَّثَنِي عَبْدُ الْجَلِيلِ بْنُ حُمَيْدٍ الْيَحْصَبِيُّ أَنَّ ابْنَ شِهَابٍ حَدَّثَهُ قَالَ حَدَّثَنِي أَبُو أُمَامَةَ بْنُ سَهْلِ بْنِ حُنَيْفٍفِي الْآيَةِ الَّتِي قَالَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تَيَمَّمُوا الْخَبِيثَ مِنْهُ تُنْفِقُونَ }قَالَ هُوَ الْجُعْرُورُ وَلَوْنُ حُبَيْقٍ فَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُؤْخَذَ فِي الصَّدَقَةِ الرُّذَالَةُ","id":"Telah mengabarkan kepada kami [Yunus bin 'Abdul A'la] dan [Al Harits bin Miskin] secara baca dan aku mendengarnya dari [Ibnu Wahb] dia berkata; telah menceritakan kepadaku ['Abdul Jalil bin Humaid Al Yahshabi] bahwasanya [Ibnu Syihab] menceritakan kepadanya, dia berkata; telah menceritakan kepadaku [Abu Umamah bin Sahl bin Hunaif] tentang ayat yang Allah -Azza wa Jalla- firmankan: \"Dan janganlah kamu memilih yang buruk-buruk lalu kamu menafkahkan daripadanya.\" Ia berkata; 'Yaitu kurma yang jelek dan warna yang tidak segar, Rasulullah shallallahu 'alaihi wasallam melarang diambilkan sesuatu yang hina (jelek, kasar, kualitas rendahan) pada zakat.'"},"2362":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا يَحْيَى عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنِي صَالِحُ بْنُ أَبِي عَرِيبٍ عَنْ كَثِيرِ بْنِ مُرَّةَ الْخَضْرَمِيِّ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِيَدِهِ عَصًا وَقَدْ عَلَّقَ رَجُلٌ قِنْوَ حَشَفٍ فَجَعَلَ يَطْعَنُ فِي ذَلِكَ الْقِنْوِ فَقَالَ لَوْ شَاءَ رَبُّ هَذِهِ الصَّدَقَةِ تَصَدَّقَ بِأَطْيَبَ مِنْ هَذَا إِنَّ رَبَّ هَذِهِ الصَّدَقَةِ يَأْكُلُ حَشَفًا يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Yahya] dari ['Abdul Hamid bin Ja'far] dia berkata; Telah menceritakan kepadaku [Shalih bin Abu 'Arib] dari [Katsir bin Murrah Al Khadrami] dari ['Auf bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam keluar dengan memegang tongkat dan seseorang telah menggantungkan ikatan kurma yang paling jelek, lalu beliau mencela ikatan tersebut, kemudian bersabda: \"Ohh, kalaulah saja pemilik zakat ini mengeluarkan zakat yang lebih baik dari ini…Oh, pemilik zakat ini akan memakan kurma yang paling jelek pada hari Kiamat.\""},"2363":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اللُّقَطَةِ فَقَالَ مَا كَانَ فِي طَرِيقٍ مَأْتِيٍّ أَوْ فِي قَرْيَةٍ عَامِرَةٍ فَعَرِّفْهَا سَنَةً فَإِنْ جَاءَ صَاحِبُهَا وَإِلَّا فَلَكَ وَمَا لَمْ يَكُنْ فِي طَرِيقٍ مَأْتِيٍّ وَلَا فِي قَرْيَةٍ عَامِرَةٍ فَفِيهِ وَفِي الرِّكَازِ الْخُمْسُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari ['Ubaidullah bin Al Akhnas] dari [Amru bin Syuaib] dari [ayahnya] dari [kakeknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya tentang barang temuan, beliau bersabda: \"Jika ia berada di jalan yang sering dilalui ataupun di desa yang ramai penduduknya maka umumkanlah selama setahun, barangkali pemiliknya datang namun jika tidak maka ia menjadi milikmu, dan jika tidak pada jalan yang dilalui atau tidak di desa yang ramai penduduknya maka di dalamnya atau pada harta karun zakatnya seperlima.\""},"2364":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَجْمَاءُ جُرْحُهَا جُبَارٌ وَالْبِئْرُ جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَفِي الرِّكَازِ الْخُمُسُأَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدٍ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Demikian juga diriwayatkan dari jalur lainnya, telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Abdul Razaq] berkata; Telah menceritakan kepada kami [Ma'mar] dari [Sa'id] dan [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Luka akibat binatang ternak tidak ada tanggungan -bagi pemiliknya-, sumur yang digali lalu menyebabkan orang lain tersungkur ke dalamnya tidak ada tanggungan -bagi pemiliknya-, tanah yang digali untuk mencari barang tambang lalu orang lain tersungkur ke dalamnya tidak ada tanggungan -bagi pemiliknya- dan pada harta karun zakatnya seperlima.\" Telah mengabarkan kepada kami [Yunus bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Ibnu Wahb] berkata; Telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Sa'id] dan [Ubaidullah bin Abdullah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam seperti itu juga."},"2365":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدٍ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جُرْحُ الْعَجْمَاءِ جُبَارٌ وَالْبِئْرُ جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَفِي الرِّكَازِ الْخُمْسُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Sa'id] dan [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kerusakan akibat binatang ternak tidak ada tanggungan -bagi pemiliknya-, sumur yang digali lalu menyebabkan orang lain tersungkur ke dalamnya tidak ada tanggungan -bagi pemiliknya-, tanah digali untuk mencari barang tambang lalu orang lain tersungkur ke dalamnya tidak ada tanggungan -bagi pemiliknya- dan pada harta karun zakatnya seperlima.\""},"2366":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا مَنْصُورٌ وَهِشَامٌ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبِئْرُ جُبَارٌ وَالْعَجْمَاءُ جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَفِي الرِّكَازِ الْخُمْسُ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Husyaim] telah memberitakan kepada kami [Manshur] dan [Hisyam] dari [Ibnu Sirin] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sumur yang digali lalu menyebabkan orang lain tersungkur ke dalamnya tidak ada tanggungan -bagi pemiliknya-, kerusakan akibat binatang ternak tidak ada tanggungan -bagi pemiliknya-, tanah yang digali untuk mencari barang tambang lalu orang lain tersungkur ke dalamnya tidak ada tanggungan -bagi pemiliknya- dan pada harta karun zakatnya seperlima.\""},"2367":{"ar":"أَخْبَرَنِي الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ عَنْ مُوسَى بْنِ أَعْيَنَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَجَاءَ هِلَالٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُشُورِ نَحْلٍ لَهُ وَسَأَلَهُ أَنْ يَحْمِيَ لَهُ وَادِيًا يُقَالُ لَهُ سَلَبَةُ فَحَمَى لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ الْوَادِيَفَلَمَّا وَلِيَ عُمَرُ بْنُ الْخَطَّابِ كَتَبَ سُفْيَانُ بْنُ وَهْبٍ إِلَى عُمَرَ بْنِ الْخَطَّابِ يَسْأَلُهُ فَكَتَبَ عُمَرُ إِنْ أَدَّى إِلَيَّ مَا كَانَ يُؤَدِّي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عُشْرِ نَحْلِهِ فَاحْمِ لَهُ سَلَبَةَ ذَلِكَ وَإِلَّا فَإِنَّمَا هُوَ ذُبَابُ غَيْثٍ يَأْكُلُهُ مَنْ شَاءَ","id":"Telah mengabarkan kepadaku [Al Mughirah bin 'Abdurrahman] dia berkata; Telah menceritakan kepada kami [Ahmad bin Abu Syu'aib] dari [Musa bin A'yan] dari ['Amr bin Al Harits] dari ['Amru bin Syuaib] dari [ayahnya] dari [kakeknya] ia berkata; \"Hilal datang menemui Rasulullah shallallahu 'alaihi wasallam dengan membawa sepersepuluh madunya dan meminta kepada beliau untuk menjaga lembah -yang dinamakan Salabah-, maka Rasulullah shallallahu 'alaihi wasallam menjaga lembah tersebut untuknya. Saat Umar bin Khaththab menjadi khalifah, Sufyan bin Wahb menulis surat kepada Umar menanyakan tentangnya, \" maka Umar menulis; 'Jika dia memberikan kepadaku zakat yang dahulu ia berikan kepada Rasulullah shallallahu 'alaihi wasallam berupa seperpuluh kurmanya, maka jagalah lebah Salabah tersebut untuknya. Jika tidak, maka itu hanyalah kurma yang mengikuti curah hujan dan yang dimakan oleh orang yang menginginkannya.\""},"2368":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى عَنْ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَكَاةَ رَمَضَانَ عَلَى الْحُرِّ وَالْعَبْدِ وَالذَّكَرِ وَالْأُنْثَى صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ فَعَدَلَ النَّاسُ بِهِ نِصْفَ صَاعٍ مِنْ بُرٍّ","id":"Telah mengabarkan kepada kami ['Imran bin Musa] dari ['Abdul Warits] dia berkata; Telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat Ramadlan atas orang merdeka, budak dan wanita sebesar satu sha' kurma atau satu sha' sya'ir (gandum), lalu orang-orang menyamakannya dengan setengah sha' burr (tepung).\""},"2369":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَةَ الْفِطْرِ عَلَى الذَّكَرِ وَالْأُنْثَى وَالْحُرِّ وَالْمَمْلُوكِ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ قَالَ فَعَدَلَ النَّاسُ إِلَى نِصْفِ صَاعٍ مِنْ بُرٍّ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat fitrah atas laki-laki, wanita, orang merdeka dan budak sebesar satu sha' kurma atau satu sha' gandum.\" Ibnu Umar berkata; 'Lalu orang-orang menyamakannya dengan setengah sha' burr.'"},"2370":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَكَاةَ رَمَضَانَ عَلَى كُلِّ صَغِيرٍ وَكَبِيرٍ حُرٍّ وَعَبْدٍ ذَكَرٍ وَأُنْثَى صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat Ramadlan atas setiap anak kecil dan orang tua, orang merdeka dan budak, laki-laki dan wanita sebesar satu sha' kurma atau satu sha' gandum.\""},"2371":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَضَ زَكَاةَ الْفِطْرِ مِنْ رَمَضَانَ عَلَى النَّاسِ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ عَلَى كُلِّ حُرٍّ أَوْ عَبْدٍ ذَكَرٍ أَوْ أُنْثَى مِنْ الْمُسْلِمِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] secara baca dan aku mendengarnya, lafazh ini miliknya, dari [Ibnul Qasim] dia berkata; Telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibnu 'Umar] bahwa Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat fitrah dari bulan Ramadlan atas manusia sebesar satu sha' kurma atau satu sha' gandum, atas setiap orang merdeka atau budak, laki-laki atau wanita dari kaum muslimin."},"2372":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ مُحَمَّدِ بْنِ السَّكَنِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَهْضَمٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ عُمَرَ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَكَاةَ الْفِطْرِ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ عَلَى الْحُرِّ وَالْعَبْدِ وَالذَّكَرِ وَالْأُنْثَى وَالصَّغِيرِ وَالْكَبِيرِ مِنْ الْمُسْلِمِينَ وَأَمَرَ بِهَا أَنْ تُؤَدَّى قَبْلَ خُرُوجِ النَّاسِ إِلَى الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Yahya bin Muhammad bin As Sakan] dia berkata; telah menceritakan kepada kami [Muhammad bin Jahdham] dia berkata; Telah menceritakan kepada kami [Isma'il bin Ja'far] dari ['Umar bin Nafi'] dari [bapaknya] dari [Ibnu 'Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat fitrah sebesar satu sha' kurma atau satu sha' gandum atas orang merdeka dan budak, laki-laki dan wanita, anak kecil dan orang tua dari kaum muslimin dan memerintahkannya agar ditunaikan sebelum orang-orang berangkat melaksanakan shalat.\""},"2373":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عِيسَى قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَةَ الْفِطْرِ عَلَى الصَّغِيرِ وَالْكَبِيرِ وَالذَّكَرِ وَالْأُنْثَى وَالْحُرِّ وَالْعَبْدِ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Isa] dia berkata; Telah menceritakan kepada kami ['Ubaidulah] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat fitrah atas anak kecil dan orang tua, laki-laki dan wanita, orang merdeka dan budak sebesar satu sha' kurma atau satu sha' gandum.\""},"2374":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ قَيْسِ بْنِ سَعْدِ بْنِ عُبَادَةَ قَالَكُنَّا نَصُومُ عَاشُورَاءَ وَنُؤَدِّي زَكَاةَ الْفِطْرِ فَلَمَّا نَزَلَ رَمَضَانُ وَنَزَلَتْ الزَّكَاةُ لَمْ نُؤْمَرْ بِهِ وَلَمْ نُنْهَ عَنْهُ وَكُنَّا نَفْعَلُهُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; Telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; Telah memberitakan kepada kami [Syu'bah] dari [Al Hakim bin 'Utaibah] dari [Al Qasim bin Mukhaimirah] dari ['Amru bin Syurahbil] dari [Qais bin Saad bin Ubadah] dia berkata; \"Kami dahulu berpuasa 'Asyura dan menunaikan zakat fitrah. Setelah turun ayat tentang Ramadlan dan kewajiban zakat, kami tidak diperintah menunaikannya dan tidak pula dilarang, namun kami terus melaksanakannya.\""},"2375":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ أَبِي عَمَّارٍ الْهَمْدَانِيِّ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَدَقَةِ الْفِطْرِ قَبْلَ أَنْ تَنْزِلَ الزَّكَاةُ فَلَمَّا نَزَلَتْ الزَّكَاةُ لَمْ يَأْمُرْنَا وَلَمْ يَنْهَنَا وَنَحْنُ نَفْعَلُهُقَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عَمَّارٍ اسْمُهُ عَرِيبُ بْنُ حُمَيْدٍ وَعَمْرُو بْنُ شُرَحْبِيلَ يُكْنَى أَبَا مَيْسَرَةَ وَسَلَمَةُ بْنُ كُهَيْلٍ خَالَفَ الْحَكَمَ فِي إِسْنَادِهِ وَالْحَكَمُ أَثْبَتُ مِنْ سَلَمَةَ بْنِ كُهَيْلٍ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Salamah bin Kuhail] dari [Al Qasim bin Mukhaimirah] dari [Abu 'Ammar Al Hamdani] dari [Qais bin Sa'd] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk menunaikan zakat fitrah sebelum turun ayat tentang kewajiban zakat. Setelah turun ayat tentang zakat, beliau tidak memerintahkan dan tidak melarangnya, namun kami terus melaksanakannya.\" Abdurrahman berkata; Abu 'Ammar namanya adalah 'Arib bin Humaid dan 'Amru bin Syurahbil biasa dipanggil dengan Abu Maisarah. Salamah bin kuhail menyelisihi Al Hakam di dalam sanadnya, dan Al Hakam lebih kuat dibanding Salamah bin Kuhail."},"2376":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا خَالِدٌ وَهُوَ ابْنُ الْحَارِثِ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ الْحَسَنِ قَالَ قَالَ ابْنُ عَبَّاسٍ وَهُوَ أَمِيرُ الْبَصْرَةِفِي آخِرِ الشَّهْرِ أَخْرِجُوا زَكَاةَ صَوْمِكُمْ فَنَظَرَ النَّاسُ بَعْضُهُمْ إِلَى بَعْضٍ فَقَالَ مَنْ هَاهُنَا مِنْ أَهْلِ الْمَدِينَةِ قُومُوا فَعَلِّمُوا إِخْوَانَكُمْ فَإِنَّهُمْ لَا يَعْلَمُونَ أَنَّ هَذِهِ الزَّكَاةَ فَرَضَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى كُلِّ ذَكَرٍ وَأُنْثَى حُرٍّ وَمَمْلُوكٍ صَاعًا مِنْ شَعِيرٍ أَوْ تَمْرٍ أَوْ نِصْفَ صَاعٍ مِنْ قَمْحٍ فَقَامُواخَالَفَهُ هِشَامٌ فَقَالَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Khalid bin Al Harits] dia berkata; Telah menceritakan kepada kami [Humaid] dari [Al Hasan] dia berkata; Pada akhir bulan [Ibnu 'Abbas] -yang waktu itu dia memimpin kota Bashrah- berkata; \"Keluarkanlah zakat puasa kalian!\". Orang-orang pun saling memandang satu sama lainnya, Ibnu Abbas melanjutkan; 'Adakah disini penduduk Madinah, berdirilah kalian dan beritahukanlah kepada sahabat-sahabat kalian karena mereka tidak mengetahui bahwa zakat ini adalah zakat yang diwajibkan Rasulullah shallallahu 'alaihi wasallam kepada setiap laki-laki maupun perempuan, orang merdeka ataupun budak, satu sha' gandum atau kurma, atau setengah sha' tepung, maka tunaikanlah. Hisyam menyelisihinya, dia berkata; 'Dari Muhammad bin Sirin.'"},"2377":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مَيْمُونٍ عَنْ مَخْلَدٍ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ ابْنِ عَبَّاسٍ قَالَذَكَرَ فِي صَدَقَةِ الْفِطْرِ قَالَ صَاعًا مِنْ بُرٍّ أَوْ صَاعًا مِنْ تَمْرِ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ سُلْتٍ","id":"Telah mengabarkan kepada kami ['Ali bin Maimun] dari [Makhlad] dari [Hisyam] dari [Ibnu Sirin] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam menyebutkan zakat fitrah beliau bersabda; 'Satu sha', tepung atau kurma atau gandum atau sejenis gandum -yang berwarna putih tak berkulit-.\""},"2378":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي رَجَاءٍ قَالَسَمِعْتُ ابْنَ عَبَّاسٍ يَخْطُبُ عَلَى مِنْبَرِكُمْ يَعْنِي مِنْبَرَ الْبَصْرَةِ يَقُولُ صَدَقَةُ الْفِطْرِ صَاعٌ مِنْ طَعَامٍقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا أَثْبَتُ الثَّلَاثَةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Raja'] dia berkata; \"Aku mendengar [Ibnu 'Abbas] berkhutbah di atas mimbar kalian -yaitu mimbar Bashrah- mengatakan; 'Zakat fitrah sebesar satu sha' makanan'.\" Abu Abdurrahman berkata; 'Hadits ini lebih kuat dari ketiga Hadits lainnya.'"},"2379":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَلِيِّ بْنِ حَرْبٍ قَالَ حَدَّثَنَا مُحْرِزُ بْنُ الْوَضَّاحِ عَنْ إِسْمَعِيلَ وَهُوَ ابْنُ أُمَيَّةَ عَنْ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي ذُبَابٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي سَرْحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَةَ الْفِطْرِ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ أَقِطٍ","id":"Telah mengabarkan kepadaku [Muhammad bin 'Ali bin Harb] dia berkata; Telah menceritakan kepada kami [Muhriz bin Al Wadhdhah] dari [Isma'il bin Umayyah] dari [Al Harits bin 'Abdurrahman bin Abu Dzubab] dari ['Iyadl bin 'Abdullah bin Abu Sarh] dari [Abu Sa'id Al Khudri] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat fitrah sebesar satu sha' gandum, satu sha' kurma atau satu sha' susu kering.\""},"2380":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي سَرْحٍ عَنْ أَبِي سَعِيدٍ قَالَكُنَّا نُخْرِجُ زَكَاةَ الْفِطْرِ إِذْ كَانَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعًا مِنْ طَعَامٍ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ زَبِيبٍ أَوْ صَاعًا مِنْ أَقِطٍ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Zaid bin Aslam] dari ['Iyadh bin 'Abdullah bin Abu Sarh] dari [Abu Sa'id] dia berkata; \"Kami mengeluarkan zakat fitrah ketika Rasulullah shallallahu 'alaihi wasallam masih ada di antara kami sebesar satu sha' makanan, satu sha' gandum, satu sha' kurma, satu sha'anggur kering atau satu sha' susu kering.\""},"2381":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ دَاوُدَ بْنِ قَيْسٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ قَالَكُنَّا نُخْرِجُ صَدَقَةَ الْفِطْرِ إِذْ كَانَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعًا مِنْ طَعَامٍ أَوْ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ أَقِطٍ فَلَمْ نَزَلْ كَذَلِكَ حَتَّى قَدِمَ مُعَاوِيَةُ مِنْ الشَّامِ وَكَانَ فِيمَا عَلَّمَ النَّاسَ أَنَّهُ قَالَ مَا أَرَى مُدَّيْنِ مِنْ سَمْرَاءِ الشَّامِ إِلَّا تَعْدِلُ صَاعًا مِنْ هَذَا قَالَ فَأَخَذَ النَّاسُ بِذَلِكَ","id":"Telah mengabarkan kepada kami [Hannad bin As Sariy] dari [Waki'] dari [Dawud bin Qais] dari ['Iyadh bin 'Abdullah] dari [Abu Sa'id] dia berkata; \"Kami mengeluarkan zakat fitrah ketika Rasulullah shallallahu 'alaihi wasallam masih ada di antara kami sebesar satu sha' makanan, satu sha' kurma, satu sha' gandum atau satu sha' susu kering. Kami terus melaksanakan seperti itu hingga Mu'awiyah datang dari Syam. Dan di antara yang ia ajarkan kepada orang-orang adalah: Ia berkata; \"Kami tidak melihat dua mud gandum Syam kecuali menyamai satu sha' dari ini.\" Abu Sa'id berkata; 'Maka orang-orang mengambil pendapat tersebut'."},"2382":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ عَجْلَانَ قَالَ سَمِعْتُ عِيَاضَ بْنَ عَبْدِ اللَّهِ يُخْبِرُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَلَمْ نُخْرِجْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ زَبِيبٍ أَوْ صَاعًا مِنْ دَقِيقٍ أَوْ صَاعًا مِنْ أَقِطٍ أَوْ صَاعًا مِنْ سُلْتٍ ثُمَّ شَكَّ سُفْيَانُ فَقَالَ دَقِيقٍ أَوْ سُلْتٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Ibnu 'Ajlan] dia berkata; Aku mendengar ['Iyadh bin 'Abdullah] mengabarkan dari [Abu Sa'id Al Khudri] dia berkata; \"Kami tidak pernah mengeluarkan zakat fitrah di zaman Rasulullah shallallahu 'alaihi wasallam kecuali satu sha' kurma, satu sha' gandum, satu sha' anggur kering, satu sha' tepung, satu sha' susu kering atau satu sha' sejenis gandum -yang berwarna putih tak berkulit-.\""},"2383":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ الْحَسَنِ أَنَّ ابْنَ عَبَّاسٍخَطَبَ بِالْبَصْرَةِ فَقَالَ أَدُّوا زَكَاةَ صَوْمِكُمْ فَجَعَلَ النَّاسُ يَنْظُرُ بَعْضُهُمْ إِلَى بَعْضٍ فَقَالَ مَنْ هَاهُنَا مِنْ أَهْلِ الْمَدِينَةِ قُومُوا إِلَى إِخْوَانِكُمْ فَعَلِّمُوهُمْ فَإِنَّهُمْ لَا يَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَضَ صَدَقَةَ الْفِطْرِ عَلَى الصَّغِيرِ وَالْكَبِيرِ وَالْحُرِّ وَالْعَبْدِ وَالذَّكَرِ وَالْأُنْثَى نِصْفَ صَاعِ بُرٍّ أَوْ صَاعًا مِنْ تَمْرٍ أَوْ شَعِيرٍقَالَ الْحَسَنُ فَقَالَ عَلِيٌّ أَمَّا إِذَا أَوْسَعَ اللَّهُ فَأَوْسِعُوا أَعْطُوا صَاعًا مِنْ بُرٍّ أَوْ غَيْرِهِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; Telah menceritakan kepada kami [Yazid bin Harun] dia berkata; Telah menceritakan kepada kami [Humaid] dari [Al Hasan] bahwasanya [Ibnu 'Abbas] berkhutbah di Bashrah dia berkata; \"Tunaikanlah zakat puasa kalian!\". Orang-orangpun saling memandang satu sama lainnya, Ibnu Abbas melanjutkan; 'Adakah disini penduduk Madinah?, berdirilah kalian dan beritahukanlah kepada sahabat-sahabat kalian karena mereka tidak mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam telah mewajibkan zakat fitrah kepada yang kecil maupun yang dewasa, orang merdeka ataupun budak, laki-laki maupun perempuan setengah sha' tepung atau satu sha' kurma, atau gandum. Al Hasan berkata; Ali berkata; 'Adapun Jika Allah melapangkan kalian, berbuat lapangkanlah kalian, keluarkanlah satu sha' tepung atau yang lainnya.'"},"2384":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي رَوَّادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّاسُ يُخْرِجُونَ عَنْ صَدَقَةِ الْفِطْرِ فِي عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعًا مِنْ شَعِيرٍ أَوْ تَمْرٍ أَوْ سُلْتٍ أَوْ زَبِيبٍ","id":"Telah mengabarkan kepada kami [Musa bin 'Abdurrahman] dia berkata; Telah menceritakan kepada kami [Husain] dari [Zaidah] dia berkata; Telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Rawwad] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Dahulu orang-orang mengeluarkan zakat fitrah di zaman Nabi shallallahu 'alaihi wasallam sebesar satu sha' gandum, kurma, atau sejenis gandum -yang berwarna putih tak berkulit- atau anggur kering.\""},"2385":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ قَالَ حَدَّثَنَا عِيَاضٌ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكُنَّا نُخْرِجُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعًا مِنْ شَعِيرٍ أَوْ تَمْرٍ أَوْ زَبِيبٍ أَوْ أَقِطٍفَلَمْ نَزَلْ كَذَلِكَ حَتَّى كَانَ فِي عَهْدِ مُعَاوِيَةَ قَالَ مَا أَرَى مُدَّيْنِ مِنْ سَمْرَاءِ الشَّامِ إِلَّا تَعْدِلُ صَاعًا مِنْ شَعِيرٍ","id":"Telah mengabarkan kepada kami ['Umar bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; Telah menceritakan kepada kami [Dawud bin Qais] dia berkata; Telah menceritakan kepada kami ['Iyadl] dari [Abu Sa'id Al Khudri] dia berkata; \"Kami mengeluarkan zakat fitrah di masa Rasulullah shallallahu 'alaihi wasallam sebesar satu sha' gandum, kurma, anggur kering atau susu kering, kami terus melaksanakan hal itu hingga pada masa Mu'awiyah, ia berkata; 'Aku tidak melihat dua mud gandum Syam kecuali menyamai satu sha' gandum'.\""},"2386":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُثْمَانَ أَنَّ عِيَاضَ بْنَ عَبْدِ اللَّهِ بْنِ سَعْدٍ حَدَّثَهُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَكُنَّا نُخْرِجُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ أَقِطٍ لَا نُخْرِجُ غَيْرَهُ","id":"Telah mengabarkan kepada kami ['Isa bin Hammad] dia berkata; Telah memberitakan kepada kami [Al Laits] dari [Yazid] dari ['Abdullah bin 'Abdullah bin 'Utsman] bahwasanya ['Iyadh bin 'Abdullah bin Sa'd] menceritakan kepadanya bahwasanya [Abu Sa'id Al Khudri] berkata; \"Kami pernah mengeluarkan zakat fitrah di masa Rasulullah shallallahu 'alaihi wasallam sebesar satu sha' kurma, satu sha' gandum atau satu sha' susu kering. Kami tidak mengeluarkan yang lain.\""},"2387":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَنْبَأَنَا الْقَاسِمُ وَهُوَ ابْنُ مَالِكٍ عَنْ الْجُعَيْدِ سَمِعْتُ السَّائِبَ بْنَ يَزِيدَ قَالَكَانَ الصَّاعُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُدًّا وَثُلُثًا بِمُدِّكُمْ الْيَوْمَ وَقَدْ زِيدَ فِيهِقَالَ أَبُو عَبْد الرَّحْمَنِ و حَدَّثَنِيهِ زِيَادُ بْنُ أَيُّوبَ","id":"Telah mengabarkan kepada kami ['Amr bin Zurarah] dia berkata; Telah memberitakan kepada kami [Al Qasim bin Malik] dari [Al Ju'aid] aku mendengar [As Saib bin Yazid] berkata; \"Satu sha' pada masa Rasulullah shallallahu 'alaihi wasallam adalah satu mud dan duapertiga takaran -dua telapak tangan- kalian sekarang dan ditambahkan sedikit.\" Abu Abdurrahman berkata; 'Dan telah menceritakan kepadaku [Ziyad bin Ayyub].'"},"2388":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حَنْظَلَةَ عَنْ طَاوُسٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمِكْيَالُ مِكْيَالُ أَهْلِ الْمَدِينَةِ وَالْوَزْنُ وَزْنُ أَهْلِ مَكَّةَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Abu Nu'aim] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Hanzhalah] dari [Thawus] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Takaran (yang benar) itu ialah takaran penduduk Madinah, dan timbangan (yang benar) itu ialah timbangan penduduk Makkah.\""},"2389":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْدَانَ بْنِ عِيسَى قَالَ حَدَّثَنَا الْحَسَنُ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُوسَى ح قَالَ وَأَنْبَأَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا الْفُضَيْلُ قَالَ حَدَّثَنَا مُوسَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِصَدَقَةِ الْفِطْرِ أَنْ تُؤَدَّى قَبْلَ خُرُوجِ النَّاسِ إِلَى الصَّلَاةِ قَالَ ابْنُ بَزِيعٍ بِزَكَاةِ الْفِطْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'dan bin 'Isa] dia berkata; Telah menceritakan kepada kami [Al Hasan]; Telah menceritakan kepada kami [Zuhair]; Telah menceritakan kepada kami [Musa]. Demikian juga diriwiyatkan dari jalur lainnya, dia berkata; Dan telah memberitakan kepada kami [Muhammad bin 'Abdullah bin Bazi'] dia berkata; Telah menceritakan kepada kami [Al Fudlail] dia berkata; Telah menceritakan kepada kami [Musa] dari [Nafi'] dari [Ibnu 'Umar] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk menunaikan zakat fitrah sebelum orang-orang berangkat untuk melaksanakan shalat. Ibnu Bazi' berkata; 'Zakat Fitrah'."},"2390":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَقَ وَكَانَ ثِقَةً عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مُعَاذَ بْنَ جَبَلٍ إِلَى الْيَمَنِ فَقَالَ إِنَّكَ تَأْتِي قَوْمَا أَهْلَ كِتَابٍ فَادْعُهُمْ إِلَى شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ فَإِنْ هُمْ أَطَاعُوكَ فَأَعْلِمْهُمْ أَنَّ اللَّهَ عَزَّ وَجَلَّ افْتَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ فَإِنْ هُمْ أَطَاعُوكَ فَأَعْلِمْهُمْ أَنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ افْتَرَضَ عَلَيْهِمْ صَدَقَةً فِي أَمْوَالِهِمْ تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ فَتُوضَعُ فِي فُقَرَائِهِمْ فَإِنْ هُمْ أَطَاعُوكَ لِذَلِكَ فَإِيَّاكَ وَكَرَائِمَ أَمْوَالِهِمْ وَاتَّقِ دَعْوَةَ الْمَظْلُومِ فَإِنَّهَا لَيْسَ بَيْنَهَا وَبَيْنَ اللَّهِ عَزَّ وَجَلَّ حِجَابٌ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; Telah menceritakan kepada kami [Waki'] dia berkata; Telah menceritakan kepada kami [Zakaria bin Ishaq] - dan dia adalah seorang yang tsiqah - dari [Yahya bin 'Abdullah bin Shaifi] dari [Abu Ma'bad] dari [Ibnu 'Abbas] bahwa Nabi shallallahu 'alaihi wasallam mengutus Mu'adz bin Jabal ke negeri Yaman, lalu beliau bersabda: \" Engkau akan mendatangi kaum Ahli Kitab, maka ajaklah mereka untuk bersaksi bahwa tiada ilah (sesembahan) yang berhak disembah kecuali Allah dan bersaksi bahwa aku adalah utusan Allah. Jika mereka menaatimu, maka beritahukanlah kepada mereka bahwa Allah -Azza Wa Jalla- mewajibkan atas mereka shalat lima waktu dalam sehari semalam. Jika mereka menaatimu, beritahukanlah bahwa Allah -Azza Wa Jalla- mewajibkan atas mereka sedekah pada harta mereka yang diambil dari orang-orang kaya di antara mereka lalu diberikan kepada orang-orang fakir diantara mereka. Jika mereka menaatimu dalam hal itu, jauhilah oleh kamu dari harta mereka yang paling berharga, dan takutlah terhadap do'a orang yang dizhalimi, karena tidak ada penghalang di antara doa tersebut dan Allah -Azza Wa Jalla-.\""},"2391":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ حَدَّثَنِي أَبُو الزِّنَادِ مِمَّا حَدَّثَهُ عَبْدُ الرَّحْمَنِ الْأَعْرَجُ مِمَّا ذَكَرَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يُحَدِّثُ بِهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ قَالَ رَجُلٌ لَأَتَصَدَّقَنَّ بِصَدَقَةٍ فَخَرَجَ بِصَدَقَتِهِ فَوَضَعَهَا فِي يَدِ سَارِقٍ فَأَصْبَحُوا يَتَحَدَّثُونَ تُصُدِّقَ عَلَى سَارِقٍ فَقَالَ اللَّهُمَّ لَكَ الْحَمْدُ عَلَى سَارِقٍ لَأَتَصَدَّقَنَّ بِصَدَقَةٍ فَخَرَجَ بِصَدَقَتِهِ فَوَضَعَهَا فِي يَدِ زَانِيَةٍ فَأَصْبَحُوا يَتَحَدَّثُونَ تُصُدِّقَ اللَّيْلَةَ عَلَى زَانِيَةٍ فَقَالَ اللَّهُمَّ لَكَ الْحَمْدُ عَلَى زَانِيَةٍ لَأَتَصَدَّقَنَّ بِصَدَقَةٍ فَخَرَجَ بِصَدَقَتِهِ فَوَضَعَهَا فِي يَدِ غَنِيٍّ فَأَصْبَحُوا يَتَحَدَّثُونَ تُصُدِّقَ عَلَى غَنِيٍّ قَالَ اللَّهُمَّ لَكَ الْحَمْدُ عَلَى زَانِيَةٍ وَعَلَى سَارِقٍ وَعَلَى غَنِيٍّ فَأُتِيَ فَقِيلَ لَهُ أَمَّا صَدَقَتُكَ فَقَدْ تُقُبِّلَتْ أَمَّا الزَّانِيَةُ فَلَعَلَّهَا أَنْ تَسْتَعِفَّ بِهِ مِنْ زِنَاهَا وَلَعَلَّ السَّارِقَ أَنْ يَسْتَعِفَّ بِهِ عَنْ سَرِقَتِهِ وَلَعَلَّ الْغَنِيَّ أَنْ يَعْتَبِرَ فَيُنْفِقَ مِمَّا أَعْطَاهُ اللَّهُ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami ['Imran bin Bakkar] dia berkata; Telah menceritakan kepada kami ['Ali bin 'Ayyasy] dia berkata; Telah menceritakan kepada kami [Syu'aib] dia berkata; Telah menceritakan kepadaku [Abu Az Zinad] dari apa-apa yang diceritakan kepadanya oleh ['Abdurrahman Al A'raj] dari apa-apa yang disebutkan bahwa ia mendengar [Abu Hurairah] menceritakannya dari Rasulullah Shalallahu 'Alaihi Wa Sallam, beliau bersabda: \"Seorang berkata; 'Sungguh aku benar-benar akan bersedekah! ' Lalu ia keluar dengan membawa sedekahnya dan memberikannya kepada seorang pencuri, maka mereka membicarakannya; 'Seorang pencuri diberi sedekah.' Ia berdoa; 'Ya Allah, segala puji hanya bagi-Mu terhadap seorang pencuri. Sungguh aku benar-benar akan bersedekah.' Lalu ia keluar dengan membawa sedekahnya dan memberikannya kepada seorang wanita yang berzina, maka mereka membicarakannya; 'Malam ini seorang wanita yang berzina diberi sedekah'. Dia berdoa; 'Ya Allah, segala puji hanya bagi-Mu terhadap seorang wanita yang berzina. Sungguh aku benar-benar akan bersedekah'. Lalu ia keluar dengan membawa sedekahnya dan memberikannya kepada orang kaya, maka mereka membicarakannya; 'Seorang kaya diberi sedekah.' Dia berdoa; 'Ya Allah, segala puji hanya bagi-Mu terhadap seorang wanita yang berzina, seorang pencuri dan seorang yang kaya'. Lalu orang tersebut dibawa dan dikatakan kepadanya dalam mimpinya; 'Sedekahmu sungguh telah diterima. Adapun seorang wanita yang berzina, barangkali ia akan menjauhkan diri dari perzinaannya; barangkali seorang pencuri akan menjauhkan diri dari pencuriannya; dan barangkali orang yang kaya akan mengambil pelajaran, lalu ia menginfakkan apa yang Allah -Azza Wa Jalla- telah berikan kepadanya'.\""},"2392":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مُحَمَّدٍ الذَّارِعُ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ وَأَنْبَأَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرٌ وَهُوَ ابْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا شُعْبَةُ وَاللَّفْظُ لِبِشْرٍ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يَقْبَلُ صَلَاةً بِغَيْرِ طُهُورٍ وَلَا صَدَقَةً مِنْ غُلُولٍ","id":"Telah mengabarkan kepada kami [Al Husain bin Muhammad Adz-Dzari'] dia berkata; Telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; telah memberitakan kepada kami [Isma'il bin Mas'ud] dia berkata; Telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal] dia berkata; telah menceritakan kepada kami [Syu'bah] dan lafadz ini milik Bisyr, dari [Qatadah] dari [Abu Al Malih] dari [bapaknya] dia berkata; Aku mendengar Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \" Allah Azza Wa Jalla tidak akan menerima shalat tanpa bersuci dan tidak menerima zakat yang diambil dari mencuri.\""},"2393":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ سَعِيدِ بْنِ يَسَارٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَصَدَّقَ أَحَدٌ بِصَدَقَةٍ مِنْ طَيِّبٍ وَلَا يَقْبَلُ اللَّهُ عَزَّ وَجَلَّ إِلَّا الطَّيِّبَ إِلَّا أَخَذَهَا الرَّحْمَنُ عَزَّ وَجَلَّ بِيَمِينِهِ وَإِنْ كَانَتْ تَمْرَةً فَتَرْبُو فِي كَفِّ الرَّحْمَنِ حَتَّى تَكُونَ أَعْظَمَ مِنْ الْجَبَلِ كَمَا يُرَبِّي أَحَدُكُمْ فَلُوَّهُ أَوْ فَصِيلَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] dari [Sa'id bin Yasar] bahwasanya ia mendengar [Abu Hurairah] berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Tidaklah seseorang bersedekah berupa sesuatu yang baik -dan Allah Azza Wa jalla tidak menerima kecuali yang baik- melainkan Ar-Rahman Azza Wa Jalla akan mengambilnya dengan tangan kanan-Nya. Jika sedekah itu berupa satu biji kurma, maka akan bertambah di telapak tangan Ar-Rahman hingga menjadi lebih besar dari gunung; seperti salah seorang dari kalian yang memelihara anak kuda atau anak untanya.\""},"2394":{"ar":"أَخْبَرَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْحَكَمِ عَنْ حَجَّاجٍ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عُثْمَانُ بْنُ أَبِي سُلَيْمَانَ عَنْ عَلِيٍّ الْأَزْدِيِّ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ حُبْشِيٍّ الْخَثْعَمِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ إِيمَانٌ لَا شَكَّ فِيهِ وَجِهَادٌ لَا غُلُولَ فِيهِ وَحَجَّةٌ مَبْرُورَةٌ قِيلَ فَأَيُّ الصَّلَاةِ أَفْضَلُ قَالَ طُولُ الْقُنُوتِ قِيلَ فَأَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ جُهْدُ الْمُقِلِّ قِيلَ فَأَيُّ الْهِجْرَةِ أَفْضَلُ قَالَ مَنْ هَجَرَ مَا حَرَّمَ اللَّهُ عَزَّ وَجَلَّ قِيلَ فَأَيُّ الْجِهَادِ أَفْضَلُ قَالَ مَنْ جَاهَدَ الْمُشْرِكِينَ بِمَالِهِ وَنَفْسِهِ قِيلَ فَأَيُّ الْقَتْلِ أَشْرَفُ قَالَ مَنْ أُهَرِيقَ دَمُهُ وَعُقِرَ جَوَادُهُ","id":"Telah mengabarkan kepada kami ['Abdul Wahhab bin 'Abdul Hakim] dari [Hajjaj], berkata; [Ibnu Juraij]; Telah mengabarkan kepadaku ['Utsman bin Abu Sulaiman] dari ['Ali Al Azdi] dari ['Ubaid bin 'Amir] dari ['Abdullah bin Hubsyi Al Khats'ami] bahwa Nabi shallallahu 'alaihi wasallam ditanya; \"Amal apa yang paling utama?\" Beliau bersabda: \"Keimanan tanpa ada keraguan padanya, jihad tanpa ada kedengkian dan haji mabrur.\" Beliau ditanya; \"Shalat apa yang paling utama?\" Beliau menjawab: \"Lama dalam berdoa ketika shalat; sebelum ruku' dan setelahnya.\" Dikatakan; \"Sedekah apa yang paling utama?\" Beliau menjawab: \"Sedekah yang diupayakan dengan kerja keras saat rejekinya terbatas.\" Dikatakan; \"Hijrah apa yang paling utama?\" Beliau menjawab: \"Orang yang berhijrah (meninggalkan) apa yang Allah -Azza Wa Jalla- haramkan.\" Dikatakan; \"Jihad apa yang paling utama?\" Beliau menjawab: \"Orang yang berjihad melawan kaum musyrikin dengan harta dan jiwanya.\" Dikatakan; \"Mati apa yang paling mulia?\" Beliau menjawab: \"Orang yang darahnya dialirkan dan kudanya disembelih.\""},"2395":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ وَالْقَعْقَاعُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَبَقَ دِرْهَمٌ مِائَةَ أَلْفِ دِرْهَمٍ قَالُوا وَكَيْفَ قَالَ كَانَ لِرَجُلٍ دِرْهَمَانِ تَصَدَّقَ بِأَحَدِهِمَا وَانْطَلَقَ رَجُلٌ إِلَى عُرْضِ مَالِهِ فَأَخَذَ مِنْهُ مِائَةَ أَلْفِ دِرْهَمٍ فَتَصَدَّقَ بِهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Sa'id bin Abu Sa'id] dan [Al Qa'qa'] dari [Abu Hurairah] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Satu Dirham -pahalanya- bisa mendahului seratus ribu Dirham.\" Mereka bertanya; 'Bagaimana hal itu? ' Beliau bersabda: 'Seseorang memiliki uang dua Dirham, lalu mensedekahkan satu Dirham; dan seseorang pergi ke tempat hartanya yang melimpah ruah, ia mengambil darinya seratus ribu Dirham, lalu ia bersedekah dengannya.\""},"2396":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى قَالَ حَدَّثَنَا ابْنُ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبَقَ دِرْهَمٌ مِائَةَ أَلْفٍ قَالُوا يَا رَسُولَ اللَّهِ وَكَيْفَ قَالَ رَجُلٌ لَهُ دِرْهَمَانِ فَأَخَذَ أَحَدَهُمَا فَتَصَدَّقَ بِهِ وَرَجُلٌ لَهُ مَالٌ كَثِيرٌ فَأَخَذَ مِنْ عُرْضِ مَالِهِ مِائَةَ أَلْفٍ فَتَصَدَّقَ بِهَا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Shafwan bin 'Isa] dia berkata; telah menceritakan kepada kami [Ibnu 'Ajlan] dari [Zaid bin Aslam] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Satu Dirham -pahalanya- bisa memenangkan seratus ribu Dirham.\" Mereka bertanya; \"Bagaimana hal itu?\" Beliau bersabda: \"Seorang memiliki uang dua Dirham, lalu mengambil satu Dirham dan bersedekah dengannya; dan seseorang memiliki harta yang banyak, lalu ia mengambil seratus ribu dari harta yang melimpah, kemudian ia bersedekah dengannya.\""},"2397":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ عَنْ مَنْصُورٍ عَنْ شَقِيقٍ عَنْ أَبِي مَسْعُودٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا بِالصَّدَقَةِ فَمَا يَجِدُ أَحَدُنَا شَيْئًا يَتَصَدَّقُ بِهِ حَتَّى يَنْطَلِقَ إِلَى السُّوقِ فَيَحْمِلَ عَلَى ظَهْرِهِ فَيَجِيءَ بِالْمُدِّ فَيُعْطِيَهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْرِفُ الْيَوْمَ رَجُلًا لَهُ مِائَةُ أَلْفٍ مَا كَانَ لَهُ يَوْمَئِذٍ دِرْهَمٌ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] dia berkata; Telah memberitakan kepada kami [Al Fadhl bin Musa] dari [Al Husain] dari [Manshur] dari [Syaqiq] dari [Abu Mas'ud] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam memerintahkan kami untuk bersedekah, lalu salah seorang di antara kami tidak mendapatkan sesuatu yang bisa disedekahkan, hingga ia pergi ke pasar dan membawa sesuatu di atas punggungnya, lalu datang dengan membawa satu mud -hasil kerja kerasnya- yang ia berikan kepada Rasulullah Shalallahu 'Alaihi Wa Sallam. Sungguh sekarang aku mengetahui seseorang yang memiliki seratus ribu yang sebelumnya ia tidak memiliki satu dirhampun.\""},"2398":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ قَالَلَمَّا أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّدَقَةِ فَتَصَدَّقَ أَبُو عَقِيلٍ بِنِصْفِ صَاعٍ وَجَاءَ إِنْسَانٌ بِشَيْءٍ أَكْثَرَ مِنْهُ فَقَالَ الْمُنَافِقُونَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَغَنِيٌّ عَنْ صَدَقَةِ هَذَا وَمَا فَعَلَ هَذَا الْآخَرُ إِلَّا رِيَاءً فَنَزَلَتْ{ الَّذِينَ يَلْمِزُونَ الْمُطَّوِّعِينَ مِنْ الْمُؤْمِنِينَ فِي الصَّدَقَاتِ وَالَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ }","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid] dia berkata; Telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] dari [Abu Mas'ud] dia berkata; \"Setelah Rasulullah Shalallahu 'Alaihi Wa Sallam memerintahkan kami untuk bersedekah, maka Abu Uqail bersedekah dengan satu sha', dan datang seseorang dengan membawa lebih banyak dari itu, lalu orang-orang munafik berkata; \" Allah Azza Wa Jalla benar-benar tidak membutuhkan sedekah orang ini, orang ini tidak melakukannya kecuali dengan riya'. Lalu turun ayat: 'Orang-orang munafik itu yaitu orang-orang yang mencela orang-orang mukmin yang memberi sedekah dengan sukarela dan (mencela) orang-orang yang tidak memperoleh (untuk disedekahkan) selain sekadar kesanggupannya.\" (Qs. At Taubah 9: 79)."},"2399":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدٌ وَعُرْوَةُ سَمِعَا حَكِيمَ بْنَ حِزَامٍ يَقُولُسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ قَالَ إِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ فَمَنْ أَخَذَهُ بِطِيبِ نَفْسٍ بُورِكَ لَهُ فِيهِ وَمَنْ أَخَذَهُ بِإِشْرَافِ نَفْسٍ لَمْ يُبَارَكْ لَهُ فِيهِ وَكَانَ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Sa'id] dan ['Urwah] keduanya mendengar [Hakim bin Hizam] berkata; \"Aku meminta kepada Rasulullah Shalallahu 'Alaihi Wa Sallam, lalu beliau memberiku. Kemudian aku meminta, lalu beliau memberiku. Kemudian aku meminta -lagi-, lalu beliau memberiku. Kemudian beliau bersabda: \" Harta ini hijau lagi manis. Barangsiapa yang mengambil dengan kerelaan jiwa, akan diberkahi; dan barangsiapa yang mengambilnya dengan kesombongan diri, ia tidak akan diberkahi. Hal itu seperti orang yang makan dan tidak merasa kenyang. Tangan di atas lebih baik daripada tangan di bawah'.\""},"2400":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ عِيسَى قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ طَارِقٍ الْمُحَارِبِيِّ قَالَقَدِمْنَا الْمَدِينَةَ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ عَلَى الْمِنْبَرِ يَخْطُبُ النَّاسَ وَهُوَ يَقُولُ يَدُ الْمُعْطِي الْعُلْيَا وَابْدَأْ بِمَنْ تَعُولُ أُمَّكَ وَأَبَاكَ وَأُخْتَكَ وَأَخَاكَ ثُمَّ أَدْنَاكَ أَدْنَاكَمُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Yusuf bin 'Isa] dia berkata; Telah memberitakan kepada kami [Al Fadl bin Musa] dia berkata; telah menceritakan kepada kami [Yazid bin Ziyad bin Abul Ja'd] dari [Jami' bin Syaddad] dari [Thariq Al Muharibi] dia berkata; \"kami sampai di Madinah dan ternyata Rasulullah Shallallahu'alaihi wa Sallam berdiri diatas mimbar berkhutbah dihadapan manusia, beliau bersabda: \"Tangan seorang pemberi adalah diatas, mulailah dengan yang engkau tanggung, ibumu, ayahmu saudari dan saudaramu, kemudian yang dibawahmu dan yang berada dibawahmu.\" Secara ringkas."},"2401":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ يَذْكُرُ الصَّدَقَةَ وَالتَّعَفُّفَ عَنْ الْمَسْأَلَةِ الْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى وَالْيَدُ الْعُلْيَا الْمُنْفِقَةُ وَالْيَدُ السُّفْلَى السَّائِلَةُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: -Beliau menyebutkan tentang sedekah dan enggan untuk meminta-minta-: \"Tangan di atas lebih baik daripada tangan di bawah. Tangan di atas adalah orang yang berinfak dan tangan yang di bawah adalah orang yang meminta-minta.\""},"2402":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا بَكْرٌ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ الصَّدَقَةِ مَا كَانَ عَنْ ظَهْرِ غِنًى وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى وَابْدَأْ بِمَنْ تَعُولُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Bakr] dari [Ibnu 'Ajlan] dari [bapaknya] dari [Abu Hurairah] dari Rasulullah Shalallahu 'Alaihi Wa Sallam, beliau bersabda: \"Sedekah yang paling utama ialah yang diambil dari sisa kebutuhan sendiri. Dan tangan di atas lebih baik daripada tangan yang di bawah, dan mulailah -memberi- orang yang menjadi tanggunganmu.\""},"2403":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَصَدَّقُوا فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ عِنْدِي دِينَارٌ قَالَ تَصَدَّقْ بِهِ عَلَى نَفْسِكَ قَالَ عِنْدِي آخَرُ قَالَ تَصَدَّقْ بِهِ عَلَى زَوْجَتِكَ قَالَ عِنْدِي آخَرُ قَالَ تَصَدَّقْ بِهِ عَلَى وَلَدِكَ قَالَ عِنْدِي آخَرُ قَالَ تَصَدَّقْ بِهِ عَلَى خَادِمِكَ قَالَ عِنْدِي آخَرُ قَالَ أَنْتَ أَبْصَرُ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dan [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Yahya] dari [Ibnu 'Ajlan] dari [Sa'id] dari [Abu Hurairah] dia berkata; Rasulullah Shallallahu'alaihi wa Sallam bersabda: \"Bersedekahlah kalian\", lalu seseorang berkata ya Rasulullah aku hanya memiliki satu dinar, beliau menjawab: \"Bersedekahlah dengannya untuk dirimu, \" ia berkata aku mempunyai yang lain, beliau bersabda: \"Bersedekahlah untuk istrimu, \" ia berkata aku mempunyai yang lain, beliau bersabda: \"Bersedekahlah untuk anakmu, \" ia berkata aku memiliki yang lain, beliau bersabda: \"Bersedekahlah untuk pembantumu, \" ia berkata aku memiliki yang lain, beliau bersabda: \"Engkau lebih tahu yang berhak engkau beri.\""},"2404":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ عَجْلَانَ عَنْ عِيَاضٍ عَنْ أَبِي سَعِيدٍأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ يَوْمَ الْجُمُعَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ صَلِّ رَكْعَتَيْنِ ثُمَّ جَاءَ الْجُمُعَةَ الثَّانِيَةَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ صَلِّ رَكْعَتَيْنِ ثُمَّ جَاءَ الْجُمُعَةَ الثَّالِثَةَ فَقَالَ صَلِّ رَكْعَتَيْنِ ثُمَّ قَالَ تَصَدَّقُوا فَتَصَدَّقُوا فَأَعْطَاهُ ثَوْبَيْنِ ثُمَّ قَالَ تَصَدَّقُوا فَطَرَحَ أَحَدَ ثَوْبَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَمْ تَرَوْا إِلَى هَذَا أَنَّهُ دَخَلَ الْمَسْجِدَ بِهَيْئَةٍ بَذَّةٍ فَرَجَوْتُ أَنْ تَفْطِنُوا لَهُ فَتَتَصَدَّقُوا عَلَيْهِ فَلَمْ تَفْعَلُوا فَقُلْتُ تَصَدَّقُوا فَتَصَدَّقْتُمْ فَأَعْطَيْتُهُ ثَوْبَيْنِ ثُمَّ قُلْتُ تَصَدَّقُوا فَطَرَحَ أَحَدَ ثَوْبَيْهِ خُذْ ثَوْبَكَ وَانْتَهَرَهُ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; Telah menceritakan kepada kami [Yahya] dia berkata; Telah menceritakan kepada kami [Ibnu 'Ajlan] dari ['Iyadl] dari [Abu Sa'id] bahwa seseorang masuk ke masjid pada hari Jum'at dan Rasulullah Shalallahu 'Alaihi Wa Sallam sedang berkhutbah, lalu beliau bersabda: \"Shalatlah dua rakaat!\" Kemudian orang itu datang pada Jum'at kedua dan Nabi shallallahu 'alaihi wasallam sedang berkhutbah, lalu beliau bersabda: 'Shalatlah dua rakaat! ' Kemudian orang itu datang pada Jum'at ketiga dan Nabi shallallahu 'alaihi wasallam sedang berkhutbah, lalu beliau bersabda: 'Shalatlah dua rakaat! ' Kemudian bersabda: 'Bersedekahlah kalian! ' Lalu mereka bersedekah dan beliau memberikannya dua pakaian, kemudian bersabda: 'Bersedekahlah kalian! ' Lalu ia melemparkan salah satu pakaiannya, maka Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: 'Tidakkah kalian melihat orang ini bahwa ia masuk ke masjid dengan kondisi yang kusut, aku berharap kalian memahaminya lalu kalian mau bersedekah kepadanya, tetapi kalian tidak melakukannya'. Lalu kukatakan, 'Bersedekahlah kalian! ' Lalu kalian bersedekah dan kuberikan dia dua pakaian. Kemudian kukatakan, 'Bersedekahlah kalian! ' Lalu ia melemparkan salah satu pakaiannya. 'Ambillah pakaianmu'. Dan beliau membentaknya."},"2405":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَاتِمٌ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ قَالَ سَمِعْتُ عُمَيْرًا مَوْلَى آبِي اللَّحْمِ قَالَأَمَرَنِي مَوْلَايَ أَنْ أُقَدِّدَ لَحْمًا فَجَاءَ مِسْكِينٌ فَأَطْعَمْتُهُ مِنْهُ فَعَلِمَ بِذَلِكَ مَوْلَايَ فَضَرَبَنِي فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَاهُ فَقَالَ لِمَ ضَرَبْتَهُ فَقَالَ يُطْعِمُ طَعَامِي بِغَيْرِ أَنْ آمُرَهُ وَقَالَ مَرَّةً أُخْرَى بِغَيْرِ أَمْرِي قَالَ الْأَجْرُ بَيْنَكُمَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Hatim] dari [Yazid bin Abu 'Ubaid] dia berkata; Aku mendengar ['Umair] -budak- Abul Lahm, berkata; \"Tuanku menyuruhku membuat dendeng, lalu datanglah seorang miskin dan aku memberi makan darinya, lalu tuanku mengetahui hal itu, iapun memukulku, lalu aku menemui Rasulullah Shallallahu'alaihi wa Sallam dan beliau memanggilnya, beliau bertanya: \" Kenapa engkau memukulnya?\" Ia menjawab, ia memberi makan orang lain dengan makananku tanpa aku suruh, ia berkata lagi; 'Tanpa perintahku', beliau bersabda: 'Pahalanya untuk kalian berdua.'"},"2406":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي ابْنُ أَبِي بُرْدَةَ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَى كُلِّ مُسْلِمٍ صَدَقَةٌ قِيلَ أَرَأَيْتَ إِنْ لَمْ يَجِدْهَا قَالَ يَعْتَمِلُ بِيَدِهِ فَيَنْفَعُ نَفْسَهُ وَيَتَصَدَّقُ قِيلَ أَرَأَيْتَ إِنْ لَمْ يَفْعَلْ قَالَ يُعِينُ ذَا الْحَاجَةِ الْمَلْهُوفَ قِيلَ فَإِنْ لَمْ يَفْعَلْ قَالَ يَأْمُرُ بِالْخَيْرِ قِيلَ أَرَأَيْتَ إِنْ لَمْ يَفْعَلْ قَالَ يُمْسِكُ عَنْ الشَّرِّ فَإِنَّهَا صَدَقَةٌ","id":"Telah mengabarkan kepadaku [Muhammad bin 'Abdul A'la] dia berkata; Telah menceritakan kepada kami [Khalid] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; Telah mengabarkan kepadaku [Ibnu Abu Burdah] dia berkata; Aku mendengar [bapakku] menceritakan dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Wajib bagi setiap muslim untuk bersedekah.\" Dikatakan; 'Bagaimana pendapatmu jika ia tidak mendapatkannya? ' Beliau bersabda: 'Berusaha dengan tangannya, sehingga ia bisa memberi manfaat untuk dirinya dan bersedekah.' Dikatakan; 'Bagaimana jika ia tidak bisa melakukannya? ' Beliau bersabda: 'Menolong orang yang sangat memerlukan bantuan.' Dikatakan; 'Bagaimana jika ia tidak bisa melakukannya? ' Beliau bersabda: 'Menyuruh untuk melakukan kebaikan.' Dikatakan; 'Bagaimana jika ia tidak melakukannya? ' Beliau bersabda: 'Menahan diri dari kejahatan, karena itu adalah sedekah.'"},"2407":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ ابْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ أَبَا وَائِلٍ يُحَدِّثُ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَصَدَّقَتْ الْمَرْأَةُ مِنْ بَيْتِ زَوْجِهَا كَانَ لَهَا أَجْرٌ وَلِلزَّوْجِ مِثْلُ ذَلِكَ وَلِلْخَازِنِ مِثْلُ ذَلِكَ وَلَا يَنْقُصُ كُلُّ وَاحِدٍ مِنْهُمَا مِنْ أَجْرِ صَاحِبِهِ شَيْئًا لِلزَّوْجِ بِمَا كَسَبَ وَلَهَا بِمَا أَنْفَقَتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dia berkata; Aku mendengar [Abu Wa'il] menceritakan dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika seorang istri bersedekah dari rumah suaminya, maka ia akan mendapatkan pahala. Suaminya juga mendapatkan pahala yang sama dan orang yang diserahi amanat -hartanya- juga mendapatkan pahala yang sama. Dan pahala masing-masing dari keduanya tidak berkurang sedikitpun karena pahala yang lainnya. Bagi suami mendapatkan pahala karena sesuatu yang ia usahakan, dan bagi istri mendapatkan pahala karena sesuatu yang ia infakkan.\""},"2408":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ أَنَّ أَبَاهُ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَلَمَّا فَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ قَامَ خَطِيبًا فَقَالَ فِي خُطْبَتِهِ لَا يَجُوزُ لِامْرَأَةٍ عَطِيَّةٌ إِلَّا بِإِذْنِ زَوْجِهَامُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; Telah menceritakan kepada kami [Khalid bin Al Harits] dia berkata; Telah menceritakan kepada kami [Husain Al Mu'allim] dari ['Amru bin Syu'aib] bahwasanya [bapaknya] menceritakan kepadanya, dari ['Abdullah bin 'Amru] dia berkata; \"Setelah Rasulullah Shalallahu 'Alaihi Wa Sallam menaklukan kota Mekkah, beliau berdiri seraya bersabda di dalam khutbahnya: 'Tidak boleh seorang istri memberi tanpa izin suaminya'.\""},"2409":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا أَبُو عَوَانَةَ عَنْ فِرَاسٍ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْتَمَعْنَ عِنْدَهُ فَقُلْنَ أَيَّتُنَا بِكَ أَسْرَعُ لُحُوقَا فَقَالَ أَطْوَلُكُنَّ يَدًا فَأَخَذْنَ قَصَبَةً فَجَعَلْنَ يَذْرَعْنَهَا فَكَانَتْ سَوْدَةُ أَسْرَعَهُنَّ بِهِ لُحُوقًا فَكَانَتْ أَطْوَلَهُنَّ يَدًا فَكَانَ ذَلِكَ مِنْ كَثْرَةِ الصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Abu Dawud] dia berkata; Telah menceritakan kepada kami [Yahya bin Hammad] dia berkata; Telah memberitakan kepada kami [Abu 'Awanah] dari [Firas] dari ['Amir] dari [Masruq] dari ['Aisyah radliallahu 'anha] bahwa istri-istri Nabi shallallahu 'alaihi wasallam berkumpul di samping beliau, lalu mereka berkata; \"Manakah di antara kita yang paling cepat menyusulmu?\" Maka beliau bersabda: 'Yang paling panjang tangannya di antara kalian.' Maka mereka mengambil bambu dan segera mengukurnya. Ternyata di kemudian hari Saudah adalah yang paling cepat menyusul beliau. Maka mereka sadar bahwa maksud beliau yang paling panjang tangannya adalah yang paling banyak bersedekah."},"2410":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ أَنْ تَصَدَّقَ وَأَنْتَ صَحِيحٌ شَحِيحٌ تَأْمُلُ الْعَيْشَ وَتَخْشَى الْفَقْرَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; Telah menceritakan kepada kami [Waki'] dia berkata; Telah menceritakan kepada kami [Sufyan] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata; Seseorang bertanya; \"Wahai Rasulullah! Sedekah apa yang paling utama?\" Beliau menjawab: 'Kamu bersedekah padahal saat itu kamu dalam keadaan sehat dan sangat berat untuk bersedekah (bakhil), kamu mendambakan kehidupan dan takut fakir.'"},"2411":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ سَمِعْتُ مُوسَى بْنَ طَلْحَةَ أَنَّ حَكِيمَ بْنَ حِزَامٍ حَدَّثَهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الصَّدَقَةِ مَا كَانَ عَنْ ظَهْرِ غِنًى وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى وَابْدَأْ بِمَنْ تَعُولُ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; Telah menceritakan kepada kami [Yahya] dia berkata; Telah menceritakan kepada kami ['Amru bin 'Utsman] dia berkata; Aku mendengar [Musa bin Thalhah] bahwa [Hakim bin Hizam] menceritakannya, dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Sedekah yang paling utama ialah yang diambil dari sisa kebutuhan sendiri. Dan tangan di atas lebih baik daripada tangan di bawah, dan mulailah -memberi sedekah- orang yang menjadi tanggunganmu.\""},"2412":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو عَنْ ابْنِ وَهْبٍ قَالَ أَنْبَأَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَا��َ حَدَّثَنَا سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ الصَّدَقَةِ مَا كَانَ عَنْ ظَهْرِ غِنًى وَابْدَأْ بِمَنْ تَعُولُ","id":"Telah mengabarkan kepada kami ['Amru bin Sawwad bin Al Aswad bin 'Amru] dari [Ibnu Wahb] dia berkata; Telah memberitakan kepada kami [Yunus] dari [Ibnu Syihab] dia berkata; Telah menceritakan kepada kami [Sa'id bin Al Musayyab] bahwasanya ia mendengar [Abu Hurairah] berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Sebaik-baik sedekah ialah yang diambil dari sisa kebutuhan sendiri. Dan mulailah -memberi sedekah- orang yang menjadi tanggunganmu.\""},"2413":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ الْأَنْصَارِيَّ يُحَدِّثُ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَنْفَقَ الرَّجُلُ عَلَى أَهْلِهِ وَهُوَ يَحْتَسِبُهَا كَانَتْ لَهُ صَدَقَةً","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; Telah menceritakan kepada kami [Muhammad] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dia berkata; Aku mendengar ['Abdullah bin Yazid Al Anshari] menceritakan dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika seseorang memberikan nafkah kepada keluarganya dan ia mengharapkan pahalanya, hal itu adalah sedekah baginya.\""},"2414":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَأَعْتَقَ رَجُلٌ مِنْ بَنِي عُذْرَةَ عَبْدًا لَهُ عَنْ دُبُرٍ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَكَ مَالٌ غَيْرُهُ قَالَ لَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَشْتَرِيهِ مِنِّي فَاشْتَرَاهُ نُعَيْمُ بْنُ عَبْدِ اللَّهِ الْعَدَوِيُّ بِثَمَانِ مِائَةِ دِرْهَمٍ فَجَاءَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَفَعَهَا إِلَيْهِ ثُمَّ قَالَ ابْدَأْ بِنَفْسِكَ فَتَصَدَّقْ عَلَيْهَا فَإِنْ فَضَلَ شَيْءٌ فَلِأَهْلِكَ فَإِنْ فَضَلَ شَيْءٌ عَنْ أَهْلِكَ فَلِذِي قَرَابَتِكَ فَإِنْ فَضَلَ عَنْ ذِي قَرَابَتِكَ شَيْءٌ فَهَكَذَا وَهَكَذَا يَقُولُ بَيْنَ يَدَيْكَ وَعَنْ يَمِينِكَ وَعَنْ شِمَالِكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir] dia berkata; \"Seseorang dari bani Udzrah -menjanjikan- untuk memerdekakan budaknya setelah ia meninggal, lalu hal itu sampai kepada Rasulullah Shalallahu 'Alaihi Wa Sallam, maka beliau bertanya: 'Apakah kamu memiliki harta selain dia? ' Ia menjawab; 'Tidak'. Lalu Rasulullah Shalallahu 'Alaihi Wa Sallam bertanya: 'Siapakah yang membelinya dariku? ' Lalu Nu'man bin Abdullah Al Adawi membelinya dengan harga delapan ratus Dirham. Ia datang dengan membawa uang tersebut kepada Rasulullah Shalallahu 'Alaihi Wa Sallam, lalu beliau memberikan kepadanya, kemudian beliau bersabda: 'Mulailah dengan dirimu, bersedekahlah padanya. Jika ada kelebihan, maka untuk keluargamu. Jika ada kelebihan dari keluargamu, maka untuk kerabatmu. Jika ada kelebihan dari kerabatmu, maka begini dan begini -beliau bersabda: - yang ada di hadapanmu, di samping kananmu dan di samping kirimu.'"},"2415":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ طَاوُسٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ ثُمَّ قَالَ حَدَّثَنَاه أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مَثَلَ الْمُنْفِقِ الْمُتَصَدِّقِ وَالْبَخِيلِ كَمَثَلِ رَجُلَيْنِ عَلَيْهِمَا جُبَّتَانِ أَوْ جُنَّتَانِ مِنْ حَدِيدٍ مِنْ لَدُنْ ثُدِيِّهِمَا إِلَى تَرَاقِيهِمَا فَإِذَا أَرَادَ الْمُنْفِقُ أَنْ يُنْفِقَ اتَّسَعَتْ عَلَيْهِ الدِّرْعُ أَوْ مَرَّتْ حَتَّى تُجِنَّ بَنَانَهُ وَتَعْفُوَ أَثَرَهُ وَإِذَا أَرَادَ الْبَخِيلُ أَنْ يُنْفِقَ قَلَصَتْ وَلَزِمَتْ كُلُّ حَلْقَةٍ مَوْضِعَهَا حَتَّى إِذَا أَخَذَتْهُ بِتَرْقُوَتِهِ أَوْ بِرَقَبَتِهِ يَقُولُ أَبُو هُرَيْرَةَ أَشْهَدُ أَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوَسِّعُهَا فَلَا تَتَّسِعُقَالَ طَاوُسٌ سَمِعْتُ أَبَا هُرَيْرَةَ يُشِيرُ بِيَدِهِ وَهُوَ يُوَسِّعُهَا وَلَا تَتَوَسَّعُ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari [Al Hasan bin Muslim] dari [Thawus] dia berkata; Aku mendengar [Abu Hurairah], kemudian dia berkata; Telah menceritakan kepada kami [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \" Perumpamaan orang yang berinfak serta bersedekah dan orang yang bakhil adalah seperti dua orang yang memakai dua jubah -atau dua tameng dari besi-, mulai dari payudara (dada) sampai tulang selangka mereka berdua. Jika orang tersebut ingin berinfak, maka baju besinya melebar atau bergerak hingga menutupi ujung jarinya dan menghilangkan bekas-jalan-nya. Jika orang yang bakhil ingin berinfak, baju besinya mengerut, dan setiap baju besi tetap di tempatnya (tidak melebar) hingga mengambilnya dengan tulang selangkanya atau dengan lehernya.\" Abu Hurairah berkata; 'Aku menyaksikan bahwa ia melihat Rasulullah Shalallahu 'Alaihi Wa Sallam melebarkan tameng besi tetapi tidak melebar.' Thawus berkata; 'Aku mendengar Abu Hurairah -ia memberikan isyarat dengan tangannya- dan beliau melebarkan tameng besi tetapi tidak melebar.'"},"2416":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْبَخِيلِ وَالْمُتَصَدِّقِ مَثَلُ رَجُلَيْنِ عَلَيْهِمَا جُنَّتَانِ مِنْ حَدِيدٍ قَدْ اضْطَرَّتْ أَيْدِيَهُمَا إِلَى تَرَاقِيهِمَا فَكُلَّمَا هَمَّ الْمُتَصَدِّقُ بِصَدَقَةٍ اتَّسَعَتْ عَلَيْهِ حَتَّى تُعَفِّيَ أَثَرَهُ وَكُلَّمَا هَمَّ الْبَخِيلُ بِصَدَقَةٍ تَقَبَّضَتْ كُلُّ حَلْقَةٍ إِلَى صَاحِبَتِهَا وَتَقَلَّصَتْ عَلَيْهِ وَانْضَمَّتْ يَدَاهُ إِلَى تَرَاقِيهِ وَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَيَجْتَهِدُ أَنْ يُوَسِّعَهَا فَلَا تَتَّسِعُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; Telah menceritakan kepada kami ['Affan] dia berkata; Telah menceritakan kepada kami [Wuhaib] dia berkata; Telah menceritakan kepada kami ['Abdullah bin Thawus] dari [Bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Permisalan orang bakhil dengan orang yang suka berinfaq adalah seperti dua orang laki-laki yang mengenakan baju besi yang membungkus tulang dadanya. Adapun orang yang suka berinfaq, setiap ia ingin berinfaq baju besi itu seakan akan membesar dan memberikan kelonggaran baginya sehingga dosanya dihapuskan, sedangkan bagi orang yang bakhil setiap ia ingin berinfaq baju besi tersebut mengecil dan menghimpitnya.\" Abu Hurairah berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ia berusaha agar baju besinya lapang, namun tidak bisa lapang.\""},"2417":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ أُمَيَّةَ بْنِ هِنْدٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ قَالَكُنَّا يَوْمًا فِي الْمَسْجِدِ جُلُوسًا وَنَفَرٌ مِنْ الْمُهَاجِرِينَ وَالْأَنْصَارِ فَأَرْسَلْنَا رَجُلًا إِلَى عَائِشَةَ لِيَسْتَأْذِنَ فَدَخَلْنَا عَلَيْهَا قَالَتْ دَخَلَ عَلَيَّ سَائِلٌ مَرَّةً وَعِنْدِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرْتُ لَهُ بِشَيْءٍ ثُمَّ دَعَوْتُ بِهِ فَنَظَرْتُ إِلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا تُرِيدِينَ أَنْ لَا يَدْخُلَ بَيْتَكِ شَيْءٌ وَلَا يَخْرُجَ إِلَّا بِعِلْمِكِ قُلْتُ نَعَمْ قَالَ مَهْلًا يَا عَائِشَةُ لَا تُحْصِي فَيُحْصِيَ اللَّهُ عَزَّ وَجَلَّ عَلَيْكِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul Hakam] dari [Syu'aib]; Telah menceritakan kepadaku [Al Laits] dia berkata; Telah menceritakan kepada kami [Khalid] dari [Ibnu Abu Hilal] dari [Umayyah bin Hind] dari [Abu Umamah bin Sahl bin Hunaif] dia berkata; \"Pada suatu hari kami duduk-duduk di masjid dengan beberapa orang dari Muhajirin dan Anshar, lalu kami menyuruh seseorang untuk meminta ijin masuk ke rumah 'Aisyah, lalu kami masuk ke rumahnya. [Aisyah] berkata; suatu kali seseorang masuk ke rumahku dan disisiku ada Rasulullah Shallallahu'alaihi wa sallam, aku menyuruhnya dan aku memanggilnya lalu melarangnya, kemudian Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Apakah engkau mau agar seseorang tidak masuk ke rumahmu dan ia tidak keluar kecuali dengan sepegetahuanmu?\" Aku menjawab; 'Ya, beliau bersabda: \"Tenanglah ya 'Aisyah janganlah engkau menghitung-hitung pemberianmu, maka Allah pun akan memperhitungkan apa yang telah kamu perbuat.\""},"2418":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ عَبْدَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا لَا تُحْصِي فَيُحْصِيَ اللَّهُ عَزَّ وَجَلَّ عَلَيْكِ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari ['Abdah] dari [Hisyam bin 'Urwah] dari [Fathimah] dari [Asma' binti Abu Bakr] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Aisyah: \"Janganlah engkau menghitung-hitung pemberianmu, maka Allah pun akan memperhitungkan apa yang telah kamu perbuat.\""},"2419":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ عَنْ حَجَّاجٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍأَنَّهَا جَاءَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا نَبِيَّ اللَّهِ لَيْسَ لِي شَيْءٌ إِلَّا مَا أَدْخَلَ عَلَيَّ الزُّبَيْرُ فَهَلْ عَلَيَّ جُنَاحٌ فِي أَنْ أَرْضَخَ مِمَّا يُدْخِلُ عَلَيَّ فَقَالَ ارْضَخِي مَا اسْتَطَعْتِ وَلَا تُوكِي فَيُوكِيَ اللَّهُ عَزَّ وَجَلَّ عَلَيْكِ","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad] dari [Hajjaj] dia berkata; [Ibnu Juraij] berkata; Telah mengabarkan kepadaku [Ibnu Abu Mulaikah] dari ['Abbad bin 'Abdullah bin Az Zubair] dari [Asma' binti Abu Bakr] bahwa ia datang menemui Nabi shallallahu 'alaihi wasallam seraya berkata; wahai Nabiyullah, aku tidak mempunyai apa-apa kecuali hanya apa yang telah diberikan Az Zubair kepadaku, apakah aku boleh berinfak dengannya? Beliau menjawab: \"Berinfaklah dan janganlah kamu menahan pemberian, Karena jika demikian Allah akan menahan pemberian-Nya kepadamu.\""},"2420":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ عَنْ خَالِدٍ حَدَّثَنَا شُعْبَةُ عَنْ الْمُحِلِّ عَنْ عَدِيِّ بْنِ حَاتِمٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اتَّقُوا النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ","id":"Telah mengabarkan kepada kami [Nashr bin 'Ali] dari [Khalid]; Telah menceritakan kepada kami [Syu'bah] dari [Al Muhil] dari ['Adi bin Hatim] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Takutlah kalian dengan api neraka, walaupun dengan menginfakkan sepotong kurma.\""},"2421":{"ar":"أَنْبَأَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ أَنَّ عَمْرَو بْنَ مُرَّةَ حَدَّثَهُمْ عَنْ خَيْثَمَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّارَ فَأَشَاحَ بِوَجْهِهِ وَتَعَوَّذَ مِنْهَا ذَكَرَ شُعْبَةُ أَنَّهُ فَعَلَهُ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ اتَّقُوا النَّارَ وَلَوْ بِشِقِّ التَّمْرَةِ فَإِنْ لَمْ تَجِدُوا فَبِكَلِمَةٍ طَيِّبَةٍ","id":"Telah memberitakan kepada kami [Isma'il bin Mas'ud] dia berkata; Telah menceritakan kepada kami [Khalid] dia berkata; Telah menceritakan kepada kami [Syu'bah] bahwa ['Amru bin Murrah] Telah menceritakan kepada mereka dari [Khaitsamah] dari ['Adi bin Hatim] dia berkata; Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang neraka, maka wajah beliau berubah (karena takut darinya), lalu beliau berlindung darinya. Syu'bah menyebutkan, bahwa Rasulullah shallallahu 'alaihi wasallam berlindung dari api neraka sebanyak tiga kali, lalu beliau bersabda: \"Takutlah kalian dari api neraka, walaupun dengan menginfakkan sepotong kurma. Jika kalian tidak mendapatkannya, maka dengan kalimat yang baik.\""},"2422":{"ar":"أَخْبَرَنَا أَزْهَرُ بْنُ جَمِيلٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ وَذَكَرَ عَوْنَ بْنَ أَبِي جُحَيْفَةَ قَالَ سَمِعْتُ الْمُنْذِرَ بْنَ جَرِيرٍ يُحَدِّثُ عَنْ أَبِيهِ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَدْرِ النَّهَارِ فَجَاءَ قَوْمٌ عُرَاةً حُفَاةً مُتَقَلِّدِي السُّيُوفِ عَامَّتُهُمْ مِنْ مُضَرَ بَلْ كُلُّهُمْ مِنْ مُضَرَ فَتَغَيَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَا رَأَى بِهِمْ مِنْ الْفَاقَةِ فَدَخَلَ ثُمَّ خَرَجَ فَأَمَرَ بِلَالًا فَأَذَّنَ فَأَقَامَ الصَّلَاةَ فَصَلَّى ثُمَّ خَطَبَ فَقَالَ{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }وَ{ اتَّقُوا اللَّهَ وَلْتَنْظُرْ نَفْسٌ مَا قَدَّمَتْ لِغَدٍ }تَصَدَّقَ رَجُلٌ مِنْ دِينَارِهِ مِنْ دِرْهَمِهِ مِنْ ثَوْبِهِ مِنْ صَاعِ بُرِّهِ مِنْ صَاعِ تَمْرِهِ حَتَّى قَالَ وَلَوْ بِشِقِّ تَمْرَةٍ فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ بِصُرَّةٍ كَادَتْ كَفُّهُ تَعْجِزُ عَنْهَا بَلْ قَدْ عَجَزَتْ ثُمَّ تَتَابَعَ النَّاسُ حَتَّى رَأَيْتُ كَوْمَيْنِ مِنْ طَعَامٍ وَثِيَابٍ حَتَّى رَأَيْتُ وَجْهَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَهَلَّلُ كَأَنَّهُ مُذْهَبَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَنَّ فِي الْإِسْلَامِ سُنَّةً حَسَنَةً فَلَهُ أَجْرُهَا وَأَجْرُ مَنْ عَمِلَ بِهَا مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أُجُورِهِمْ شَيْئًا وَمَنْ سَنَّ فِي الْإِسْلَامِ سُنَّةً سَيِّئَةً فَعَلَيْهِ وِزْرُهَا وَوِزْرُ مَنْ عَمِلَ بِهَا مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أَوْزَارِهِمْ شَيْئًا","id":"Telah mengabarkan kepada kami [Azhar bin Jamil] dia berkata; Telah menceritakan kepada kami [Khalid bin Al Harits] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; -dan dia menyebutkan ['Aun bin Abu Juhaifah], - dia berkata; Aku mendengar [Al Mundzir bin Jarir] bercerita dari [Bapaknya] dia berkata; \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam di siang hari, tiba-tiba datang suatu kaum dalam keadaan telanjang kaki sambil menggantungkan pedang-pedang mereka. Mayoritas mereka -bahkan seluruhnya- dari kalangan Mudlar. Maka wajah Rasulullah shallallahu 'alaihi wasallam pun berubah karena kemiskinan yang terlihat pada mereka. Kemudian beliau keluar dan menyuruh Bilal untuk mengumandangkan adzan, lalu mendirikan shalat. Kemudian beliau shalat dan setelah itu berkhuthbah seraya bersabda: \" Hai sekalian manusia, bertakwalah kepada Tuhan-mu yang telah menciptakan kamu dari seorang diri, dan dari padanya Allah menciptakan isterinya; dan dari pada keduanya Allah memperkembang biakkan laki-laki dan perempuan yang banyak. Dan bertakwalah kepada Allah yang dengan nama-Nya kamu saling meminta satu sama lain, dan hubungan silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasi kamu Annisa: 1. Hai orang-orang yang beriman, bertakwalah kepada Allah dan hendaklah setiap diri memperhatikan apa yang telah diperbuatnya untuk hari esok Al Hasyr: 18. Lalu bersabda: 'seseorang bersedekah dengan uang dinarnya, atau dirhamnya, atau pakaiannya, atau satu sha gandum, atau satu sha kurma, hingga beliau bersabda; walaupun dengan sepotong kurma.' Lalu seseorang dari kalangan Anshar datang dengan membawa satu ikat barang yang ia bawa, seolah-olah ia sudah tidak sanggup untuk membawanya. Orang-orangpun berdatangan hingga aku melihat dua karung makanan dan pakaian. Akupun melihat wajah Rasulullah shallallahu 'alaihi wasallam bersinar gembira seperti gemerlapnya emas. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membuat contoh baik di dalam Islam, maka baginya pahala dan pahala orang yang mengamalkan contoh baik tersebut tanpa mengurangi pahala mereka sedikit pun. Dan barang siapa yang membuat contoh buruk di dalam Islam, maka baginya dosa dan dosa orang yang mengamalkan contoh buruk tersebut tanpa mengurangi dosa mereka sedikitpun.\""},"2423":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَعْبَدِ بْنِ خَالِدٍ عَنْ حَارِثَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَصَدَّقُوا فَإِنَّهُ سَيَأْتِي عَلَيْكُمْ زَمَانٌ يَمْشِي الرَّجُلُ بِصَدَقَتِهِ فَيَقُولُ الَّذِي يُعْطَاهَا لَوْ جِئْتَ بِهَا بِالْأَمْسِ قَبِلْتُهَا فَأَمَّا الْيَوْمَ فَلَا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; Telah menceritakan kepada kami [Khalid] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Ma'bad bin Khalid] dari [Haritsah] dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersedekahlah kalian, karena akan datang kepada kalian suatu zaman ketika seseorang bersedakah, lalu berkatalah orang yang diberi sedekah; \"Kalaulah engkau datang kemarin, pastilah aku terima, adapun sekarang maka aku tidak memerlukan lagi.\""},"2424":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ أَخْبَرَنِي أَبُو بُرْدَةَ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَس��لَّمَ قَالَ اشْفَعُوا تُشَفَّعُوا وَيَقْضِي اللَّهُ عَزَّ وَجَلَّ عَلَى لِسَانِ نَبِيِّهِ مَا شَاءَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; Telah menceritakan kepada kami [Yahya] dia berkata; Telah menceritakan kepada kami [Sufyan] dia berkata; Telah mengabarkan kepadaku [Abu Burdah bin 'Abdullah bin Abu Burdah] dari Kakeknya [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Berikanlah pertolongan agar kalian saling memperoleh pahala dan semoga Allah melaksanakan apa yang dikehendaki-Nya melalui ucapan nabi-Nya.\""},"2425":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ سَعِيدٍ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ ابْنِ مُنَبِّهٍ عَنْ أَخِيهِ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الرَّجُلَ لَيَسْأَلُنِي الشَّيْءَ فَأَمْنَعُهُ حَتَّى تَشْفَعُوا فِيهِ فَتُؤْجَرُوا وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اشْفَعُوا تُؤْجَرُوا","id":"Telah mengabarkan kepada kami [Harun bin Sa'id] dia berkata; Telah memberitakan kepada kami [Sufyan] dari ['Amru] dari [Ibnu Munabih] dari [Saudaranya] dari [Mu'awiyah bin Abu Sufyan] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang laki-laki telah meminta sesuatu kepadaku lalu aku menolaknya hingga kalian saling menolong kepadanya lalu kalian memperoleh pahala karenanya. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikanlah pertolongan agar kalian saling memperoleh pahala.\""},"2426":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيُّ عَنْ ابْنِ جَابِرٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الْغَيْرَةِ مَا يُحِبُّ اللَّهُ عَزَّ وَجَلَّ وَمِنْهَا مَا يَبْغُضُ اللَّهُ عَزَّ وَجَلَّ وَمِنْ الْخُيَلَاءِ مَا يُحِبُّ اللَّهُ عَزَّ وَجَلَّ وَمِنْهَا مَا يَبْغُضُ اللَّهُ عَزَّ وَجَلَّ فَأَمَّا الْغَيْرَةُ الَّتِي يُحِبُّ اللَّهُ عَزَّ وَجَلَّ فَالْغَيْرَةُ فِي الرِّيبَةِ وَأَمَّا الْغَيْرَةُ الَّتِي يَبْغُضُ اللَّهُ عَزَّ وَجَلَّ فَالْغَيْرَةُ فِي غَيْرِ رِيبَةٍ وَالِاخْتِيَالُ الَّذِي يُحِبُّ اللَّهُ عَزَّ وَجَلَّ اخْتِيَالُ الرَّجُلِ بِنَفْسِهِ عِنْدَ الْقِتَالِ وَعِنْدَ الصَّدَقَةِ وَالِاخْتِيَالُ الَّذِي يَبْغُضُ اللَّهُ عَزَّ وَجَلَّ الْخُيَلَاءُ فِي الْبَاطِلِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; Telah menceritakan kepada kami [Muhammad bin Yusuf] dia berkata; Telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dia berkata; Telah menceritakan kepadaku [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Ibnu Jabir] dari [Bapaknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya diantara cemburu itu ada yang disukai Allah dan ada yang dibenci Allah dan diantara sikap sombong itu ada yang disukai Allah dan ada yang dibenci Allah. Cemburu yang disukai Allah adalah cemburu dalam keraguan dan yang dibenci Allah adalah cemburu diluar keraguan, sedangkan sikap sombong yang disukai Allah adalah sombongnya seseorang dengan dirinya di saat perang dan sombong di saat sedekah. Sedangkan sombong yang dibenci Allah adalah sombong dalam kebathilan.\""},"2427":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا وَتَصَدَّقُوا وَالْبَسُوا فِي غَيْرِ إِسْرَافٍ وَلَا مَخِيلَةٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Yazid] dia berkata; Telah menceritakan kepada kami [Hammam] dari [Qatadah] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah dan bersedekahlah serta berpakaianlah dengan tidak berlebihan dan sombong.\""},"2428":{"ar":"أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ الْهَيْثَمِ بْنِ عُثْمَانَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ بُرَيْدِ بْنِ أَبِي بُرْدَةَ عَنْ جَدِّهِ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤْمِنُ لِلْمُؤْمِنِ كَالْبُنْيَانِ يَشُدُّ بَعْضُهُ بَعْضًا وَقَالَ الْخَازِنُ الْأَمِينُ الَّذِي يُعْطِي مَا أُمِرَ بِهِ طَيِّبًا بِهَا نَفْسُهُ أَحَدُ الْمُتَصَدِّقَيْنِ","id":"Telah mengabarkan kepadaku ['Abdullah bin Al Haitsam bin 'Utsman] dia berkata; Telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Buraid bin Abu Burdah] dari [Kakeknya] dari [Abu Musa] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mukmin dengan mukmin yang lainnya bagaikan satu bangunan yang sebagiannya dengan sebagian yang lain saling menopang. Beliau juga bersabda: \"Sesungguhnya bendahara yang dapat dipercaya adalah orang yang memberikan apa yang diperintahkan kepadanya secara baik, dan hatinya merasa rela hingga pun menjadi salah satu dari dua pemberi sedekah.\""},"2429":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْجَاهِرُ بِالْقُرْآنِ كَالْجَاهِرِ بِالصَّدَقَةِ وَالْمُسِرُّ بِالْقُرْآنِ كَالْمُسِرِّ بِالصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; Telah menceritakan kepada kami [Ibnu Wahb] dari [Mu'awiyah bin Shalih] dari [Bahir bin Sa'ad] dari [Khalid bin Ma'dan] dari [Katsir bin Murrah] dari ['Uqbah bin 'Amir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang membaca Qur'an dengan suara keras bagaikan orang yang bersedekah secara terang-terangan, dan orang yang membaca Qur'an dengan pelan-pelan, seperti orang yang bersedekah secara sembunyi-sembunyi.\""},"2430":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا عُمَرُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ يَسَارٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يَنْظُرُ اللَّهُ عَزَّ وَجَلَّ إِلَيْهِمْ يَوْمَ الْقِيَامَةِ الْعَاقُّ لِوَالِدَيْهِ وَالْمَرْأَةُ الْمُتَرَجِّلَةُ وَالدَّيُّوثُ وَثَلَاثَةٌ لَا يَدْخُلُونَ الْجَنَّةَ الْعَاقُّ لِوَالِدَيْهِ وَالْمُدْمِنُ عَلَى الْخَمْرِ وَالْمَنَّانُ بِمَا أَعْطَى","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; Telah menceritakan kepada kami [Yazid bin Zura'i] dia berkata; Telah menceritakan kepada kami ['Umar bin Muhammad] dari ['Abdullah bin Yasar] dari [Salim bin 'Abdullah] dari [Bapaknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga golongan yang Allah tidak akan melihat mereka pada hari kiamat; anak yang durhaka kepada orang tua, wanita yang menyerupai laki-laki, dan Dayyuts, yaitu seorang yang merelakan keluarganya berbuat kekejian. Dan tiga golongan mereka tidak akan masuk surga; anak yang durhaka kepada orang tua, pecandu khamer, dan orang yang selalu menyebut-nyebut pemberiannya.\""},"2431":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ الْمُدْرِكِ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ وَلَا يَنْظُرُ إِلَيْهِمْ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ فَقَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو ذَرٍّ خَابُوا وَخَسِرُوا خَابُوا وَخَسِرُوا قَالَ الْمُسْبِلُ إِزَارَهُ وَالْمُنَفِّقُ سِلْعَتَهُ بِالْحَلِفِ الْكَاذِبِ وَالْمَنَّانُ عَطَاءَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dari [Muhammad] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari ['Ali bin Al Mudrik] dari [Abu Zur'ah bin 'Amru bin Jarir] dari [Kharasyah bin Al Hur] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tiga golongan yang tidak akan diajak bicara, tidak akan dilihat dan tidak akan disucikan oleh Allah Azza wa Jalla pada hari kiamat, bagi mereka adzab yang pedih, lalu Rasulullah shallallahu 'alaihi wasallam menyebutkannya, kemudian Abu Dzar berkata; Rugilah mereka, rugilah mereka. Rasulullah shallallahu 'alaihi wasallam bersabda: Orang yang memanjangkan kainnya dibawah mata kaki, orang yang menjual dagangannya dengan sumpah palsu, dan orang yang menyebut-nyebut pemberiannya.\""},"2432":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ قَالَ سَمِعْتُ سُلَيْمَانَ وَهُوَ الْأَعْمَشُ عَنْ سُلَيْمَانَ بْنِ مُسْهِرٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ وَلَا يَنْظُرُ إِلَيْهِمْ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ الْمَنَّانُ بِمَا أَعْطَى وَالْمُسْبِلُ إِزَارَهُ وَالْمُنَفِّقُ سِلْعَتَهُ بِالْحَلِفِ الْكَاذِبِ","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid] dia berkata; Telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dia berkata; Aku mendengar [Sulaiman] yaitu Al A'masy dari [Sulaiman bin Mushir] dari [Kharasyah bin Al Hur] dari [Abu Dzar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga golongan yang tidak akan diajak bicara, tidak akan dilihat dan tidak akan disucikan oleh Allah Azza wa Jalla pada hari kiamat, dan bagi mereka adzab yang pedih, yaitu orang yang menyebut-nyebut pemberiannya, orang yang memanjangkan kainnya dibawah mata kaki, dan orang yang menjual dagangannya dengan sumpah palsu.\""},"2433":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ ح وَأَنْبَأَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ ابْنِ بُجَيْدٍ الْأَنْصَارِيِّ عَنْ جَدِّتِهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُدُّوا السَّائِلَ وَلَوْ بِظِلْفٍ فِي حَدِيثِ هَارُونَ مُحْرَقٍ","id":"Telah mengabarkan kepadaku [Harun bin 'Abdullah] dia berkata; Telah menceritakan kepada kami [Ma'an] dia berkata; Telah menceritakan kepada kami [Malik]; (Demikian juga diriwayatkan dari jalur lain), Dan telah memberitakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Zaid bin Aslam] dari [Ibnu Bujaid Al Anshari] dari [Neneknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah orang yang meminta-minta walaupun dengan kaki (unta, kambing dsb).\" Sedangkan di dalam hadits Harun disebutkan kata; 'Muhraq' (yang sudah dibakar)."},"2434":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِ��ُ قَالَ سَمِعْتُ بَهْزَ بْنَ حَكِيمٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَأْتِي رَجُلٌ مَوْلَاهُ يَسْأَلُهُ مِنْ فَضْلٍ عِنْدَهُ فَيَمْنَعُهُ إِيَّاهُ إِلَّا دُعِيَ لَهُ يَوْمَ الْقِيَامَةِ شُجَاعٌ أَقْرَعُ يَتَلَمَّظُ فَضْلَهُ الَّذِي مَنَعَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al A'la] dia berkata; Telah menceritakan kepada kami [Al Mu'tamir] dia berkata; Aku mendengar [Bahz bin Hakim] bercerita dari [Bapaknya] dari [Kakeknya] dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang datang kepada tuannya untuk meminta suatu kelebihan yang dimilikinya, lalu ia menolaknya, maka pada hari kiamat akan didatangkan kepadanya seekor ular berbisa yang akan menjilat-jilat kelebihan yang dulu ia tidak mau memberikannya.\""},"2435":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اسْتَعَاذَ بِاللَّهِ فَأَعِيذُوهُ وَمَنْ سَأَلَكُمْ بِاللَّهِ فَأَعْطُوهُ وَمَنْ اسْتَجَارَ بِاللَّهِ فَأَجِيرُوهُ وَمَنْ آتَى إِلَيْكُمْ مَعْرُوفًا فَكَافِئُوهُ فَإِنْ لَمْ تَجِدُوا فَادْعُوا لَهُ حَتَّى تَعْلَمُوا أَنْ قَدْ كَافَأْتُمُوهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Abu 'Awanah] dari [Al A'masy] dari [Mujahid] dari [Ibnu 'Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang memintamu perlindungan dengan menyebut nama Allah maka berilah dia perlindungan. Dan barangsiapa yang meminta kepada kalian dengan menyebut nama Allah maka berikanlah, dan siapa yang datang kepada kalian meminta bantuan maka berilah ia bantuan, dan barang siapa yang datang kepada kalian dengan kebaikan, maka balaslah ia, jika kalian tidak mendapatkan sesuatu untuk membalasnya maka doakanlah kebaikan baginya hingga kalian merasa telah membalas kebaikannya.\""},"2436":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ بَهْزَ بْنَ حَكِيمٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقُلْتُ يَا نَبِيَّ اللَّهِ مَا أَتَيْتُكَ حَتَّى حَلَفْتُ أَكْثَرَ مِنْ عَدَدِهِنَّ لِأَصَابِعِ يَدَيْهِ أَلَّا آتِيَكَ وَلَا آتِيَ دِينَكَ وَإِنِّي كُنْتُ امْرَأً لَا أَعْقِلُ شَيْئًا إِلَّا مَا عَلَّمَنِي اللَّهُ وَرَسُولُهُ وَإِنِّي أَسْأَلُكَ بِوَجْهِ اللَّهِ عَزَّ وَجَلَّ بِمَا بَعَثَكَ رَبُّكَ إِلَيْنَا قَالَ بِالْإِسْلَامِ قَالَ قُلْتُ وَمَا آيَاتُ الْإِسْلَامِ قَالَ أَنْ تَقُولَ أَسْلَمْتُ وَجْهِي إِلَى اللَّهِ عَزَّ وَجَلَّ وَتَخَلَّيْتُ وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ كُلُّ مُسْلِمٍ عَلَى مُسْلِمٍ مُحَرَّمٌ أَخَوَانِ نَصِيرَانِ لَا يَقْبَلُ اللَّهُ عَزَّ وَجَلَّ مِنْ مُشْرِكٍ بَعْدَمَا أَسْلَمَ عَمَلًا أَوْ يُفَارِقَ الْمُشْرِكِينَ إِلَى الْمُسْلِمِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; Telah menceritakan kepada kami [Al Mu'tamir] dia berkata; Aku mendengar [Bahz bin Hakim] dia bercerita dari [Bapaknya] dari [Kakeknya] dia berkata; Aku berkata; 'Wahai Nabiyullah, Aku tidak mendatangimu hingga aku bersumpah sebanyak (jumlah jari-jari tangannya), bahwa aku tidak akan mendatangimu dan tidak pula memeluk agamamu, dan sesungguhnya aku sekarang adalah seseorang yang tidak mengetahui sesuatupun kecuali apa yang telah Allah dan Rasul-Nya ajarkan kepadaku, Aku bertanya kepadamu karena Allah Azza wa Jalla, dengan apa Allah mengutusmu kepada kami? Rasul menjawab: \"Dengan Islam.\" Ia berkata; Aku bertanya lagi; Apa tanda-tanda Islam itu? Beliau bersabda: \"Hendaklah kamu mengucapkan; 'Aku telah berserah diri dengan wajahku kepada Allah Azza Wa Jalla dan melepaskan semua bentuk penyekutuan, lalu kamu mengerjakan shalat, mengeluarkan zakat. Setiap muslim dengan muslim yang lainnya adalah haram darahnya karena mereka menjadi saling bersaudara. Allah Azza wa Jalla tidak akan menerima amal seorang musyrik yang telah masuk Islam hingga ia meninggalkan negri kaum musyirikin dan pindah ke negri Islam.\""},"2437":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ قَالَ أَنْبَأَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ خَالِدٍ الْقَارِظِيِّ عَنْ إِسْمَعِيلَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِخَيْرِ النَّاسِ مَنْزِلًا قُلْنَا بَلَى يَا رَسُولَ اللَّهِ قَالَ رَجُلٌ آخِذٌ بِرَأْسِ فَرَسِهِ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ حَتَّى يَمُوتَ أَوْ يُقْتَلَ وَأُخْبِرُكُمْ بِالَّذِي يَلِيهِ قُلْنَا نَعَمْ يَا رَسُولَ اللَّهِ قَالَ رَجُلٌ مُعْتَزِلٌ فِي شِعْبٍ يُقِيمُ الصَّلَاةَ وَيُؤْتِي الزَّكَاةَ وَيَعْتَزِلُ شُرُورَ النَّاسِ وَأُخْبِرُكُمْ بِشَرِّ النَّاسِ قُلْنَا نَعَمْ يَا رَسُولَ اللَّهِ قَالَ الَّذِي يُسْأَلُ بِاللَّهِ عَزَّ وَجَلَّ وَلَا يُعْطِي بِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; Telah menceritakan kepada kami [Ibnu Abu Fudaik] dia berkata; Telah memberitakan kepada kami [Ibnu Abu Dzi'b] dari [Sa'id bin Khalid Al Qarizhi] dari [Isma'il bin 'Abdurrahman] dari ['Atha bin Yasar] dari [Ibnu 'Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku kabarkan kepada kalian mengenai sebaik-baik kedudukan manusia?\" kami menjawab; iya ya Rasulullah, beliau bersabda: \"Seseorang yang memegang tali kudanya di jalan Allah Azza wa Jalla hingga ia mati atau terbunuh, maukah aku kabarkan kalian dengan yang setelahnya?\" kami menjawab; iya ya Rasulullah, beliau bersabda: \"Seseorang yang mengasingkan dari kaumnya lalu ia mendirikan shalat dan membayar zakat, ia mengasingkan dari keburukan manusia, dan maukah aku kabarkan kepada kalian akan seburuk-buruk manusia?\" kami berkata; iya ya Rasulullah, beliau bersabda: \"Yaitu orang yang diminta dengan nama Allah Azza wa Jalla namun ia tidak memberinya.\""},"2438":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ رِبْعِيًّا يُحَدِّثُ عَنْ زَيْدِ بْنِ ظَبْيَانَ رَفَعَهُ إِلَى أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ يُحِبُّهُمْ اللَّهُ عَزَّ وَجَلَّ وَثَلَاثَةٌ يَبْغُضُهُمْ اللَّهُ عَزَّ وَجَلَّ أَمَّا الَّذِينَ يُحِبُّهُمْ اللَّهُ عَزَّ وَجَلَّ فَرَجُلٌ أَتَى قَوْمًا فَسَأَلَهُمْ بِاللَّهِ عَزَّ وَجَلَّ وَلَمْ يَسْأَلْهُمْ بِقَرَابَةٍ بَيْنَهُ وَبَيْنَهُمْ فَمَنَعُوهُ فَتَخَلَّفَهُ رَجُلٌ بِأَعْقَابِهِمْ فَأَعْطَاهُ سِرًّا لَا يَعْلَمُ بِعَطِيَّتِهِ إِلَّا اللَّهُ عَزَّ وَجَلَّ وَالَّذِي أَعْطَاهُ وَقَوْمٌ سَارُوا لَيْلَتَهُمْ حَتَّى إِذَا كَانَ النَّوْمُ أَحَبَّ إِلَيْهِمْ مِمَّا يُعْدَلُ بِهِ نَزَلُوا فَوَضَعُوا رُءُوسَهُمْ فَقَامَ يَتَمَلَّقُنِي وَيَتْلُو آيَاتِي وَرَجُلٌ كَانَ فِي سَرِيَّةٍ فَلَقُوا الْعَدُوَّ فَهُزِمُوا فَأَقْبَلَ بِصَدْرِهِ حَتَّى يُقْتَلَ أَوْ يَفْتَحَ اللَّهُ لَهُ وَالثَّلَاثَةُ الَّذِينَ يَبْغُضُهُمْ اللَّهُ عَزَّ وَجَلَّ الشَّيْخُ الزَّانِي وَالْفَقِيرُ الْمُخْتَالُ وَالْغَنِيُّ الظَّلُومُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Muhammad] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Manshur] dia berkata; Aku mendengar [Rib'i] bercerita dari [Zaid bin Zhabyan] yang ia sandarkan kepada [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Ada tiga golongan yang Allah cintai dan tiga golongan yang Allah benci.\" Adapun tiga golongan yang Allah cintai adalah seseorang yang mendatangi suatu kaum lalu ia meminta karena Allah bukan meminta atas dasar kekerabatan antara dia dengan mereka, namun mereka menolak memberikan kepadanya. Kemudian ada seseorang yang mengikuti dari belakang mereka lalu ia memberikan sesuatu kepada orang yang meminta tadi secara sembunyi-sembunyi tidak ada yang mengetahui dia dan apa yang berikannya kecuali Allah. Dan suatu kaum yang berjalan di malam hari, hingga tidur merupakan sesuatu yang paling disukai mereka, maka mereka pun singgah dan meletakkan kepala-kepala mereka (tidur). Lalu seseorang bangun untuk berdo'a kepadaku dengan penuh ketawadluan dan ia membaca ayat-ayatku. Yang ketiga, adalah seseorang yang ikut dalam sebuah ekspedisi peperangan, hingga tatkala mereka menghadapi musuh dan kalah, ia tetap maju dengan jiwanya hingga ia terbunuh atau Allah memenangkannya. Adapun tiga golongan yang Allah benci adalah orang yang sudah lanjut usia berzina, orang fakir yang sombong, dan orang kaya yang suka berbuat zhalim.\""},"2439":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ الْمِسْكِينُ الَّذِي تَرُدُّهُ التَّمْرَةُ وَالتَّمْرَتَانِ وَاللُّقْمَةُ وَاللُّقْمَتَانِ إِنَّ الْمِسْكِينَ الْمُتَعَفِّفُ اقْرَءُوا إِنْ شِئْتُمْ{ لَا يَسْأَلُونَ النَّاسَ إِلْحَافًا }","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; Telah memberitakan kepada kami [Isma'il] dia berkata; Telah menceritakan kepada kami [Syarik] dari ['Atha bin Yasar] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukanlah orang miskin itu yang datang untuk mendapatkan satu atau dua butir kurma, atau satu atau dua suap makanan, sesungguhnya orang miskin itu adalah orang yang dapat menjaga diri dari meminta-minta, jika kalian mau maka bacalah (ayat): \" mereka tidak meminta kepada orang secara mendesak.\""},"2440":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ الْمِسْكِينُ بِهَذَا الطَّوَّافِ الَّذِي يَطُوفُ عَلَى النَّاسِ تَرُدُّهُ اللُّقْمَةُ وَاللُّقْمَتَانِ وَالتَّمْرَةُ وَالتَّمْرَتَانِ قَالُوا فَمَا الْمِسْكِينُ قَالُوا الَّذِي لَا يَجِدُ غِنًى يُغْنِيهِ وَلَا يُفْطَنُ لَهُ فَيُتَصَدَّقَ عَلَيْهِ وَلَا يَقُومُ فَيَسْأَلَ النَّاسَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukanlah seorang yang miskin itu yang mengelilingi manusia lalu meminta-minta dan dia mendapatkan sepotong atau dua potong roti, sebutir atau dua butir korma.\" Para shahabat bertanya: 'ya Rasulullah lalu siapakah yang disebut miskin itu? Beliau bersabda: \"Dia adalah orang yang tidak mendapatkan kekayaan untuk mencukupi dirinya dan orang-orang tidak memahami kebutuhannya lalu memberinya sedekah, dan dia tidak bisa mandiri sehingga meminta-minta manusia.\""},"2441":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ الْمِسْكِينُ الَّذِي تَرُدُّهُ الْأُكْلَةُ وَالْأُكْلَتَانِ وَالتَّمْرَةُ وَالتَّمْرَتَانِ قَالُوا فَمَا الْمِسْكِينُ يَا رَسُولَ اللَّهِ قَالَ الَّذِي لَا يَجِدُ غِنًى وَلَا يَعْلَمُ النَّاسُ حَاجَتَهُ فَيُتَصَدَّقَ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Nashr bin 'Ali] dia berkata; Telah menceritakan kepada kami ['Abdul A'la] dia berkata; Telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukanlah orang miskin itu yang datang untuk mendapatkan satu atau dua suap makanan atau satu atau dua butir kurma\". Para sahabat bertanya; 'Lalu bagaimanakah orang yang miskin itu ya Rasulullah? Beliau menjawab: \"Yaitu orang yang tidak mempunyai kecukupan untuk hidupnya, dan orang lain tidak mengetahui kebutuhannya hingga berhak mendapat sedekah.\""},"2442":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بُجَيْدٍ عَنْ جَدَّتِهِ أُمِّ بُجَيْدٍ وَكَانَتْ مِمَّنْ بَايَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهَا قَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمِسْكِينَ لَيَقُومُ عَلَى بَابِي فَمَا أَجِدُ لَهُ شَيْئًا أُعْطِيهِ إِيَّاهُ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ لَمْ تَجِدِي شَيْئًا تُعْطِينَهُ إِيَّاهُ إِلَّا ظِلْفًا مُحْرَقًا فَادْفَعِيهِ إِلَيْهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] dari ['Abdurrahman bin Bujaid] dari [Kakeknya, Ummu Bujaid] -dan ia termasuk orang yang membai'at Rasulullah shallallahu 'alaihi wasallam-, ia berkata kepada Rasulullah; \"Sesungguhnya terdapat seorang miskin yang berdiri di depan pintuku, dan aku tidak memiliki sesuatu yang dapat aku berikan kepadanya. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Apabila engkau tidak mendapatkan sesuatu yang dapat engkau berikan kepadanya kecuali kaki kambing yang telah dibakar, maka berikanlah kepadanya.\""},"2443":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ الشَّيْخُ الزَّانِي وَالْعَائِلُ الْمَزْهُوُّ وَالْإِمَامُ الْكَذَّابُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Yahya] dari [Ibnu 'Ajlan] dia berkata; Aku mendengar [Bapakku] bercerita dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga golongan yang tidak akan diajak bicara oleh Allah pada hari kiamat; 'Seorang yang sudah tua berzina, orang miskin namun sombong, dan pemimpin yang pendusta.\""},"2444":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا عَارِمٌ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعَةٌ يَبْغُضُهُمْ اللَّهُ عَزَّ وَجَلَّ الْبَيَّاعُ الْحَلَّافُ وَالْفَقِيرُ الْمُخْتَالُ وَالشَّيْخُ الزَّانِي وَالْإِمَامُ الْجَائِرُ","id":"Telah mengabarkan kepada kami [Abu Dawud] dia berkata; Telah menceritakan kepada kami ['Arim] dia berkata; Telah menceritakan kepada kami [Hammad] dia berkata; Telah menceritakan kepada kami ['Ubaidullah bin 'Umar] dari [Sa'id Al Maqburi] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Empat golongan yang Allah Azza wa Jalla membenci mereka; \"Penjual yang suka bersumpah, orang fakir yang sombong, orang tua renta yang berzina, dan pemimpin yang durjana.\""},"2445":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ حَدَّثَنَا مَالِكٌ عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيْلِيِّ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّاعِي عَلَى الْأَرْمَلَةِ وَالْمِسْكِينِ كَالْمُجَاهِدِ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] dia berkata; Telah menceritakan kepada kami ['Abdullah bin Maslamah] dia berkata; Telah menceritakan kepada kami [Malik] dari [Tsaur bin Zaid Ad Dili] dari [Abu Al Ghaits] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang membantu para janda dan orang-orang miskin seperti orang yang berjihad di jalan Allah.\""},"2446":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي نُعْمٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَعَثَ عَلِيٌّ وَهُوَ بِالْيَمَنِ بِذُهَيْبَةٍ بِتُرْبَتِهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَسَمَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَرْبَعَةِ نَفَرٍ الْأَقْرَعِ بْنِ حَابِسٍ الْحَنْظَلِيِّ وَعُيَيْنَةَ بْنِ بَدْرٍ الْفَزَارِيِّ وَعَلْقَمَةَ بْنِ عُلَاثَةَ الْعَامِرِيِّ ثُمَّ أَحَدِ بَنِي كِلَابٍ وَزَيْدٍ الطَّائِيِّ ثُمَّ أَحَدِ بَنِي نَبْهَانَ فَغَضِبَتْ قُرَيْشٌ وَقَالَ مَرَّةً أُخْرَى صَنَادِيدُ قُرَيْشٍ فَقَالُوا تُعْطِي صَنَادِيدَ نَجْدٍ وَتَدَعُنَا قَالَ إِنَّمَا فَعَلْتُ ذَلِكَ لِأَتَأَلَّفَهُمْ فَجَاءَ رَجُلٌ كَثُّ اللِّحْيَةِ مُشْرِفُ الْوَجْنَتَيْنِ غَائِرُ الْعَيْنَيْنِ نَاتِئُ الْجَبِينِ مَحْلُوقُ الرَّأْسِ فَقَالَ اتَّقِ اللَّهَ يَا مُحَمَّدُ قَالَ فَمَنْ يُطِيعُ اللَّهَ عَزَّ وَجَلَّ إِنْ عَصَيْتُهُ أَيَأْمَنُنِي عَلَى أَهْلِ الْأَرْضِ وَلَا تَأْمَنُونِي ثُمَّ أَدْبَرَ الرَّجُلُ فَاسْتَأْذَنَ رَجُلٌ مِنْ الْقَوْمِ فِي قَتْلِهِ يَرَوْنَ أَنَّهُ خَالِدُ بْنُ الْوَلِيدِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ ضِئْضِئِ هَذَا قَوْمًا يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حَنَاجِرَهُمْ يَقْتُلُونَ أَهْلَ الْإِسْلَامِ وَيَدَعُونَ أَهْلَ الْأَوْثَانِ يَمْرُقُونَ مِنْ الْإِسْلَامِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ لَئِنْ أَدْرَكْتُهُمْ لَأَقْتُلَنَّهُمْ قَتْلَ عَادٍ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Al Ahwash] dari [Sa'id bin Masruq] dari ['Abdurrahman bin bin Abu Nu'am] dari [Abu Sa'id Al Khudri] dia berkata; \"Ali yang sedang berada di Yaman mengirimkan emas yang masih kotor dengan tanah kepada Nabi shallallahu 'alaihi wasallam, lalu beliau membagi-bagikannya kepada empat orang, yaitu; Al Aqra` bin Habis Al Hanzhali, 'Uyainah bin Badr Al Fazari, 'Alqamah bin Ulatsah Al 'Amiri, seorang dari bani Kilab, dan Zaid Al Khair Ath Tha`i, dan seorang dari bani Nabhan.\" Abu Sa'id berkata; \"Maka marahlah orang-orang Quraisy -atau di saat lain ia berkata; 'para pemuka Quraisy'- mereka berkata; \"Beliau memberikan kepada para pembesar penduduk Najed dan membiarkan kita semua.\" Beliau bersabda: \"Sesungguhnya aku berbuat demikian karena ingin melunakkan hati mereka.\" Kemudian datanglah seorang laki-laki yang berjanggot lebat, dahinya menonjol keluar, kedua matanya cekung, tulang pipinya tebal dan berkepala botak.\" Laki-laki itu berkata; \"Wahai Muhammad, takutlah engkau kepada Allah, \" Beliau bersabda: \"Lalu siapakah yang takut kepada Allah jika aku melakukan maksiat kepada-Nya, bagaimana penduduk bumi mempercayaiku tapi kenapa kalian tidak mempercayaiku?\" kemudian orang itu mundur ke belakang. Lalu ada seorang sahabat yang meminta izin kepada Rasulullah shallallahu 'alaihi wasallam untuk membunuhnya, mereka menganggap ia adalah Khalid bin Al Walid. Setelah itu beliau bersabda: \"Sesungguhnya dari keturunan orang itu akan muncul suatu kaum yang membaca Al Qur`an namun tidak pernah sampai pada tenggorokan mereka, mereka membunuh orang-orang Islam dan membiarkan para penyembah berhala, mereka keluar dari Islam sebagaimana meluncurnya anak panah dari busurnya, sekiranya aku menjumpai mereka sungguh akan aku bunuh mereka sebagaimana pembunuhan kaum 'Aad.\""},"2447":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ عَنْ حَمَّادٍ عَنْ هَارُونَ بْنِ رِئَابٍ قَالَ حَدَّثَنِي كِنَانَةُ بْنُ نُعَيْمٍ ح و أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ وَاللَّفْظُ لَهُ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ هَارُونَ عَنْ كِنَانَةَ بْنِ نُعَيْمٍ عَنْ قَبِيصَةَ بْنِ مُخَارِقٍ قَالَتَحَمَّلْتُ حَمَالَةً فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ فِيهَا فَقَالَ إِنَّ الْمَسْأَلَةَ لَا تَحِلُّ إِلَّا لِثَلَاثَةٍ رَجُلٍ تَحَمَّلَ بِحَمَالَةٍ بَيْنَ قَوْمٍ فَسَأَلَ فِيهَا حَتَّى يُؤَدِّيَهَا ثُمَّ يُمْسِكَ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dari [Hammad] dari [Harun bin Riab] dia berkata; Telah menceritakan kepadaku [Kinanah bin Nu'aim]; (Demikian juga diriwayatkan dari jalur lain), Dan telah mengabarkan kepada kami ['Ali bin Hujr] dan lafazh ini miliknya; dia berkata; Telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Harun] dari [Kinanah bin Nu'aim] dari [Qabishah bin Mukhariq] dia berkata; Aku merasa terbebani dengan tanggunganku (berupa diat, atau hutang), lalu aku mendatangi Nabi shallallahu 'alaihi wasallam, aku bertanya kepadanya tentang penyelesaiannya, beliau menjawab: \"Sesungguhnya permintaan itu tidak halal kecuali bagi tiga orang; yaitu orang laki-laki yang mempunyai tanggungan bagi kaumnya, lalu ia meminta-minta hingga ia dapat menyelesaikan tanggungannya, setelah itu ia berhenti (untuk meminta-minta).\""},"2448":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ النَّضْرِ بْنِ مُسَاوِرٍ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ هَارُونَ بْنِ رِئَابٍ قَالَ حَدَّثَنِي كِنَانَةُ بْنُ نُعَيْمٍ عَنْ قَبِيصَةَ بْنِ مُخَارِقٍ قَالَتَحَمَّلْتُ حَمَالَةً فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْأَلُهُ فِيهَا فَقَالَ أَقِمْ يَا قَبِيصَةُ حَتَّى تَأْتِيَنَا الصَّدَقَةُ فَنَأْمُرَ لَكَ قَالَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا قَبِيصَةُ إِنَّ الصَّدَقَةَ لَا تَحِلُّ إِلَّا لِأَحَدِ ثَلَاثَةٍ رَجُلٍ تَحَمَّلَ حَمَالَةً فَحَلَّتْ لَهُ الْمَسْأَلَةُ حَتَّى يُصِيبَ قِوَامًا مِنْ عَيْشٍ أَوْ سِدَادًا مِنْ عَيْشٍ وَرَجُلٍ أَصَابَتْهُ جَائِحَةٌ فَاجْتَاحَتْ مَالَهُ فَحَلَّتْ لَهُ الْمَسْأَلَةُ حَتَّى يُصِيبَهَا ثُمَّ يُمْسِكَ وَرَجُلٍ أَصَابَتْهُ فَاقَةٌ حَتَّى يَشْهَدَ ثَلَاثَةٌ مِنْ ذَوِي الْحِجَا مِنْ قَوْمِهِ قَدْ أَصَابَتْ فُلَانًا فَاقَةٌ فَحَلَّتْ لَهُ الْمَسْأَلَةُ حَتَّى يُصِيبَ قِوَامًا مِنْ عَيْشٍ أَوْ سِدَادًا مِنْ عَيْشٍ فَمَا سِوَى هَذَا مِنْ الْمَسْأَلَةِ يَا قَبِيصَةُ سُحْتٌ يَأْكُلُهَا صَاحِبُهَا سُحْتًا","id":"Telah mengabarkan kepada kami [Muhammad bin An Nadlr bin Musawir] dia berkata; Telah menceritakan kepada kami [Hammad] dari [Harun bin Ri'ab] dia berkata; Telah menceritakan kepadaku [Kinanah bin Nu'aim] dari [Qabishah bin Mukhariq] dia berkata; Aku mempunyai beban tanggungan (hutang, atau diat), maka aku mendatangi Rasulullah shallallahu 'alaihi wasallam untuk minta penyelesaiannya. Beliau berkata: \"Berdirilah wahai Qabisah hingga datang kepada kami sedekah, maka kami memerintahkan untuk memberikan kepadamu darinya. Qabisah berkata; lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Qabisah sesungguhnya sedekah itu tidak halal kecuali bagi salah seorang dari tiga golongan; yaitu seorang laki-laki yang menahan tanggungan (di luar kemampuannya), maka halal baginya meminta-minta sehingga dia mendapatkannya yang dapat mencukupi kebutuhan hidupnya, seorang laki-laki yang tertimpa musibah besar hingga habis hartanya, maka halal baginya meminta-minta, sampai dia mendapatkannya lalu ia berhenti dari meminta-minta. Dan seorang laki-laki yang terkena musibah kefaqiran hingga tiga orang dari kaumnya bersaksi seraya berkata: kefaqiran telah menimpa Fulan, maka halal baginya meminta-minta, sehingga ia mampu menegakkan kehidupannya kembali kemudian ia menahan diri dari meminta-minta. wahai Qabishah selain dari tiga golongan itu maka meminta-minta adalah haram. Keharaman yang menyebabkan pelakunya memakan dari barang yang haram.\""},"2449":{"ar":"أَخْبَرَنِي زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ قَالَ أَخْبَرَنِي هِشَامٌ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي هِلَالٌ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ وَجَلَسْنَا حَوْلَهُ فَقَالَ إِنَّمَا أَخَافُ عَلَيْكُمْ مِنْ بَعْدِي مَا يُفْتَحُ لَكُمْ مِنْ زَهْرَةٍ وَذَكَرَ الدُّنْيَا وَزِينَتَهَا فَقَالَ رَجُلٌ أَوَ يَأْتِي الْخَيْرُ بِالشَّرِّ فَسَكَتَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقِيلَ لَهُ مَا شَأْنُكَ تُكَلِّمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يُكَلِّمُكَ قَالَ وَرَأَيْنَا أَنَّهُ يُنْزَلُ عَلَيْهِ فَأَفَاقَ يَمْسَحُ الرُّحَضَاءَ وَقَالَ أَشَاهِدٌ السَّائِلُ إِنَّهُ لَا يَأْتِي الْخَيْرُ بِالشَّرِّ وَإِنَّ مِمَّا يُنْبِتُ الرَّبِيعُ يَقْتُلُ أَوْ يُلِمُّ إِلَّا آكِلَةُ الْخَضِرِ فَإِنَّهَا أَكَلَتْ حَتَّى إِذَا امْتَدَّتْ خَاصِرَتَاهَا اسْتَقْبَلْتَ عَيْنَ الشَّمْسِ فَثَلَطَتْ ثُمَّ بَالَتْ ثُمَّ رَتَعَتْ وَإِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ وَنِعْمَ صَاحِبُ الْمُسْلِمِ هُوَ إِنْ أَعْطَى مِنْهُ الْيَتِيمَ وَالْمِسْكِينَ وَابْنَ السَّبِيلِ وَإِنَّ الَّذِي يَأْخُذُهُ بِغَيْرِ حَقِّهِ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ وَيَكُونُ عَلَيْهِ شَهِيدًا يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepadaku [Ziyad bin Ayyub] dia berkata; Telah menceritakan kepada kami [Isma'il bin 'Ulayyah]; dia berkata; Telah mengabarkan kepadaku [Hisyam] dia berkata; Telah menceritakan kepadaku [Yahya bin Abu Katsir] dia berkata; Telah menceritakan kepadaku [Hilal] dari ['Atha bin Yasar] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam duduk diatas mimbar, dan kami duduk di sekelilingnya, beliau bersabda: \"Hanyasanya aku takutkan atas kalian setelahku, apa yang dibukakan untuk kalian dari kemewahan, \" lalu beliau menyebutkan dunia dan keindahannya, kemudian seseorang bertanya apakah kebaikan datang dengan keburukan? Namun Rasulullah shallallahu 'alaihi wasallam diam, kemudian dikatakan kepada orang itu kenapa engkau mengatakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam dan beliau tidak menjawabmu? Dan ternyata kami melihat bahwa wahyu turun kepada beliau, setelah itu beliau sadar dan mengusap keringatnya yang bercucuran, beliau bersabda: \"Apakah penanya tadi tadi tidak menyaksikan, sesungguhnya kebaikan tidak datang dengan keburukan, dan sungguh apa yang tumbuh pada musim gugur akan terbunuh atau binasa, kecuali pemakan dedaunan karena ia akan memakannya hingga jika kenyang ia akan menghadap matahari dan memuntahkan apa yang ada diperutnya, lalu ia kencing dan kembali merumput, dan sesungguhnya harta ini adalah hijau dan manis, sebaik-baik teman seorang muslim adalah jika ia memberikan dari hartanya kepada seorang yatim, orang miskin dan ibnu sabil, dan sesungguhnya orang yang mengambilnya secara tidak benar seperti halnya orang yang makan namun tidak kenyang dan ia akan menjadi saksi atasnya pada hari kiamat.\""},"2450":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعَلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ حَفْصَةَ عَنْ أُمِّ الرَّائِحِ عَنْ سَلْمَانَ بْنِ عَامِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الصَّدَقَةَ عَلَى الْمِسْكِينِ صَدَقَةٌ وَعَلَى ذِي الرَّحِمِ اثْنَتَانِ صَدَقَةٌ وَصِلَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Khalid] dia berkata; Telah menceritakan kepada kami [Ibnu 'Aun] dari [Hafshah] dari [Ummu Ar Raaih] dari [Salman bin 'Amir] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sedekah kepada orang miskin pahalanya satu sedekah, sedangkan sedekah kepada kerabat pahalanya dua; pahala sedekah dan pahala silaturrahim.\""},"2451":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلنِّسَاءِ تَصَدَّقْنَ وَلَوْ مِنْ حُلِيِّكُنَّ قَالَتْ وَكَانَ عَبْدُ اللَّهِ خَفِيفَ ذَاتِ الْيَدِ فَقَالَتْ لَهُ أَيَسَعُنِي أَنْ أَضَعَ صَدَقَتِي فِيكَ وَفِي بَنِي أَخٍ لِي يَتَامَى فَقَالَ عَبْدُ اللَّهِ سَلِي عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا عَلَى بَابِهِ امْرَأَةٌ مِنْ الْأَنْصَارِ يُقَالُ لَهَا زَيْنَبُ تَسْأَلُ عَمَّا أَسْأَلُ عَنْهُ فَخَرَجَ إِلَيْنَا بِلَالٌ فَقُلْنَا لَهُ انْطَلِقْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلْهُ عَنْ ذَلِكَ وَلَا تُخْبِرْهُ مَنْ نَحْنُ فَانْطَلَقَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ هُمَا قَالَ زَيْنَبُ قَالَ أَيُّ الزَّيَانِبِ قَالَ زَيْنَبُ امْرَأَةُ عَبْدِ اللَّهِ وَزَيْنَبُ الْأَنْصَارِيَّةُ قَالَ نَعَمْ لَهُمَا أَجْرَانِ أَجْرُ الْقَرَابَةِ وَأَجْرُ الصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid] dia berkata; Telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Sulaiman] dari [Abu Wail] dari ['Amru bin Al Harits] dari [Zainab] istri 'Abdullah dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda pada para wanita: \"Bersedekahlah walaupun dengan perhiasan kalian dia berkata.\" Zainab berkata; Abdullah adalah seseorang yang ringan tangannya (sedikit harta), maka Zainabberkata kepadanya; Bolehkah jika aku memberikan sedekahku kepadamu dan kepada anak saudaraku yang yatim. Abdullah berkata; 'Tanyakanlah hal itu pada Rasulullah shallallahu 'alaihi wasallam.' lalu saya pergi menuju rumah beliau, ternyata di pintu rumah beliau ada seorang wanita Anshar yang namanya Zainab, dia ingin menanyakan seperti yang akan aku tanyakan. Kemudian Bilal keluar menemui kami, maka kami berkata kepadanya; \"Tolong tanyakan kepada Rasulullah shallallahu 'alaihi wasallam tentang hal itu dan jangan beritahukan kepada beliau siapa kami. Maka ia pun pergi menemui Rasulullah shallallahu 'alaihi wasallam. Kemudian Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapakah dua orang itu? Bilal menjawab; 'Zainab.' Rasulullah bertanya lagi: 'Zainab yang mana? ' Bilal menjawab; 'Zainab istri Abdullah dan Zainab wanita Anshar, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya bagi mereka dua pahala, pahala karib kerabat dan pahala sedekah.\""},"2452":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا عُبَيْدٍ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ أَزْهَرَ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَحْتَزِمَ أَحَدُكُمْ حُزْمَةَ حَطَبٍ عَلَى ظَهْرِهِ فَيَبِيعَهَا خَيْرٌ مِنْ أَنْ يَسْأَلَ رَجُلًا فَيُعْطِيَهُ أَوْ يَمْنَعَهُ","id":"Telah mengabarkan kepada kami [Abu Dawud] dia berkata; Telah menceritakan kepada kami [Ya'qub bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Bapakku] dari [Shalih] dari [Ibnu Syihab] bahwasanya [Abu 'Ubaid] -mantan budak- 'Abdurrahman bin Azhar telah mengabarkan kepadanya bahwasanya ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya salah seorang dari kalian mengikat satu ikat kayu bakar, kemudian mamanggul di atas punggungnya dan menjualnya adalah lebih baik baginya daripada meminta-minta kepada orang lain, yang kadang memberi dan kadang tidak.\""},"2453":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ قَالَ سَمِعْتُ حَمْزَةَ بْنَ عَبْدِ اللَّهِ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَزَالُ الرَّجُلُ يَسْأَلُ حَتَّى يَأْتِيَ يَوْمَ الْقِيَامَةِ لَيْسَ فِي وَجْهِهِ مُزْعَةٌ مِنْ لَحْمٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakam] dari [Syu'aib] dari [Al Laits bin Sa'd] dari ['Ubaidullah bin Abi Ja'far] ia berkata; Saya mendengar [Hamzah bin Abdullah] berkata; Saya mendengar [Abdullah bin Umar] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seseorang tiada berhenti meminta-minta, hingga ia datang pada Hari Kiamat dalam keadaan di wajahnya tidak ada daging sedikitpun\" "},"2454":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ أَبِي صَفْوَانَ الثَّقَفِيُّ قَالَ حَدَّثَنَا أُمَيَّةُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ بِسْطَامَ بْنِ مُسْلِمٍ عَنْ عَبْدِ اللَّهِ بْنِ خَلِيفَةَ عَنْ عَائِذِ بْنِ عَمْرٍوأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ فَأَعْطَاهُ فَلَمَّا وَضَعَ رِجْلَهُ عَلَى أُسْكُفَّةِ الْبَابِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَعْلَمُونَ مَا فِي الْمَسْأَلَةِ مَا مَشَى أَحَدٌ إِلَى أَحَدٍ يَسْأَلُهُ شَيْئًا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Utsman bin abu Shafwan Ats Tsaqafi], ia berkata; Telah menceritakan kepada kami [Umayyah bin Khalid], ia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Bistham bin Muslim] dari [Abdullah bin Khalifah] dari ['Aidz bin 'Amru], seseorang menemui Nabi shallallahu 'alaihi wasallam lalu ia meminta sesuatu kepada beliau. Beliau memberinya. Tatkala ia meletakkan kakinya didepan pintu, Rasulullah shallallahu 'alaihi wasallam bersabda: \" Jika kalian tahu resiko meminta-minta, tidak ada seorang pun yang pergi kepada seseorang untuk meminta sesuatu kepadanya.\""},"2455":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ مُسْلِمِ بْنِ مَخْشِيٍّ عَنْ ابْنِ الْفِرَاسِيِّ أَنَّ الْفِرَاسِيَّقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْأَلُ يَا رَسُولَ اللَّهِ قَالَ لَا وَإِنْ كُنْتَ سَائِلًا لَا بُدَّ فَاسْأَلْ الصَّالِحِينَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; Telah menceritakan kepada kami [Al Laits] dari [Ja'far bin Rabi'ah] dari [Bakr bin Sawadah] dari [Muslim bin Makhsyi] dari [Ibnu Al Firasi], ia berkata kepada Rasulullah shallallahu 'alaihi wasallam; Apakah saya boleh meminta wahai Rasulullah!\" Rasulullah menjawab: \"Tidak, dan seandainya engkau harus meminta, mintalah kepada orang shaleh.\""},"2456":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ نَاسًا مِنْ الْأَنْصَارِ سَأَلُوا رَسُولَ اللَّهِ فَأَعْطَاهُمْ ثُمَّ سَأَلُوهُ فَأَعْطَاهُمْ حَتَّى إِذَا نَفِدَ مَا عِنْدَهُ قَالَ مَا يَكُونُ عِنْدِي مِنْ خَيْرٍ فَلَنْ أَدَّخِرَهُ عَنْكُمْ وَمَنْ يَسْتَعْفِفْ يُعِفَّهُ اللَّهُ عَزَّ وَجَلَّ وَمَنْ يَصْبِرْ يُصَبِّرْهُ اللَّهُ وَمَا أُعْطِيَ أَحَدٌ عَطَاءً هُوَ خَيْرٌ وَأَوْسَعُ مِنْ الصَّبْرِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari ['Atho` bin Yazid] dari [Abu Sa'id Al Khudri], terdapat beberapa orang dari Anshar meminta kepada Rasulullah, lalu beliau memberi mereka. Kemudian mereka meminta lagi kepadanya, dan beliau memberi mereka hingga habis yang beliau miliki. Beliau bersabda: \"Aku tidak lagi memiliki sesuatu yang baik, aku tidak menyimpannya. Barang siapa yang menjaga kehormatan dirinya, Allah Azza wa Jalla menjaga kehormatannya, dan barang siapa yang bersabar, Allah akan menjadikannya bersabar. Tidaklah seseorang diberi suatu pemberian yang lebih baik dan lebih luas daripada kesabaran.\" "},"2457":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ شُعَيْبٍ قَالَ أَنْبَأَنَا مَعْنٌ قَالَ أَنْبَأَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَنْ يَأْخُذَ أَحَدُكُمْ حَبْلَهُ فَيَحْتَطِبَ عَلَى ظَهْرِهِ خَيْرٌ لَهُ مِنْ أَنْ يَأْتِيَ رَجُلًا أَعْطَاهُ اللَّهُ عَزَّ وَجَلَّ مِنْ فَضْلِهِ فَيَسْأَلَهُ أَعْطَاهُ أَوْ مَنَعَهُ","id":"Telah mengabarkan kepada kami [Ali bin Syu'aib], ia berkata; Telah memberitakan kepada kami [Ma'n], ia berkata; telah memberitakan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullallah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku ada di tangan-Nya, sungguh seseorang diantara kalian mengambil talinya kemudian menggendong kayu bakar di atas punggungnya, adalah lebih baik baginya daripada ia datang kepada seseorang yang Allah 'azza wajalla berikan kepadanya sebagian karunianya, kemudian memintanya hingga orang tersebut memberinya atau menolaknya.\""},"2458":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنِي مُحَمَّدُ بْنُ قَيْسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ مُعَاوِيَةَ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَضْمَنْ لِي وَاحِدَةً وَلَهُ الْجَنَّةُ قَالَ يَحْيَى هَاهُنَا كَلِمَةٌ مَعْنَاهَا أَنْ لَا يَسْأَلَ النَّاسَ شَيْئًا","id":"Telah mengabarkan kepada kami ['Amr bin Ali] ia berkata; Telah menceritakan kepada kami [Yahya], ia berkata; Telah menceritakan kepada kami [Ibnu Abu Dzi`b] berkata; Telah menceritakan kepadaku [Muhammad bin Qais] dari [Abdur Rahman bin Yazid bin Mu'awiyah] dari [Tsauban], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang menanggung untukku satu perkara maka baginya Surga.\" Yahya berkata; Di sini terdapat sebuah kata yang maknanya adalah agar tidak meminta sesuatu kepada manusia. "},"2459":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا يَحْيَى وَهُوَ ابْنُ حَمْزَةَ قَالَ حَدَّثَنِي الْأَوْزَاعِيُّ عَنْ هَارُونَ بْنِ رِئَابٍ أَنَّهُ حَدَّثَهُ عَنْ أَبِي بَكْرٍ عَنْ قَبِيصَةَ بْنِ مُخَارِقٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَصْلُحُ الْمَسْأَلَةُ إِلَّا لِثَلَاثَةٍ رَجُلٍ أَصَابَتْ مَالَهُ جَائِحَةٌ فَيَسْأَلُ حَتَّى يُصِيبَ سِدَادًا مِنْ عَيْشٍ ثُمَّ يُمْسِكُ وَرَجُلٍ تَحَمَّلَ حَمَالَةً فَيَسْأَلُ حَتَّى يُؤَدِّيَ إِلَيْهِمْ حَمَالَتَهُمْ ثُمَّ يُمْسِكُ عَنْ الْمَسْأَلَةِ وَرَجُلٍ يَحْلِفُ ثَلَاثَةُ نَفَرٍ مِنْ قَوْمِهِ مِنْ ذَوِي الْحِجَا بِاللَّهِ لَقَدْ حَلَّتْ الْمَسْأَلَةُ لِفُلَانٍ فَيَسْأَلُ حَتَّى يُصِيبَ قِوَامًا مِنْ مَعِيشَةٍ ثُمَّ يُمْسِكُ عَنْ الْمَسْأَلَةِ فَمَا سِوَى ذَلِكَ سُحْتٌ","id":"Telah mengabarkan kepada kami [Hisyam bin 'Ammar], ia berkata; telah menceritakan kepada kami [Yahya] yaitu ibnu Hamzah, ia berkata; Telah menceritakan kepadaku [Al Auza'i] dari [Harun bin Riab] bahwa ia telah menceritakan kepadanya dari [Abu Bakr] dari [Qubaishah bin Mukhari], ia berkata; Saya telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak baik meminta-minta kecuali bagi tiga orang, seorang laki-laki yang hartanya tertimpa bencana sehingga ia meminta-minta untuk penopang hidupnya kemudian ia menahan diri dari meminta-minta, dan seorang laki-laki yang membawa barang bawaan (milik orang lain) kemudian ia meminta, hingga ia dapat menyampaikan kepada mereka barang bawaan mereka kemudian menahan diri dari meminta-minta, dan seorang laki-laki yang menyumpah tiga orang adil diantara kaumnya yang mempunyai kebutuhan mendesak, ia berkata \"Dengan nama Allah sungguh telah boleh bagi Si Fulan untuk meminta-minta\", kemudian ia meminta hingga mendapatkan penopang kehidupannya kemudian ia menahan diri dari meminta-minta. Selain hal tersebut adalah perkara yang haram.\" "},"2460":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ حَكِيمِ بْنِ جُبَيْرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ وَلَهُ مَا يُغْنِيهِ جَاءَتْ خُمُوشًا أَوْ كُدُوحًا فِي وَجْهِهِ يَوْمَ الْقِيَامَةِ قِيلَ يَا رَسُولَ اللَّهِ وَمَاذَا يُغْنِيهِ أَوْ مَاذَا أَغْنَاهُ قَالَ خَمْسُونَ دِرْهَمًا أَوْ حِسَابُهَا مِنْ الذَّهَبِقَالَ يَحْيَى قَالَ سُفْيَانُ وَسَمِعْتُ زُبَيْدًا يُحَدِّثُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; Telah menceritakan kepada kami [Yahya bin Adam], ia berkata; Telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Hakim bin Jubair] dari [Muhammad bin Abdur Rahman bin Yazid] dari [bapaknya] dari [Abdullah bin Mas'ud], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang meminta-minta sedang ia memiliki sesuatu yang dapat mencukupinya, ia datang dalam keadaan mencakar atau menggaruk bagian pada wajahnya pada Hari Kiamat\" Beliau ditanya; Wahai Rasulullah, sesuatu apakah yang dapat mencukupinya?\" Beliau menjawab: \"Uang lima puluh dirham atau emas yang seukuran dengannya\" [Yahya] berkata; [Sufyan] berkata; Dan aku telah mendengar [Zubaid] menceritakannya dari [Muhammad bin Abdur Rahman bin Yazid]."},"2461":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ أَخِيهِ عَنْ مُعَاوِيَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُلْحِفُوا فِي الْمَسْأَلَةِ وَلَا يَسْأَلْنِي أَحَدٌ مِنْكُمْ شَيْئًا وَأَنَا لَهُ كَارِهٌ فَيُبَارَكَ لَهُ فِيمَا أَعْطَيْتُهُ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits], ia berkata; Telah memberitakan kepada kami [Sufyan] dari ['Amr] dari [Wahb bin Munabbih] dari [saudaranya] dari [Mu'awiyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan kalian meminta dengan setengah memaksa, dan janganlah salah seorang diantara kalian meminta sesuatu yang tidak aku sukai, sehingga ia mendapat berkah dari yang aku berikan kepadanya.\""},"2462":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ أَنْبَأَنَا يَحْيَى بْنُ آدَمَ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ دَاوُدَ بْنِ شَابُورَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ وَلَهُ أَرْبَعُونَ دِرْهَمًا فَهُوَ الْمُلْحِفُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; Telah memberitahukan kepada kami [Yahya bin Adam] dari [Sufyan bin 'Uyainah] dari [Daud bin Syabur] dari ['Amr bin bin Syu'aib] dari [ayahnya] dari [kakekknya] ia berkata Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa siapa meminta sesuatu kepada orang lain padahal ia memiliki empat puluh dirham, berarti ia orang yang meminta dengan paksaan.\""},"2463":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي الرِّجَالِ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَسَرَّحَتْنِي أُمِّي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ وَقَعَدْتُ فَاسْتَقْبَلَنِي وَقَالَ مَنْ اسْتَغْنَى أَغْنَاهُ اللَّهُ عَزَّ وَجَلَّ وَمَنْ اسْتَعَفَّ أَعَفَّهُ اللَّهُ عَزَّ وَجَلَّ وَمَنْ اسْتَكْفَى كَفَاهُ اللَّهُ عَزَّ وَجَلَّ وَمَنْ سَأَلَ وَلَهُ قِيمَةُ أُوقِيَّةٍ فَقَدْ أَلْحَفَ فَقُلْتُ نَاقَتِي الْيَاقُوتَةُ خَيْرٌ مِنْ أُوقِيَّةٍ فَرَجَعْتُ وَلَمْ أَسْأَلْهُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; Telah menceritakan kepada kami [Ibnu Abi Ar Rijal] dari ['Umarah bin Ghazziyah] dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [bapaknya], ia berkata; Ibuku mengutusku datang kepada Rasulullah shallallahu 'alaihi wasallam kemudian aku menemuinya dan duduk, maka beliau menghadap kepadaku dan bersabda: \"Barang siapa yang merasa cukup, Allah Azza wa Jalla memberinya kecukupan, dan barang siapa yang menjaga kehormatan dirinya, Allah 'azza wajalla menjaga kehormatannya, dan barang siapa yang menahan diri dari meminta, Allah 'azza wajalla memberikan kecukupan, dan barang siapa yang meminta-minta sedangkan ia memiliki harta senilai satu uqiyah maka sungguh ia telah meminta dengan setengah paksaan.\" Maka aku katakan; untaku lebih baik dari pada satu uqiyah, kemudian aku kembali dan tidak lagi bertanya kepada beliau."},"2464":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ أَنْبَأَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ بَنِي أَسَدٍ قَالَنَزَلْتُ أَنَا وَأَهْلِي بِبَقِيعِ الْغَرْقَدِ فَقَالَتْ لِي أَهْلِي اذْهَبْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلْهُ لَنَا شَيْئًا نَأْكُلُهُ فَذَهَبْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدْتُ عِنْدَهُ رَجُلًا يَسْأَلُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا أَجِدُ مَا أُعْطِيكَ فَوَلَّى الرَّجُلُ عَنْهُ وَهُوَ مُغْضَبٌ وَهُوَ يَقُولُ لَعَمْرِي إِنَّكَ لَتُعْطِي مَنْ شِئْتَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيَغْضَبُ عَلَيَّ أَنْ لَا أَجِدَ مَا أُعْطِيهِ مَنْ سَأَلَ مِنْكُمْ وَلَهُ أُوقِيَّةٌ أَوْ عِدْلُهَا فَقَدْ سَأَلَ إِلْحَافًا قَالَ الْأَسَدِيُّ فَقُلْتُ لَلَقْحَةٌ لَنَا خَيْرٌ مِنْ أُوقِيَّةٍ وَالْأُوقِيَّةُ أَرْبَعُونَ دِرْهَمًا فَرَجَعْتُ وَلَمْ أَسْأَلْهُ فَقَدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ شَعِيرٌ وَزَبِيبٌ فَقَسَّمَ لَنَا مِنْهُ حَتَّى أَغْنَانَا اللَّهُ عَزَّ وَجَلَّ","id":"Telah berkata [Al Harits bin Miskin] dengan membacakan riwayat dan aku mendengar dari [Ibnu Al Qasim], ia berkata; telah memberitakan kepada kami [Malik] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [seorang laki-laki] dari kalangan Bani Asad berkata; aku dan isteriku singgah di sebuah tempat yang terdapat padanya Pohon Ghorqod, kemudian isteriku berkata kepadaku; pergilah kepada Rasulullah shallallah 'alahi wa sallam kemudian mintalah kepada beliau sesuatu yang dapat kita makan. Maka saya pergi kepada Rasulullah shallallahu 'alaihi wasallam. Saya dapati di sisi beliau terdapat seseorang yang meminta kepadanya, dan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya tidak mendapatkan sesuatu yang dapat saya berikan kepadamu.\" Maka orang tersebut berpaling dari beliau dalam keadaan marah seraya berkata; demi umurku, engkau hanya memberi kepada orang yang engkau kehendaki. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh ia marah kepadaku karena saya tidak mendapatkan sesuatu yang dapat aku berikan kepadanya, barang siapa yang meminta-minta sedangkan ia memiliki satu uqiyah atau yang setara dengannya maka sungguh ia telah meminta dengan setengah memaksa.\" Al Asadi berkata, \"Sungguh satu ekor unta perah kami lebih baik daripada satu uqiyah, sedangkan satu uqiyah adalah empat puluh dirham. Kemudian aku kembali dan tidak bertanya kepada beliau, lalu datang kepada Rasulullah shallallahu 'alaihi wasallam setelah itu gandum dan kismis, maka kemudian beliau membagikan sebagiannya kepada kami hingga Allah 'azza wajalla memberikan kecukupan kepada kami. "},"2465":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي بَكْرٍ عَنْ أَبِي حَصِينٍ عَنْ سَالِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِلُّ الصَّدَقَةُ لِغَنِيٍّ وَلَا لِذِي مِرَّةٍ سَوِيٍّ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Bakr] dari [Abu Hashin] dari [Salim] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal sedekah untuk orang yang kaya, dan orang yang sehat kuat dan memiliki kemampuan untuk bekerja.\""},"2466":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَدِيِّ بْنِ الْخِيَارِ أَنَّ رَجُلَيْنِ حَدَّثَاهُأَنَّهُمَا أَتَيَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلَانِهِ مِنْ الصَّدَقَةِ فَقَلَّبَ فِيهِمَا الْبَصَرَ وَقَالَ مُحَمَّدٌ بَصَرَهُ فَرَآهُمَا جَلْدَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ شِئْتُمَا وَلَا حَظَّ فِيهَا لِغَنِيٍّ وَلَا لِقَوِيٍّ مُكْتَسِبٍ","id":"Telah mengabarkan kepada kami ['Amr bin Ali] dan [Muhammad bin Al Mutsanna], mereka berkata; telah menceritakan kepada kami [Yahya] dari [Hisyam bin 'Urwah], ia berkata; telah menceritakan kepadaku [Ayahku], ia berkata; telah menceritakan kepadaku ['Ubaidullah bin 'Adi bin Al Khiyar], [dua orang laki-laki] menceritakan kepadanya, mereka berdua datang kepada Rasulullah shallallahu 'alaihi wasallam dan meminta beliau sebagian dari sedekah, maka beliau membolak-balikkan pandangan kepada mereka berdua. Muhammad berkata dengan redaksi; pandangan beliau. Beliau lihat mereka berdua adalah orang yang kuat, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian berdua mau (saya akan memberikannya), namun ingat, sebenarnya tidak ada bagian bagi orang yang kaya dalam sedekah tersebut dan juga tidak bagi orang yang kuat dan bisa berusaha.\" "},"2467":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ مُحَمَّدُ بْنُ بِشْرٍ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ عَنْ زَيْدِ بْنِ عُقْبَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَسَائِلَ كُدُوحٌ يَكْدَحُ بِهَا الرَّجُلُ وَجْهَهُ فَمَنْ شَاءَ كَدَحَ وَجْهَهُ وَمَنْ شَاءَ تَرَكَ إِلَّا أَنْ يَسْأَلَ الرَّجُلُ ذَا سُلْطَانٍ أَوْ شَيْئًا لَا يَجِدُ مِنْهُ بُدًّا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], berkata [Muhammad bin Bisyr], ia berkata; telah memberitakan kepada kami [Syu'bah] dari [Abdul Malik] dari [Zaid bin 'Uqbah] dari [Samurah bin Jundab], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Sesungguhnya meminta-minta itu (berakibat) seseorang mencakar-cakar wajahnya di hari kiamat, barangsiapa mau, hendaklah ia tinggalkan, kecuali jika seseorang meminta kepada pemimpin atau meminta sesuatu yang harus ia dapatkan.\""},"2468":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ عَنْ زَيْدِ بْنِ عُقْبَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْأَلَةُ كَدٌّ يَكُدُّ بِهَا الرَّجُلُ وَجْهَهُ إِلَّا أَنْ يَسْأَلَ الرَّجُلُ سُلْطَانًا أَوْ فِي أَمْرٍ لَا بُدَّ مِنْهُ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Waki'], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abdul Malik] dari [Zaid bin 'Uqbah] dari [Samurah bin Jundab], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Meminta-minta adalah pekerjaan yang berakibat seseorang mencakar wajahnya (di hari kiamat), kecuali seorang laki-laki yang meminta kepada penguasa atau perkara yang harus ia dapatkan.\""},"2469":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ بْنِ عَبْدِ الْجَبَّارِ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا حَكِيمُ إِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ فَمَنْ أَخَذَهُ بِطِيبِ نَفْسٍ بُورِكَ لَهُ فِيهِ وَمَنْ أَخَذَهُ بِإِشْرَافِ نَفْسٍ لَمْ يُبَارَكْ لَهُ فِيهِ وَكَانَ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى","id":"Telah mengabarkan kepada kami [Abdul Jabbar bin Al 'Ala` bin Abdul Jabbar] dari [Sufyan] dari [Az Zuhri], ia berkata; telah mengabarkan kepada kami ['Urwah] dari [Hakim bin Hizam], ia berkata; saya pernah meminta Rasulullah shallallahu 'alaihi wasallam, lalu beliau memberiku, kemudian saya meminta kepadanya, lalu beliau memberiku kemudian saya meminta kepadanya lalu beliau memberiku dan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Hakim, sesungguhnya harta adalah hijau dan manis, barang siapa yang mengambilnya dengan dengan kerelaan hati (orang yang memberi) maka ia akan diberkahi dalam harta tersebut, sebaliknya barang siapa yang mengambilnya dengan ketamakan hati maka ia tidak akan diberkahi dalam hartanya, dan ia seperti orang yang makan akan tetapi tidak merasa kenyang. Tangan yang di atas lebih baik daripada tangan yang di bawah.\""},"2470":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مِسْكِينُ بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا حَكِيمُ إِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ مَنْ أَخَذَهُ بِسَخَاوَةِ نَفْسٍ بُورِكَ لَهُ فِيهِ وَمَنْ أَخَذَهُ بِإِشْرَافِ النَّفْسِ لَمْ يُبَارَكْ لَهُ فِيهِ وَكَانَ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Miskin bin Bukair], ia berkata; telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Hakim bin Hizam], ia berkata; saya pernah meminta? Rasulullah shallallahu 'alaihi wasallam dan beliau memberiku, kemudian saya memintanya dan beliau memberiku, kemudian saya memintanya, dan beliau memberiku, kemudian Rasulullah shallallahu 'alaihi wasallam? bersabda: \"Wahai Hakim, harta ini adalah hijau dan manis, barang siapa yang mengambilnya dengan kelapangan hati (orang yang memberi) maka ia akan diberkati dalam harta tersebut, sedangkan barang siapa mengambilnya dengan ketamakan hati ia tidak diberkahi dalam harta tersebut, dan ia seperti orang yang makan tapi tidak merasakan kenyang. Tangan di atas lebih baik daripada tangan yang di bawah.\""},"2471":{"ar":"أَخْبَرَنِي الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ بَكْرٍ قَالَ حَدَّثَنِي أَبِي عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَسَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ حَكِيمَ بْنَ حِزَامٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا حَكِيمُ إِنَّ هَذَا الْمَالَ حُلْوَةٌ فَمَنْ أَخَذَهُ بِسَخَاوَةِ نَفْسٍ بُورِكَ لَهُ فِيهِ وَمَنْ أَخَذَهُ بِإِشْرَافِ نَفْسٍ لَمْ يُبَارَكْ لَهُ فِيهِ وَكَانَ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى قَالَ حَكِيمٌ فَقُلْتُ يَا رَسُولَ اللَّهِ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَا أَرْزَأُ أَحَدًا بَعْدَكَ حَتَّى أُفَارِقَ الدُّنْيَا بِشَيْءٍ","id":"Telah? mengabarkan kepada kami [Ar Rabi' bin Sulaiman bin Daud], ia berkata; telah? menceritakan kepada kami [Ishaq bin Bakr], ia berkata;? menceritakan kepadaku [ayahku] dari ['Amr bin Al Haris] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] serta [Sa'id bin Al Musayyab] bahwa [Hakim bin Hizam] berkata; Saya pernah meminta? Rasulullah shallallahu 'alaihi wasallam lalu beliau memberiku, kemudian saya memintanya lalu beliau memberiku kemudian? Rasulullah shallallahu 'alaihi wasallam? bersabda: \"Wahai Hakim, harta ini adalah manis, barang siapa yang mengambilnya dengan kelapangan hati (orang yang memberi) maka ia akan diberkahi, sebaliknya orang yang mengambilnya dengan ketamakan hati maka ia tidak diberkahi dalam harta tersebut, ia seperti orang yang makan akan tetapi tidak kenyang. Tangan yang di atas lebih baik daripada tangan yang di bawah.\" Hakim berkata; lalu saya berkata; wahai Rasulullah, demi Dzat yang mengutusmu dengan kebenaran, aku tidak akan mengurangi harta seorangpun sedikitpun setelahmu hingga berpisah dengan dunia. "},"2472":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَ��ْ بُكَيْرٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ ابْنِ السَّاعِدِيِّ الْمَالِكِيِّ قَالَاسْتَعْمَلَنِي عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ عَلَى الصَّدَقَةِ فَلَمَّا فَرَغْتُ مِنْهَا فَأَدَّيْتُهَا إِلَيْهِ أَمَرَ لِي بِعُمَالَةٍ فَقُلْتُ لَهُ إِنَّمَا عَمِلْتُ لِلَّهِ عَزَّ وَجَلَّ وَأَجْرِي عَلَى اللَّهِ عَزَّ وَجَلَّ فَقَالَ خُذْ مَا أَعْطَيْتُكَ فَإِنِّي قَدْ عَمِلْتُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ مِثْلَ قَوْلِكَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُعْطِيتَ شَيْئًا مِنْ غَيْرِ أَنْ تَسْأَلَ فَكُلْ وَتَصَدَّقْ","id":"Telah? mengabarkan kepada kami [Qutaibah], ia berkata;? menceritakan kepada kami [Al Laits] dari [Bukair] dari [Busr bin Sa'id] dari [Ibnu As Sa'idi Al Maliki], ia berkata; saya pernah ditunjuk [Umar] untuk mengurusi masalah sedekah, tatkala saya selesai mengurusinya dan menyampaikannya kepadanya, ia memerintahkan agar saya diberi uang, maka saya katakan; sesungguhnya saya bekerja hanya untuk Allah Azza wa Jalla, dan pahalaku di sisi Allah 'azza wajalla. Kemudian ia berkata; ambillah apa yang telah saya berikan kepadamu, karena saya pernah bekerja pada masa? Rasulullah shallallahu 'alaihi wasallam dan mengatakan seperti apa yang telah engkau katakan, kemudian beliau berkata kepadaku: \"Apabila engkau diberi sesuatu dengan tanpa meminta maka makan (ambillah) dan sedekahkan.\""},"2473":{"ar":"أَخْبَرَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ أَبُو عُبَيْدِ اللَّهِ الْمَخْزُومِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ حُوَيْطِبِ بْنِ عَبْدِ الْعُزَّى قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ السَّعْدِيِّأَنَّهُ قَدِمَ عَلَى عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ مِنْ الشَّامِ فَقَالَ أَلَمْ أُخْبَرْ أَنَّكَ تَعْمَلُ عَلَى عَمَلٍ مِنْ أَعْمَالِ الْمُسْلِمِينَ فَتُعْطَى عَلَيْهِ عُمَالَةً فَلَا تَقْبَلُهَا قَالَ أَجَلْ إِنَّ لِي أَفْرَاسًا وَأَعْبُدًا وَأَنَا بِخَيْرٍ وَأُرِيدُ أَنْ يَكُونَ عَمَلِي صَدَقَةً عَلَى الْمُسْلِمِينَ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ إِنِّي أَرَدْتُ الَّذِي أَرَدْتَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِينِي الْمَالَ فَأَقُولُ أَعْطِهِ مَنْ هُوَ أَفْقَرُ إِلَيْهِ مِنِّي وَإِنَّهُ أَعْطَانِي مَرَّةً مَالًا فَقُلْتُ لَهُ أَعْطِهِ مَنْ هُوَ أَحْوَجُ إِلَيْهِ مِنِّي فَقَالَ مَا آتَاكَ اللَّهُ عَزَّ وَجَلَّ مِنْ هَذَا الْمَالِ مِنْ غَيْرِ مَسْأَلَةٍ وَلَا إِشْرَافٍ فَخُذْهُ فَتَمَوَّلْهُ أَوْ تَصَدَّقْ بِهِ وَمَا لَا فَلَا تُتْبِعْهُ نَفْسَكَ","id":"Telah? mengabarkan kepada kami [Sa'id bin Abdur Rahman abu Ubaidillah Al Makhzumi], ia berkata; telah? menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [As Saib bin Yazin] dari [Huwaithib bin Abdul 'Uzza], ia berkata; telah mengabarkan kepadaku [Abdullah bin As Sa'di] bahwa ia pernah datang kepada Umar bin Al Khathab radliallahu 'anhu dari Syam kemudian ia berkata; bukankah aku telah diberi khabar bahwa engkau bekerja mengurusi suatu pekerjaan diantara pekerjaan orang-orang muslim lalu engkau diberi uang dan engkau tidak menerimanya?. Abdullah bin As Sa'di berkata; \"Benar, aku memiliki beberapa ekor kuda, dan beberapa orang sahaya dan aku dalam keadaan baik serta ingin agar amalku menjadi sedekah bagi orang-orang muslim. Maka [Umar] radliallahu 'anhu berkata; sesungguhnya aku telah menginginkan apa yang engkau inginkan, dahulu Nabi shallallahu 'alaihi wasallam memberiku harta, lalu aku mengatakan; berikan kepada orang yang lebih membutuhkannya daripada diriku. Dan beliau suatu kali memberiku harta, lalu aku mengatakan kepadanya; berikan kepada orang yang lebih membutuhkan kepadanya daripada diriku. Maka beliau bersabda: \"Apa yang telah Allah Azza wa Jalla berikan kepadamu tidak karena meminta dan tidak karena ketamakan maka ambillah, kemudian kembangkan atau sedekahkan, dan yang tidak demikian maka janganlah engkau perturutkan dirimu.\" "},"2474":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ أَنَّ حُوَيْطِبَ بْنَ عَبْدِ الْعُزَّى أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ السَّعْدِيِّ أَخْبَرَهُأَنَّهُ قَدِمَ عَلَى عُمَرَ بْنِ الْخَطَّابِ فِي خِلَافَتِهِ فَقَالَ لَهُ عُمَرُ أَلَمْ أُحَدَّثْ أَنَّكَ تَلِي مِنْ أَعْمَالِ النَّاسِ أَعْمَالًا فَإِذَا أُعْطِيتَ الْعُمَالَةَ رَدَدْتَهَا فَقُلْتُ بَلَى فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَمَا تُرِيدُ إِلَى ذَلِكَ فَقُلْتُ لِي أَفْرَاسٌ وَأَعْبُدٌ وَأَنَا بِخَيْرٍ وَأُرِيدُ أَنْ يَكُونَ عَمَلِي صَدَقَةً عَلَى الْمُسْلِمِينَ فَقَالَ لَهُ عُمَرُ فَلَا تَفْعَلْ فَإِنِّي كُنْتُ أَرَدْتُ مِثْلَ الَّذِي أَرَدْتَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِينِي الْعَطَاءَ فَأَقُولُ أَعْطِهِ أَفْقَرَ إِلَيْهِ مِنِّي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْهُ فَتَمَوَّلْهُ أَوْ تَصَدَّقْ بِهِ مَا جَاءَكَ مِنْ هَذَا الْمَالِ وَأَنْتَ غَيْرُ مُشْرِفٍ وَلَا سَائِلٍ فَخُذْهُ وَمَا لَا فَلَا تُتْبِعْهُ نَفْسَكَ","id":"Telah? mengabarkan kepada kami [Katsir bin 'Ubaid], ia berkata; telah? menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidy] dari [Az Zuhri] dari [As Saib bin Yazid] bahwa [Huwaithib bin Abdul 'Uzza] telah mengabarkan kepadanya bahwa [Abdullah bin As Sa'di] telah mengabarkan kepadanya bahwa ia datang kepada Umar bin Al Khathab pada masa kekhilafahannya, lalu [Umar] berkata kepadanya; Benarkah berita yang sampai padaku, bahwa engkau mengurusi beberapa pekerjaan manusia, kemudian apabila engkau diberi uang maka engkau menolaknya?. Maka aku katakan; benar. Lalu Umar radliallahu 'anhu berkata; \"apa yang kamu inginkan dengan melakukan hal tersebut?\" Maka saya katakan; \"saya memiliki beberapa ekor kuda, serta beberapa sahaya dan aku dalam keadaan baik. Saya ingin amalanku menjadi sedekah kepada orang-orang muslim\". Maka Umar berkata kepadanya; \"Janganlah engkau melakukan hal tersebut, sesungguhnya aku pernah berkeinginan seperti yang engkau inginkan. Dahulu Rasulullah shallallahu 'alaihi wasallam memberikan pemberian kepadaku lalu aku katakan; berikan kepada orang yang lebih membutuhkannya daripada diriku. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ambillah kemudian kembangkan atau sedekahkan, apa yang datang kepadamu dari harta ini sedang kamu tidak tamak dan tidak meminta maka ambillah dan yang tidak demikian maka janganlah engkau perturutkan dirimu.\""},"2475":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ وَإِسْحَقُ بْنُ مَنْصُورٍ عَنْ الْحَكَمِ بْنِ نَافِعٍ قَالَ أَنْبَأَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي السَّائِبُ بْنُ يَزِيدَ أَنَّ حُوَيْطِبَ بْنَ عَبْدِ الْعُزَّى أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ السَّعْدِيِّ أَخْبَرَهُأَنَّهُ قَدِمَ عَلَى عُمَرَ بْنِ الْخَطَّابِ فِي خِلَافَتِهِ فَقَالَ عُمَرُ أَلَمْ أُخْبَرْ أَنَّكَ تَلِي مِنْ أَعْمَالِ النَّاسِ أَعْمَالًا فَإِذَا أُعْطِيتَ الْعُمَالَةَ كَرِهْتَهَا قَالَ فَقُلْتُ بَلَى قَالَ فَمَا تُرِيدُ إِلَى ذَلِكَ فَقُلْتُ إِنَّ لِي أَفْرَاسًا وَأَعْبُدًا وَأَنَا بِخَيْرٍ وَأُرِيدُ أَنْ يَكُونَ عَمَلِي صَدَقَةً عَلَى الْمُسْلِمِينَ فَقَالَ عُمَرُ فَلَا تَفْعَلْ فَإِنِّي كُنْتُ أَرَدْتُ الَّذِي أَرَدْتَ فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِينِي الْعَطَاءَ فَأَقُولُ أَعْطِهِ أَفْقَرَ إِلَيْهِ مِنِّي حَتَّى أَعْطَانِي مَرَّةً مَالًا فَقُلْتُ أَعْطِهِ أَفْقَرَ إِلَيْهِ مِنِّي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْهُ فَتَمَوَّلْهُ وَتَصَدَّقْ بِهِ فَمَا جَاءَكَ مِنْ هَذَا الْمَالِ وَأَنْتَ غَيْرُ مُشْرِفٍ وَلَا سَائِلٍ فَخُذْهُ وَمَا لَا فَلَا تُتْبِعْهُ نَفْسَكَ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dan [Ishaq bin Manshur] dari [Al Hakam bin Nafi'], ia berkata; telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri], ia berkata; telah mengabarkan kepadaku [As Saib bin Yazid] bahwa [Huwaithib bin Abdul 'Uzza] telah mengabarkan kepadanya [Abdullah bin As Sa'di] telah mengabarkan kepadanya bahwa ia telah datang kepada Umar bin Al Khathab pada masa kekhilafahannya, lalu [Umar] berkata; Benarkah berita yang sampai kepadaku, bahwa engkau mengurusi beberapa pekerjaan manusia, kemudian apabila engkau diberi uang, maka engkau tidak menginginkannya. Ia berkata; maka aku katakan; \"Iya\". Umar bertanya; \"Apa yang kamu inginkan dengan melakukan hal tersebut?\" Maka saya katakan; \"Saya memiliki beberapa ekor kuda, serta beberapa sahaya dan aku dalam keadaan baik. Saya ingin amalanku menjadi sedekah kepada orang-orang muslim. Maka Umar berkata kepadanya; \"Janganlah engkau melakukan hal tersebut, sesungguhnya aku pernah berkeinginan seperti yang engkau inginkan. Dahulu Nabi shallallahu 'alaihi wasallam memberikan pemberian kepadaku lalu aku katakan; berikan kepada orang yang lebih membutuhkannya daripada diriku. Hingga beliau suatu kali beliau memberiku harta, lalu saya katakan; berikan kepada orang yang lebih membutuhkannya daripada diriku. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Ambillah kemudian kembangkan dan sedekahkan, apa yang datang kepadamu dari harta ini sedang engkau tidak tamak dan tidak meminta maka ambillah dan yang tidak demikian maka jangan engkau perturutkan dirimu.\""},"2476":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ قَالَ أَنْبَأَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ سَمِعْتُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِينِي الْعَطَاءَ فَأَقُولُ أَعْطِهِ أَفْقَرَ إِلَيْهِ مِنِّي حَتَّى أَعْطَانِي مَرَّةً مَالًا فَقُلْتُ لَهُ أَعْطِهِ أَفْقَرَ إِلَيْهِ مِنِّي فَقَالَ خُذْهُ فَتَمَوَّلْهُ وَتَصَدَّقْ بِهِ وَمَا جَاءَكَ مِنْ هَذَا الْمَالِ وَأَنْتَ غَيْرُ مُشْرِفٍ وَلَا سَائِلٍ فَخُذْهُ وَمَا لَا فَلَا تُتْبِعْهُ نَفْسَكَ","id":"Telah? mengabarkan kepada kami ['Amr bin Manshur], ia berkata; telah? menceritakan kepada kami [Al Hakam bin Nafi'], ia berkata; telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; telah mengabarkan kepadaku [Salim bin Abdullah] bahwa [Abdullah bin Umar] berkata; saya pernah mendengar [Umar] radliallahu 'anhu berkata; Nabi shallallahu 'alaihi wasallam pernah memberikan pemberian kepadaku, lalu saya katakan; berikan kepada orang yang lebih membutuhkannya daripada diriku, hingga suatu kali beliau memberiku harta lalu aku katakan kepadanya; berikan kepada orang yang lebih membutuhkannya daripada diriku. Maka beliau bersabda: \"Ambillah, kemudian kembangkan dan sedekahkan. Apa yang datang kepadamu dari harta ini sedang kamu tidak tamak, dan tidak meminta maka ambillah dan yang tidak demikian, maka janganlah engkau perturutkan dirimu.\" "},"2477":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو عَنْ ابْنِ وَهْبٍ قَالَ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ الْهَاشِمِيِّ أَنَّ عَبْدَ الْمُطَّلِبِ بْنَ رَبِيعَةَ بْنِ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ أَخْبَرَهُأَنَّ أَبَاهُ رَبِيعَةَ بْنَ الْحَارِثِ قَالَ لِعَبْدِ الْمُطَّلِبِ بْنِ رَبِيعَةَ بْنِ الْحَارِثِ وَالْفَضْلِ بْنِ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ ائْتِيَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُولَا لَهُ اسْتَعْمِلْنَا يَا رَسُولَ اللَّهِ عَلَى الصَّدَقَاتِ فَأَتَى عَلِيُّ بْنُ أَبِي طَالِبٍ وَنَحْنُ عَلَى تِلْكَ الْحَالِ فَقَالَ لَهُمَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَسْتَعْمِلُ مِنْكُمْ أَحَدًا عَلَى الصَّدَقَةِ قَالَ عَبْدُ الْمُطَّلِبِ فَانْطَلَقْتُ أَنَا وَالْفَضْلُ حَتَّى أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَنَا إِنَّ هَذِهِ الصَّدَقَةَ إِنَّمَا هِيَ أَوْسَاخُ النَّاسِ وَإِنَّهَا لَا تَحِلُّ لِمُحَمَّدٍ وَلَا لِآلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah? mengabarkan kepada kami ['Amr bin Sawwad bin Al Aswad bin 'Amr] dari [Ibnu Wahb], ia berkata; telah? menceritakan kepada kami [Yunus] dari [Ibnu Syihab] dari [Abdullah bin Al Harits bin Naufal Al Hasyimi] bahwa [Abdul Muththalib bin Rabi'ah bin Al Harits bin Abdul Muththalib] telah mengabarkan kepadanya bahwa bapaknya yaitu Rabi'ah bin Al Harits berkata kepada Abdul Muththalib bin Rabi'ah bin Al Harits serta Al Fadhl bin Al Abbas bin Abdul Muththalib; \"Datanglah kalian berdua kepada Rasulullah shallallahu 'alaihi wasallam kemudian katakan kepadanya; angkatlah kami untuk mengurusi masalah shadaqah wahai Rasulullah. Lalu datang [Ali bin Abu Thalib] dan kami dalam keadaan tersebut, kemudian ia berkata kepada mereka berdua; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam tidak mengangkat salah seorang dari kalian untuk mengurusi masalah shadaqah. Abdul Muththalib berkata; lalu aku bersama Al Fadhl pergi, hingga kami datang kepada Rasulullah shallallahu 'alaihi wasallam. Lalu beliau bersabda kepada kami: \"Sesungguhnya shadaqah ini merupakan kotoran-kotoran manusia, dan shadaqah tersebut tidak halal bagi Muhammad dan keluarga Muhammad shallallahu 'alaihi wasallam.\" "},"2478":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ قُلْتُ لِأَبِي إِيَاسٍ مُعَاوِيَةَ بْنِ قُرَّةَ أَسَمِعْتَ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنُ أُخْتِ الْقَوْمِ مِنْ أَنْفُسِهِمْ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah? bercerita kepada kami [Waki'], ia berkata; telah bercerita kepada kami [Syu'bah], ia berkata; saya pernah mengatakan kepada [Abu Iyas Mu'awiyah bin Qurrah], apakah engkau pernah mendengar [Anas bin bin Malik] mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak laki-laki saudara perempuan suatu kaum termasuk bagian dari mereka?\" Ia berkata; ya. "},"2479":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ أُخْتِ الْقَوْمِ مِنْهُمْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah? memberitakan kepada kami [Waki'], ia berkata; telah bercerita kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak laki-laki saudara perempuan suatu kaum merupakan bagian dari mereka.\" "},"2480":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا الْحَكَمُ عَنْ ابْنِ أَبِي رَافِعٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ رَجُلًا مِنْ بَنِي مَخْزُومٍ عَلَى الصَّدَقَةِ فَأَرَادَ أَبُو رَافِعٍ أَنْ يَتْبَعَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الصَّدَقَةَ لَا تَحِلُّ لَنَا وَإِنَّ مَوْلَى الْقَوْمِ مِنْهُمْ","id":"Telah? mengabarkan kepada kami ['Amr bin Ali], ia berkata; bercerita kepada kami [Yahya], ia berkata;? bercerita kepada kami [Syu'bah] ia berkata; telah? bercerita kepada kami [Al Hakam] dari [Ibnu Abi Rafi'] dari [bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam mengangkat seseorang dari Bani Makhzum untuk mengurusi permasalahan shadaqah, lalu Abu Rafi' ingin mengikutinya, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya shadaqah tidaklah halal bagi kami, dan sesungguhnya hamba sahaya suatu kaum merupakan bagian dari mereka.\" "},"2481":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ وَاصِلٍ قَالَ حَدَّثَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُتِيَ بِشَيْءٍ سَأَلَ عَنْهُ أَهَدِيَّةٌ أَمْ صَدَقَةٌ فَإِنْ قِيلَ صَدَقَةٌ لَمْ يَأْكُلْ وَإِنْ قِيلَ هَدِيَّةٌ بَسَطَ يَدَهُ","id":"Telah? mengabarkan kepada kami [Ziyad bin Ayub], ia berkata; telah? menceritakan kepada kami [Abdul Wahid bin Washil], ia berkata; telah? menceritakan kepada kami [Bahz bin Hakim] dari [bapaknya] dari [kakeknya], ia berkata; Nabi shallallahu 'alaihi wasallam apabila diberi sesuatu maka beliau bertanya: \"Apakah itu hadiah atau shadaqah?\" Kemudian apabila ada berita itu adalah shadaqah, maka beliau tidak memakannya dan apabila ada berita itu adalah hadiah, maka beliau membentangkan tangannya. "},"2482":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا الْحَكَمُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّهَا أَرَادَتْ أَنْ تَشْتَرِيَ بَرِيرَةَ فَتُعْتِقَهَا وَإِنَّهُمْ اشْتَرَطُوا وَلَاءَهَا فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اشْتَرِيهَا وَأَعْتِقِيهَا فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ وَخُيِّرَتْ حِينَ أُعْتِقَتْ وَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْمٍ فَقِيلَ هَذَا مِمَّا تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَقَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ وَكَانَ زَوْجُهَا حُرًّا","id":"Telah? mengabarkan kepada kami ['Amr bin Yazid], ia berkata;? telah menceritakan kepada kami [Bahz bin Asad], ia berkata;? telah menceritakan kepada kami [Syu'bah], ia berkata;? telah menceritakan kepada kami [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] bahwa ia ingin membeli Barirah lalu ia memerdekakannya, namun mereka (tuan-tuannya) memberikan syarat agar mereka tetap menjadi walinya, lalu ia menceritakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam maka beliau bersabda: \" Belilah dia dan merdekakan, sesungguhnya perwalian itu bagi yang memerdekakakan.\" Lalu ia diberi pilihan ketika dimerdekakan, dan Rasulullah shallallahu 'alaihi wasallam diberi daging kemudian dikatakan ini adalah sebagian shadaqah yang diberikan kepada Barirah. Maka beliau bersabda: \"Hal itu baginya merupakan shadaqah dan bagi kami merupakan hadiah.\" Dan suami Barirah adalah orang yang merdeka. "},"2483":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ قَالَ سَمِعْتُ عُمَرَ يَقُولُحَمَلْتُ عَلَى فَرَسٍ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَأَضَاعَهُ الَّذِي كَانَ عِنْدَهُ وَأَرَدْتُ أَنْ أَبْتَاعَهُ مِنْهُ وَظَنَنْتُ أَنَّهُ بَائِعُهُ بِرُخْصٍ فَسَأَلْتُ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَشْتَرِهِ وَإِنْ أَعْطَاكَهُ بِدِرْهَمٍ فَإِنَّ الْعَائِدَ فِي صَدَقَتِهِ كَالْكَلْبِ يَعُودُ فِي قَيْئِهِ","id":"Telah? mengabarkan kepada kami [Muhammad bin Salamah] dan [Harits bin Miskin] dengan membacakan riwayat, dan saya mendengarkan dari [Ibnul Qasim], ia berkata;? menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari [bapaknya], ia berkata; saya pernah mendengar [Umar] berkata; saya pernah menanggung kuda di jalan Allah 'azza wajalla, kemudian oang yang memilikinya tidak memperhatikannya, dan saya ingin membelinya dari orang tersebut dan menyangka bahwa ia akan menjualnya dengan harga murah. Lalu saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hal tersebut, maka beliau bersabda: \"Jangan engkau membelinya, walaupun ia memberimu dengan harga satu dirham, karena orang yang mengambil shadaqahnya seperti seekor anjing yang menjilat kembali muntahannya.\""},"2484":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ عُمَرَأَنَّهُ حَمَلَ عَلَى فَرَسٍ فِي سَبِيلِ اللَّهِ فَرَآهَا تُبَاعُ فَأَرَادَ شِرَاءَهَا فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَعْرِضْ فِي صَدَقَتِكَ","id":"Telah? mengabarkan kepada kami [Harun bin Ishaq], ia berkata; telah? menceritakan kepada kami [Abdur Razzaq] dari [Ma'mar] dari [Az Zuhri] dari [Salim bin Abdullah] dari [bapaknya] dari [Umar] bahwa ia telah menanggung kuda di jalan Allah, kemudian ia melihatnya dijual, maka ia ingin membelinya. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan engkau menawar shadaqahmu.\""},"2485":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ أَنْبَأَنَا حُجَيْنٌ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ كَانَ يُحَدِّثُأَنَّ عُمَرَ تَصَدَّقَ بِفَرَسٍ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَوَجَدَهَا تُبَاعُ بَعْدَ ذَلِكَ فَأَرَادَ أَنْ يَشْتَرِيَهُ ثُمَّ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْمَرَهُ فِي ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَعُدْ فِي صَدَقَتِكَ","id":"Telah? mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak], ia berkata; telah memberitakan kepada kami [Hujain], ia berkata; telah? menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Salim bin Abdullah] bahwa [Abdullah bin Umar] pernah menceritakan bahwa Umar bershadah dengan seekor kuda di jalan Allah Azza wa jalla, lalu ia mendapati kuda tersebut dijual setelah itu. Maka ia ingin membelinya kemudian ia datang kepada Rasulullah shallallahu 'alaihi wasallam, meminta petunjuk mengenai hal tersebut, maka Rasulullah shallallahu 'alaihi wasallam bersabda: Jangan engkau mengambil kembali shadaqahmu.\""},"2486":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا بِشْرٌ وَيَزِيدُ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ عَتَّابَ بْنَ أَسِيدٍ أَنْ يَخْرُصَ الْعِنَبَ فَتُؤَدَّى زَكَاتُهُ زَبِيبًا كَمَا تُؤَدَّى زَكَاةُ النَّخْلِ تَمْرًا","id":"Telah? mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah? menceritakan kepada kami [Bisyr] serta [Yazid], mereka berdua berkata; telah? menceritakan kepada kami [Abdur Rahman bin Ishaq] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] bahwa Rasulullah shallallahu 'alaihi wasallam menyuruh Atab bin Asid untuk menakar anggur, lalu menunaikan zakatnya dalam bentuk kismis seperti halnya zakat pohon kurma ditunaikan zakatnya dalam bentuk buah kurma."},"2487":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرِّمِيُّ قَالَ حَدَّثَنَا أَبُو هِشَامٍ وَاسْمُهُ الْمُغِيرَةُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا الرَّبِيعُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ قَالَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ فَرَضَ عَلَيْكُمْ الْحَجَّ فَقَالَ رَجُلٌ فِي كُلِّ عَامٍ فَسَكَتَ عَنْهُ حَتَّى أَعَادَهُ ثَلَاثًا فَقَالَ لَوْ قُلْتُ نَعَمْ لَوَجَبَتْ وَلَوْ وَجَبَتْ مَا قُمْتُمْ بِهَا ذَرُونِي مَا تَرَكْتُكُمْ فَإِنَّمَا هَلَكَ مَنْ كَانَ قَبْلَكُمْ بِكَثْرَةِ سُؤَالِهِمْ وَاخْتِلَافِهِمْ عَلَى أَنْبِيَائِهِمْ فَإِذَا أَمَرْتُكُمْ بِالشَّيْءِ فَخُذُوا بِهِ مَا اسْتَطَعْتُمْ وَإِذَا نَهَيْتُكُمْ عَنْ شَيْءٍ فَاجْتَنِبُوهُ","id":"Telah? mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak Al Makhzumi], ia berkata; telah? menceritakan kepada kami [Abu Hisyam namanya adalah Al Mughirah bin Salamah], ia berkata; telah? menceritakan kepada kami [Ar Rabi' bin Muslim], ia berkata; telah? menceritakan kepada kami [Muhammad bin Ziyad] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada manusia kemudian beliau bersabda: \"Sesungguhnya Allah Azza wa Jalla telah mewajibkan kepada kalian untuk melakukan haji.\" Lalu terdapat seorang laki-laki yang bertanya; apakah setiap tahun? Maka beliau terdiam hingga orang tersebut mengulangnya sebanyak tiga kali. Lalu beliau bersabda: \"Jika saya katakan \"ya\", niscaya akan menjadi wajib, dan jika telah wajib maka kalian tidak mampu melakukannya. Biarkan saya, tidaklah saya meninggalkan kalian, sesungguhnya orang-orang sebelum kalian binasa karena banyak bertanya, dan sering menyelisihi para nabi. Maka apabila saya perintahkan sesuatu kepada kalian, lakukanlah sesuai dengan kemampuan kalian, dan jika saya melarang kalian dari sesuatu maka jauhilah.\""},"2488":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ النَّيْسَابُورِيُّ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ قَالَ أَنْبَأَنَا مُوسَى بْنُ سَلَمَةَ قَالَ حَدَّثَنِي عَبْدُ الْجَلِيلِ بْنُ حُمَيْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سِنَانٍ الدُّؤَلِيِّ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فَقَالَ إِنَّ اللَّهَ تَعَالَى كَتَبَ عَلَيْكُمْ الْحَجَّ فَقَالَ الْأَقْرَعُ بْنُ حَابِسٍ التَّمِيمِيُّ كُلُّ عَامٍ يَا رَسُولَ اللَّهِ فَسَكَتَ فَقَالَ لَوْ قُلْتُ نَعَمْ لَوَجَبَتْ ثُمَّ إِذًا لَا تَسْمَعُونَ وَلَا تُطِيعُونَ وَلَكِنَّهُ حَجَّةٌ وَاحِدَةٌ","id":"Telah? mengabarkan kepada kami [Muhammad bin Yahya bin Abdullah An Naisaburi], ia berkata; telah? menceritakan kepada kami [Sa'id bin Abu Maryam], ia berkata; telah memberitakan kepada kami [Musa bin Salamah], ia berkata; telah? menceritakan kepada kami [Abdul Jalil bin Humaid] dari [Ibnu Syihab] dari [Abu Sinan Ad Duali] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah berdiri seraya bersabda: \"Allah ta'ala telah mewajibkan haji kepada kalian.\" Lalu Al Aqra' bin Habis At Taimi berkata; \"Apakah setiap tahun wahai Rasulullah?\" beliau terdiam, lalu bersabda: \"Jika saya katakan \"ya\", niscaya menjadi wajib, kemudian jika demikian maka kalian tidak akan mendengar dan mentaati, akan tetapi haji hanyalah sekali.\" "},"2489":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ سَالِمٍ قَالَ سَمِعْتُ عَمْرَو بْنَ أَوْسٍ يُحَدِّثُ عَنْ أَبِي رَزِينٍ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنَّ أَبِي شَيْخٌ كَبِيرٌ لَا يَسْتَطِيعُ الْحَجَّ وَلَا الْعُمْرَةَ وَلَا الظَّعْنَ قَالَ فَحُجَّ عَنْ أَبِيكَ وَاعْتَمِرْ","id":"Telah? mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah? menceritakan kepada kami [Khalid], ia berkata; telah? menceritakan kepada kami [Syu'bah], ia berkata; saya pernah mendengar [An Nu'man bin Salim] berkata; saya pernah mendengar ['Amr bin Aus] menceritakan dari [Abu Razin] bahwa ia berkata; wahai Rasulullah, ayahku adalah orang yang telah tua, tidak mampu melakukan haji serta umrah, serta bersafar. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lakukanlah haji untuk ayahmu dan berumrahlah.\""},"2490":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ الصَّفَّارِ الْبَصْرِيُّ قَالَ حَدَّثَنَا سُوَيْدٌ وَهُوَ ابْنُ عَمْرٍو الْكَلْبِيُّ عَنْ زُهَيْرٍ قَالَ حَدَّثَنَا سُهَيْلٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَجَّةُ الْمَبْرُورَةُ لَيْسَ لَهَا جَزَاءٌ إِلَّا الْجَنَّةُ وَالْعُمْرَةُ إِلَى الْعُمْرَةِ كَفَّارَةٌ لِمَا بَيْنَهُمَا","id":"Telah mengabarkan kepada kami [Abdah bin Abdullah Ash Shaffar Al Bashri], ia berkata; telah menceritakan kepada kami [Suwaid yaitu Ibnu 'Amr Al Kalbi] dari [Zuhair], ia berkata; telah menceritakan kepada kami [Suhail] dari [Sumay] dari [Abu Shaleh] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Haji yang mabrur tidak ada balasan baginya kecuali Surga, dan umrah satu hingga umrah yang lain merupakan penghapus dosa diantara keduanya.\""},"2491":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي سُهَيْلٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَجَّةُ الْمَبْرُورَةُ لَيْسَ لَهَا ثَوَابٌ إِلَّا الْجَنَّةُ مِثْلَهُ سَوَاءً إِلَّا أَنَّهُ قَالَ تُكَفِّرُ مَا بَيْنَهُمَا","id":"Telah mengabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah mengabarkan kepadaku [Suhail] dari [Sumay] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Haji mabrur tidak mendatangkan pahala kecuali Surga.\" Persis seperti itu, hanya saja beliau bersabda: \"Menghapuskan dosa diantara keduanya.\""},"2492":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَسَأَلَ رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ الْإِيمَانُ بِاللَّهِ قَالَ ثُمَّ مَاذَا قَالَ الْجِهَادُ فِي سَبِيلِ اللَّهِ قَالَ ثُمَّ مَاذَا قَالَ ثُمَّ الْحَجُّ الْمَبْرُورُ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'], ia berkata; telah menceritakan kepada kami [Abdurrazzaq], ia berkata; telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnul Musayyab] dari [Abu Hurairah], ia berkata; terdapat seorang laki-laki yang bertanya kepada Nabi shallallahu 'alaihi wasallam, ia berkata; \"Wahai Rasulullah, amalan apakah yang paling baik? Beliau menjawab: \"Beriman kepada Allah.\" Orang tersebut berkata; kemudian apa? Beliau menjawab: \"Berjihad di jalan Allah.\" Laki-laki tersebut berkata; kemudian apa? beliau menjawab: \"Haji mabrur.\""},"2493":{"ar":"أَخْبَرَنَا عِيسَى بْنُ إِبْرَاهِيمَ بْنِ مَثْرُودٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ مَخْرَمَةَ عَنْ أَبِيهِ قَالَ سَمِعْتُ سُهَيْلَ بْنَ أَبِي صَالِحٍ قَالَ سَمِعْتُ أَبِي يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفْدُ اللَّهِ ثَلَاثَةٌ الْغَازِي وَالْحَاجُّ وَالْمُعْتَمِرُ","id":"Telah mengabarkan kepada kami [Isa bin Ibrahim bin Matsrud], ia berkarta; telah menceritakan kepada kami [Ibnu Wahb] dari [Makhramah] dari [Bapaknya], ia berkata; saya mendengar [Suhail bin Abi Shaleh] berkata; aku mendengar [ayahku] berkata; aku mendengar [Abu Hurairah] berkata Rasulullah shallallahu 'alaihi wasallam bersabda: \"Utusan Allah itu ada tiga, yaitu: orang yang berjuang, orang yang melakukan haji dan orang yang melakukan umrah.\" "},"2494":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ قَالَ حَدَّثَنَا خَالِدٌ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جِهَادُ الْكَبِيرِ وَالصَّغِيرِ وَالضَّعِيفِ وَالْمَرْأَةِ الْحَجُّ وَالْعُمْرَةُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakam] dari [Syu'aib] dari [Al Laits], ia berkata; telah menceritakan kepada kami [Khalid] dari [Ibnu Abi Hilal] dari [Yazid bin Abdullah], dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jihad orang yang sudah tua, anak kecil, orang yang lemah dan seorang wanita adalah melakukan haji dan umrah.\""},"2495":{"ar":"أَخْبَرَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا الْفُضَيْلُ وَهُوَ ابْنُ عِيَاضٍ عَنْ مَنْصُورٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَجَّ هَذَا الْبَيْتَ فَلَمْ يَرْفُثْ وَلَمْ يَفْسُقْ رَجَعَ كَمَا وَلَدَتْهُ أُمُّهُ","id":"Telah mengabarkan kepada kami [Abu 'Ammar Al Husaini bin Huwairits Al Maruzi], ia berkata; telah menceritakan kepada kami [Al Fudhail yaitu Ibnu 'Iyadh], dari [Manshur], dari [Abu Hazim], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang melakukan haji ke Ka'bah ini, lantas tidak berkata-kata kotor serta tidak melakukan tindakan kefasikan, ia kembali seperti dilahirkan ibunya.\""},"2496":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ حَبِيبٍ وَهُوَ ابْنُ أَبِي عَمْرَةَ عَنْ عَائِشَةَ بِنْتِ طَلْحَةَ قَالَتْ أَخْبَرَتْنِي أُمُّ الْمُؤْمِنِينَ عَائِشَةُ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ أَلَا نَخْرُجُ فَنُجَاهِدَ مَعَكَ فَإِنِّي لَا أَرَى عَمَلًا فِي الْقُرْآنِ أَفْضَلَ مِنْ الْجِهَادِ قَالَ لَا وَلَكُنَّ أَحْسَنُ الْجِهَادِ وَأَجْمَلُهُ حَجُّ الْبَيْتِ حَجٌّ مَبْرُورٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Jarir] dari [Hubaib yaitu Ibnu Abu 'Amrah] dari [Aisyah binti Thalhah], ia berkata; telah mengabarkan kepadaku [Ummul mukminin Aisyah], ia berkata; aku pernah mengatakan; \"Wahai Rasulullah, tidakkah kami boleh berangkat berjihad bersamamu, karena aku tidak melihat suatu amalan didalam Alquran yang lebih utama daripada jihad?. Maka beliau bersabda: \" Tapi sebaik-baik jihad dan yang paling indah adalah haji di Ka'bah atau haji mabrur.\""},"2497":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَةُ إِلَى الْعُمْرَةِ كَفَّارَةٌ لِمَا بَيْنَهُمَا وَالْحَجُّ الْمَبْرُورُ لَيْسَ لَهُ جَزَاءٌ إِلَّا الْجَنَّةُ","id":"Telah mengabarkan kepada kami [Qutaiabah bin Sa'id] dari [Malik] dari [Sumay] dari [Abu Shaleh] dari [Abu Hurairah], ia berkata Rasulullah shallallahu 'alaihi wasallam bersabda; \"Umrah satu hingga umrah yang lain adalah penghapus dosa antara keduanya, dan haji mabrur tidak ada balasan baginya kecuali Surga.\""},"2498":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا أَبُو عَتَّابٍ قَالَ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ قَالَ ابْنُ عَبَّاسٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَابِعُوا بَيْنَ الْحَجِّ وَالْعُمْرَةِ فَإِنَّهُمَا يَنْفِيَانِ الْفَقْرَ وَالذُّنُوبَ كَمَا يَنْفِي الْكِيرُ خَبَثَ الْحَدِيدِ","id":"Telah mengabarkan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Abu 'Attab], ia berkata; telah menceritakan kepada kami ['Azrah bin Tsabit] dari ['Amr bin Dinar], ia berkata; [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ikutsertakanlah antara haji dan umrah karena keduanya menghilangkan kefakiran dan dosa sebagaimana kiir (alat peniup api) menghilangkan kotoran besi.\""},"2499":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ أَيُّوبَ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَيَّانَ أَبُو خَالِدٍ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ عَاصِمٍ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَابِعُوا بَيْنَ الْحَجِّ وَالْعُمْرَةِ فَإِنَّهُمَا يَنْفِيَانِ الْفَقْرَ وَالذُّنُوبَ كَمَا يَنْفِي الْكِيرُ خَبَثَ الْحَدِيدِ وَالذَّهَبِ وَالْفِضَّةِ وَلَيْسَ لِلْحَجِّ الْمَبْرُورِ ثَوَابٌ دُونَ الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Ayyub], ia berkata; telah menceritakan kepada kami [Sulaiman bin Hayyan Abu Khalid] dari ['Amr bin Qais] dari ['Ashim] dari [Syaqiq] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ikutkanlah antara haji dan umrah, keduanya dapat menghilangkan kefakiran dan dosa sebagaimana peniup api menghilangkan kotoran besi, emas, serta perak. Dan tidak ada pahala bagi haji selain Surga.\""},"2500":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍأَنَّ امْرَأَةً نَذَرَتْ أَنْ تَحُجَّ فَمَاتَتْ فَأَتَى أَخُوهَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ ذَلِكَ فَقَالَ أَرَأَيْتَ لَوْ كَانَ عَلَى أُخْتِكَ دَيْنٌ أَكُنْتَ قَاضِيَهُ قَالَ نَعَمْ قَالَ فَاقْضُوا اللَّهَ فَهُوَ أَحَقُّ بِالْوَفَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar], ia berkata; telah menceritakan kepada kami [Muhammad], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr], ia berkata; saya pernah mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Abbas] bahwa terdapat seorang wanita yang bernadzar untuk melakukan haji lalu ia meninggal. Kemudian saudara laki-lakinya menemui Nabi shallallahu 'alaihi wasallam dan bertanya kepada beliau mengenai hal tersebut, maka beliau bersabda: \"Bagaimana pendapatmu apabila saudaramu memiliki hutang, apakah engkau akan membayarnya?\" Maka orang tersebut mengatakan; \"Iya\". Beliau bersabda: \"Bayarlah hutang kepada Allah, Dia lebih berhak untuk ditunaikan hutang-Nya.\""}};
